window.HADITH_CACHE["nasai_2"] = {"1001":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ عَنْ وَكِيعٍ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ أَبِي الْعَلَاءِ عَنْ يَحْيَى بْنِ جَعْدَةَ عَنْ أُمِّ هَانِئٍ قَالَتْكُنْتُ أَسْمَعُ قِرَاءَةَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا عَلَى عَرِيشِي","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad Dauraqiy] dari [Waki'] dia berkata; telah menceritakan kepada kami [Mis'ar] dari [Abu Al 'Alaa] dari [Yahya bin Ja'dah] dari [Ummu Hani'] dia berkata; \"Aku mendengar bacaan Rasulullah Shallallahu'alaihi wasallam, sementara aku sedang berada di atas bangsal (tandu).\""},"1002":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ قَالَ سَأَلْتُ أَنَسًاكَيْفَ كَانَتْ قِرَاءَةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَانَ يَمُدُّ صَوْتَهُ مَدًّا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Jarir bin Hazim] dari [Qatadah] dia berkata; \"Aku bertanya kepada [Anas], 'Bagaimana bacaan (Al Qur'an) Rasulullah Shallallahu'alaihi wasallam? ' la menjawab, \"Rasulullah Shallallahu'alaihi wasallam memanjangkan suaranya.\""},"1003":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْسَجَةَ عَنْ الْبَرَاءِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيِّنُوا الْقُرْآنَ بِأَصْوَاتِكُمْ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Thalhah bin Musharrif] dari ['Abdurrahman bin 'Ausajah] dari [Al Barra'] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Indahkan suaramu dalam membaca AI Qur 'an.\""},"1004":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي طَلْحَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَوْسَجَةَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيِّنُوا الْقُرْآنَ بِأَصْوَاتِكُمْقَالَ ابْنُ عَوْسَجَةَ كُنْتُ نَسِيتُ هَذِهِ زَيِّنُوا الْقُرْآنَ حَتَّى ذَكَّرَنِيهِ الضَّحَّاكُ بْنُ مُزَاحِمٍ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Thalhah] dari ['Abdurrahman bin 'Ausajah] dari [Al Barra' bin 'Azib] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Indahkan suaramu dalam membaca AI Qur'an.\" "},"1005":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ زُنْبُورٍ الْمَكِّيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي حَازِمٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ حَسَنِ الصَّوْتِ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Zunbur Al Makki] dia berkata; telah menceritakan kepada kami [Ibnu Abu Hazim] dari [Yazid bin 'Abdullah] dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] dia pernah mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Allah subhanahu wata'ala tidak pernah mengijinkan untuk (melakukan) sesuatu sebagaimana Dia mengizinkan nabi-Nya untuk memperindah dan mengeraskan suaranya saat membaca Al Qur'an.\""},"1006":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَذِنَ اللَّهُ عَزَّ وَجَلَّ لِشَيْءٍ يَعْنِي أَذَنَهُ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Allah tidak pernah mengijinkan untuk sesuatu sebagaimana Dia mengijinkan Nabi-Nya untuk memperindah suara saat membaca Al Qur'an.\""},"1007":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ أَنَّ أَبَا سَلَمَةَ أَخْبَرَهُ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ قِرَاءَةَ أَبِي مُوسَى فَقَالَ لَقَدْ أُوتِيَ مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ عَلَيْهِ السَّلَام","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amr bin Al Harits] Telah mengabarkan kepadanya [Ibnu Syihab] telah mengabarkan kepadanya [Abu Salamah] telah menceritakan kepadanya [Abu Hurairah] bahwa; Rasulullah Shallallahu'alaihi wasallam mendengar bacaan Abu Musa, maka beliau bersabda: \"la telah diberi suara indah dari suara indahnya keluarga nabi Daud Alaihissalam.\""},"1008":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ بْنِ عَبْدِ الْجَبَّارِ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةَ أَبِي مُوسَى فَقَالَ لَقَدْ أُوتِيَ هَذَا مِنْ مَزَامِيرِ آلِ دَاوُدَ عَلَيْهِ السَّلَام","id":"Telah mengabarkan kepada kami ['Abdul Jabbar bin Al 'Alaa bin 'Abdul Jabbar] dari [Sufyan] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; Rasulullah Shallallahu'alaihi wasallam mendengar bacaan Abu Musa, maka beliau bersabda: \"la telah diberi suara indah ini dari keluarga Nabi Daud Alaihissalam.\""},"1009":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةَ أَبِي مُوسَى فَقَالَ لَقَدْ أُوتِيَ هَذَا مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ عَلَيْهِ السَّلَام","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; Rasulullah Shallallahu'alaihi wasallam mendengar bacaan Abu Musa, maka beliau bersabda: \"la telah diberi suara indah ini dari keluarga Nabi Daud Alaihissalam.\""},"1010":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ أَبِي مُلَيْكَةَ عَنْ يَعْلَى بْنِ مَمْلَكٍ أَنَّهُسَأَلَ أُمَّ سَلَمَةَ عَنْ قِرَاءَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَلَاتِهِ قَالَتْ مَا لَكُمْ وَصَلَاتَهُ ثُمَّ نَعَتَتْ قِرَاءَتَهُ فَإِذَا هِيَ تَنْعَتُ قِرَاءَةً مُفَسَّرَةً حَرْفًا حَرْفًا","id":"Telah mengkhabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits bin Sa'ad] dari ['Abdullah bin 'Ubaidillah bin Abu Mulaikah] dari [Ya'la bin Mamlak] bahwa dia bertanya kepada [Ummu Salamah] tentang bacaan dan shalat Rasulullah shallallahu 'alaihi wasallam. Ummu Salamah balik bertanya; 'Ada apa dengan Shalat Rasulullah Shalallahu 'Alaihi Wa sallam? lalu dia menyifati bacaan Rasulullah Shalallahu 'Alaihi Wa sallam dengan bacaan yang jelas huruf demi huruf.'"},"1011":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَحِينَ اسْتَخْلَفَهُ مَرْوَانُ عَلَى الْمَدِينَةِ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ الْمَكْتُوبَةِ كَبَّرَ ثُمَّ يُكَبِّرُ حِينَ يَرْكَعُ فَإِذَا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يُكَبِّرُ حِينَ يَهْوِي سَاجِدًا ثُمَّ يُكَبِّرُ حِينَ يَقُومُ مِنْ الثِّنْتَيْنِ بَعْدَ التَّشَهُّدِ يَفْعَلُ مِثْلَ ذَلِكَ حَتَّى يَقْضِيَ صَلَاتَهُ فَإِذَا قَضَى صَلَاتَهُ وَسَلَّمَ أَقْبَلَ عَلَى أَهْلِ الْمَسْجِدِ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَشْبَهُكُمْ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Suaid bin Nashr] dia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Yunus] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] bahwasanya [Abu Hurairah] ketika menggantikan (kepemimpinan imam) Marwan di Madinah, jika ia berdiri untuk shalat wajib maka ia bertakbir dan bila hendak ruku' ia juga bertakbir. Jika ia mengangkat kepalanya dari ruku' maka ia mengucapkan, \"Sami'alluhu liman hamidah rabbana lakal hamdu (Allah Mendengar semua yang memuji-Nya. Ya Allah, hanya untuk-Mu segala pujian).\" Kemudian ia bertakbir ketika turun untuk sujud dan bertakbir ketika hendak bangun dari dua rakaat setelah tasyahhud. la melakukan semua itu sampai selesai shalat. Jika ia selesai shalat dan telah mengucapkan salam, maka ia menghadap kepada jamaah masjid, lalu berkata, \"Demi Dzat yang jiwaku ada di Tangan-Nya, aku adalah orang yang paling serupa shalatnya dengan shalat Rasulullah Shallallahu'alaihi wasallam diantara kalian.\""},"1012":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ اللَّيْثِيِّ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا كَبَّرَ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ حَتَّى بَلَغَتَا فُرُوعَ أُذُنَيْهِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Sa'ad] dari [Qatadah] dari [Nashr bin 'Ashim Al Laitsi] dari [Malik bin Al Huwairits] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam tatkala memulai shalat mengangkat kedua tangannya sejajar dengan kedua daun telinganya, juga ketika hendak ruku' serta saat mengangkat kepala dari ruku'.\""},"1013":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ يَرْفَعُ يَدَيْهِ حَتَّى يُحَاذِيَ مَنْكِبَيْهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Bapaknya] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam jika memulai shalat maka beliau mengangkat kedua tangannya sampai lurus dengan kedua bahunya. Beliau Shallallahu'alaihi wasallam juga melakukan hal itu saat takbir untuk ruku' dan saat mengangkat kepala dari ruku'.\""},"1014":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سُفْيَانَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَأَلَا أُخْبِرُكُمْ بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ فَرَفَعَ يَدَيْهِ أَوَّلَ مَرَّةٍ ثُمَّ لَمْ يُعِدْ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Sufyan] dari ['Ashim bin Kulaib] dari ['Abdurrahman bin Al Aswad] dari ['Alqamah] dari ['Abdullah] dia berkata; \"Maukah kalian aku beritahu tentang cara shalat Rasulullah Shallallahu'alaihiwasallam? Beliau Shallallahu'alaihi wasallam mengangkat kedua tangan pertama kali kemudian tidak mengulanginya.\""},"1015":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْفُضَيْلُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ الرَّجُلُ فِيهَا صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Fudhail] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abu Ma'mar] dari [Abu Mas'ud] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Tidak sempurna shalat seseorang yang tidak meluruskan punggungnya (Thuma'ninah) ketika ruku' dan sujud.\""},"1016":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ وَحَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي الرُّكُوعِ وَالسُّجُودِ وَلَا يَبْسُطْ أَحَدُكُمْ ذِرَاعَيْهِ كَالْكَلْبِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Sa'id bin Abu 'Arubah] dan [Hammad bin Salamah] dari [Qatadah] dari [Anas] dari Rasulullah Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bersabda: \"Luruskanlah saat ruku' dan sujud, serta janganlah salah seorang dari kalian menghamparkan kedua lengannya di tanah seperti anjing.\""},"1017":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ إِبْرَاهِيمَ يُحَدِّثُ عَنْ عَلْقَمَةَ وَالْأَسْوَدِأَنَّهُمَا كَانَا مَعَ عَبْدِ اللَّهِ فِي بَيْتِهِ فَقَالَ أَصَلَّى هَؤُلَاءِ قُلْنَا نَعَمْ فَأَمَّهُمَا وَقَامَ بَيْنَهُمَا بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ قَالَ إِذَا كُنْتُمْ ثَلَاثَةً فَاصْنَعُوا هَكَذَا وَإِذَا كُنْتُمْ أَكْثَرَ مِنْ ذَلِكَ فَلْيَؤُمَّكُمْ أَحَدُكُمْ وَلْيَفْرِشْ كَفَّيْهِ عَلَى فَخْذَيْهِ فَكَأَنَّمَا أَنْظُرُ إِلَى اخْتِلَافِ أَصَابِعِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dari [Sulaiman] dia berkata; aku mendengar [Ibrahim] menceritakan dari ['Alqamah] dan [Al Aswad] bahwasanya keduanya pernah bersama Abdullah di rumahnya, lalu [Abdullah] bertanya; \"Apakah kalian sudah shalat?\" Kami menjawab; \"Ya.\" Lalu dia mengimami keduanya dan dia berdiri di antara keduanya tanpa adzan dan iqamah. la berkata; \"Jika kalian bertiga, maka berbuatlah seperti ini, dan jika kalian lebih banyak lagi maka salah seorang dari kalian menjadi imam, dan bentangkan kedua telapak tangannya di atas kedua pahanya -seolah-olah aku melihat rapatnya jari-jari Rasulullah Shallallahu'alaihi wasallam-.\""},"1018":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدٍ الرُّبَاطِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ ابْنُ عَبْدِ اللَّهِ قَالَ أَنْبَأَنَا عَمْرٌو وَهُوَ ابْنُ أَبِي قَيْسٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ قَالَاصَلَّيْنَا مَعَ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ فِي بَيْتِهِ فَقَامَ بَيْنَنَا فَوَضَعْنَا أَيْدِيَنَا عَلَى رُكَبِنَا فَنَزَعَهَا فَخَالَفَ بَيْنَ أَصَابِعِنَا وَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id Ar Rubathiy] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin 'Abdullah] dia berkata; telah memberitakan kepada kami ['Amr bin Abu Qais] dari [Az Zubair bin 'Adiy] dari [Ibrahim] dari [Al Aswad] dan ['Alqamah] mereka berdua berkata; \"Kami shalat bersama [Abdullah bin Mas'ud] di rumahnya, dan ia berdiri di antara kami. Kami meletakkan tangan-tangan kami di atas lutut kami, lalu ia menariknya dan merapatkan jari-jari kami, kemudian berkata, 'Aku melihat Rasulullah Shallallahu'alaihi wasallam melakukan hal ini'.\""},"1019":{"ar":"أَخْبَرَنَا نُوحُ بْنُ حَبِيبٍ قَالَ أَنْبَأَنَا ابْنُ إِدْرِيسَ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ فَقَامَ فَكَبَّرَ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ طَبَّقَ يَدَيْهِ بَيْنَ رُكْبَتَيْهِ وَرَكَعَفَبَلَغَ ذَلِكَ سَعْدًا فَقَالَ صَدَقَ أَخِي قَدْ كُنَّا نَفْعَلُ هَذَا ثُمَّ أُمِرْنَا بِهَذَا يَعْنِي الْإِمْسَاكَ بِالرُّكَبِ","id":"Telah mengabarkan kepada kami [Nuh bin Habib] dia berkata; telah memberitakan kepada kami [Ibnu Idris] dari ['Ashim bin Kulaib] dari ['Abdurrahman bin Al Aswad] dari ['Alqamah] dari ['Abdullah] dia berkata, \"Rasulullah Shallallahu'alaihi wasallam mengajari kami tentang cara shalat.\" Lalu dia berdiri dan bertakbir, dan ketika hendak ruku' dia merapatkan kedua tangannya di antara kedua lututnya, lantas ia ruku\". Hal tersebut sampai kepada [Sa'ad], maka dia berkata; \"Saudaraku benar, kami dulu juga melakukan hal ini. Kemudian kami disuruh melakukan hal ini - yakni memegang lutut -.\""},"1020":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي يَعْفُورٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَصَلَّيْتُ إِلَى جَنْبِ أَبِي وَجَعَلْتُ يَدَيَّ بَيْنَ رُكْبَتَيَّ فَقَالَ لِيَ اضْرِبْ بِكَفَّيْكَ عَلَى رُكْبَتَيْكَ قَالَ ثُمَّ فَعَلْتُ ذَلِكَ مَرَّةً أُخْرَى فَضَرَبَ يَدِي وَقَالَ إِنَّا قَدْ نُهِينَا عَنْ هَذَا وَأُمِرْنَا أَنْ نَضْرِبَ بِالْأَكُفِّ عَلَى الرُّكَبِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Ya'fur] dari [Mush'ab bin Sa'ad] dia berkata; \"Aku pernah shalat di sisi ayahku, dan aku meletakkan tanganku di antara kedua lututku. Lalu [ayahku] berkata kepadaku; 'Rapatkan kedua telapak tanganmu pada lututmu'. Kemudian aku melakukan hal itu sekali lagi, dan ayahku memukul tanganku sambil berkata; 'Kita dilarang melakukannya - yaitu meletakkan tangan di antara dua lutut - dan kita diperintahkan meletakkan telapak tangan di atas lutut'.\""},"1021":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ مُصْعَبِ بْنِ سَعْدٍ قَالَرَكَعْتُ فَطَبَّقْتُ فَقَالَ أَبِي إِنَّ هَذَا شَيْءٌ كُنَّا نَفْعَلُهُ ثُمَّ ارْتَفَعْنَا إِلَى الرُّكَبِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Isma'il bin Abu Khalid] dari [Az Zubair bin 'Adiy] dari [Mush'ab bin Sa'ad] dia berkata; \"Aku pernah ruku' dan merapatkan tanganku, lalu [ayahku] berkata kepadaku, 'Hal ini pernah kami lakukan, kemudian kami mengangkatnya di atas lutut'.'"},"1022":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عُمَرَ قَالَسُنَّتْ لَكُمْ الرُّكَبُ فَأَمْسِكُوا بِالرُّكَبِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al A'masy] dari [Ibrahim] dari [Abu 'Abdurrahman] dari ['Umar] dia berkata; \"Disunahkan bagi kalian (memegang) lutut, maka peganglah lutut-lutut kalian (saat ruku').\""},"1023":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ أَبِي حَصِينٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السُّلَمِيِّ قَالَ قَالَ عُمَرُإِنَّمَا السُّنَّةُ الْأَخْذُ بِالرُّكَبِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Abu Husain] dari [Abu 'Abdurrahman As-Sulamiy] dia berkata; [Umar] berkata; \"Memegang lutut adalah sunnah.\" "},"1024":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَالِمٍ قَالَأَتَيْنَا أَبَا مَسْعُودٍ فَقُلْنَا لَهُ حَدِّثْنَا عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ بَيْنَ أَيْدِينَا وَكَبَّرَ فَلَمَّا رَكَعَ وَضَعَ رَاحَتَيْهِ عَلَى رُكْبَتَيْهِ وَجَعَلَ أَصَابِعَهُ أَسْفَلَ مِنْ ذَلِكَ وَجَافَى بِمِرْفَقَيْهِ حَتَّى اسْتَوَى كُلُّ شَيْءٍ مِنْهُ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقَامَ حَتَّى اسْتَوَى كُلُّ شَيْءٍ مِنْهُ","id":"Telah mengabarkan kepada kami [Hunnad bin As Sariy] dalam haditsnya dari [Abul Ahwash] dari ['Atha bin As-Sa'ib] dari [Salim] dia berkata; \"kami mendatangi [Abu Mas'ud] dan berkata kepadanya; 'Ceritakan kepadaku tentang cara shalat Rasulullah Shallallahu'alaihiwasallam. Lalu ia berdiri di depan kami dan segera bertakbir, ketika hendak ruku', ia meletakkan kedua telapak tangannya di atas kedua lututnya dan menjadikan jari-jarinya di bawah itu. Dia juga menjauhkan kedua sikunya dari lambung hingga semuanya lurus, kemudian mengucapkan, 'Sami'allahu liman hamidah' berdiri hingga semuanya lurus.\""},"1025":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ الرَّهَاوِيُّ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ عَطَاءٍ عَنْ سَالِمٍ أَبِي عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَمْرٍو قَالَأَلَا أُصَلِّي لَكُمْ كَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَقُلْنَا بَلَى فَقَامَ فَلَمَّا رَكَعَ وَضَعَ رَاحَتَيْهِ عَلَى رُكْبَتَيْهِ وَجَعَلَ أَصَابِعَهُ مِنْ وَرَاءِ رُكْبَتَيْهِ وَجَافَى إِبْطَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ حَتَّى اسْتَوَى كُلُّ شَيْءٍ مِنْهُ ثُمَّ سَجَدَ فَجَافَى إِبْطَيْهِ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ قَعَدَ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ سَجَدَ حَتَّى اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ ثُمَّ صَنَعَ كَذَلِكَ أَرْبَعَ رَكَعَاتٍ ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهَكَذَا كَانَ يُصَلِّي بِنَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman Ar Rahawiy] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari ['Atha] dari [Salim Abu 'Abdulah] dari ['Uqbah bin 'Amr] dia berkata; \"Maukah kalian aku ajari cara shalat yang pernah kulihat dari Rasulullah Shallallahu'alaihiwasallam?\" Kami menjawab, \"Tentu.\" Lalu ia berdiri, dan ketika hendak ruku' ia meletakkan kedua telapak tangannya pada dua lututnya dan meletakkan jari-jarinya merenggang di kedua lututnya. la merenggangkan kedua sikunya dari kedua lambungnya, kemudian mengangkat kepalanya, dan berdiri lagi hingga lurus semuanya. Kemudian ia sujud, lalu merenggangkan kedua sikunya dari kedua lambungnya. Lalu ia duduk hingga tenang, kemudian sujud lagi hingga tenang. la melakukan semua itu dalam empat rakaat, kemudian berkata, \"Beginilah aku melihat Rasulullah Shallallahu'alaihi wasallam melakukan shalat dan begitulah Rasulullah Shallallahu'alaihi wasallam melakukan shalat bersama kami.\""},"1026":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ ابْنِ عُلَيَّةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَالِمٍ الْبَرَّادِ قَالَ قَالَ أَبُو مَسْعُودٍأَلَا أُرِيكُمْ كَيْفَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قُلْنَا بَلَى فَقَامَ فَكَبَّرَ فَلَمَّا رَكَعَ جَافَى بَيْنَ إِبْطَيْهِ حَتَّى لَمَّا اسْتَقَرَّ كُلُّ شَيْءٍ مِنْهُ رَفَعَ رَأْسَهُ فَصَلَّى أَرْبَعَ رَكَعَاتٍ هَكَذَا وَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Ibnu 'Ulayyah] dari ['Atha bin As-Sa'ib] dari [Salim Al Barrad] dia berkata; [Abu Mas'ud] berkata \"Maukah kalian aku beritahu tentang cara shalat Rasulullah Shallallahu'alaihiwasallam?\" Kami menjawab; \"Tentu.\" Lalu ia berdiri dan ketika hendak ruku' ia merenggangkan kedua sikunya dari kedua lambungnya hingga tenang, kemudian ia mengangkat kepalanya. Setelah itu ia shalat empat rakaat, kemudian berkata, \"Beginilah aku melihat Rasulullah Shallallahu'alaihi wasallam melakukan shalat.\""},"1027":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَكَعَ اعْتَدَلَ فَلَمْ يَنْصِبْ رَأْسَهُ وَلَمْ يُقْنِعْهُ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami ['Abdul Humaid bin Ja'far] dia berkata; telah menceritakan kepadaku [Muhammad bin 'Amr bin 'Atha] dari [Abu Humaid As-Sa'diy] dia berkata; \"Apabila Rasulullah Shallallahu'alaihi wasallam ruku' maka beliau melakukannya dengan lurus, tidak mengangkat kepalanya dan tidak mengangkatnya melebihi punggungnya. Beliau meletakkan kedua tangan diatas kedua lututnya.\""},"1028":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ عَنْ أَشْعَثَ عَنْ مُحَمَّدٍ عَنْ عَبِيدَةَ عَنْ عَلِيٍّ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقَسِّيِّ وَالْحَرِيرِ وَخَاتَمِ الذَّهَبِ وَأَنْ أَقْرَأَ وَأَنَا رَاكِعٌ وَقَالَ مَرَّةً أُخْرَى وَأَنْ أَقْرَأَ رَاكِعًا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Hammad bin Mas'adah] dari [Asy'ats] dari [Muhammad] dari ['Ubaidah] dari ['Ali] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melarangku memakai pakaian sutra, kain sutra, dan cincin emas, serta melarang membaca (Al Qur'an) saat ruku. Dia berkata lagi; dan beliau melarangku membaca (Al Qur'an) saat ruku'.\""},"1029":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ عَجْلَانَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيٍّ قَالَنَهَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ الْقِرَاءَةِ رَاكِعًا وَعَنْ الْقَسِّيِّ وَالْمُعَصْفَرِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu 'Ajlan] dari [Ibrahim bin 'Abdullah bin Hunain] dari [bapaknya] dari [Ibnu 'Abbas] dari [Ali] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melarangku memakai cincin emas, melarangku membaca (Al Qur'an) saat ruku', serta melarangku memakai pakaian berbordir sutra dan pakaian yang dicelup warna kuning.\""},"1030":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ دَاوُدَ الْمُنْكَدِرِيُّ قَالَ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ إِبْرَاهِيمَ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا أَقُولُ نَهَاكُمْ عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيِّ وَعَنْ لُبْسِ الْمُفَدَّمِ وَالْمُعَصْفَرِ وَعَنْ الْقِرَاءَةِ فِي الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Dawud Al Munkadiriy] dia berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adh Dhahak bin 'Utsman] dari [Ibrahim bin Hunain] dari [bapaknya] dari ['Abdullah bin 'Abbas] dari [Ali] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melarangku - aku tidak mengatakan, beliau melarang kalian - memakai cincin emas, memakai pakaian berbordir sutra, memakai pakaian yang dicelup dengan warna menyala-nyala, yang dicelup dengan warna kuning, dan melarang membaca (Al Qur'an) saat ruku'.\""},"1031":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ زُغْبَةُ عَنْ اللَّيْثِ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ إِبْرَاهِيمَ بْنَ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ حَدَّثَهُ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ عَلِيًّا يَقُولُنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ خَاتَمِ الذَّهَبِ وَعَنْ لَبُوسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَقِرَاءَةِ الْقُرْآنِ وَأَنَا رَاكِعٌ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad Zughbah] dari [Al Laits] dari [Yazid bin Abu Habib] bahwasanya [Ibrahim bin 'Abdullah bin Hunain] menceritakan kepadanya bahwasanya [bapaknya] menceritakan kepadanya bahwasanya dia (bapaknya) mendengar ['Ali] berkata; \"Rasulullah Shallallahu'alaihi wasallam melarangku memakai cincin emas, memakai pakaian sutra serta pakaian yang dicelup warna kuning, dan melarangku membaca (Al Qur'an) saat ruku'.\""},"1032":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ عَلِيٍّ قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ لُبْسِ الْقَسِّيِّ وَالْمُعَصْفَرِ وَعَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ الْقِرَاءَةِ فِي الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibrahim bin 'Abdullah bin Hunain] dari [bapaknya] dari ['Ali] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam melarangku memakai pakaian sutra serta pakaian yang dicelup warna kuning, melarangku memakai cincin emas, dan melarangku membaca (Al Qur'an) saat ruku'.\""},"1033":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سُلَيْمَانَ بْنِ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَكَشَفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السِّتَارَةَ وَالنَّاسُ صُفُوفٌ خَلْفَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ فَقَالَ أَيُّهَا النَّاسُ إِنَّهُ لَمْ يَبْقَ مِنْ مُبَشِّرَاتِ النُّبُوَّةِ إِلَّا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ ثُمَّ قَالَ أَلَا إِنِّي نُهِيتُ أَنْ أَقْرَأَ رَاكِعًا أَوْ سَاجِدًا فَأَمَّا الرُّكُوعُ فَعَظِّمُوا فِيهِ الرَّبَّ وَأَمَّا السُّجُودُ فَاجْتَهِدُوا فِي الدُّعَاءِ قَمِنٌ أَنْ يُسْتَجَابَ لَكُمْ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Sulaiman bin Suhaim] dari [Ibrahim bin 'Abdullah bin Ma'bad bin 'Abbas] dari [Bapaknya] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam suatu saat menyingkap tirai, sedangkan orang-orang sedang shalat di belakang Abu Bakar Radliyallahu'anhu, maka beliau Shallallahu'alaihi wasallam bersabda: 'Wahai manusia, tidak tersisa lagi kabar kenabian kecuali mimpi yang benar, yakni mimpi yang dilihat atau diperlihatkan kepada seorang muslim.\" Kemudian Beliau Shallallahu'alaihi wasallam menambahkan: 'Ketahuilah, bahwa aku dilarang membaca saat ruku' atau sujud, adapun dalam ruku' maka agungkanlah Rabb kalian dan saat sujud maka bersungguh-sungguhlah dalam berdoa, karena saat itu sangat mungkin sekali doa kalian dikabulkan'.\""},"1034":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَكَعَ فَقَالَ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Sa'ad bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Aku pemah shalat bersama Rasulullah Shallallahu'alaihi wasallam, lalu beliau ruku\". Saat ruku\" beliau membaca Subbhana Rabbiyal 'Adziim (Maha Suci Tuhanku Yang Maha Agung). Sedangkan saat sujud beliau Shallallahu'alaihi wasallam membaca Subbhana Rabbiyal A'laa (Maha Suci Tuhanku Yang Maha Tinggi).\""},"1035":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ وَيَزِيدُ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ أَنْ يَقُولَ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dan [Yazid] mereka berdua berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Abu Adh-Dhuha] dari [Masruq] dari ['Aisyah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam dalam ruku' dan sujudnya memperbanyak membaca, 'Subbahanaka Rabbana Wabihamdika Allahummaghfirlii (Maha Suci Engkau wahai Rabb kami, dan segala puji untuk-Mu. Ya Allah, ampunilah aku) \""},"1036":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنِي قَتَادَةُ عَنْ مُطَرِّفٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ سُبُّوحٌ قُدُّوسٌ رَبُّ الْمَلَائِكَةِ وَالرُّوحِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah memberitakan kepadaku [Qatadah] dari [Mutharrif] dari ['Aisyah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam dalam ruku' dan sujudnya memperbanyak membaca; 'Subbuuhun qudduusun, rabbul malaaikati wurruh (Maha Suci Tuhan para malaikat dan malaikat Jibril) '.\""},"1037":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ يَعْنِي النَّسَائِيَّ قَالَ حَدَّثَنَا آدَمُ بْنُ أَبِي إِيَاسٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُعَاوِيَةَ يَعْنِي ابْنَ صَالِحٍ عَنْ ابْنِ قَيْسٍ الْكِنْدِيِّ وَهُوَ عَمْرُو بْنُ قَيْسٍ قَالَ سَمِعْتُ عَاصِمَ بْنَ حُمَيْدٍ قَالَ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُقُمْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةً فَلَمَّا رَكَعَ مَكَثَ قَدْرَ سُورَةِ الْبَقَرَةِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur An Nasaai] dia berkata; telah menceritakan kepada kami [Adam bin Abu Iyas] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Mu'awiyah bin Shalih] dari ['Amru bin Qais Al Kindi] dia berkata; aku mendengar ['Ashim bin Humaid] berkata; aku mendengar ['Auf bin Malik] berkata; \"Suatu malam aku pernah shalat bersama Rasulullah Shallallahu'alaihi wasallam, dan ketika ruku' beliau berdiam seukuran seseorang membaca surat Al Baqarah. Saat ruku' beliau membaca, 'Subhaana dzil jabaruuti wal malaakuti wal kibriyaai wal 'adzamati (Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan, serta yang memiliki kesombongan dan keagungan) '.\""},"1038":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ قَالَ حَدَّثَنَا عَمِّي الْمَاجِشُونُ بْنُ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَكَعَ قَالَ اللَّهُمَّ لَكَ رَكَعْتُ وَلَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ خَشَعَ لَكَ سَمْعِي وَبَصَرِي وَعِظَامِي وَمُخِّي وَعَصَبِي","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] dia berkata; telah menceritakan kepada kami pamanku [Al Majisyun bin Abu Salamah] dari ['Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] bahwa apabila Rasulullah Shallallahu'alaihi wasallam ruku' maka beliau mengucapkan Alloohumma laka Roka'tu walaka aslamtu, wabika aamantu khosya'a laka sam'ii wa bashorii wa'izhoomii wamukhkhii wa 'ashobii yang artinya, 'Ya Allah, kepada-Mu aku ruku', kepada-Mu aku pasrah, dan kepada-Mu aku beriman Pendengaranku, pandanganku, tulangku, otakku, dan persendianku semua khusyu' (tunduk) kepada-Mu.\""},"1039":{"ar":"أَخْبَرَنَا يَ��ْيَى بْنُ عُثْمَانَ الْحِمْصِيُّ قَالَ حَدَّثَنَا أَبُو حَيْوَةَ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا رَكَعَ قَالَ اللَّهُمَّ لَكَ رَكَعْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ وَعَلَيْكَ تَوَكَّلْتُ أَنْتَ رَبِّي خَشَعَ سَمْعِي وَبَصَرِي وَدَمِي وَلَحْمِي وَعَظْمِي وَعَصَبِي لِلَّهِ رَبِّ الْعَالِمِينَ","id":"Telah mengabarkan kepada kami [Yahya bin 'Utsman Al Himshi] dia berkata; telah menceritakan kepada kami [Abu Haiwah] dia berkata; telah menceritakan kepada kami [Syu'aib] dari [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah] dari Rasulullah Shallallahu'alaihi wasallam, bahwa apabila beliau Shallallahu'alaihi wasallam ruku' maka beliau mengucapkan doa -yang artinya-, \"Ya Allah, kepada-Mu aku ruku' kepada-Mu aku pasrah. dan kepada- Mu aku bertawakal. Pendengaranku, pandanganku, darahku, dagingku, tulangku, dan persendianku semua khusyu ' (tunduk) kepada Allah, Rabb semesta alam.\""},"1040":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ عُثْمَانَ قَالَ حَدَّثَنَا ابْنُ حِمْيَرٍ قَالَ حَدَّثَنَا شُعَيْبٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ وَذَكَرَ آخَرَ قَبْلَهُ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ مُحَمَّدِ بْنِ مَسْلَمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَامَ يُصَلِّي تَطَوُّعًا يَقُولُ إِذَا رَكَعَ اللَّهُمَّ لَكَ رَكَعْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ وَعَلَيْكَ تَوَكَّلْتُ أَنْتَ رَبِّي خَشَعَ سَمْعِي وَبَصَرِي وَلَحْمِي وَدَمِي وَمُخِّي وَعَصَبِي لِلَّهِ رَبِّ الْعَالَمِينَ","id":"Telah mengabarkan kepada kami [Yahya bin 'Utsman] dia berkata; telah menceritakan kepada kami [Ibnu Himyar] dia berkata; telah menceritakan kepada kami [Syu'aib] dari [Muhammad bin Al Munkadir] dan yang lain menyebutkan sebelumnya yaitu dari ['Abdurrahman Al A'raj] dari [Muhammad bin Maslamah] bahwa Rasulullah Shallallahu'alaihi wasallam apabila berdiri untuk shalat sunnah maka beliau saat ruku' membaca doa - yang artinya -, \"Ya Allah, kepada-Mu aku ruku', kepada-Mu aku pasrah, kepada-Mu aku bertawakal. Pendengaranku, pandanganku, darahku, dagingku, tulangku, dan persendianku semua khusyu' (tunduk) kepada Allah, Rabb semesta alam.\""},"1041":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ ابْنِ عَجْلَانَ عَنْ عَلِيِّ بْنِ يَحْيَى الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَة�� بْنِ رَافِعٍ وَكَانَ بَدْرِيًّا قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ دَخَلَ رَجُلٌ الْمَسْجِدَ فَصَلَّى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُهُ وَلَا يَشْعُرُ ثُمَّ انْصَرَفَ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ عَلَيْهِ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ قَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ قَالَ لَا أَدْرِي فِي الثَّانِيَةِ أَوْ فِي الثَّالِثَةِ قَالَ وَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَهِدْتُ فَعَلِّمْنِي وَأَرِنِي قَالَ إِذَا أَرَدْتَ الصَّلَاةَ فَتَوَضَّأْ فَأَحْسِنْ الْوُضُوءَ ثُمَّ قُمْ فَاسْتَقْبِلْ الْقِبْلَةَ ثُمَّ كَبِّرْ ثُمَّ اقْرَأْ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ رَأْسَكَ حَتَّى تَطْمَئِنَّ قَاعِدًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا فَإِذَا صَنَعْتَ ذَلِكَ فَقَدْ قَضَيْتَ صَلَاتَكَ وَمَا انْتَقَصْتَ مِنْ ذَلِكَ فَإِنَّمَا تَنْقُصُهُ مِنْ صَلَاتِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr bin Mudhar] dari [Ibnu 'Ajlan] dari ['Ali bin Yahya Az Zuraqiy] dari [bapaknya] dari pamannya [Rifa'ah bin Rafi'] -termasuk orang yang ikut perang Badar- dia berkata; \"Kami pernah bersama Rasulullah Shallallahu'alaihi wasallam saat ada seorang laki-laki yang masuk ke dalam masjid, lalu ia shalat dan Rasulullah Shallallahu'alaihi wasallam mengamatinya tanpa ia sadari. Setelah selesai ia datang kepada Rasulullah Shallallahu'alaihi wasallam sambil mengucapkan salam kepada beliau, maka beliau Shallallahu'alaihi wasallam membalas salamnya lalu berkata kepadanya: 'Kembalilah dan shalatlah lagi, sesungguhnya engkau belum shalat'. la menjawab pada jawaban yang ketiga atau yang kedua, 'Aku tidak tahu'. la lalu berkata, 'Demi Dzat yang mengutus engkau dengan membawa kitab Al Qur'an, aku telah bersungguh-sungguh, maka ajari aku dan perlihatkanlah kepadaku'. Rasulullah Shallallahu'alaihi wasallam bersabda: 'Jika kamu hendak shalat, maka berwudhulah dan perbaikilah wudlumu. Kemudian berdirilah dan menghadaplah ke kiblat. Lalu bertakbirlah dan bacalah (Al Qur^an). Kemudian ruku'lah hingga kamu tenang (thuma 'ninah) dalam ruku 'mu, dan bangkitlah dari ruku' hingga kamu berdiri tegak. Lalu sujudlah hingga kamu tenang (thuma 'ninah) dalam sujudmu dan bangkitlah dari sujud hingga kamu tenang (thuma 'ninah) dalam keadaan duduk. Jika kamu telah mengerjakan itu semua, maka kamu telah menyelesaikan shalatmu. Jika kamu menguranginya, maka pahala shalatmu akan dikurangi'.\""},"1042":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتِمُّوا الرُّكُوعَ وَالسُّجُودَ إِذَا رَكَعْتُمْ وَسَجَدْتُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; aku mendengar [Anas] berkata; dari Nabi Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bersabda: \"Sempurnakanlah ruku ' dan sujud jika kalian sedang ruku ' dan sujud.\""},"1043":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ قَيْسِ بْنِ سُلَيْمٍ الْعَنْبَرِيِّ قَالَ حَدَّثَنِي عَلْقَمَةُ بْنُ وَائِلٍ قَالَ حَدَّثَنِي أَبِي قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُهُ يَرْفَعُ يَدَيْهِ إِذَا افْتَتَحَ الصَّلَاةَ وَإِذَا رَكَعَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ هَكَذَا وَأَشَارَ قَيْسٌ إِلَى نَحْوِ الْأُذُنَيْنِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Qais bin Salim Al 'Anbariy] dia berkata; telah menceritakan kepada kami ['Alqamah bin Wa'il] dia berkata; telah menceritakan kepadaku [bapakku], dia berkata; \"Aku pernah shalat di belakang Rasulullah Shallallahu'alaihi wasallam, dan aku melihat beliau Shallallahu'alaihi wasallam mengangkat kedua tangannya ketika mengawali shalat dan ketika hendak ruku'. Dan saat mengucapkan, 'Sami'allahu liman hamidah\", seperti ini.\" -Qais (perawi) mengisyaratkan dengan mengangkat kedua tangannya hingga sejajar kedua telinganya-."},"1044":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ أَنَّهُ حَدَّثَهُمْ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ حَتَّى يُحَاذِيَ بِهِمَا فُرُوعَ أُذُنَيْهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Nashr bin 'Ashim] bahwasanya dia menceritakan kepada mereka, dari [Malik bin Al Huwairits] bahwa dia pernah melihat Rasulullah Shallallahu'alaihi wasallam mengangkat kedua tangannya saat hendak ruku' serta saat mengangkat kepalanya dari ruku', hingga sejajar dengan bagian atas telinganya."},"1045":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَرْفَعُ يَدَيْهِ إِذَا دَخَلَ فِي الصَّلَاةِ حَذْوَ مَنْكِبَيْهِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَبَّنَا لَكَ الْحَمْدُ وَكَانَ لَا يَرْفَعُ يَدَيْهِ بَيْنَ السَّجْدَتَيْنِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Malik bin Anas] dari [Az Zuhri] dari [Salim] dari [Bapaknya] bahwa Rasulullah Shallallahu'alaihi wasallam mengangkat kedua tangannya sejajar dengan kedua bahunya saat memulai shalat, saat mengangkat kepala dari ruku', serta saat mengucapkan, \"Sami'allahu liman hamidah (Allah Maha Mendengar semua yang memuji-Nya).\" Lantas mengucapkan, \"Rabbana lakal hamdu. (Wahai Tuhan kami, hanya untuk-Mu segala pujian).\" Beliau Shallallahu'alaihi wasallam tidak melakukannya pada dua sujud."},"1046":{"ar":"قَالَ الْبُخَارِي أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ الْمَرْوَزِيُّ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَأَلَا أُصَلِّي بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمْ يَرْفَعْ يَدَيْهِ إِلَّا مَرَّةً وَاحِدَةً","id":"Al Bukhari berkata; Telah mengabarkan kepada kami [Mahmud bin Ghailan Al Marwazi] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashijm bin Kulaib] dari ['Abdurrahman bin Al Aswad] dari ['Alqamah] dari ['Abdullah] dia berkata; \"Maukah kalian aku peragakan cara shalat Rasulullah Shallallahu'alaihiwasallam?\" Lalu ia mengerjakan shalat, dan ia tidak mengangkat kedua tangannya kecuali hanya sekali."},"1047":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا افْتَتَحَ الصَّلَاةَ رَفَعَ يَدَيْهِ حَذْوَ مَنْكِبَيْهِ وَإِذَا كَبَّرَ لِلرُّكُوعِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا كَذَلِكَ أَيْضًا وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ وَكَانَ لَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Malik] dari [Ibnu Syihab] dari [Salim] dari [Ibnu 'Umar] bahwa jika Rasulullah Shallallahu'alaihi wasallam memulai shalat maka beliau mengangkat kedua tangannya sampai lurus dengan pundaknya. Beliau Shallallahu'alaihi wasallam juga melakukan hal itu saat takbir untuk ruku' dan saat mengangkat kepala dari ruku', sambil mengucapkan doa - yang artinya -: \"Allah Mendengar semua yang memuji-Nya. Wahai Tuhan kami, untuk-Mu segala pujian.\" Beliau Shallallahu'alaihi wasallam tidak melakukannya saat sujud."},"1048":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam apabila mengangkat kepalanya dari ruku' maka beliau mengucapkan: 'allahumma Rabbana Lakal Hamdu (Ya Allah Tuhan kami, untuk-Mu segala pujian) '.\""},"1049":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَقَطَ مِنْ فَرَسٍ عَلَى شِقِّهِ الْأَيْمَنِ فَدَخَلُوا عَلَيْهِ يَعُودُونَهُ فَحَضَرَتْ الصَّلَاةُ فَلَمَّا قَضَى الصَّلَاةَ قَالَ إِنَّمَا جُعِلَ الْإِمَامُ لِيُؤْتَمَّ بِهِ فَإِذَا رَكَعَ فَارْكَعُوا وَإِذَا رَفَعَ فَارْفَعُوا وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami [Hunnad bin As Sari] dari [Ibnu 'Uyainah] dari [Az Zuhri] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam pernah jatuh dari kudanya, sehingga beliau Shallallahu'alaihi wasallam terluka di bagian kanan badannya. Lantas para sahabat segera membesuknya, dan tibalah waktu shalat. Setelah selesai shalat beliau Shallallahu'alaihi wasallam bersabda: \"Tidaklah seorang imam itu dijadikan melainkan untuk diikuti. Jika dia ruku ' maka rukulah kalian ', bila ia mengangkat kepalanya maka hendaklah kalian mengangkat kepala, jika sujud maka sujudlah kalian, dan jika ia mengucapkan, 'Sami'allahu liman hamidah (Allah Mendengar semua yang memuji-Nya) ' maka ucapkanlah, 'Rabbana lakal hamdu (Ya Allah, untuk-Mu segala pujian) '.\""},"1050":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي نُعَيْمُ بْنُ عَبْدِ اللَّهِ عَنْ عَلِيِّ بْنِ يَحْيَى الزُّرَقِيِّ عَنْ أَبِيهِ عَنْ رِفَاعَةَ بْنِ رَافِعٍ قَالَ كُنَّا يَوْمًا نُصَلِّي وَرَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرَّكْعَةِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ رَجُلٌ وَرَاءَهُ رَبَّنَا وَلَكَ الْحَمْدُ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ الْمُتَكَلِّمُ آنِفًا فَقَالَ الرَّجُلُ أَنَا يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ رَأَيْتُ بِضْعَةً وَثَلَاثِينَ مَلَكًا يَبْتَدِرُونَهَا أَيُّهُمْ يَكْتُبُهَا أَوَّلًا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dia berkata; telah menceritakan kepada kami [Nu'aim bin 'Abdullah] dari ['Ali bin Yahya Az Zurqiy] dari [bapaknya] dari [Rifa'ah bin Rafi'] dia berkata; \"Suatu hari aku shalat di belakang Rasulullah Shallallahu'alaihi wasallam, dan saat mengangkat kepalanya dari ruku' beliau mengucapkan, 'Sami'allahu liman hamidah\". Tiba-tiba seseorang di belakangnya mengucapkan, 'Rabbana wa lakal hamdu hamdan katsiran thayyiban mubarakan fiih (Wahai Rabb kami, untuk-Mu segala pujian-pujian yang banyak serta baik, dan diberkahi) '. Setelah Rasulullah Shallallahu'alaihi wasallam selesai shalat, beliau bertanya, 'Siapa yang berbicara saat shalat? 'Lalu ada seorang laki-laki berkata; 'Aku wahai Rasulullah Shallallahu'alaihiwasallam! ' Kemudian Rasulullah Shallallahu'alaihi wasallam bersabda: 'Demi Dzat yang jiwaku ada di tangan-Nya, sungguh, aku melihat tiga puluh lebih malaikat yang berebut untuk menulisnya pertama kali.\""},"1051":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قَالَ الْإِمَامُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا وَلَكَ الْحَمْدُ فَإِنَّ مَنْ وَافَقَ قَوْلُهُ قَوْلَ الْمَلَائِكَةِ غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Sumiy] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Apabila imam mengucapkan, 'Sami'allahu liman hamidah ' maka ucapkan, 'Rabbana lakal hamdu'. Barangsiapa ucapannya berbarengan dengan ucapan para malaikat, maka dosa-dosa yang telah lewat akan diampuni.\""},"1052":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ أَنَّهُ حَدَّثَهُ أَنَّهُ سَمِعَ أَبَا مُوسَى قَالَ إِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا وَبَيَّنَ لَنَا سُنَّتَنَا وَعَلَّمَنَا صَلَاتَنَا فَقَالَ إِذَا صَلَّيْتُمْ فَأَقِيمُوا صُفُوفَكُمْ ثُمَّ لِيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ الْإِمَامُ فَكَبِّرُوا وَإِذَا قَرَأَ غَيْرِ الْمَغْضُوبِ عَلَيْهِمْ وَلَا الضَّالِّينَ فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ وَإِذَا كَبَّرَ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ يَسْمَعْ اللَّهُ لَكُمْ فَإِنَّ اللَّهَ قَالَ عَلَى لِسَانِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَإِذَا كَبَّرَ وَسَجَدَ فَكَبِّرُوا وَاسْجُدُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ فَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ سَلَامٌ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ سَلَامٌ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ سَبْعُ كَلِمَاتٍ وَهِيَ تَحِيَّةُ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin 'Abdullah] bahwasanya ia mendengar [Abu Musa] berkata; \"Sesungguhnya Nabi Allah Shallallahu'alaihi wasallam pernah berkhutbah di hadapan kami, beliau menjelaskan sunnah dan mengajarkan kami cara shalat, beliau berkata: 'Jika kalian shalat maka luruskan barisan kalian. Hendaklah salah seorang dari kalian menjadi imam. Bila imam bertakbir maka bertakbirlah kalian dan bila imam mengucapkan, \"Ghairil maghdluubi 'alahim waladl-dlaalliin (Bukan orang-orang yang dimurkai dan bukan orang-orang yang sesat) \" maka hendaklah kalian mengucapkan, \"Aamiin (semoga Allah mengabulkan) niscaya Allah akan mengabulkan kalian\". Jika imam bertakbir dan ruku' maka bertakbirlah dan ruku'lah, sesungguhnya imam ruku' dan mengangkat kepala dari ruku' sebelum kalian'. Lalu Nabi Shallallahu'alaihi wasallam bersabda: 'Hendaklah gerakan imam itu kalian ikuti sesudahnya'. Dan jika ia mengangkat kepala dari ruku dengan mengucapkan, \"Sami'allaahu It man lamidah (Allah mendengar orang yang memuji-Nya) \" maka ucapkanlah, \"Allahumma rabbanaa wa lakal hamdu (Wahai Rabb kami, untuk-Mu segala pujian) \" niscaya Allah mendengar kalian. Sesungguhnya Allah berfirman melalui lisan Nabi-Nya, \"Sami'alladhu liman hamidah \". Bila imam bertakbir dan sujud maka ikutlah bertakbir dan sujud, sesungguhnya imam bertakbir dan sujud sebelum kalian'. Lalu Rasulullau Shallallahu'alaihi wasallam bersabda: -'Hendaklah gerakan imam itu kalian ikuti sesudahnya - dan jika ia duduk maka yang pertama kali diucapkan oleh salah seorang dari kalian adalah -doa yang artinya-: \"Ucapan selamat yang baik dan shalawat bagi Allah, semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan semoga juga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya\" -ini adalah tujuh kalimat sebagai tahiyyat shalat'.\""},"1053":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ رُكُوعُهُ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَسُجُودُهُ وَمَا بَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Al Hakam] dari ['Abdurrahman bin Abu Laila] dari [Al Barra bin 'Azib] bahwa rukuk Rasulullah Shallallahu'alaihi wasallam dan bila mengangkat kepala dari rukuk juga sujudnya dan -duduk- antara dua sujudnya hampir sama (lamanya)."},"1054":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ قَالَ اللَّهُمَّ لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ","id":"Telah mengabarkan kepada kami [Abu Dawud Sulaiman bin Saif Al Harraniy] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Amir] dia berkata; telah menceritakan kepada kami [Hisyam bin Hassan] dari [Qais bin Sa'ad] dari ['Atha] dari [Ibnu 'Abbas] bahwa Rasulullah Shallallahu'alaihi wasallam apabila telah mengucapkan, \"Sami'allahu liman hamidah\" maka beliau Shallallahu'alaihi wasallam mengucapkan - doa yang artinya -: 'Ya Allah, segala pujian bagi-Mu sepenuh langit dan sepenuh bumi, juga sepenuh apa yang Engkau kehendaki dari sesuatu setelah itu) '.\""},"1055":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ نَافِعٍ عَنْ وَهْبِ بْنِ مِينَاسٍ الْعَدَنِيِّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أَرَادَ السُّجُودَ بَعْدَ الرَّكْعَةِ يَقُولُ اللَّهُمَّ رَبَّنَا وَلَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Bakr] dia berkata; telah menceritakan kepada kami [Ibrahim bin Nafi'] dari [Wahb bin Minas Al 'Adaniy] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] bahwa bila Nabi Shallallahu'alaihi wasallam hendak sujud setelah ruku' maka beliau Shallallahu'alaihi wasallam mengucapkan - doa yang artinya -, \"Ya Allah, segala pujian bagi-Mu sepenuh langit dan sepenuh bumi, juga sepenuh apa yang Engkau kehendaki dari sesuatu setelah itu.\""},"1056":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ هِشَامٍ أَبُو أُمَيَّةَ الْحَرَّانِيُّ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ سَعِيدِ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَطِيَّةَ بْنِ قَيْسٍ عَنْ قَزَعَةَ بْنِ يَحْيَى عَنْ أَبِي سَعِيدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ حِينَ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ أَهْلَ الثَّنَاءِ وَالْمَجْدِ خَيْرُ مَا قَالَ الْعَبْدُ وَكُلُّنَا لَكَ عَبْدٌ لَا مَانِعَ لَمَا أَعْطَيْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah mengabarkan kepada kami ['Amr bin Hisyam Abu Umayyah Al Harrani] dia berkata; telah menceritakan kepada kami [Makhlad] dari [Sa'id bin 'Abdul 'Aziz] dari ['Athiyyah bin Qais] dari [Qaza'ah bin Yahya] dari [Abu Sa'id] bahwa Rasulullah Shallallahu'alaihi wasallam setelah mengucapkan, \"Sami'allahu liman hamidah\" maka beliau Shallallahu'alaihi wasallam mengucapkan-doa yang artinya-: ' Ya Allah, segala pujian bagi-Mu sepenuh langit dan sepenuh bumi, juga sepenuh apa yang Engkau kehendaki dari sesuatu setelah itu, Yang berhak menerima pujian dan keluhuran.- Itulah sebaik-baik yang diucapkan oleh seorang hamba- dan kami semua adalah hamba-Mu. Tiada yang bisa menghalangi apa yang Engkau berikan dan tidak memberi manfaat harta kekayaan dari-Mu kepada pemiliknya.'"},"1057":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي حَمْزَةَ عَنْ رَجُلٍ مِنْ بَنِي عَبْسٍ عَنْ حُذَيْفَةَأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَسَمِعَهُ حِينَ كَبَّرَ قَالَ اللَّهُ أَكْبَرُ ذَا الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ وَكَانَ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ لِرَبِّيَ الْحَمْدُ لِرَبِّيَ الْحَمْدُ وَفِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى وَبَيْنَ السَّجْدَتَيْنِ رَبِّي اغْفِرْ لِي رَبِّي اغْفِرْ لِي وَكَانَ قِيَامُهُ وَرُكُوعُهُ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَسُجُودُهُ وَمَا بَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Abu Hamzah] dari [seorang lelaki] dari bani 'Abas, dari [Hudzaifah] bahwa suatu malam ia pernah shalat bersama Rasulullah Shallallahu'alaihi wasallam. la mendengar Rasulullah Shallallahu'alaihi wasallam mengucapkan: \"Allahu Akbar dzal Jabaruuti wal Malaakuti wal Kibriyaai wal 'Adzamti (Allah Maha Besar, Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan serta yang memiliki kesombongan dan keagungan) \" setelah takbir. Saat ruku' beliau mengucapkan, \"Subbhana Rabbiyal 'Azhiim (Maha Suci Tuhanku yang Maha Agung).\" Jika mengangkat kepala dari ruku' maka beliau mengucapkan: \"Lirabbil Hamdu lirabbil hamdu (Segala pujian bagi Rabbku, segala pujian bagi Rabbku).\" Saat sujud beliau mengucapkan, \"Subbhana Rabbiyal A'laa (Maha Suci Tuhanku yang Maha Tinggi) \", sedangkan saat dua sujud beliau mengucapkan, \"Rabbighfirlii, rabbighfirlii (Wahai Tuhanku ampunilah aku. Wahai Tuhanku, ampunilah aku).\" Berdirinya Rasulullah Shallallahu'alaihi wasallam, ruku'nya, sujudnya, serta saat duduk diantara dua sujud dan saat mengangkat kepala dari ruku', semuanya hampir sama (lamanya)."},"1058":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي مِجْلَزٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا بَعْدَ الرُّكُوعِ يَدْعُو عَلَى رِعْلٍ وَذَكْوَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Jarir] dari [Sulaiman At Tamimi] dari [Abu Mijlaz] dari [Anas bin Malik] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam pernah qunut setelah ruku' selama satu bulan, dalam doanya dia melaknat suku Ri'il, Dakwan, serta Ushayyah, karena mereka berbuat maksiat kepada Allah dan Rasul-Nya.\""},"1059":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ ابْنِ سِيرِينَأَنَّ أَنَسَ بْنَ مَالِكٍ سُئِلَ هَلْ قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ قَالَ نَعَمْ فَقِيلَ لَهُ قَبْلَ الرُّكُوعِ أَوْ بَعْدَهُ قَالَ بَعْدَ الرُّكُوعِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Ibnu Sirin] bahwasanya [Anas bin Malik] ditanya, \"Apakah Rasulullah Shallallahu'alaihi wasallam pernah qunut saat shalat Subuh? la menjawab, \"Ya.\" Lalu ia ditanya lagi, \"Setelah atau sebelum ruku'?\" la menjawab; \"Setelah ruku', \""},"1060":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ يُونُسَ عَنْ ابْنِ سِيرِينَ قَالَحَدَّثَنِي بَعْضُ مَنْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فِي الرَّكْعَةِ الثَّانِيَةِ قَامَ هُنَيْهَةً","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadhfhal] dari [Yunus] dari [Ibnu Sirin] dia berkata; \" [Sebagian orang] yang pernah shalat Subuh bersama Rasulullah Shallallahu'alaihi wasallam bercerita kepadaku bahwa setelah Rasulullah Shallallahu'alaihi wasallam mengucapkan, 'Sami'allahu liman hamidah pada rakaat kedua\" beliau Shallallahu'alaihi wasallam berdiri sejenak.' "},"1061":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَفِظْنَاهُ مِنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا رَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْسَهُ مِنْ الرَّكْعَةِ الثَّانِيَةِ مِنْ صَلَاةِ الصُّبْحِ قَالَ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ بِمَكَّةَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ سِنِينَ كَسِنِي يُوسُفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; kami menghafal dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dia berkata; \"Setelah Rasulullah Shallallahu'alaihi wasallam mengangkat kepalanya dari rakaat kedua pada shalat Subuh, beliau mengucapkan-doa yang artinya-: 'Ya Allah, selamatkanlah Al Walid bin Al Walid, Salamah bin Hisyam, Ayyasy bin Abu Rabi'ah, serla orang-orang lemah di Makkah. Ya Allah, tampakkan kehancuran-Mu (siksaan-Mu) kepada Bani Mudlar dan jadikanlah tahun-tahun mereka seperti tahun-tahunnya Yusuf (yang penuh paceklik dan kekeringan -penerj) '.\""},"1062":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ ابْنِ أَبِي حَمْزَةَ قَالَ حَدَّثَنِي مُحَمَّدٌ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي الصَّلَاةِ حِينَ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ قَبْلَ أَنْ يَسْجُدَ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ ثُمَّ يَقُولُ اللَّهُ أَكْبَرُ فَيَسْجُدُ وَضَاحِيَةُ مُضَرَ يَوْمَئِذٍ مُخَالِفُونَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Ibnu Abu Hamzah] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihi wasallam pernah berdoa dalam shalat ketika beliau Shallallahu'alaihi wasallam selesai mengucapkan, \"Sami'allahu liman hamidah rabbana lakal hamdu (Allah Maha Mendengar terhadap semua yang memuji-Nya. Ya Allah, hanya untuk-Mu).\" Kemudian beliau mengucapkan doa - sambil berdiri sebelum sujud -, \"Ya Allah, selamatkanlah Al Walid bin Al Walid, Salamah bin Hisyam, Ayyasy bin Abu Rabi 'ah, serta orang-orang lemah dari kalangan kaum mukmin. Ya Allah, timpakan siksaan-Mu kepada Bani Mudhar dan jadikanlah tahun-tahun mereka seperti tahun-tahun Yusuf (penuh penderitaan, paceklik, kekeringan -penerj).\" Kemudian beliau Shallallahu'alaihi wasallam mengucapkan, \"Allahu Akbar\" lantas sujud. Bani Mudhar saat itu menyelisihi (tidak mentaati) Rasulullah Shallallallahu'alaihi wasallam."},"1063":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ سَلْمٍ الْبَلْخِيُّ قَالَ حَدَّثَنَا النَّضْرُ قَالَ أَنْبَأَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَأُقَرِّبَنَّ لَكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَانَ أَبُو هُرَيْرَةَ يَقْنُتُ فِي الرَّكْعَةِ الْآخِرَةِ مِنْ صَلَاةِ الظُّهْرِ وَصَلَاةِ الْعِشَاءِ الْآخِرَةِ وَصَلَاةِ الصُّبْحِ بَعْدَ مَا يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَيَدْعُو لِلْمُؤْمِنِينَ وَيَلْعَنُ الْكَفَرَةَ","id":"Telah mengabarkan kepada kami [Sulaiman bin Salm Al Balkhi] dia berkata; telah menceritakan kepada kami [An Nadhr] dia berkata; telah memberitakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Akan aku mudahkan kalian untuk memahami cara shalatnya Rasulullah Shallallahu'alaihiwasallam.\" Lalu Abu Hurairah melakukan qunut pada rakaat terakhir saat shalat Zuhur, Isya', serta Subuh setelah mengucapkan, \"Sami'allahu liman hamidah.\" Beliau Shallallahu'alaihi wasallam berdoa kebaikan bagi orang-orang mukmin dan melaknat orang-orang kafir.\""},"1064":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ وَشُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ ح و أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ وَسُفْيَانَ قَالَا حَدَّثَنَا عَمْرُو بْنُ مُرَّةَ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ بْنِ عَازِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي الصُّبْحِ وَالْمَغْرِبِ وَقَالَ عُبَيْدُ اللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dari ['Abdurrahman] dari [Sufyan] dan [Syu'bah] dari ['Amr bin Murrah] -lewat jalur periwayatan lain-- dan telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] dan [Sufyan] mereka berdua berkata; telah menceritakan kepada kami ['Amr bin Murrah] dari [Ibnu Abu Laila] dari [Al Barra bin 'Azib] bahwa Nabi Shallallahu'alaihi wasallam pernah qunut saat shalat Subuh dan Maghrib. Dan Ubaidullah mengatakannya; dengan lafazh ('Inna Rasulullah Shallallahu'alaihi wasallam)."},"1065":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ ح وَهِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا قَالَ شُعْبَةُ لَعَنَ رِجَالًا وَقَالَ هِشَامٌ يَدْعُو عَلَى أَحْيَاءٍ مِنْ أَحْيَاءِ الْعَرَبِ ثُمَّ تَرَكَهُ بَعْدَ الرُّكُوعِ هَذَا قَوْلُ هِشَامٍ وَقَالَ شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا يَلْعَنُ رِعْلًا وَذَكْوَانَ وَلِحْيَانَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas]. Dari jalur lain, dari [Hisyam] dari [Qatadah] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam pernah qunut selama satu bulan - Syu'bah berkata; 'Beliau melaknat beberapa laki-laki.' Hisyam berkata; 'Mendoakan kejelekan (melaknat) beberapa kabilah (suku) dari kabilah-kabilah Arab, kemudian meninggalkannya setelah ruku'-. Ini adalah perkataan Hisyam. Sedangkan perkataan Syu'bah dari Qatadah Anas, bahwa Rasulullah Shallallahu'alaihi wasallam pernah qunut selama satu bulan: beliau melaknat Bani Ri'il, Dzakwan, dan Lihyan."},"1066":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ رَفَعَ رَأْسَهُ مِنْ صَلَاةِ الصُّبْحِ مِنْ الرَّكْعَةِ الْآخِرَةِ قَالَ اللَّهُمَّ الْعَنْ فُلَانًا وَفُلَانًا يَدْعُو عَلَى أُنَاسٍ مِنْ الْمُنَافِقِينَ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Bapaknya] bahwa ia pernah mendengar Rasulullah Shallallahu'alaihi wasallam ketika mengangkat kepalanya dari ruku' terakhir pada shalat Subuh mengucapkan: \"Ya Allah, laknatlah si Fulan dan si Fulan.\" Beliau mendoakan kejelekan kepada kalangan munafik, lalu Allah Azza wa Jalla menurunkan ayat; \"Tidak ada sedikitpun campur tanganmu dalam urusan mereka itu atau Allah menerima taubat mereka atau mengadzab mereka karena sesungguhnya mereka itu orang-orang yang zalim\" (Qs. Aali 'Imraan (3): 128)."},"1067":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا يَدْعُو عَلَى حَيٍّ مِنْ أَحْيَاءِ الْعَرَبِ ثُمَّ تَرَكَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam] dia berkata; [Bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Anas] bahwa Rasulullah Shallallahu'alaihi wasallam pernah qunut selama satu bulan; beliau mendoakan kejelekan kepada suatu kabilah dari kabilah-kabilah Arab, kemudian beliau Shallallahu'alaihi wasallam meninggalkan (qunut) nya."},"1068":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ خَلَفٍ وَهُوَ ابْنُ خَلِيفَةَ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِيهِ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يَقْنُتْوَصَلَّيْتُ خَلْفَ أَبِي بَكْرٍ فَلَمْ يَقْنُتْ وَصَلَّيْتُ خَلْفَ عُمَرَ فَلَمْ يَقْنُتْ وَصَلَّيْتُ خَلْفَ عُثْمَانَ فَلَمْ يَقْنُتْ وَصَلَّيْتُ خَلْفَ عَلِيٍّ فَلَمْ يَقْنُتْ ثُمَّ قَالَ يَا بُنَيَّ إِنَّهَا بِدْعَةٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Khalaf bin Khalifah] dari [Abu Malik Al Asyja'i] dari [bapaknya] dia berkata; \"Aku pernah shalat di belakang Rasulullah Shallallahu'alaihi wasallam, dan beliau tidak qunut. Aku juga pernah shalat di belakang Abu Bakar, dan ia tidak qunut. Aku pernah shalat di belakang Umar, dan beliau tidak qunut. Aku pernah shalat di belakang Utsman, dan beliau tidak qunut. Aku juga pernah shalat di belakang Ali, dan beliau juga tidak qunut. Kemudian ia berkata, 'Wahai anakku, itu adalah bid'ah.\""},"1069":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبَّادٌ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ سَعِيدِ بْنِ الْحَارِثِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ فَآخُذُ قَبْضَةً مِنْ حَصًى فِي كَفِّي أُبَرِّدُهُ ثُمَّ أُحَوِّلُهُ فِي كَفِّي الْآخَرِ فَإِذَا سَجَدْتُ وَضَعْتُهُ لِجَبْهَتِي","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abbad] dari [Muhammad bin 'Amr] dari [Sa'id bin Al Harits] dari [Jabir bin 'Abdullah] dia berkata; \"Kami pernah shalat Zhuhur bersama Rasulullah Shallallahu'alaihi wasallam, lalu aku mengambil segenggam kerikil di telapak tanganku untuk kudinginkan. Kemudian aku pindahkan ke telapak tanganku yang lain, dan jika aku sujud maka aku letakkan kerikil itu pada dahiku.\""},"1070":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ غَيْلَانَ بْنِ جَرِيرٍ عَنْ مُطَرِّفٍ قَالَصَلَّيْتُ أَنَا وَعِمْرَانُ بْنُ حُصَيْنٍ خَلْفَ عَلِيِّ بْنِ أَبِي طَالِبٍ فَكَانَ إِذَا سَجَدَ كَبَّرَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ كَبَّرَ وَإِذَا نَهَضَ مِنْ الرَّكْعَتَيْنِ كَبَّرَ فَلَمَّا قَضَى أَخَذَ عِمْرَانُ بِيَدِي فَقَالَ لَقَدْ ذَكَّرَنِي هَذَا قَالَ كَلِمَةً يَعْنِي صَلَاةَ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَ��َّمَ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabiy] dia berkata; telah menceritakan kepada kami [Hammad] dari [Ghailan bin Jarir] dari [Mutharrif] dia berkata; aku Shalat bersama 'Imran bin Hushain di belakang 'Ali bin Abu Thalib dan beliau jika hendak sujud dan jika hendak mengangkat kepalanya dari sujud maka ia bertakbir. Demikian pula jika bangkit dari (duduk) setelah dua rakaat. Setelah selesai shalat [Imran] memegang tanganku dan berkata; 'Ini mengingatkanku -ia mengatakan ucapan yang maksudnya shalat nabi Muhammad Shallallahu'alaihi wasallam- '.\""},"1071":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُعَاذٌ وَيَحْيَى قَالَا حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ وَيُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِوَكَانَ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلَانِهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Mu'adz] dan [Yahya] mereka berdua berkata; telah menceritakan kepada kami [Zuhair] dia berkata; telah menceritakan kepadaku [Abu Ishaq] dari ['Abdurrahman bin Al Aswad] dari ['Alqamah] dan [Al Aswad] dari ['Abdullah bin Mas'ud] dia berkata; \"Dulu Rasulullah Shallallahu'alaihi wasallam selalu takbir pada setiap turun ataupun bangun. Beliau Shallallahu'alaihi wasallam juga mengucapkan salam kekanan dan ke kiri. Abu Bakar dan Umar Radliyallahu'anhu juga melakukannya.\""},"1072":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ قَالَ سَمِعْتُ يُوسُفَ وَهُوَ ابْنُ مَاهَكَ يُحَدِّثُ عَنْ حَكِيمٍ قَالَبَايَعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ لَا أَخِرَّ إِلَّا قَائِمًا","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Abu Basyr] dia berkata; aku mendengar [Yusuf bin Mahak] menceritakan dari [Hakim] dia berkata; \"Aku berbai'at kepada Rasulullah Shallallahu'alaihi wasallam untuk tidak turun menuju sujud kecuali jika betul-betul telah berada dalam posisi berdiri tegak (dalam shalat).\""},"1073":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفَعَ يَدَيْهِ فِي صَلَاتِهِ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ حَتَّى يُحَاذِيَ بِهِمَا فُرُوعَ أُذُنَيْهِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَفَعَ يَدَيْهِ فَذَكَرَ مِثْلَهُ أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ أَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ فِي الصَّلَاةِ فَذَكَرَ نَحْوَهُ وَزَادَ فِيهِ وَإِذَا رَكَعَ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ فَعَلَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhamamd bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Ibnu Abu 'Adiy] dari [Syu'bah] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] bahwasanya ia pernah melihat Rasulullah Shallallahu'alaihi wasallam saat shalat mengangkat kedua tangannya sejajar dengan kedua telinganya, juga ketika hendak ruku', saat mengangkat kepalanya dari ruku', saat sujud, dan ketika mengangkat kepalanya dari sujud. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Abdul A'la] dia berkata; Telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] bahwa dia melihat Rasulullah Shallallahu'alaihi wasallam mengangkat kedua tangannya (maka ia menyebutkan hal yang senada dengan hadits sebelumnya). Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; telah menceritakan kepadaku [Bapakku] dari [Qatadah] dari [Nashr bin Ashim] dari [Malik bin Al Huwairits] bahwa Rasulullah Shallallahu'alaihi wasallam tatkala masuk untuk memulai shalat...(ia menyebutkan hal yang senada dengan hadits sebelumnya). Dia menambahkan: Beliau juga melakukan hal itu ketika hendak ruku', saat mengangkat kepala dari ruku' dan ketika hendak mengangkat kepala dari sujud."},"1074":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْكُوفِيُّ الْمُحَارِبِيُّ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا افْتَتَحَ الصَّلَاةَ وَإِذَا رَكَعَ وَإِذَا رَفَعَ وَكَانَ لَا يَفْعَلُ ذَلِكَ فِي السُّجُودِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid Al Kufi Al Muharibi] dia berkata; telah menceritakan kepada kami [Ibnul Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu 'Umar] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam jika berdiri untuk shalat maka beliau mengangkat kedua tangannya. Begitu juga saat ruku' dan saat mengangkat kepala dari ruku', tetapi beliau Shallallahu'alaihi wasallam tidak melakukan hal tersebut saat sujud.\""},"1075":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى الْقُوْمَسِيُّ الْبَسْطَامِيُّ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ هَارُونَ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَضَعَ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ","id":"Telah mengabarkan kepada kami [Al Husain bin 'Isa Al Qaumasi Al Basthami] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [bapaknya] dari [Wa'il bin Hujr] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihi wasallam meletakan lututnya terlebih dahulu sebelum kedua tangannya apabila hendak sujud, dan mengangkat kedua tangannya dahulu sebelum kedua lututnya apabila bangkit dari sujud.\" "},"1076":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نَافِعٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ حَسَنٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْمِدُ أَحَدُكُمْ فِي صَلَاتِهِ فَيَبْرُكَ كَمَا يَبْرُكُ الْجَمَلُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdullah bin Nafi'] dari [Muhammad bin 'Abdullah bin Hasan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda: 'Hendaklah Salah seorang dari kalian dalam shalatnya turun (untuk sujud) seperti turunnya unta, yaitu meletakkan kedua lututnya lebih dahulu sebelum kedua tangannya.\""},"1077":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ مِنْ كِتَابِهِ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَسَنِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ أَحَدُكُمْ فَلْيَضَعْ يَدَيْهِ قَبْلَ رُكْبَتَيْهِ وَلَا يَبْرُكْ بُرُوكَ الْبَعِيرِ","id":"Telah mengabarkan kepada kami [Harun bin Muhammad bin Bakkar bin Bilal] dari kitabnya dia berkata; telah menceritakan kepada kami [Marwan bin Muhammad] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin Muhammad] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Abdullah bin Al Hasan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam bersabda: 'Jika salah seorang dari kalian hendak sujud, maka hendaklah ia meletakkan kedua tangannya sebelum kedua lututnya dan janganlah ia turun (untuk sujud) seperti menderumnya unta.\""},"1078":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ دَلُّوَيْهِ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَرَفَعَهُ قَالَ إِنَّ الْيَدَيْنِ تَسْجُدَانِ كَمَا يَسْجُدُ الْوَجْهُ فَإِذَا وَضَعَ أَحَدُكُمْ وَجْهَهُ فَلْيَضَعْ يَدَيْهِ وَإِذَا رَفَعَهُ فَلْيَرْفَعْهُمَا","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub Dalluwaih] dia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] -ia menisbatkan hadits ini kepada Nabi Shallallahu'alaihi wasallam- ia berkata; \"Kedua tangan wajib bersujud sebagaimana wajah juga ikut sujud. Jika salah seorang dari kalian telah meletakkan wajahnya, maka hendaklah ia meletakkan kedua tangannya, dan jika mengangkatnya maka hendaklah ia mengangkat keduanya.\""},"1079":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ أَعْضَاءٍ وَلَا يَكُفَّ شَعْرَهُ وَلَا ثِيَابَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari ['Amr] dari [Thawus] dari [Ibnu 'Abbas] dia berkata: \"Nabi Shallallahu'alaihi wasallam diperintahkan sujud di atas tujuh anggota tubuh tanpa mengikat rambut atau melipat bajunya (untuk menghindari debu).\" "},"1080":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ الْعَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مِنْهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدَمَاهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr] dari [Ibnul Had] dari [Muhammad bin Ibrahim] dari ['Amir bin Sa'd] dari [Al 'Abbas bin 'Abdul Muththalib] bahwasanya dia mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika ada seorang hamba yang sujud, maka ia sujud dengan tujuh anggola lubuhnya; wajahnya, kedua telapak tangannya, kedua lulutnya, dan kedua telapak kakinya.\""},"1081":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَبَصُرَتْ عَيْنَايَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَبِينِهِ وَأَنْفِهِ أَثَرُ الْمَاءِ وَالطِّينِ مِنْ صُبْحِ لَيْلَةِ إِحْدَى وَعِشْرِينَمُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] telah dibacakan kepadanya yang saya mendengarnya, dan lafazhnya miliknya dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Yazid bin 'Abdullah bin Al Had] dari [Muhammad bin Ibrahim bin Al Harits] dari [Abu Salamah] dari [Abu Sa'id Al Khudri] dia berkata, \"Mataku melihat dahi dan hidung Rasulullah Shallallahu'alaihi wasallam ada bekas air dan lumpur pada pagi hari, tanggal dua puluh satu.\" (Diringkas)."},"1082":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةٍ لَا أَكُفَّ الشَّعْرَ وَلَا الثِّيَابَ الْجَبْهَةِ وَالْأَنْفِ وَالْيَدَيْنِ وَالرُّكْبَتَيْنِ وَالْقَدَمَيْنِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As-Sarh] dan [Yunus bin 'Abdul A'la] dan [Al Harits bin Miskin] telah dibacakan kepadanya yang saya mendengarnya, dan lafazhnya miliknya dari [Ibnu Wahb] dari [Ibnu Juraij] dari ['Abdullah bin Thawus] dari [bapaknya] dari [Ibnu 'Abbas] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Aku diperintahkan sujud di atas tujuh anggota badan, tanpa mengikat rambut atau melipat baju, yaitu wajah, kedua telapak tangan, kedua lutut, dan kedua telapak kaki.\""},"1083":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ النَّسَائِيُّ قَالَ حَدَّثَنَا الْمُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ عَبْدِ اللَّهِ بْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ عَلَى الْجَبْهَةِ وَأَشَارَ بِيَدِهِ عَلَى الْأَنْفِ وَالْيَدَيْنِ وَالرُّكْبَتَيْنِ وَأَطْرَافِ الْقَدَمَيْنِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur An Nasaa'i] dia berkata; telah menceritakan kepada kami [Al Mu'alla bin Asad] dia berkata; telah menceritakan kepada kami [Wuhaib] dari ['Abdullah bin Thawus] dari [bapaknya] dari [Ibnu 'Abbas] bahwa Rasulullah Shallallahu'alaihi wasallam bersabda: \"Aku diperintahkan sujud di atas tujuh anggota badan, yaitu dahi -ia menunjukkan dengan tangannya ke arah hidung-, kedua tangan, kedua lutut, dan ujung jari-jari kedua telapak kaki.\""},"1084":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الْمَكِّيُّ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعٍ وَنُهِيَ أَنْ يَكْفِتَ الشَّعْرَ وَالثِّيَابَ عَلَى يَدَيْهِ وَرُكْبَتَيْهِ وَأَطْرَافِ أَصَابِعِهِقَالَ سُفْيَانُ قَالَ لَنَا ابْنُ طَاوُسٍ وَوَضَعَ يَدَيْهِ عَلَى جَبْهَتِهِ وَأَمَرَّهَا عَلَى أَنْفِهِ قَالَ هَذَا وَاحِدٌ وَاللَّفْظُ لِمُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Al Makki] dan ['Abdullah Muhammad bin 'Abdurrahman Az Zuhri] mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Thawus] dari [bapaknya] dari [Ibnu 'Abbas] bahwa Nabi Shallallahu'alaihi wasallam diperintahkan sujud di atas tujuh anggota badan -dan dilarang mengikat rambut dan melipat baju- yaitu kedua tangan, kedua lutut, dan ujung jari-jemari (kaki). Sufyan berkata; \"Ibnu Thawus berkata kepada kami; 'la meletakkan kedua tangannya di atas dahi dan hidungnya, lalu berkata, \"Ini adalah satu bagian.\" Lafazh ini dari Muhammad."},"1085":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ أَنْبَأَنَا ابْنُ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ بْنِ الْحَارِثِ عَنْ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ عَنْ عَبَّاسِ بْنِ عَبْدِ الْمُطَّلِبِأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا سَجَدَ الْعَبْدُ سَجَدَ مَعَهُ سَبْعَةُ آرَابٍ وَجْهُهُ وَكَفَّاهُ وَرُكْبَتَاهُ وَقَدَمَاهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Hakim] dari [Syu'aib] dari [Al Laits] dia berkata; telah memberitakan kepada kami [Ibnu Al Had] dari [Muhammad bin Ibrahim bin Al Harits] dari ['Amir bin Sa'ad bin Abu Waqqash] dari ['Abbas bin 'Abdul Muththalib] bahwa ia pernah mendengar Rasulullah Shallallahu'alaihi wasallam bersabda: \"Jika seorang hamba sujud, maka ia sujud dengan tujuh anggota badanya, yaitu wajah, kedua telapak tangan, kedua lutut, dan kedua telapak kaki.\""},"1086":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَانْتَهَيْتُ إِلَيْهِ وَهُوَ سَاجِدٌ وَقَدَمَاهُ مَنْصُوبَتَانِ وَهُوَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَبِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَبِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنْتَ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Ubdah] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Muhammad bin Yahya bin Habban] dari [Al A'raj] dari [Abu Hurairah] dari ['Aisyah] dia berkata; \"Suatu malam aku kehilangan Rasulullah Shallallahu'alaihi wasallam, dan aku menyentuh beliau yang sedang sujud, sedangkan kedua telapak kakinya tegak, dan beliau mengucapkan doa - yang artinya -: 'Ya Allah, aku berlindung dengan keridhaan-Mu dari kemurkaan-Mu, (berlindung juga) dengan kemurahan-Mu dari siksa-Mu. Aku (berlindung) dengan-Mu dan dari adzab-Mu. Aku tidak bisa menghitung pujian kepada-Mu, Engkau sebagaimana yang telah Engkau memuji terhadap diri-Mu sendiri'.\""},"1087":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَهْوَى إِلَى الْأَرْضِ سَاجِدًا جَافَى عَضُدَيْهِ عَنْ إِبِطَيْهِ وَفَتَخَ أَصَابِعَ رِجْلَيْهِمُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdul Humaid bin Ja'far] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Atha] dari [Abu Humaid As Sa'idi] dia berkata; \"Rasulullah Shallallahu'alaihi wasallam apabila hendak turun untuk sujud maka beliau shallallahu 'alaihi wasallam merenggangkan lengan dari kedua ketiaknya dan menancapkan (menegakkan) jari-jemari kedua kakinya.\" (diringkas)."},"1088":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ نَاصِحٍ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ قَالَ سَمِعْتُ عَاصِمَ بْنَ كُلَيْبٍ يَذْكُرُ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَقَدِمْتُ الْمَدِينَةَ فَقُلْتُ لَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى رَأَيْتُ إِبْهَامَيْهِ قَرِيبًا مِنْ أُذُنَيْهِ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ كَبَّرَ وَرَفَعَ يَدَيْهِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ كَبَّرَ وَسَجَدَ فَكَانَتْ يَدَاهُ مِنْ أُذُنَيْهِ عَلَى الْمَوْضِعِ الَّذِي اسْتَقْبَلَ بِهِمَا الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashih] dia berkata; telah menceritakan kepada kami [Ibnu Idris] dia berkata; aku mendengar ['Ashim bin Kulaib] menyebutkan dari [bapaknya] dari [Wa'il bin Hujr] dia berkata; \"Aku datang ke Madinah, lalu aku berkata; 'Aku benar-benar pernah melihat shalatnya Rasulullah Shallallahu'alaihi wasallam, beliau Shallallahu'alaihi wasallam bertakbir dengan mengangkat kedua tangan hingga' aku melihat kedua jempolnya berdekatan dengan kedua telinganya, dan ketika hendak ruku' beliau bertakbir dan mengangkat kedua tangannya, kemudian mengangkat kepalanya sambil mengucapkan, \"Sami'allahu liman Hamidah.\" Kemudian ia bertakbir dan sujud. Kedua tanganya sejajar dengan kedua telinganya, seperti posisi saat menghadap kiblat'.\""},"1089":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ هَارُونَ قَالَ حَدَّثَنَا أَبُو الْعَلَاءِ وَاسْمُهُ أَيُّوبُ بْنُ أَبِي مِسْكِينٍ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَفْتَرِشْ أَحَدُكُمْ ذِرَاعَيْهِ فِي السُّجُودِ افْتِرَاشَ الْكَلْبِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah menceritakan kepada kami [Abul 'Alaa Ayyub bin Abu Miskin] dari [Qatadah] dari [Anas] dari Rasulullah Shallallahu'alaihi wasallam, beliau bersabda: \"Janganlah salah seorang dari kalian menghamparkan kedua lengannya (di tanah) dalam sujud seperti anjing yang menghamparkan (kedua sikunya).\""},"1090":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ قَالَوَصَفَ لَنَا الْبَرَاءُ السُّجُودَ فَوَضَعَ يَدَيْهِ بِالْأَرْضِ وَرَفَعَ عَجِيزَتَهُ وَقَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah mengkhabarkan kepada kami ['Ali bin Hujr Al Marwazi] dia berkata; telah memberitakan kepada kami [Syarik] dari [Abu Ishaq] dia berkata; Al Barra' menjelaskan sujud kepada kami, maka ia meletakkan kedua tangannya dan mengangkat perutnya dari menempel tanah. [Al Barra] berkata; Beginilah yang dilakukan oleh Rasulullah Shalallahu 'Alaihi Wa sallam. "},"1091":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا ابْنُ شُمَيْلٍ هُوَ النَّضْرُ قَالَ أَنْبَأَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى جَخَّى","id":"Telah mengabarkan kepada kami ['Ubdah bin 'Abdurrahim Al Marwazi] dia berkata; telah memberitakan kepada kami [Ibnu Syumail An Nadhr] dia berkata; telah memberitakan kepada kami [Yunus bin Abu Ishaq] dari [Abu Ishaq] dari [Al Barra'] bahwa Rasulullah Shallallahu'alaihi wasallam bila shalat maka beliau merenggangkan kedua sikunya dari kedua lambungnya, dan menjauhkan perutnya dari tanah."},"1092":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى فَرَّجَ بَيْنَ يَدَيْهِ حَتَّى يَبْدُوَ بَيَاضُ إِبْطَيْهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr] dari [Ja'far bin Abu Rabi'ah] dari [Al A'raj] dari ['Abdullah bin Malik bin Buhainah] bahwa Rasulullah Shallallahu'alaihi wasallam apabila melaksanakan shalat maka beliau merenggangkan kedua sikunya hingga kelihatan ketiaknya yang putih."},"1093":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا مُعْتَمِرُ بْنُ سُلَيْمَانَ عَنْ عِمْرَانَ عَنْ أَبِي مِجْلَزٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ قَالَلَوْ كُنْتُ بَيْنَ يَدَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَأَبْصَرْتُ إِبْطَيْهِقَالَ أَبُو مِجْلَزٍ كَأَنَّهُ قَالَ ذَلِكَ لِأَنَّهُ فِي صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Bazi'] dia berkata; telah menceritakan kepada kami [Mu'tamir bin Sulaiman] dari ['Imran] dari [Abu Mijlaz] dari [Basyir bin Nahik] dari [Abu Hurairah] dia berkata; \"Seandainya aku berada di hadapan Rasulullah Shallallahu'alaihi wasallam (saat sujud), maka aku pasti bisa melihat ketiak Rasulullah Shallallahu'alaihi wasallam.\" Abu Mijlaz (perawi) berkata; \"Sepertinya ia mengatakan demikian karena ia dalam keadaan (di waktu) shalat.\""},"1094":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَقْرَمَ عَنْ أَبِيهِ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنْتُ أَرَى عُفْرَةَ إِبْطَيْهِ إِذَا سَجَدَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Dawud bin Qais] dari ['Ubaidillah bin 'Abdullah bin Aqram] dari [Bapaknya], dia berkata; \"Aku shalat bersama Rasulullah Shallallahu'alaihi wasallam dan aku melihat putihnya ketiak beliau Shallallahu'alaihi wasallam apabila sujud.\""},"1095":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ وَهُوَ ابْنُ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ عَنْ عَمِّهِ يَزِيدَ وَهُوَ ابْنُ الْأَصَمِّ عَنْ مَيْمُونَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ جَافَى يَدَيْهِ حَتَّى لَوْ أَنَّ بَهْمَةً أَرَادَتْ أَنْ تَمُرَّ تَحْتَ يَدَيْهِ مَرَّتْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ubaidillah bin 'Abdullah bin Al Asham] dari pamannya [Yazid bin Al Asham] dari [Maimunah] bahwa Nabi Shallallahu'alaihi wasallam bila sujud maka beliau merenggangkan kedua sikunya dari lambung, hingga apabila ada anak kambing (yang baru lahir) yang hendak lewat di bawah kedua tangannya maka ia bisa melewatinya."},"1096":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسٍ ح و أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ خَالِدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًاعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اعْتَدِلُوا فِي السُّجُودِ وَلَا يَبْسُطْ أَحَدُكُمْ ذِرَاعَيْهِ انْبِسَاطَ الْكَلْبِاللَّفْظُ لِإِسْحَقَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdah] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Anas] -dan lewat jalur periwayatan lain-- dan telah mengabarkan kepada kami [Isma'il bin Mas'ud] dari [Khalid] dari [Syu'bah] dari [Qatadah] dia berkata; Aku mendengar [Anas] dari Rasulullah Shallallahu'alaihi wasallam beliau bersabda: \"Luruslah saat sujud. Janganlah salah seorang dari kalian membentangkan kedua lengannya seperti anjing.\" Lafazh ini dari Ishaq."},"1097":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي مَعْمَرٍ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُجْزِئُ صَلَاةٌ لَا يُقِيمُ الرَّجُلُ فِيهَا صُلْبَهُ فِي الرُّكُوعِ وَالسُّجُودِ","id":"Telah mengabarkan kepada kami ['Ali bin Khasyram Al Marwazi] dia berkata; telah memberitakan kepada kami ['Isa bin Yunus] dari [Al A'masy] dari ['Umarah] dari [Abu Ma'mar] dari [Abu Mas'ud] dia berkata; Rasulullah Shallallahu'alaihi wasallam bersabda: \"Shalat seseorang tidak sah bila tulang rusuk (punggung) nya tidak tegak (thuma 'ninah) saat ruku' dan sujud.\""},"1098":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ عَنْ شُعَيْبٍ عَنْ اللَّيْثِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي هِلَالٍ عَنْ جَعْفَرِ بْنِ عَبْدِ اللَّهِ أَنَّ تَمِيمَ بْنَ مَحْمُودٍ أَخْبَرَهُ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ شِبْلٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ ثَلَاثٍ عَنْ نَقْرَةِ الْغُرَابِ وَافْتِرَاشِ السَّبُعِ وَأَنْ يُوَطِّنَ الرَّجُلُ الْمَقَامَ لِلصَّلَاةِ كَمَا يُوَطِّنُ الْبَعِيرُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dari [Syu'aib] dari [Al Laits] dia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Hilal] dari [Ja'far bin 'Abdullah] telah mengabarkan kepadanya [Tamim bin Mahmud] telah mengabarkan kepadanya ['Abdurrahman bin Syibl] bahwa Rasulullah Shallallahu'alaihi wasallam melarang tiga hal -dalam shalat-: mematuk seperti burung Gagak, menghamparkan kedua lengan seperti binatang buas, dan membentuk tempat khusus baginya untuk shalat sebagaimana unta membentuk tempat khusus untuk menderum."},"1099":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ الْبَصْرِيُّ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ وَرَوْحٌ يَعْنِي ابْنَ الْقَاسِمِ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أُمِرْتُ أَنْ أَسْجُدَ عَلَى سَبْعَةٍ وَلَا أَكُفَّ شَعْرًا وَلَا ثَوْبًا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah Al Bashri] dari [Yazid] -yaitu Ibnu Zura'i- dia berkata; telah menceritakan kepada kami [Syu'bah] dan [Rauh] yaitu Ibnu Al Qashim dari [Amr bin Dinar] dari [Thawus] dari [Ibnu Abbas] dia berkata; \"Nabi Shallallahu'alaihiwasallam Bersabda: Aku diperintahkan sujud di atas tujuh anggota badan, tanpa mengikat rambut atau baju.\""},"1100":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو السَّرْحِيُّ مِنْ وَلَدِ عَبْدِ اللَّهِ بْنِ سَعْدِ بْنِ أَبِي سَرْحٍ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ بُكَيْرًا حَدَّثَهُ أَنَّ كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّهُ رَأَى عَبْدَ اللَّهِ بْنَ الْحَارِثِ يُصَلِّي وَرَأْسُهُ مَعْقُوصٌ مِنْ وَرَائِهِ فَقَامَ فَجَعَلَ يَحُلُّهُ فَلَمَّا انْصَرَفَ أَقْبَلَ إِلَى ابْنِ عَبَّاسٍ فَقَالَ مَا لَكَ وَرَأْسِي قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّمَا مَثَلُ هَذَا مَثَلُ الَّذِي يُصَلِّي وَهُوَ مَكْتُوفٌ","id":"Telah mengabarkan kepada kami [Amr bin Sawwad bin Al Aswad bin Amr As-Sarhiy] -ia salah seorang anak Abdullah bin Sa'ad bin Abu Sarh- dia berkata; telah memberitakan kepada kami [Ibnu Wahab] dia berkata; telah memberitakan kepada kami [Amr bin Al Harits] bahwasanya [Bukair] telah bercerita kepadanya bahwa [Kuraiba] -budak Ibnu Abbas- berkata kepadanya dari [Abdullah bin Abbas] bahwa dia melihat Abdullah bin Al Harits sedang shalat dan rambut kepalanya dililit ke belakang, lalu dia bangkit dan melepaskan ikatan tersebut. Setelah selesai shalat, dia menghadap Ibnu Abbas dan berkata; \"Kenapa kamu dengan (melepaskan ikatan) kepalaku?\" Ia menjawab; \"Aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: 'Perumpamaan orang ini -yang shalat dengan mengikat rambutnya- seperti orang yang shalat sedangkan kedua tangannya diikat ke belakang'.\""},"1101":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الْمَكِّيُّ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَأُمِرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَسْجُدَ عَلَى سَبْعَةِ أَعْظُمٍ وَنُهِيَ أَنْ يَكُفَّ الشَّعْرَ وَالثِّيَابَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Al Makii] dari [Sufyan] dari ['Amr] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Nabi Shallallahu'alaihiwasallam diperintahkan sujud di atas tujuh anggota badan dan melarang mengikat rambut atau melipat baju.\""},"1102":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ خَالِدِ بْنِ عَبْدِ الرَّحْمَنِ هُوَ السُّلَمِيُّ قَالَ حَدَّثَنِي غَالِبٌ الْقَطَّانُ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ أَنَسٍ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالظَّهَائِرِ سَجَدْنَا عَلَى ثِيَابِنَا اتِّقَاءَ الْحَرِّ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Mubarak] dari [Khalid bin 'Abdurrahman As-Sulami] dia berkata telah menceritakan kepada kami [Ghalib Al Quththan] dari [Bakr bin 'Abdullah Al Muzanni] dari [Anas] dia berkata; \"Kami pernah shalat di belakang Rasulullah Shallallahu'alaihiwasallam pada pertengahan siang (saat panas sekali), lalu kami sujud di atas baju-baju kami untuk menghindari panas.\" "},"1103":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَتِمُّوا الرُّكُوعَ وَالسُّجُودَ فَوَاللَّهِ إِنِّي لَأَرَاكُمْ مِنْ خَلْفِ ظَهْرِي فِي رُكُوعِكُمْ وَسُجُودِكُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdah] dari [Sa'id] dari [Qatadah] dari [Anas] dari Rasulullah Shallallahu'alaihiwasallam, beliau bersabda: \"Sempurnakanlah ruku' dan sujud kalian. Demi Allah, aku melihat kalian dari balik punggungku saat kalian sedang melakukan ruku ' dan sujud.\""},"1104":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ وَعُثْمَانُ بْنُ عُمَرَ قَالَ أَبُو عَلِيٍّ حَدَّثَنَا وَقَالَ عُثْمَانُ أَنْبَأَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَانِي حِبِّي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ثَلَاثٍ لَا أَقُولُ نَهَى النَّاسَ نَهَانِي عَنْ تَخَتُّمِ الذَّهَبِ وَعَنْ لُبْسِ الْقَسِّيِّ وَعَنْ الْمُعَصْفَرِ الْمُفَدَّمَةِ وَلَا أَقْرَأُ سَاجِدًا وَلَا رَاكِعًا","id":"Telah mengabarkan kepada kami [Abu Dawud Sulaiman bin Saif] dia berkata; telah menceritakan kepada kami [Abu 'Ali Al Hanafi] dan ['Utsman bin 'Umar], Abu 'Ali berkata; telah menceritakan kepada kami dan 'Utsman berkata; telah memberitakan kepada kami [Dawud bin Qais] dari [Ibrahim bin 'Abdullah bin Hunain] dari [bapaknya] dari [Ibnu 'Abbas] dari ['Ali bin Abu Thalib] Radliyallahu'anhu dia berkata; \"Kekasihku, Rasulullah Shallallahu'alaihiwasallam melarangku tiga hal -aku tidak mengatakan beliau melarang manusia- untuk memakai cincin emas, pakaian yang berbordir sutra, pakaian yang dicelup warna kuning menyala, dan melarang membaca (Al Qur'an) saat aku ruku' dan sujud.\""},"1105":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُ سَمِعَ عَلِيًّا قَالَنَهَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقْرَأَ رَاكِعًا أَوْ سَاجِدًا","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As-Sarh] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dari [Yunus] dan [Al Harits bin Miskin] telah dibacakan kepadanya dan saya mendengarkannya dari [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku [Ibrahim bin 'Abdullah] bahwasanya [bapaknya] menceritakan kepadanya, dia mendengar [Ali] berkata; \"Rasulullah Shallallahu'alaihiwasallam melarangku membaca (Al Qur'an) saat ruku' dan sujud.\""},"1106":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا إِسْمَعِيلُ هُوَ ابْنُ جَعْفَرٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ سُحَيْمٍ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ مَعْبَدِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكَشَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السِّتْرَ وَرَأْسُهُ مَعْصُوبٌ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ فَقَالَ اللَّهُمَّ قَدْ بَلَّغْتُ ثَلَاثَ مَرَّاتٍ إِنَّهُ لَمْ يَبْقَ مِنْ مُبَشِّرَاتِ النُّبُوَّةِ إِلَّا الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْعَبْدُ أَوْ تُرَى لَهُ أَلَا وَإِنِّي قَدْ نُهِيتُ عَنْ الْقِرَاءَةِ فِي الرُّكُوعِ وَالسُّجُودِ فَإِذَا رَكَعْتُمْ فَعَظِّمُوا رَبَّكُمْ وَإِذَا سَجَدْتُمْ فَاجْتَهِدُوا فِي الدُّعَاءِ فَإِنَّهُ قَمِنٌ أَنْ يُسْتَجَابَ لَكُمْ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr Al Marwazi] dia berkata; telah memberitakan kepada kami [Ismail ibnu Ja'far] dia berkata; telah menceritakan kepada kami [Sulaiman bin Suhaim] dari [Ibrahim bin Abdullah bin Ma'bad bin 'Abbas] dari [bapaknya] dari ['Abdullah bin 'Abbas] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam suatu saat menyingkap tirai, dan kepalanya dililit (diperban) dengan kain karena sakit -yang akhirnya menyebabkan beliau meninggal dunia- lalu beliau Shallallahu'alaihiwasallam bersabda: 'Ya Allah, telah kusampaikan - tiga kali -, sesungguhnya tidak tersisa lagi kabar kenabian kecuali mimpi yang benar, yakni mimpi yang dilihat atau diperlihatkan kepada seorang hamba '. Kemudian beliau Shallallahu'alaihiwasallam menambahkan, 'Ketahuilah, aku dilarang membaca (Al Qur'an) saat ruku' atau sujud. Ketika ruku' maka agungkanlah Rabb kalian dan ketika sujud maka bersungguh-sungguhlah dalam berdoa. karena saat itu kemungkinan besar doa kalian dikabulkan.'"},"1107":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي رِشْدِينَ وَهُوَ كُرَيْبٌ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ بِنْتِ الْحَارِثِ وَبَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا فَرَأَيْتُهُ قَامَ لِحَاجَتِهِ فَأَتَى الْقِرْبَةَ فَحَلَّ شِنَاقَهَا ثُمَّ تَوَضَّأَ وُضُوءًا بَيْنَ الْوُضُوءَيْنِ ثُمَّ أَتَى فِرَاشَهُ فَنَامَ ثُمَّ قَامَ قَوْمَةً أُخْرَى فَأَتَى الْقِرْبَةَ فَحَلَّ شِنَاقَهَا ثُمَّ تَوَضَّأَ وُضُوءًا هُوَ الْوُضُوءُ ثُمَّ قَامَ يُصَلِّي وَكَانَ يَقُولُ فِي سُجُودِهِ اللَّهُمَّ اجْعَلْ فِي قَلْبِي نُورًا وَاجْعَلْ فِي سَمْعِي نُورًا وَاجْعَلْ فِي بَصَرِي نُورًا وَاجْعَلْ مِنْ تَحْتِي نُورًا وَاجْعَلْ مِنْ فَوْقِي نُورًا وَعَنْ يَمِينِي نُورًا وَعَنْ يَسَارِي نُورًا وَاجْعَلْ أَمَامِي نُورًا وَاجْعَلْ خَلْفِي نُورًا وَأَعْظِمْ لِي نُورًا ثُمَّ نَامَ حَتَّى نَفَخَ فَأَتَاهُ بِلَالٌ فَأَيْقَظَهُ لِلصَّلَاةِ","id":"Telah mengabarkan kepada kami [Hunnad bin As Sari] dari [Abul Ahwas] dari [Sa'id bin Masruq] dari [Salamah bin Kuhail] dari [Abu Risydin Karib] dari [Ibnu 'Abbas] dia berkata; \"Aku pernah menginap di rumah bibiku Maimunah binti Al Harits, dan Rasulullah Shallallahu'alaihiwasallam juga bermalam di sana. Aku melihat beliau bangun untuk suatu keperluan, lalu mengambil qirbah (kantong kulit untuk tempat air) kemudian melepaskan tali pengikat tutupnya, lantas beliau wudhu dengan sederhana. Setelah itu Rasulullah Shallallahu'alaihiwasallam pergi ke tempat tidur dan tertidur, kemudian bangun lagi. Lalu beliau mengambil qirbahnya lagi dan melepaskan tali, penutupnya lantas berwudhu' dengan wudhu yang sederhana, kemudian berdiri untuk shalat. Ketika sujud beliau berdoa: 'Ya Allah, berikanlah cahaya dalam hati dan lisanku, pendengaranku dan penglihatanku. Berilah cahaya dari arah bawahku, atasku, sebelah kananku, sebelah kiriku, sebelah depanku, sebelah belakangku, serta pada jiwaku, dan agungkanlah cahaya itu padaku, kemudian beliau tidur hingga terdengar napas tidur beliau, lalu Bilal mendatanginya dan membangunkannya untuk shalat'.\""},"1108":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Manshur] dari [Abu Adl Dluha] dari [Masruq] dari ['Aisyah] dia berkata; Rasulullah Shallallahu'alaihiwasallam saat ruku' dan sujud membaca doa -yang artinya-: \"Ya Allah, Maha Suci Engkau Rabb kami dan kami memuji-Mu. Ya Allah, ampunilah aku.\" Ini merupakan tafsiran dari Al Qur'an."},"1109":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبْحَانَكَ اللَّهُمَّ رَبَّنَا وَبِحَمْدِكَ اللَّهُمَّ اغْفِرْ لِي يَتَأَوَّلُ الْقُرْآنَ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghalian] dia berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Manshur] dari [Abu Adl Dluhaa] dari [Masruq] dari ['Aisyah] dia berkata; bahwa Rasulullah Shallallahu'alaihiwasallam saat ruku' dan sujud membaca doa -yang artinya-: \"Ya Allah, Maha Suci Engkau Rabb kami dan kami memuji-Mu. Ya Allah, ampunilah aku.\" Ini merupakan tafsiran dari Al Qur'an."},"1110":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَظَنَنْتُ أَنَّهُ أَتَى بَعْضَ جَوَارِيهِ فَطَلَبْتُهُ فَإِذَا هُوَ سَاجِدٌ يَقُولُ رَبِّ اغْفِرْ لِي مَا أَسْرَرْتُ وَمَا أَعْلَنْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Hilal bin Yasaf] dari ['Aisyah] Radliyallahu'anha dia berkata; \"Aku pernah kehilangan Rasulullah Shallallahu'alaihi wasallam, dan kukira beliau telah mendatangi sebagian istrinya yang lain. Aku mencarinya dan ternyata beliau sedang sujud. Beliau Shallallahu'alaihiwasallam mengucapkan doa -yang artinya-: \"Ya Allah, ampunilah aku dari apa yang aku perlihatkan dan yang aku sembunyikan.\""},"1111":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ هُوَ ابْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ قَالَ حَدَّثَنِي عَمِّي الْمَاجِشُونُ بْنُ أَبِي سَلَمَةَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيٍّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَجَدَ يَقُولُ اللَّهُمَّ لَكَ سَجَدْتُ وَلَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَصَوَّرَهُ فَأَحْسَنَ صُورَتَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ تَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Mahdi] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] dia berkata; telah menceritakan kepadaku pamanku [Al Majisyun bin Abu Salamah] dari ['Abdurrahman Al A'raj] dari ['Ubaidullah bin Abu Rafi'] dari ['Ali] bahwa Rasulullah Shallallahu'alaihiwasallam bila sujud mengucapkan doa, Ya Allah, kepada-Mu aku sujud, kepada-Mu aku pasrah, dan kepada-Mu aku beriman. Wajahku sujud kepada Dzat yang telah menciptakannya dan membentuknya serta membuat bentuknya dengan sangat bagus, lalu la menciptakan pendengaran dan penglihatannya. Maha Suci Allah sebaik-sebaik pencipta."},"1112":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ عُثْمَانَ قَالَ أَنْبَأَنَا أَبُو حَيْوَةَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي سُجُودِهِ اللَّهُمَّ لَكَ سَجَدْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ وَأَنْتَ رَبِّي سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَصَوَّرَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ تَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ","id":"Telah mengabarkan kepada kami [Yahya bin 'Utsman] dia berkata; telah memberitakan kepada kami [Abu Haiwah] dia berkata; telah menceritakan kepada kami [Syu'aib bin Abu Hamzah] dari [Muhammad bin Al Munkadir] dari [Jabir bin 'Abdullah] dari Nabi Shallallahu'alaihi wasallam, beliau Shallallahu'alaihiwasallam dalam' sujudnya mengucapkan doa: Ya Allah, kepada-Mu aku sujud, kepada-Mu aku beriman, dan kepada-Mu aku pasrah. Engkau Rabbku, wajahku sujud kepada Dzat yang telah menciptakannya dan membentuknya, serta membuat bentuknya dengan sangat bagus, lalu la menciptakan pendengaran dan penglihatannya. Maha Suci Allah sebaik-baik pencipta.\""},"1113":{"ar":"أَخْبَرَنَا سَوَّارُ بْنُ عَبْدِ اللَّهِ بْنِ سَوَّارٍ الْقَاضِي وَمُحَمَّدُ بْنُ بَشَّارٍ عَنْ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي الْعَالِيَةِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي سُجُودِ الْقُرْآنِ بِاللَّيْلِ سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ بِحَوْلِهِ وَقُوَّتِهِ","id":"Telah mengabarkan kepada kami [Sawwar bin 'Abdullah bin Sawwar Al Qadli] dan [Muhammad bin Basysyar] dari ['Abdul Wahhab] dia berkata; telah menceritakan kepada kami [Khalid] dari [Abul 'Aliyah] dari ['Aisyah] bahwa Rasulullah Shallallahu'alaihiwasallam pada suatu malam saat sujud (tilawah/ayat alquran yang terdapat ayat sajdah) mengucapkan doa, \"Wajahku sujud kepada Dzat yang telah menciptakannya dan membentuknya, serta membuat bentuknya dengan sangat bagus, lalu la menciptakan pendengaran dan penglihatannya dengan segala daya dan kekuatan-Nya.\""},"1114":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَائِشَةَ قَالَتْفَقَدْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَوَجَدْتُهُ وَهُوَ سَاجِدٌ وَصُدُورُ قَدَمَيْهِ نَحْوَ الْقِبْلَةِ فَسَمِعْتُهُ يَقُولُ أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَأَعُوذُ بِمُعَافَاتِكَ مِنْ عُقُوبَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا أُحْصِي ثَنَاءً عَلَيْكَ أَنَتْ كَمَا أَثْنَيْتَ عَلَى نَفْسِكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari ['Aisyah] dia berkata; \"Suatu malam aku kehilangan Rasulullah Shallallahu'alaihiwasallam dan aku menyentuh beliau yang sedang sujud, sedangkan kedua telapak kakinya tegak menghadap kiblat. Beliau mengucapkan doa, 'Ya Allah, aku berlindung dengan keridhaan-Mu dari kemurkaan-Mu dan dengan kemurahan-Mu dari siksa-Mu. Aku (berlindung) kepada-Mu dari adzab-Mu, aku tidak bisa menghitung pujian kepada-Mu, Engkau sebagaimana yang Engkau memuji diri-Mu sendiri.\""},"1115":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ قَالَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ عَنْ عَمْرِو بْنِ قَيْسٍ الْكِنْدِيِّ أَنَّهُ سَمِعَ عَاصِمَ بْنَ حُمَيْدٍ يَقُولُ سَمِعْتُ عَوْفَ بْنَ مَالِكٍ يَقُولُقُمْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَدَأَ فَاسْتَاكَ وَتَوَضَّأَ ثُمَّ قَامَ فَصَلَّى فَبَدَأَ فَاسْتَفْتَحَ مِنْ الْبَقَرَةِ لَا يَمُرُّ بِآيَةِ رَحْمَةٍ إِلَّا وَقَفَ وَسَأَلَ وَلَا يَمُرُّ بِآيَةِ عَذَابٍ إِلَّا وَقَفَ يَتَعَوَّذُ ثُمَّ رَكَعَ فَمَكَثَ رَاكِعًا بِقَدْرِ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ سَجَدَ بِقَدْرِ رُكُوعِهِ يَقُولُ فِي سُجُودِهِ سُبْحَانَ ذِي الْجَبَرُوتِ وَالْمَلَكُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ قَرَأَ آلَ عِمْرَانَ ثُمَّ سُورَةً ثُمَّ سُورَةً فَعَلَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Sawwar] dia berkata; telah menceritakan kepada kami [Laits bin Sa'ad] dari [Mu'awiyah bin Shalih] dari ['Amr bin Qais Al Kindi] bahwasanya dia mendengan ['Ashim bin Humaid] berkata; aku mendengar ['Auf bin Malik] berkata; \"Aku pernah bangun bersama Nabi Shallallahu'alaihi wasallam, lalu beliau mulai bersiwak dan berwudhu. Kemudian beliau berdiri dan shalat. Beliau mengawali shalatnya dengan membaca surat Al Baqarah. Beliau tidak melewati ayat tentang rahmat kecuali beliau berhenti dan memohon (rahmat). Beliau juga tidak melewati ayat tentang adzab kecuali beliau berhenti dan berlindung darinya. Kemudian beliau ruku' hingga ia tenang dalam keadaan ruku' seukuran berdirinya, sambil membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati (Maha Suci Dzat yang mempunyai hak memaksa dan kekuasaan, serta yang memiliki kesombongan dan keagungan) ' saat ruku'. Lantas beliau Shallallahu'alaihiwasallam sujud seukuran ruku'nya tadi dengan membaca: 'Subhana dzil jabaruuti wal malakuuti wal kibriyaai wal 'adzamati'. Kemudian beliau membaca surat Ali 'Imran, kemudian surat lainnya, dan beliau juga melakukan hal yang sama - di rakaat berikutnya -.\" "},"1116":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَاسْتَفْتَحَ بِسُورَةِ الْبَقَرَةِ فَقَرَأَ بِمِائَةِ آيَةٍ لَمْ يَرْكَعْ فَمَضَى قُلْتُ يَخْتِمُهَا فِي الرَّكْعَتَيْنِ فَمَضَى قُلْتُ يَخْتِمُهَا ثُمَّ يَرْكَعُ فَمَضَى حَتَّى قَرَأَ سُورَةَ النِّسَاءِ ثُمَّ قَرَأَ سُورَةَ آلِ عِمْرَانَ ثُمَّ رَكَعَ نَحْوًا مِنْ قِيَامِهِ يَقُولُ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ وَأَطَالَ الْقِيَامَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى لَا يَمُرُّ بِآيَةِ تَخْوِيفٍ أَوْ تَعْظِيمٍ لِلَّهِ عَزَّ وَجَلَّ إِلَّا ذَكَرَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Sa'ad bin 'Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] dia berkata; \"Pada suatu malam aku mengerjakan shalat bersama Rasulullah Shallallahu'alaihiwasallam, beliau mulai dengan membaca surat Al Baqarah. Beliau telah membaca seratus ayat dan belum ruku lalu tetap membacanya.\" Hudzaifah berkata; \"Beliau menyelesaikannya pada dua rakaat, lantas berlalu.\" Hudzaifah berkata lagi; \"Beliau menyelesaikannya kemudian ruku' dan terus berlalu hinggga beliau membaca surat An-Nisaa', kemudian membaca surat Ali 'Imraan, lalu ruku' yang lamanya seperti berdiri. Saat ruku' beliau mengucapkan, 'Subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi, subhana rabbiyal 'adzimi (Maha suci Tuhan-ku yang Maha Agung) '. Lalu beliau mengangkat kepala sambil mengucapkan, 'Sami'allahu liman hamidah rabbana lakal hamdu (Allah Maha mendengar orang yang memuji-Nya, segala puji untuk-Mu) '. Beliau memperpanjang berdirinya kemudian sujud, dan beliau memperlama sujudnya sambil mengucapkan, 'Subhana rabbiyal a'laa, subhana rabbiyal a'laa, subhana rabbiyal a'laa (Maha Suci Tuhanku yang Maha Tinggi) '. Beliau Shallallahu'alaihiwasallam tidak melalui ayat ancaman atau pengagungan Allah Azza wa Jalla kecuali beliau Shallallahu'alaihiwasallam berdzikir kepada-Nya.\""},"1117":{"ar":"أَخْبَرَنَا بُنْدَارٌ مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ وَابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ قَالَا حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ فِي رُكُوعِهِ وَسُجُودِهِ سُبُّوحٌ قُدُّوسٌ رَبُّ الْمَلَائِكَةِ وَالرُّوحِ","id":"Telah mengabarkan kepada kami [Bundar Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dan [Ibnu Abu 'Adi] dari [Syu'bah] dia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Mutharrif] dari ['Aisyah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam ketika ruku' dan sujudnya memperbanyak bacaan, 'Subbuuhun qudduusun, rabbul malaaikati warruh (Maha Suci dan Maha Qudus, Rabb para malaikat dan malaikat Jibril) '.\""},"1118":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِبْرَاهِيمَ بْنِ عُمَرَ بْنِ كَيْسَانَ قَالَ حَدَّثَنِي أَبِي عَنْ وَهْبِ بْنِ مَانُوسَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُمَا رَأَيْتُ أَحَدًا أَشْبَهَ صَلَاةً بِصَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ هَذَا الْفَتَى يَعْنِي عُمَرَ بْنَ عَبْدِ الْعَزِيزِ فَحَزَرْنَا فِي رُكُوعِهِ عَشْرَ تَسْبِيحَاتٍ وَفِي سُجُودِهِ عَشْرَ تَسْبِيحَاتٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdullah bin Ibrahim bin 'Umar bin Kaisan] dia berkata; [bapakku] telah menceritakan kepadaku dari [Wahb bin Manus] dia berkata; aku mendengar [Sa'id bin Jubair] berkata; aku mendengar [Anas bin Malik] berkata; \"Tidaklah aku melihat seorangpun yang shalatnya lebih menyerupai shalat Rasulullah Shalallahu 'Alaihi Wa Sallam dari pemuda ini, -yaitu Umar bin Abdul Aziz-. Kami mengira dia membaca sepuluh tasbih dalam setiap ruku dan sujudnya.\""},"1119":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ أَبُو يَحْيَى بِمَكَّةَ وَهُوَ بَصْرِيٌّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا هَمَّامٌ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ أَنَّ عَلِيَّ بْنَ يَحْيَى بْنِ خَلَّادِ بْنِ مَالِكِ بْنِ رَافِعِ بْنِ مَالِكٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَمِّهِ رِفَاعَةَ بْنِ رَافِعٍ قَالَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ وَنَحْنُ حَوْلَهُ إِذْ دَخَلَ رَجُلٌ فَأَتَى الْقِبْلَةَ فَصَلَّى فَلَمَّا قَضَى صَلَاتَهُ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى الْقَوْمِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ اذْهَبْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَذَهَبَ فَصَلَّى فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُ صَلَاتَهُ وَلَا يَدْرِي مَا يَعِيبُ مِنْهَا فَلَمَّا قَضَى صَلَاتَهُ جَاءَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى الْقَوْمِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْكَ اذْهَبْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَأَعَادَهَا مَرَّتَيْنِ أَوْ ثَلَاثًا فَقَالَ الرَّجُلُ يَا رَسُولَ اللَّهِ مَا عِبْتَ مِنْ صَلَاتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَمْ تَتِمَّ صَلَاةُ أَحَدِكُمْ حَتَّى يُسْبِغَ الْوُضُوءَ كَمَا أَمَرَهُ اللَّهُ عَزَّ وَجَلَّ فَيَغْسِلَ وَجْهَهُ وَيَدَيْهِ إِلَى الْمِرْفَقَيْنِ وَيَمْسَحَ بِرَأْسِهِ وَرِجْلَيْهِ إِلَى الْكَعْبَيْنِ ثُمَّ يُكَبِّرَ اللَّهَ عَزَّ وَجَلَّ وَيَحْمَدَهُ وَيُمَجِّدَهُ قَالَ هَمَّامٌ وَسَمِعْتُهُ يَقُولُ وَيَحْمَدَ اللَّهَ وَيُمَجِّدَهُ وَيُكَبِّرَهُ قَالَ فَكِلَاهُمَا قَدْ سَمِعْتُهُ يَقُولُ قَالَ وَيَقْرَأَ مَا تَيَسَّرَ مِنْ الْقُرْآنِ مِمَّا عَلَّمَهُ اللَّهُ وَأَذِنَ لَهُ فِيهِ ثُمَّ يُكَبِّرَ وَيَرْكَعَ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ وَتَسْتَرْخِيَ ثُمَّ يَقُولَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ يَسْتَوِيَ قَائِمًا حَتَّى يُقِيمَ صُلْبَهُ ثُمَّ يُكَبِّرَ وَيَسْجُدَ حَتَّى يُمَكِّنَ وَجْهَهُ وَقَدْ سَمِعْتُهُ يَقُولُ جَبْهَتَهُ حَتَّى تَطْمَئِنَّ مَفَاصِلُهُ وَتَسْتَرْخِيَ وَيُكَبِّرَ فَيَرْفَعَ حَتَّى يَسْتَوِيَ قَاعِدًا عَلَى مَقْعَدَتِهِ وَيُقِيمَ صُلْبَهُ ثُمَّ يُكَبِّرَ فَيَسْجُدَ حَتَّى يُمَكِّنَ وَجْهَهُ وَيَسْتَرْخِيَ فَإِذَا لَمْ يَفْعَلْ هَكَذَا لَمْ تَتِمَّ صَلَاتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin yazid Al Muqri Abu Yahya] di Mekkah dan dia adalah orang Bashrah dia berkata; telah menceritakan kepada kami [bapakku], dia berkata; telah menceritakan kepada kami [Hammam] dia berkata; telah menceritakan kepada kami [Ishaq bin 'Abdullah bin Abu Thalhah] bahwasanya ['Ali bin Yahya bin Khallad bin Malik bin Rafi' bin Malik], telah menceritakan kepadanya dari [Bapaknya], dari pamannya [Rifa'ah bin Rafi'] dia berkata; \"Tatkala Rasulullah Shallallahu'alaihiwasallam sedang duduk-duduk dan kami di sekelilingnya, tiba-tiba ada seorang laki-laki masuk ke dalam masjid dan menghadap ke kiblat, lalu shalat. Setelah selesai shalat ia datang kepada Rasulullah Shallallahu'alaihiwasallam sambil mengucapkan salam kepada beliau dan kepada kaum Muslimin, maka beliau Shallallahu'alaihiwasallam membalas salamnya lalu bersabda kepadanya: \"Alaikassalam, kembalilah dan shalatlah lagi, sesungguhnya engkau belum shalat'. Lalu ia pergi dan shalat lagi. Rasulullah Shallallahu'alaihiwasallam mengawasi shalatnya tanpa ia sadari kesalahannya! Setelah selesai dari shalatnya ia datang lagi kepada Rasulullah Shallallahu'alaihiwasallam sambil mengucapkan salam kepadanya dan kepada kaum Muslimin, maka beliau Shallallahu'alaihiwasallam membalas salamnya lalu bersabda kepadanya, ' 'Alaikassalam, kembalilah dan shalatlah lagi, sesungguhnya, engkau belum shalat'. la mengulanginya dua atau tiga kali, lantas orang tersebut berkata; 'Wahai Rasulullah Shallallahu'alaihiwasallam, apa yang engkau cela dari shalatku? ' Rasulullah Shallallahu'alaihiwasallam bersabda: \"Belum sempurna shalat salah seorang dari kalian hingga ia menyempurnakan wudhunya sebagaimana yang telah \"Allah Azza wa Jalla perintahkan, Membasuh wajahnya dan kedua tangannya sampai ke siku-sikunya, mengusap kepalanya dan membasuh kedua kakinya sampai ke kedua mata kakinya, lalu bertakbir kepada Allah Azza wa Jalla -dan memuji serta mengagungkan-Nya-Pada lafazh lain: beliau mengatakan: lalu memuji Allah dan mengagungkan-Nya. Rifa'ah berkata; \"Kedua (kalimat) tadi kudengar dari Rasulullah Shallallahu'alaihi wasallam.\" Lalu membaca Al Qur'an yang mudah baginya, yang diajarkan oleh Allah dan diizinkan-Nya. Kemudian bertakbir lalu ruku' hingga tenang persendiannya, kemudian mengucapkan, \"Sami'allahu liman hamidah.\" Kemudian ia berdiri tegak hingga lurus punggungnya, lalu bertakbir dan sujud hingga menempelkan wajahnya-pada lafazh lain: dahinya-hingga tenang persendiannya, kemudian bertakbir dan bangkit dari sujud hingga duduk di tempatnya dan lurus punggungya. Lantas bertakbir dan sujud lagi hingga menempel wajahnya dan tenang. Jika tidak melakukan seperti itu maka belum sempurna shalatnya'.\""},"1120":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرٍو يَعْنِي ابْنَ الْحَارِثِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ سُمَيٍّ أَنَّهُ سَمِعَ أَبَا صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَبُ مَا يَكُونُ الْعَبْدُ مِنْ رَبِّهِ عَزَّ وَجَلَّ وَهُوَ سَاجِدٌ فَأَكْثِرُوا الدُّعَاءَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr ibnu Al Harits] dari ['Umarah bin Ghaziyah] dari [Sumayya] bahwasanya dia mendengar [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: \"Keadaan hamba yang paling dekat dengan Allah Azza wa Jalla adalah saat ia sujud, maka perbanyaklah berdoa saat sujud.\""},"1121":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَمَّارٍ عَنْ هِقْلِ بْنِ زِيَادٍ الدِّمَشْقِيِّ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ كَعْبٍ الْأَسْلَمِيُّ قَالَكُنْتُ آتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَضُوئِهِ وَبِحَاجَتِهِ فَقَالَ سَلْنِي قُلْتُ مُرَافَقَتَكَ فِي الْجَنَّةِ قَالَ أَوَ غَيْرَ ذَلِكَ قُلْتُ هُوَ ذَاكَ قَالَ فَأَعِنِّي عَلَى نَفْسِكَ بِكَثْرَةِ السُّجُودِ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Ammar] dari [Hiql bin Ziyad Ad Dimsyqi] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Rabi'ah bin Ka'ab Al Aslami] dia berkata; \"Aku pernah datang kepada Rasulullah Shallallahu'alaihiwasallam dengan membawa air wudhunya dan kebutuhannya. Lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepadaku: 'Mintalah kepadaku Aku lalu berkata; 'Aku ingin bersama engkau di surga'. Beliau menegaskan, 'Adakah yang lain? 'Aku menjawab, 'Itu saja'. Beliau Shallallahu'alaihiwasallam bersabda: 'Bantu aku untuk dirimu sendiri dengan memperbanyak sujud'.\""},"1122":{"ar":"أَخْبَرَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ أَنْبَأَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي الْوَلِيدُ بْنُ هِشَامٍ الْمُعَيْطِيُّ قَالَ حَدَّثَنِي مَعْدَانُ بْنُ طَلْحَةَ الْيَعْمُرِيُّ قَالَلَقِيتُ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ دُلَّنِي عَلَى عَمَلٍ يَنْفَعُنِي أَوْ يُدْخِلُنِي الْجَنَّةَ فَسَكَتَ عَنِّي مَلِيًّا ثُمَّ الْتَفَتَ إِلَيَّ فَقَالَ عَلَيْكَ بِالسُّجُودِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ عَزَّ وَجَلَّ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةًقَالَ مَعْدَانُ ثُمَّ لَقِيتُ أَبَا الدَّرْدَاءِ فَسَأَلْتُهُ عَمَّا سَأَلْتُ عَنْهُ ثَوْبَانَ فَقَالَ لِي عَلَيْكَ بِالسُّجُودِ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ يَسْجُدُ لِلَّهِ سَجْدَةً إِلَّا رَفَعَهُ اللَّهُ بِهَا دَرَجَةً وَحَطَّ عَنْهُ بِهَا خَطِيئَةً","id":"Telah mengabarkan kepada kami [Abu 'Ammar Al Husain bin Huraits] dia berkata; telah memberitakan kepada kami [Al Walid bin Muslim] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepada kami [Al Walid bin Hisyam Al Mu'aithi] dia berkata; telah menceritakan kepada kami [Ma'dan bin Thalhah Al Ya'muri] dia berkata; \"Aku berjumpa dengan [Tsauban] -hamba sahaya Rasulullah Shallallahu'alaihiwasallam- lalu aku berkata; Tunjukkan padaku suatu perbuatan yang bermanfaat bagiku dan dapat membuatku masuk surga'. la terdiam beberapa saat, kemudian menoleh kepadaku dan berkata; 'Perbanyaklah bersujud, karena aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang hamba sujud kepada Allah satu kali sujud kecuali Allah Azza wa Jalla mengangkat derajatnya dan menghapus satu kesalahan karenanya.\" Ma'dan berkata; \"Kemudian aku berjumpa dengan [Abu Darda], maka aku bertanya kepadanya suatu hal yang aku tanyakan kepada Tsauban. la berkata; 'Perbanyaklah bersujud, karena aku mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang hamba sujud kepada Allah satu kali sujud kecuali Allah Azza wa Jalla mengangkat derajatnya dan menghapuskan satu kesalahan dengannya.\""},"1123":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سُلَيْمَانَ لُوَيْنٌ بِالْمَصِّيْصَةِ عَنْ حَمَّادِ بْنِ زَيْدٍ عَنْ مَعْمَرٍ وَالنُّعْمَانُ بْنُ رَاشِدٍ عَنْ الزُّهْرِيِّ عَنْ عَطَاءِ بْنِ يَزِيدَ قَالَ كُنْتُ جَالِسًا إِلَى أَبِي هُرَيْرَةَ وَأَبِي سَعِيدٍ فَحَدَّثَ أَحَدُهُمَا حَدِيثَ الشَّفَاعَةِ وَالْآخَرُ مُنْصِتٌ قَالَ فَتَأْتِي الْمَلَائِكَةُ فَتَشْفَعُ وَتَشْفَعُ الرُّسُلُ وَذَكَرَ الصِّرَاطَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَكُونُ أَوَّلَ مَنْ يُجِيزُ فَإِذَا فَرَغَ اللَّهُ عَزَّ وَجَلَّ مِنْ الْقَضَاءِ بَيْنَ خَلْقِهِ وَأَخْرَجَ مِنْ النَّارِ مَنْ يُرِيدُ أَنْ يُخْرِجَ أَمَرَ اللَّهُ الْمَلَائِكَةَ وَالرُّسُلَ أَنْ تَشْفَعَ فَيُعْرَفُونَ بِعَلَامَاتِهِمْ إِنَّ النَّارَ تَأْكُلُ كُلَّ شَيْءٍ مِنْ ابْنِ آدَمَ إِلَّا مَوْضِعَ السُّجُودِ فَيُصَبُّ عَلَيْهِمْ مِنْ مَاءِ الْجَنَّةِ فَيَنْبُتُونَ كَمَا تَنْبُتُ الْحِبَّةُ فِي حَمِيلِ السَّيْلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Sulaiman Luwain bil Mashishah] dari [Hammad bin Zaid] dari [Ma'mar] dan [Nu'man bin Rasyid] dari [Az Zuhri] dari ['Atha bin Yazid] dia berkata; \"Aku pernah duduk di samping [Abu Hurairah] dan [Abu Sa'id], lalu salah seorang dari keduanya memberitahukan tentang hadits syafaat, sedangkan yang lain diam, ia berkata; 'Lalu malaikat datang dan memberi syafaat. Para Rasul juga memberi syafaat'. la menyebutkan tentang Shirath. Dia mengatakan bahwa Rasulullah Shallallahu'alaihiwasallam bersabda: 'Aku menjadi orang pertama kali yang diperbolehkan. Jika Allah Azza wa Jalla selesai memutuskan (hukum) di antara hamba-hamba-Nya, maka Dia mengeluarkan orang yang dikehendaki-Nya dari neraka. Allah memerintahkan para malaikat dan rasul-Nya untuk memberi syafaat, kemudian mereka dapat dikenali dengan tanda-tanda mereka. Sesungguhnya api neraka memakan segala apa yang ada pada manusia, kecuali tempat sujud. Lalu mereka akan disiram dengan air dari surga, lalu mereka akan tumbuh laksana tumbuhnya tanaman pada hanyutan banjir'.\""},"1124":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي يَعْقُوبَ الْبَصْرِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ عَنْ أَبِيهِ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي إِحْدَى صَلَاتَيْ الْعِشَاءِ وَهُوَ حَامِلٌ حَسَنًا أَوْ حُسَيْنًا فَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعَهُ ثُمَّ كَبَّرَ لِلصَّلَاةِ فَصَلَّى فَسَجَدَ بَيْنَ ظَهْرَانَيْ صَلَاتِهِ سَجْدَةً أَطَالَهَا قَالَ أَبِي فَرَفَعْتُ رَأْسِي وَإِذَا الصَّبِيُّ عَلَى ظَهْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ سَاجِدٌ فَرَجَعْتُ إِلَى سُجُودِي فَلَمَّا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ قَالَ النَّاسُ يَا رَسُولَ اللَّهِ إِنَّكَ سَجَدْتَ بَيْنَ ظَهْرَانَيْ صَلَاتِكَ سَجْدَةً أَطَلْتَهَا حَتَّى ظَنَنَّا أَنَّهُ قَدْ حَدَثَ أَمْرٌ أَوْ أَنَّهُ يُوحَى إِلَيْكَ قَالَ كُلُّ ذَلِكَ لَمْ يَكُنْ وَلَكِنَّ ابْنِي ارْتَحَلَنِي فَكَرِهْتُ أَنْ أُعَجِّلَهُ حَتَّى يَقْضِيَ حَاجَتَهُ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Jarir bin Hazim] dia berkata; telah menceritakan kepada kami [Muhammad bin Abu Ya'qub Al Bashri] dari ['Abdullah bin Syaddad] dari [bapaknya], dia berkata; \"Rasulullah Shallallahu'alaihiwasallam pergi kepada kami didalam salah satu shalat 'Isya', ia membawa Hasan atau Husain. Kemudian Rasulullah Shallallahu'alaihiwasallam ke depan dan meletakkan (Hasan dan Husain), kemudian beliau bertakbir untuk shalat lalu mengerjakan shalat. Saat shalat beliau sujud yang lama, maka ayahku berkata, 'Lalu aku mengangkat kepalaku, dan ternyata ada anak kecil di atas punggung Rasulullah Shallallahu'alaihiwasallam yang sedang sujud, lalu aku kembali sujud'. Setelah Rasulullah Shallallahu'alaihiwasallam selesai shalat, orang-orang berkata, 'Wahai Rasulullah Shallallahu'alaihiwasallam saat shalat engkau memperlama sujud, hingga kami mengira bahwa ada sesuatu yang telah terjadi atau ada wahyu yang diturunkan kepadamu? ' Beliau Shallallahu'alaihiwasallam menjawab, 'Bukan karena semua itu, tetapi cucuku (Hasan dan Husain) menjadikanku sebagai kendaraan, maka aku tidak mau\" membuatnya terburu-buru, (aku biarkan) hingga ia selesai dari bermainnya'.\""},"1125":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ دُكَيْنٍ وَيَحْيَى بْنُ آدَمَ قَالَا حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ وَعَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ وَقِيَامٍ وَقُعُودٍ وَيُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ حَتَّى يُرَى بَيَاضُ خَدِّهِقَالَ وَرَأَيْتُ أَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلَانِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrohim] dia berkata; telah memberitakan kepada kami [Al Fadhl bin Dukain] dan [Yahya bin Adam] mereka berdua berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari ['Abdurrahman bin Al Aswadi] dari [bapaknya] dan [Alqamah] dari ['Abdullah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam selalu takbir pada setiap turun ataupun bangun. Beliau Shallallahu'alaihiwasallam juga mengucapkan salam ke kanan dan ke kiri, 'Assalamu'alaikum warahmatullah' hingga terlihat pipinya yang putih.\" la berkata; \"Aku melihat Abu Bakar dan Umar Radliyallahu'anhuma melakukannya juga.\" "},"1126":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ نَصْرِ بْنِ عَاصِمٍ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا دَخَلَ فِي الصَّلَاةِ رَفَعَ يَدَيْهِ وَإِذَا رَكَعَ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَعَلَ مِثْلَ ذَلِكَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ فَعَلَ مِثْلَ ذَلِكَ كُلَّهُ يَعْنِي رَفْعَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [bapakkku] telah menceritakan kepadaku dari [Qatadah] dari [Nashr bin 'Ashim] dari [Malik bin Al Huwairits] bahwa jika Rasulullah Shallallahu'alaihiwasallam masuk untuk memulai shalat, maka beliau mengangkat kedua tangannya. Beliau juga melakukan hal itu ketika hendak ruku', saat mengangkat kepala dari ruku', dan ketika hendak bangkit dari sujud.\""},"1127":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا افْتَتَحَ الصَّلَاةَ كَبَّرَ وَرَفَعَ يَدَيْهِ وَإِذَا رَكَعَ وَبَعْدَ الرُّكُوعِ وَلَا يَرْفَعُ بَيْنَ السَّجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Sufyan] dari [Az Zuhri] dari [Salim] dari [bapaknya] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam jika memulai shalat maka beliau bertakbir lalu mengangkat kedua tangannya. Begitu juga saat hendak ruku' dan setelah ruku'. Beliau Shallallahu'alaihiwasallam tidak melakukannya diantara dua sujud.\""},"1128":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي حَمْزَةَ سَمِعَهُ يُحَدِّثُ عَنْ رَجُلٍ مِنْ عَبْسٍ عَنْ حُذَيْفَةَأَنَّهُ انْتَهَى إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ إِلَى جَنْبِهِ فَقَالَ اللَّهُ أَكْبَرُ ذُو الْمَلَكُوتِ وَالْجَبَرُوتِ وَالْكِبْرِيَاءِ وَالْعَظَمَةِ ثُمَّ قَرَأَ بِالْبَقَرَةِ ثُمَّ رَكَعَ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ فَقَالَ فِي رُكُوعِهِ سُبْحَانَ رَبِّيَ الْعَظِيمِ سُبْحَانَ رَبِّيَ الْعَظِيمِ وَقَالَ حِينَ رَفَعَ رَأْسَهُ لِرَبِّيَ الْحَمْدُ لِرَبِّيَ الْحَمْدُ وَكَانَ يَقُولُ فِي سُجُودِهِ سُبْحَانَ رَبِّيَ الْأَعْلَى سُبْحَانَ رَبِّيَ الْأَعْلَى وَكَانَ يَقُولُ بَيْنَ السَّجْدَتَيْنِ رَبِّ اغْفِرْ لِي رَبِّ اغْفِرْ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Murrah] dari [Abu Hamzah], dari [seseorang] dari 'Abs dari [Hudzaifah] bahwa ia menemui Rasulullah Shallallahu'alaihiwasallam, lalu ia berdiri di sampingnya, kemudian beliau mengucapkan: \"Allahu akbar dzul malaakuti wal jabaruuti wal kibriya'ai wal 'adzamati (Allah Maha Besar, Dzat yang memiliki kerajaan dan keperkasaan, serta yang memiliki kesombongan dan keagungan).\" Kemudian beliau membaca Al Baqarah, lalu ruku' dan-lama-ruku'nya seperti berdirinya. Saat ruku' beliau mengucapkan, \"Subhana Rabbiyal 'Azhiimi, Subhana Rabbiyal 'Azhiimi (Maha Suci Tuhanku yang Maha Agung, Maha Suci Tuhanku yang Maha Agung).\" Jika beliau mengangkat kepala dari ruku', maka beliau mengucapkan, \"Lirabbil hamdu lirabbil hamdu (Segala pujian bagi Tuhanku, segala pujian bagi Tuhanku).\" Saat sujud beliau mengucapkan, \"Subhana Rabbiyal A'laa (Maha Suci Tuhanku yang Maha Tinggi).\" Sedangkan diantara dua sujud beliau membaca, \"Rabbighfirlii, rahhighfirlii (Wahai Rabbku ampunilah aku, wahai Rabbku ampunilah aku).\""},"1129":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ اللَّهِ بْنِ مُوسَى الْبَصْرِيُّ قَالَ حَدَّثَنَا النَّضْرُ بْنُ كَثِيرٍ أَبُو سَهْلٍ الْأَزْدِيُّ قَالَصَلَّى إِلَى جَنْبِي عَبْدُ اللَّهِ بْنُ طَاوُسٍ بِمِنًى فِي مَسْجِدِ الْخَيْفِ فَكَانَ إِذَا سَجَدَ السَّجْدَةَ الْأُولَى فَرَفَعَ رَأْسَهُ مِنْهَا رَفَعَ يَدَيْهِ تِلْقَاءَ وَجْهِهِفَأَنْكَرْتُ أَنَا ذَلِكَ فَقُلْتُ لِوُهَيْبِ بْنِ خَالِدٍ إِنَّ هَذَا يَصْنَعُ شَيْئًا لَمْ أَرَ أَحَدًا يَصْنَعُهُ فَقَالَ لَهُ وَهَيْبٌ تَصْنَعُ شَيْئًا لَمْ نَرَ أَحَدًا يَصْنَعُهُ فَقَالَ عَبْدُ اللَّهِ بْنُ طَاوُسٍ رَأَيْتُ أَبِي يَصْنَعُهُ وَقَالَ أَبِي رَأَيْتُ ابْنَ عَبَّاسٍ يَصْنَعُهُ وَقَالَ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُهُ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdullah bin Musa Al Bashri] dia berkata; telah menceritakan kepada kami [An Nadlr bin Katsir Abu Sahl Al Azdi] dia berkata; \"Abdullah bin Thawus shalat di sampingku saat di Mina, di dalam masjid AI Khaif. Jika ia sujud pada rakaat pertama maka ia mengangkat kepalanya dari sujud dengan mengangkat kedua tangannya di hadapan wajahnya, dan aku mengingkari hal itu. Lalu aku berkata kepada Wuhaib bin Khalid, 'Orang ini telah berbuat sesuatu yang tidak pernah kulihat ada orang yang melakukannya'. Lalu Wuhaib berkata kepadanya, 'Kamu telah berbuat sesuatu yang tidak pernah kami lihat ada orang yang melakukannya! ' [Abdullah bin Thawus] berkata; 'Aku melihat ayahku melakukannya. [Ayahku] juga mengatakan bahwa dirinya melihat Ibnu Abbas melakukannya, dan [Ibnu Abbas] juga mengatakan bahwa ia pernah melihat Rasulullah Shallallahu'alaihiwasallam melakukan hal itu'.\""},"1130":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ دُحَيْمٌ قَالَ حَدَّثَنَا مَرْوَان�� بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ الْأَصَمِّ قَالَ حَدَّثَنِي يَزِيدُ بْنُ الْأَصَمِّ عَنْ مَيْمُونَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ خَوَّى بِيَدَيْهِ حَتَّى يُرَى وَضَحَ إِبْطَيْهِ مِنْ وَرَائِهِ وَإِذَا قَعَدَ اطْمَأَنَّ عَلَى فَخِذِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Ibrahim Duhaim] dia berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Abdullah bin Al Ashammi] dia berkata; telah menceritakan kepada kami [Yazid bin Al Ashammi] dari [Maimunah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam jika sujud maka beliau menjauhkan kedua sikunya (dari kedua lambungnya) hingga kedua ketiaknya yang putih terlihat dari belakang. Bila beliau duduk maka beliau duduk dengan tenang di atas paha kirinya.\""},"1131":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو قُدَامَةَ قَالَ حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ ابْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَكَانَ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رُكُوعُهُ وَسُجُودُهُ وَقِيَامُهُ بَعْدَ مَا يَرْفَعُ رَأْسَهُ مِنْ الرُّكُوعِ وَبَيْنَ السَّجْدَتَيْنِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id Abu Qudamah] dia berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] dia berkata; telah menceritakan kepada kami [Al Hakam] dari [Ibnu Abi Laila] dari [Al Barra] dia berkata; \"(Lama) shalat Rasulullah Shallallahu'alaihiwasallam ruku'nya, sujudnya, berdirinya setelah mengangkat kepalanya dari ruku' dan diantara dua sujudnya, semuanya hampir sama.\""},"1132":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ رَفْعٍ وَوَضْعٍ وَقِيَامٍ وَقُعُودٍ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ رَضِيَ اللَّهُ عَنْهُمْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari ['Abdurrahman bin Al Aswad] dari [Al Aswad] dan ['Alqamah] dari ['Abdullah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam selalu takbir pada setiap turun ataupun bangun. Juga setiap hendak berdiri ataupun duduk. Abu Bakar, Umar dan Utsman radliyallahu'anhum juga melakukannya.\""},"1133":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا حُجَيْنٌ وَهُوَ ابْنُ الْمُثَنَّى قَالَ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ إِلَى الصَّلَاةِ يُكَبِّرُ حِينَ يَقُومُ ثُمَّ يُكَبِّرُ حِينَ يَرْكَعُ ثُمَّ يَقُولُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ حِينَ يَرْفَعُ صُلْبَهُ مِنْ الرَّكْعَةِ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ رَبَّنَا لَكَ الْحَمْدُ ثُمَّ يُكَبِّرُ حِينَ يَهْوِي سَاجِدًا ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأْسَهُ ثُمَّ يُكَبِّرُ حِينَ يَسْجُدُ ثُمَّ يُكَبِّرُ حِينَ يَرْفَعُ رَأَسَهُ ثُمَّ يَفْعَلُ ذَلِكَ فِي الصَّلَاةِ كُلِّهَا حَتَّى يَقْضِيَهَا وَيُكَبِّرُ حِينَ يَقُومُ مِنْ الثِّنْتَيْنِ بَعْدَ الْجُلُوسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Laits] dari ['Uqail] dari [Ibnu Syihab] dia berkata; Telah mengabarkan kepadaku [Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] bahwasanya ia mendengar [Abu Hurairah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam jika bangun untuk shalat maka beliau bertakbir dan bila hendak ruku' maka beliau juga bertakbir. Kemudian beliau mengucapkan, 'Sami'allahu liman hamidah' ketika mengangkat punggungnya dari ruku'. Lalu sambil berdiri beliau mengucapkan, 'Rabbana lakal hamdu. ' Kemudian ia bertakbir ketika turun untuk sujud, lalu bertakbir ketika mengangkat kepalanya. Lantas beliau bertakbir ketika sujud, kemudian bertakbir lagi saat mengangkat kepalanya. Beliau melakukan semua hal itu sampai selesai shalat. Beliau juga bertakbir ketika bangun dari dua rakaat setelah duduk.\""},"1134":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ قَالَجَاءَنَا أَبُو سُلَيْمَانَ مَالِكُ بْنُ الْحُوَيْرِثِ إِلَى مَسْجِدِنَا فَقَالَ أُرِيدُ أَنْ أُرِيَكُمْ كَيْفَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي قَالَ فَقَعَدَ فِي الرَّكْعَةِ الْأُولَى حِينَ رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الْآخِرَةِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dia berkata; [Abu Sulaiman Malik bin Al Huwairits] datang ke masjid kami, lalu berkata; \"Aku ingin memperlihatkan cara shalat Rasulullah Shallallahu'alaihiwasallam kepada kalian'.\" Abu Qilabah berkata lagi; \"Beliau duduk pada rakaat pertama ketika mengangkat kepalanya saat sujud terakhir.\""},"1135":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا هُشَيْمٌ عَنْ خَالِدٍ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَإِذَا كَانَ فِي وَتْرٍ مِنْ صَلَاتِهِ لَمْ يَنْهَضْ حَتَّى يَسْتَوِيَ جَالِسًا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah memberitakan kepada kami [Husyaim] dari [Khalid] dari [Abu Qilabah] dari [Malik bin Al Huwairits] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihiwasallam shalat; jika dalam (rakaat) ganjil dari shalatnya maka beliau tidak bangun hingga ia duduk dengan lurus.\""},"1136":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ قَالَكَانَ مَالِكُ بْنُ الْحُوَيْرِثِ يَأْتِينَا فَيَقُولُ أَلَا أُحَدِّثُكُمْ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيُصَلِّي فِي غَيْرِ وَقْتِ الصَّلَاةِ فَإِذَا رَفَعَ رَأْسَهُ مِنْ السَّجْدَةِ الثَّانِيَةِ فِي أَوَّلِ الرَّكْعَةِ اسْتَوَى قَاعِدًا ثُمَّ قَامَ فَاعْتَمَدَ عَلَى الْأَرْضِ","id":"Telah mengabarkan kepada kami [Muhammad bin Busysyar] dia berkata; telah menceritakan kepada kami ['Abdul Wahhab] dia berkata; telah menceritakan kepada kami [Khalid] dari [Abu Qilabah] dia berkata; bahwa [Malik bin Huwairits] datang kepada kami lalu berkata, \"Maukah kalian aku perlihatkan cara Rasulullah Shallallahu'alaihiwasallam shalat?\" Lalu -Malik- mengerjakan shalat diluar waktu shalat; jika mengangkat kepalanya saat sujud kedua pada rakaat pertama maka ia duduk dalam keadaan lurus, kemudian bangun dengan bertumpu ke tanah."},"1137":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَجَدَ وَضَعَ رُكْبَتَيْهِ قَبْلَ يَدَيْهِ وَإِذَا نَهَضَ رَفَعَ يَدَيْهِ قَبْلَ رُكْبَتَيْهِقَالَ أَبُو عَبْد الرَّحْمَنِ لَمْ يَقُلْ هَذَا عَنْ شَرِيكٍ غَيْرُ يَزِيدَ بْنِ هَارُونَ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah memberitakan kepada kami [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Syarik] dari ['Ashim bin Kulaib] dari [bapaknya] dari [Wail bin Hujr] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihiwasallam apabila hendak sujud, beliau meletakan kedua lututnya sebelum kedua tangannya, dan apabila bangkit, beliau mengangkat kedua tangannya sebelum kedua lututnya. Abu Abdurrahman berkata; 'Tidak ada yang mengatakan perkataan ini dari Syarik kecuali Yazid bin Harun. Wallahu Ta'ala A'lam.'"},"1138":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَأَنَّ أَبَا هُرَيْرَةَ كَانَ يُصَلِّي بِهِمْ فَيُكَبِّرُ كُلَّمَا خَفَضَ وَرَفَعَ فَإِذَا انْصَرَفَ قَالَ وَاللَّهِ إِنِّي لَأَشْبَهُكُمْ صَلَاةً بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] bahwasanya [Abu Hurairah] pernah shalat bersama mereka', ia bertakbir setiap hendak turun atau bangkit. Tatkala selesai shalat ia berkata; \"Demi Allah, aku adalah orang yang shalatnya paling mirip dengan Rasulullah Shallallahu'alaihi wasallam.\""},"1139":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيٍّ وَسَوَّارُ بْنُ عَبْدِ اللَّهِ بْنِ سَوَّارٍ قَالَا حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِأَنَّهُمَا صَلَّيَا خَلْفَ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ فَلَمَّا رَكَعَ كَبَّرَ فَلَمَّا رَفَعَ رَأْسَهُ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ سَجَدَ وَكَبَّرَ وَرَفَعَ رَأْسَهُ وَكَبَّرَ ثُمَّ كَبَّرَ حِينَ قَامَ مِنْ الرَّكْعَةِ ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ إِنِّي لَأَقْرَبُكُمْ شَبَهًا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَتْ هَذِهِ صَلَاتُهُ حَتَّى فَارَقَ الدُّنْيَاوَاللَّفْظُ لِسَوَّارٍ","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali] dan [Sawwar bin 'Abdullah bin Sawwar] dia berkata; telah menceritakan kepada kami ['Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Abu Bakr bin 'Abdurrahman] dan dari [Abu Salamah bin 'Abdurrahman] bahwasanya keduanya shalat di belakang [Abu Hurairah] Radliyallahu'anhu; bila hendak ruku' maka ia bertakbir. Jika ia mengangkat kepalanya dari ruku' maka ia mengucapkan, \"Sami'allahu liman hamidah rabbana lakal hamdu (Allah Mendengar semua yang memuji-Nya. Ya Allah, untuk-Mu segala pujian).\" Kemudian ia bertakbir ketika turun untuk sujud dan bertakbir ketika hendak bangun dari rakaat. Kemudian ia berkata; \"Demi Dzat yang jiwaku ada di tangan-Nya, aku adalah orang yang paling serupa dengan Rasulullah Shallallahu'alaihiwasallam, dan masih seperti inilah shalat beliau sampai meninggal dunia.\" Lafazh ini milik Surur."},"1140":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ أَنَّهُ قَالَإِنَّ مِنْ سُنَّةِ الصَّلَاةِ أَنْ تُضْجِعَ رِجْلَكَ الْيُسْرَى وَتَنْصِبَ الْيُمْنَى","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Al Qasim bin Muhammad] dari ['Abdullah bin 'Abdullah bin 'Umar] dari [bapaknya] dia berkata; \"Termasuk sunnah shalat adalah engkau menidurkan kaki kiri dan menegakkan kaki kanan.\" "},"1141":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ بَكْرِ بْنِ مُضَرَ قَالَ حَدَّثَنِي أَبِي عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَحْيَى أَنَّ الْقَاسِمَ حَدَّثَهُ عَنْ عَبْدِ اللَّهِ وَهُوَ ابْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَمِنْ سُنَّةِ الصَّلَاةِ أَنْ تَنْصِبَ الْقَدَمَ الْيُمْنَى وَاسْتِقْبَالُهُ بِأَصَابِعِهَا الْقِبْلَةَ وَالْجُلُوسُ عَلَى الْيُسْرَى","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Dawud] dia berkata; telah menceritakan kepada kami [Ishaq bin Bakr bin Mudhar] dia berkata; [bapakku] telah menceritakan kepadaku dari ['Amr bin Al Harits] dari [Yahya] bahwasanya [Al Qasim] menceritakan kepadanya dari ['Abdullah bin 'Abdullah bin 'Umar] dari [bapaknya] dia berkata; \"Termasuk sunnah shalat adalah engkau menegakkan kaki kanan dan menghadapkan jari-jemari kedua kaki ke kiblat, serta duduk di atas kaki kiri.\""},"1142":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَأَيْتُهُ يَرْفَعُ يَدَيْهِ إِذَا افْتَتَحَ الصَّلَاةَ حَتَّى يُحَاذِيَ مَنْكِبَيْهِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَإِذَا جَلَسَ فِي الرَّكْعَتَيْنِ أَضْجَعَ الْيُسْرَى وَنَصَبَ الْيُمْنَى وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى وَنَصَبَ أُصْبُعَهُ لِلدُّعَاءِ وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى قَالَ ثُمَّ أَتَيْتُهُمْ مِنْ قَابِلٍ فَرَأَيْتُهُمْ يَرْفَعُونَ أَيْدِيَهُمْ فِي الْبَرَانِسِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid Al Muqri'] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dari [Bapaknya] dari [Wail bin Hujr] dia berkata; \"Aku datang kepada Rasulullah Shalallahu 'Alaihi Wa Sallam dan melihat beliau mengangkat kedua tangannya sejajar dengan kedua bahunya bila memulai shalat, demikian juga saat ketika hendak ruku'. Dan saat duduk pada dua rakaat, beliau Shalallahu 'Alaihi Wa Sallam memiringkan kaki kiri dan menegakkan kaki kanan, meletakkan tangan kanan di atas paha kanan, menegakkan jari untuk berdoa, dan meletakkan tangan kiri di atas paha kiri.\" Beliau Shalallahu 'Alaihi Wa Sallam berkata; \"Kemudian aku datang kepada mereka di waktu lain dan aku melihat mereka mengangkat kedua tangan mereka di burnus (kain yang biasa di pakai untuk menutup kepala).\""},"1143":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ مُسْلِمِ بْنِ أَبِي مَرْيَمَ عَنْ عَلِيِّ بْنِ عَبْدِ الرَّحْمَنِ الْمُعَاوِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ رَأَى رَجُلًا يُحَرِّكُ الْحَصَى بِيَدِهِ وَهُوَ فِي الصَّلَاةِ فَلَمَّا انْصَرَفَ قَالَ لَهُ عَبْدُ اللَّهِ لَا تُحَرِّكْ الْحَصَى وَأَنْتَ فِي الصَّلَاةِ فَإِنَّ ذَلِكَ مِنْ الشَّيْطَانِ وَلَكِنْ اصْنَعْ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ قَالَ وَكَيْفَ كَانَ يَصْنَعُ قَالَ فَوَضَعَ يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى وَأَشَارَ بِأُصْبُعِهِ الَّتِي تَلِي الْإِبْهَامَ فِي الْقِبْلَةِ وَرَمَى بِبَصَرِهِ إِلَيْهَا أَوْ نَحْوِهَا ثُمَّ قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Muslim bin Abu Maryam] dari ['Ali bin 'Abdurrahman Al Mu'awiy] dari ['Abdullah bin 'Umar] dia melihat seorang laki-laki menggerak-gerakkan kerikil dengan tangannya saat shalat. Setelah selesai, Abdullah berkata kepadanya; \"Janganlah kamu menggerak-gerakkan kerikil saat shalat, sesungguhnya itu perbuatan syetan. Berbuatlah sebagaimana yang dilakukan oleh Rasulullah Shallallahu'alaihi wasallam.\" la berkata; \"Bagaimana cara Rasulullah Shallallahu'alaihiwasallam melakukannya?\" Aku menjawab; \"Beliau meletakkan tangan kanan di atas paha kanan, lalu menunjukkan jari telunjuknya ke kiblat dan mengarahkan pandangan ke jari tersebut-atau ke sekitarnya.\" Kemudian ia berkata, \"Begitulah cara Rasulullah Shallallahu'alaihiwasallam melakukannya.\""},"1144":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى السِّجْزِيُّ يُعْرَفُ بِخَيَّاطِ السُّنَّةِ نَزَلَ بِدِمَشْقَ أَحَدُ الثِّقَاتِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ عِيسَى قَالَ أَنْبَأَنَا ابْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا مَخْرَمَةُ بْنُ بُكَيْرٍ قَالَ أَنْبَأَنَا عَامِرُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَلَسَ فِي الثِّنْتَيْنِ أَوْ فِي الْأَرْبَعِ يَضَعُ يَدَيْهِ عَلَى رُكْبَتَيْهِ ثُمَّ أَشَارَ بِأُصْبُعِهِ","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya As Sijziy] yang dikenal dengan penjahit sunnah dia tinggal di Damakus, salah satu orang yang tsiqah (terpercaya) dia berkata; telah menceritakan kepada kami [Al Hasan bin 'Isa] dia berkata; telah memberitakan kepada kami [Ibnul Mubarak] dia berkata; telah menceritakan kepada kami [Makhramah bin Bukair] dia berkata; telah memberitakan kepada kami ['Amir bin 'Abdullah bin Az Zubair] dari [bapaknya] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam apabila duduk pada dua rakaat atau empat rakaat maka beliau meletakkan kedua tangan di atas paha, kemudian mengisyaratkan dengan jarinya.\""},"1145":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ عَنْ الْأَشْجَعِيِّ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَقُولَ إِذَا جَلَسْنَا فِي الرَّكْعَتَيْنِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad-Dauraqiy] dari [Al Asyja'iy] dari [Sufyan] dari [Abu Ishaq] dari [Al Aswad] dari ['Abdullah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam mengajarkan doa saat duduk pada dua rakaat kepada kami - yang artinya -: \"Penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah dan Muhammad adalah hamba dan utusan-Nya'.\""},"1146":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا لَا نَدْرِي مَا نَقُولُ فِي كُلِّ رَكْعَتَيْنِ غَيْرَ أَنْ نُسَبِّحَ وَنُكَبِّرَ وَنَحْمَدَ رَبَّنَا وَإِنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَ فَوَاتِحَ الْخَيْرِ وَخَوَاتِمَهُ فَقَالَ إِذَا قَعَدْتُمْ فِي كُلِّ رَكْعَتَيْنِ فَقُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَلْيَتَخَيَّرْ أَحَدُكُمْ مِنْ الدُّعَاءِ أَعْجَبَهُ إِلَيْهِ فَلْيَدْعُ اللَّهَ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu Al Ahwash] dari ['Abdullah] dia berkata; \"Kami dulu tidak mengetahui apa yang mesti diucapkan saat duduk pada dua rakaat selain bertasbih, bertakbir, dan memuji Rabb kami, lalu Nabi Muhammad Shallallahu'alaihiwasallam mengajari pembuka dan penutup kebaikan. Kemudian beliau Shallallahu'alaihiwasallam bersabda: 'Jika kalian duduk pada setiap dua rakaat, maka ucapkan-doa yang artinya: \"Penghormatan. rahmat dan kebaikan hanya milik Allah. Semoga keselamatan, rahmat dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah dan Muhammad adalah hamba dan utusan-Nya '.\" Hendaklah salah seorang dari kalian memilih doa yang disukainya, dan hendaklah ia berdoa kepada Allah 'azza wajalla.\""},"1147":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّشَهُّدَ فِي الصَّلَاةِ وَالتَّشَهُّدَ فِي الْحَاجَةِ فَأَمَّا التَّشَهُّدُ فِي الصَّلَاةِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ إِلَى آخِرِ التَّشَهُّدِأَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ آدَمَ قَالَ سَمِعْتُ سُفْيَانَ يَتَشَهَّدُ بِهَذَا فِي الْمَكْتُوبَةِ وَالتَّطَوُّعِ وَيَقُولُ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح وَحَدَّثَنَا مَنْصُورٌ وَحَمَّادٌ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abtsar] dari [Al A'masy] dari [Abu Ishaq] dari [Abu Al Ahwash] dari ['Abdullah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam mengajari kami tasyahud dalam shalat dan tasyahud dalam (khutbah) Hajah. Tasyahud dalam shalat adalah, 'At-tahiyyatut lillahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan Abduhu wa rasuuluh' (penghormatan, rahmat dan kebaikan hanya milik yang baik dan Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah kecuali Allah, dan Muhammad adalah hamba dan utusan-Nya) ' sampai akhir tasyahud.\" Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Adam] dia berkata; 'Aku mendengar [Sufyan] bertasyahud dengan lafazh ini dalam shalat wajib maupun sunnah, dan dia berkata; telah menceritakan kepada kami [Abu Ishaq] dari [Abu Ahwash] dari [Abdullah] dari Nabi Shallallahu'alaihiwasallam. Dan pada jalur lain, telah menceritakan kepada kami [Manshur] dan [Hammad] dari [Abu Wa'il] dari [Abdullah] dari Nabi Shallallahu'alaihi wasallam."},"1148":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ زَيْدَ بْنَ أَبِي أُنَيْسَةَ الْجَزَرِيَّ حَدَّثَهُ أَنَّ أَبَا إِسْحَقَ حَدَّثَهُ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَكُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نَعْلَمُ شَيْئًا فَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا فِي كُلِّ جَلْسَةٍ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin Sarh] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; Telah mengabarkan kepadaku ['Amr bin Al Harits] bahwasanya [Zaid bin Abu Unaisah Al Jazariy] menceritakan kepadanya bahwasanya [Abu Ishaq] menceritakan kepadanya dari [Al Aswad] dan [Alqamah] dari ['Abdullah bin Mas'ud] dia berkata; \"Kami bersama Rasulullah Shallallahu'alaihiwasallam dalam keadaan tidak mengetahui apa-apa, lalu Rasulullah Shallallahu'alaihiwasallam bersabda kepada kami, 'Pada setiap duduk (tasyahud) ucapkanlah, \"At-tahiyyatut lillahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, asalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan Abduhu wa rasuuluh (penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah kecuali Allah, dan Muhammad adalah hamba dan utusan-Nya).\""},"1149":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ جَبَلَةَ الرَّافِقِيُّ قَالَ حَدَّثَنَا الْعَلَاءُ بْنُ هِلَالٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ وَهُوَ ابْنُ عَمْرٍو وَعَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ حَمَّادٍ عَنْ إِ��ْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ قَيْسٍ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا لَا نَدْرِي مَا نَقُولُ إِذَا صَلَّيْنَا فَعَلَّمَنَا نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَوَامِعَ الْكَلِمِ فَقَالَ لَنَا قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُقَالَ عُبَيْدُ اللَّهِ قَالَ زَيْدٌ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ لَقَدْ رَأَيْتُ ابْنَ مَسْعُودٍ يُعَلِّمُنَا هَؤُلَاءِ الْكَلِمَاتِ كَمَا يُعَلِّمُنَا الْقُرْآنَ","id":"Telah mengabarkan kepadaku [Muhammad bin Jabalah Ar Rafiqiy] dia berkata; telah menceritakan kepada kami [Al 'Ala bin Hilal] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dan dari [Zaid bin Abu Unaisah] dari [Hammad] dari [Ibrahim] dari [Alqamah bin Qais] dari ['Abdullah] dia berkata; \"Kami dulu tidak tahu apa yang mesti diucapkan jika kami dalam shalat. Lalu Nabi Allah Shallallahu'alaihiwasallam mengajarkan \"Jawami'ul kalim' (kalimat yang singkat penuh makna) Beliau Shallallahu'alaihiwasallam bersabda: 'Ucapkanlah, \"At-tahiyyatu lillahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna Muhammadan Abduhu wa rasuuluh (penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).\" Ubaidullah berkata; Zaid berkata; dari Hammad dari Ibrahim dari Alqomah, dia berkata; 'Aku telah melihat Ibnu Mas'ud mengajarkan kalimat tersebut kepada kami, sebagaimana ia mengajarkan Al Qur'an kepada kami.'"},"1150":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ الرَّقِّيُّ قَالَ حَدَّثَنَا حَارِثُ بْنُ عَطِيَّةَ وَكَانَ مِنْ زُهَّادِ النَّاسِ عَنْ هِشَامٍ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍ قَالَكُنَّا إِذَا صَلَّيْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَقُولُ السَّلَامُ عَلَى اللَّهِ السَّلَامُ عَلَى جِبْرِيلَ السَّلَامُ عَلَى مِيكَائِيلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepadaku ['Abdurrahman bin Khalid Ar Riqqiy] dia berkata; telah menceritakan kepada kami [Harits bin 'Athiyyah] dan dia adalah termasuk orang yang paling zuhud, dari [Hisyam] dari [Hammad] dari [Ibrahim] dari ['Alqamah] dari [Ibnu Mas'ud] dia berkata; \"Kami dulu shalat bersama Rasulullah Shallallahu'alaihiwasallam dengan mengucapkan, 'Assalaamu 'alallah, Assalaamu 'alaa Jibriil, Assalaamu 'ala Mikail (Keselamatan atas Allah, keselamatan atas Jibril, keselamatan atas Mikail) '. Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: 'Janganlah kalian mengalakan; \"Assalaamu 'alallah (Keselamatan atas Allah) \" karena Allah adalah Assalaam (Maha pemberi keselamatan), tetapi ucapkanlah, \"At Tahiyyatut lillaahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wahdahu laa syariikalah wa asyhadu anna muhammadan abduhu warasuuluh (penghormatan yang baik dan shalawat bagi Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah semata tiada sekutu bagi-Nya, dan aku bersaksi Muhammad adalah hamba dan utusan-Nya).\""},"1151":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ هُوَ الدَّسْتَوَائِيُّ عَنْ حَمَّادٍ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَقُولُ السَّلَامُ عَلَى اللَّهِ السَّلَامُ عَلَى جِبْرِيلَ السَّلَامُ عَلَى مِيكَائِيلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Hisyam Ad Dastawaiy] dari [Hammad] dari [Abu Wa'il] dari [Ibnu Mas'ud] dia berkata; \"Kami shalat bersama Rasulullah Shallallahu'alaihiwasallam dengan mengucapkan, 'Assalaamu 'alallah, Assalaamu 'alaa Jibriil, Assalaamu 'ala Mikail (Keselamatan atas Allah, keselamatan atas Jibril, keselamatan atas Mikail) '. Kemudian Rasulullah Shallallahu'alaihiwasallam bersabda: 'Janganlah kalian mengatakan; \"Assalaamu 'alallah (Keselamatan atas Allah) \" karena Allah adalah Assalaam (Maha pemberi keselamatan), tetapi ucapkanlah, \"At-Tahiyyatut lillaahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan abduhu warasuuluh (penghormatan yang baik dan shalawat bagi Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).\""},"1152":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ وَمَنْصُورٍ وَحَمَّادٍ وَمُغِيرَةَ وَأَبِي هَاشِمٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي التَّشَهُّدِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُقَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو هَاشِمٍ غَرِيبٌ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalild Al'Askariy] dia berkata; telah menceritakan kepada kami [Ghundar] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], [Manshur], [Hammad], [Mughirah] dan [Abu Hasyim] dari [Abu Wa'il] dari ['Abdullah] dari dari Nabi Shallallahu'alaihiwasallam, beliau Shallallahu'alaihiwasallam pada tasyahud mengucapkan doa, \"At-tahiyyatut lillahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan abduhu wa rasuuluh (penghormatan, rahmat dan kebaikan dan hanya milik Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).\" Abu Abdurrahman berkata; 'Abu Hasyim orangnya gharib (asing).'"},"1153":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ دُكَيْنٍ قَالَ حَدَّثَنَا سَيْفٌ الْمَكِّيُّ قَالَ سَمِعْتُ مُجَاهِدًا يَقُولُ حَدَّثَنِي أَبُو مَعْمَرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ يَقُولُعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ وَكَفُّهُ بَيْنَ يَدَيْهِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Al Fadhl bin Dukain] dia berkata; telah menceritakan kepada kami [Saif Al Makkiy] dia berkata; aku mendengar [Mujahid] berkata; telah menceritakan kepadaku [Abu Ma'mar] dia berkata; aku mendengar ['Abdullah] berkata; \"Rasulullah Shallallahu'alaihiwasallam mengajarkan kami cara tasyahud sebagaimana beliau mengajarkan kami suatu surat dari Al Qur'an-dan telapak tangannya di hadapannya-: 'At-tahiyyatut lillaahi wash-shalawaatu wath-thayyibaatu, assalaamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, assalaamu 'alainaa wa 'ala 'ibadillaahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna Muhamadan abduhu wa rasuuluh (penghormatan, rahmat dan kebaikan henya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak diibadahi selain Allah, dan Muhammad adalah hamba dan utusan-Nya)."},"1154":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ أَبُو قُدَامَةَ السَّرْخَسِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنِي قَتَادَةُ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ أَنَّ الْأَشْعَرِيَّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا فَعَلَّمَنَا سُنَّتَنَا وَبَيَّنَ لَنَا صَلَاتَنَا فَقَالَ أَقِيمُوا صُفُوفَكُمْ ثُمَّ لِيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَالَ وَلَا الضَّالِّينَ فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ وَإِذَا كَبَّرَ الْإِمَامُ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا رَبَّنَا لَكَ الْحَمْدُ يَسْمَعْ اللَّهُ لَكُمْ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَ عَلَى لِسَانِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ إِذَا كَبَّرَ الْإِمَامُ وَسَجَدَ فَكَبِّرُوا وَاسْجُدُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ فَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ أَنْ يَقُولَ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id Abu Qudamah As Sarkhasi] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Hisyam] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin 'Abdullah] bahwasanya [Al Asy'ari] berkata; \"Nabi Allah Shallallahu'alaihiwasallam pernah berkhutbah di hadapan kami, beliau menjelaskan sunnah dan mengajarkan cara shalat dengan bersabda: 'Jika kalian shalat maka luruskanlah barisan kalian, kemudian hendaklah salah seorang dari kalian menjadi imam. Bila imam bertakbir maka bertakbirlah kalian, dan bila imam mengucapkan, \"Waladl Dlaalliin\" maka ucapkan: \"Aamiin\" semoga Allah mengabulkan permohonan kalian. Jika imam bertakbir dan ruku' maka bertakbirlah dan rukulah, sesungguhnya imam ruku' dan mengangkat kepala dari ruku' sebelum kalian.-Nabi Shallallahu'alaihiwasallam bersabda: \"Gerakan imam harus kalian ikuti sesudahnya. Jika ia mengangkat (kepala dari ruku') dengan mengucapkan: \"Sami'allahu liman hamidah (Allah mendengar orang yang memuji-Nya) \"maka ucapkan: \"Allahumma rabbanaa wa lakal hamdu (Wahai Rabb kami, untuk-Mu segala puji) \" semoga Allah mendengar kalian. Sesungguhnya Allah berfirman dengan lisan Nabi Shallallahu'alaihi wasallam; \"Sami'allahu liman hamidah.\"Bila imam bertakbir dan sujud maka ikutlah bertakbir dan sujud, sesungguhnya imam bertakbir dan sujud sebelum kalian - Nabi Allah Shallallahu'alaihiwasallam bersabda: Gerakan Imam harus kalian ikuti sesudahnya-dan jika ia duduk maka yang pertama kali diucapkan oleh salah seorang dari kalian adalah: At-tahiyyatut-thayyibaatus-shalawaatu lillahi, As-salaamun 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, salaamun 'alaina wa 'ala 'ibadillahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan abduhu wa rasuuluh (Penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada Engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan Muhammad adalah hamba dan utusan-Nya).\""},"1155":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ أَحْمَدُ بْنُ الْمِقْدَامِ الْعِجْلِيُّ الْبَصْرِيُّ قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ حَدَّثَنَا أَبِي يُحَدِّثُ عَنْ قَتَادَةَ عَنْ أَبِي غَلَّابٍ وَهُوَ يُونُسُ بْنُ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِأَنَّهُمْ صَلَّوْا مَعَ أَبِي مُوسَى فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ أَوَّلِ قَوْلِ أَحَدِكُمْ التَّحِيَّاتُ لِلَّهِ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats Ahmad bin Al Miqdam Al 'Ijliy Al Bashriy] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; [bapakku] telah menceritakan kepada kami dari [Qatadah] dari [Abu Ghallab Yunus bin Jubair] dari [Hiththan bin 'Abdullah] bahwasanya mereka Shalat bersama [Abu Musa] maka dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Hendaklah yang pertama kali diucapkan oleh salah seorang diantara kalian ketika duduk adalah, At-tahiyyatu lillah At thayyibaatus-shalawaatu lillahi, As-salaamun 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, salaamun 'alaina wa 'ala 'ibadillahish-shaalihiin, asyhadu allaa ilaah illallaah wahdahu laa syarikalah, wa asyhadu anna muhammadan abduhu wa rasuuluh (Penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada Engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah semata tiada sekutu bagi-Nya, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya).\""},"1156":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ وَطَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا الْقُرْآنَ وَكَانَ يَقُولُ التَّحِيَّاتُ الْمُبَارَكَاتُ الصَّلَوَاتُ الطَّيِّبَاتُ لِلَّهِ سَلَامٌ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ سَلَامٌ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits bin Sa'ad] dari [Abu Az Zubair] dari [Sa'id bin Jubair] dan [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam mengajari kami tasyahud sebagaimana beliau mengajari kami Al Qur'an, beliau bersabda: 'At-tahiyyatul-Mubarakaatu-shalawaatut-thayyibaatu lillahi, Salaamun 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, salaamun 'alaina wa 'ala 'ibadillahish-shaalihiin, asyhadu allaa ilaah illallaah wa asyhadu anna muhammadan abduhu wa rasuuluh (Penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada Engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya).\""},"1157":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ أَيْمَنَ وَهُوَ ابْنُ نَابِلٍ يَقُولُ حَدَّثَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ بِسْمِ اللَّهِ وَبِاللَّهِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِاللَّهِ مِنْ النَّارِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; aku mendengar [Aiman bin Nabil] dia berkata; telah menceritakan kepadaku [Abu Az Zubair] dari [Jabir] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam mengajari kami tasyahud sebagaimana beliau mengajari kami surat dari Al Qur'an, dengan menyebut nama Allah dan demi Allah, At-tahiyyatu lillah -wash shalawaatu wat thayyibaat, As-salaamun 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakaatuh, salaamun 'alaina wa 'ala 'ibadillahish-shaalihiin, asyhadu allaa ilaah illallaah, wa asyhadu anna muhammadan abduhu wa rasuuluh as alullahal jannata wa a'udzu billahi minannar. (Penghormatan, rahmat dan kebaikan hanya untuk Allah. Semoga keselamatan, rahmat, dan keberkahan tetap ada pada Engkau wahai Nabi. Keselamatan juga semoga ada pada hamba-hamba Allah yang shalih. Aku bersaksi bahwa tiada Dzat yang berhak disembah selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya. Aku memohon surgaNya kepada Allah dan aku berlindung kepada-Nya dari adzab neraka).\""},"1158":{"ar":"أَخْبَرَنَا الْهَيْثَمُ بْنُ أَيُّوبَ الطَّالَقَانِيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ قَالَ حَدَّثَنَا أَبِي عَنْ أَبِي عُبَيْدَةَ بْنِ مَسْعُودٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّكْعَتَيْنِ كَأَنَّهُ عَلَى الرَّضْفِقُلْتُ حَتَّى يَقُومَ قَالَ ذَلِكَ يُرِيدُ","id":"Telah mengabarkan kepada kami [Al Haitsam bin Ayyub Ath Thalaqaniy] dia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'ad bin Ibrahim bin 'Abdurrahman bin 'Auf] dia berkata; [bapakku] telah menceritakan kepada kami dari [Abu 'Ubaidah bin Mas'ud] dari [bapaknya] dia berkata; Rasulullah Shalallahu 'Alaihi Wa sallam ketika hendak bangkit dari raka'at pertama beliau duduk seakan-akan berada di atas batu yang di panaskan, hingga beliau segera berdiri lagi."},"1159":{"ar":"أَخْبَرَنِي يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ الْبَصْرِيُّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فَقَامَ فِي الشَّفْعِ الَّذِي كَانَ يُرِيدُ أَنْ يَجْلِسَ فِيهِ فَمَضَى فِي صَلَاتِهِ حَتَّى إِذَا كَانَ فِي آخِرِ صَلَاتِهِ سَجَدَ سَجْدَتَيْنِ قَبْلَ أَنْ يُسَلِّمَ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepadaku [Yahya bin Habib bin 'Arabiy Al Bashriy] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya] dari ['Abdurrahman Al A'raj] dari [Ibnu Buhainah]. Pernah Nabi Shalallahu 'Alaihi Wa sallam shalat. Saat beliau menyelesaikan rakaat genap (dua atau empat) dan berkehendak duduk, beliau terus melanjutkan shalatnya hingga ketika beliau sudah hampir selesai dari shalatnya, beliau sujud dua kali sebelum mengucapkan salam. Setelah itu beliau mengucapkan salam."},"1160":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ ابْنِ بُحَيْنَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فَقَامَ فِي الرَّكْعَتَيْنِ فَسَبَّحُوا فَمَضَى فَلَمَّا فَرَغَ مِنْ صَلَاتِهِ سَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Dawud Sulaiman bin Saif] dia berkata; telah menceritakan kepada kami [Wahab bin Jarir] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yahya bin Sa'id] dari ['Abdurrahman Al A'raj] dari [Ibnu Buhainah] bahwa Nabi Shalallahu 'Alaihi Wa sallam shalat dua raka'at. Tiba-tiba beliau bangkit, orang-orangpun mengucapkan subhanallah, namun beliau tetap melanjutkan shalatnya hingga ketika beliau telah selesai shalatnya beliau sujud dua kali kemudian salam. "},"1161":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَصَمِّ قَالَسُئِلَ أَنَسُ بْنُ مَالِكٍ عَنْ التَّكْبِيرِ فِي الصَّلَاةِ فَقَالَ يُكَبِّرُ إِذَا رَكَعَ وَإِذَا سَجَدَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ السُّجُودِ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ فَقَالَ حُطَيْمٌ عَمَّنْ تَحْفَظُ هَذَا فَقَالَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا ثُمَّ سَكَتَ فَقَالَ لَهُ حُطَيْمٌ وَعُثْمَانُ قَالَ وَعُثْمَانُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari ['Abdurrahman bin Al Ashammi] dia berkata; [Anas bin Malik] pernah ditanya tentang takbir dalam shalat, lalu ia menjawab, 'Bertakbir jika hendak ruku', sujud, mengangkat kepala dari sujud, dan saat hendak bangkit dari rakaat kedua'. Huthaim berkata; 'Dari siapa kamu menghafal hal ini?\" la menjawab, 'Dari Nabi Shallallahu'alaihiwasallam, Abu Bakar, dan Umar radliallahu 'anhuma'. kemudian ia terdiam. Huthaim berkata kepadanya; 'Utsman juga? ' la menjawab; juga 'Utsman'.\""},"1162":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ حَدَّثَنَا غَيْلَانُ بْنُ جَرِيرٍ عَنْ مُطَرِّفِ بْنِ عَبْدِ اللَّهِ قَالَصَلَّى عَلِيُّ بْنُ أَبِي طَالِبٍ فَكَانَ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ يُتِمُّ التَّكْبِيرَ فَقَالَ عِمْرَانُ بْنُ حُصَيْنٍ لَقَدْ ذَكَّرَنِي هَذَا صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dia berkata; telah menceritakan kepada kami [Ghailan bin Jarir] dari [Muththarrif bin 'Abdullah] dia berkata; \"Ali bin Thalib ketika shalat dia bertakbir jika hendak turun, Jika hendak mengangkat kepalanya dari sujud ia juga bertakbir, dan ia menyempurnakan takbirnya.\" [Imran bin Hushain] berkata; \"Ini mengingatkanku kepada shalatnya Rasulullah Shalallahu 'Alaihi Wa Sallam.\""},"1163":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّقَالَ سَمِعْتُهُ يُحَدِّثُ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ مِنْ السَّجْدَتَيْنِ كَبَّرَ وَرَفَعَ يَدَيْهِ حَتَّى يُحَاذِيَ بِهِمَا مَنْكِبَيْهِ كَمَا صَنَعَ حِينَ افْتَتَحَ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad-Dauraqiy] dan [Muhammad bin Basysyar] -dan lafadz baginya- mereka berdua berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdul Humaid bin Ja'far] dia berkata; telah menceritakan kepadaku [Muhammad bin 'Amr bin 'Atha] dari [Abu Humaid As Sa'idi] dia berkata; aku mendengarnya dia berkata; \"Rasulullah Shallallahu'alaihiwasallam bila bangun dari dua sujud maka beliau bertakbir dengan mengangkat kedua tangan hingga sejajar dengan kedua bahu, sebagaimana yang beliau perbuat saat mengawali shalat.\""},"1164":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ وَهُوَ ابْنُ عُمَرَ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَرْفَعُ يَدَيْهِ إِذَا دَخَلَ فِي الصَّلَاةِ وَإِذَا أَرَادَ أَنْ يَرْكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا قَامَ مِنْ الرَّكْعَتَيْنِ يَرْفَعُ يَدَيْهِ كَذَلِكَ حَذْوَ الْمَنْكِبَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la Ash Shan'aniy] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; aku mendengar ['Ubaidullah bin 'Umar] dari [Ibnu Syihab] dari [Salim] dari [Ibnu 'Umar] dari Rasulullah Shallallahu'alaihiwasallam, bahwa beliau mengangkat kedua tangan bila memulai shalat, ruku', serta jika mengangkat kepala dari ruku'. Dan jika berdiri dari dua rakaat maka beliau mengangkat kedua tangan sejajar dengan kedua bahu."},"1165":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ وَهُوَ ابْنُ عُمَرَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَانْطَلَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصْلِحُ بَيْنَ بَنِي عَمْرِو بْنِ عَوْفٍ فَحَضَرَتْ الصَّلَاةُ فَجَاءَ الْمُؤَذِّنُ إِلَى أَبِي بَكْرٍ فَأَمَرَهُ أَنْ يَجْمَعَ النَّاسَ وَيَؤُمَّهُمْ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَقَ الصُّفُوفَ حَتَّى قَامَ فِي الصَّفِّ الْمُقَدَّمِ وَصَفَّحَ النَّاسُ بِأَبِي بَكْرٍ لِيُؤْذِنُوهُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ أَبُو بَكْرٍ لَا يَلْتَفِتُ فِي الصَّلَاةِ فَلَمَّا أَكْثَرُوا عَلِمَ أَنَّهُ قَدْ نَابَهُمْ شَيْءٌ فِي صَلَاتِهِمْ فَالْتَفَتَ فَإِذَا هُوَ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ كَمَا أَنْتَ فَرَفَعَ أَبُو بَكْرٍ يَدَيْهِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ لِقَوْلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ رَجَعَ الْقَهْقَرَى وَتَقَدَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى فَلَمَّا انْصَرَفَ قَالَ لِأَبِي بَكْرٍ مَا مَنَعَكَ إِذْ أَوْمَأْتُ إِلَيْكَ أَنْ تُصَلِّيَ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ مَا كَانَ يَنْبَغِي لِابْنِ أَبِي قُحَافَةَ أَنْ يَؤُمَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ لِلنَّاسِ مَا بَالُكُمْ صَفَّحْتُمْ إِنَّمَا التَّصْفِيحُ لِلنِّسَاءِ ثُمَّ قَالَ إِذَا نَابَكُمْ شَيْءٌ فِي صَلَاتِكُمْ فَسَبِّحُوا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Bazi'] dia berkata; telah menceritakan kepada kami ['Abdul A'la bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Umar] dari [Abu Hazim] dari [Sahl bin Sa'ad] dia berkata; Pernah Rasulullah Shallallahu'alaihiwasallam pergi untuk mendamaikan Bani Amru bin Auf yang mempunyai suatu masalah. Ketika' tiba waktu shalat, muadzin datang kepada Abu Bakar dan menyuruhnya mengumpulkan orang-orang dan mengimami mereka. Kemudian datang Rasulullah Shallallahu'alaihiwasallam melalui celah-celah barisan shalat hingga beliau Shallallahu'alaihiwasallam berdiri di barisan terdepan. Orang-orang lalu mulai menepukkan tangannya kepada Abu Bakar untuk memberitahu keberadaan Rasulullah Shallallahu'alaihiwasallam, namun Abu Bakar tidak menoleh dalam shalatnya. Setelah orang-orang banyak yang menepukkan tangannya (sebagai isyarat), Abu Bakar tahu bahwa mereka mengingatkan sesuatu, maka ia menoleh dan mendapati Rasulullah Shallallahu'alaihiwasallam. Rasulullah Shallallahu'alaihiwasallam mengisyaratkan kepadanya untuk terus melanjutkan shalatnya. Maka Abu Bakar mengangkat kedua tangannya dan memuji Allah dengan ucapan Rasulullah Shallallahu'alaihiwasallam lantas mundur ke belakang, maka Rasulullah Shallallahu'alaihiwasallam maju untuk menjadi imam. Setelah selesai shalat beliau Shallallahu'alaihiwasallam bertanya kepada Abu Bakar, 'Wahai Abu Bakar, apakah yang menghalangimu untuk shalat menjadi imam bagi manusia saat kuisyaratkan demikian? ' Abu Bakar berkata; 'Tidaklah pantas bagi Ibnu Quhafah untuk mengimami shalat Rasulullah Shallallahu'alaihi wasallam'. Kemudian beliau Shallallahu'alaihiwasallam bersabda kepada orang-orang: 'Wahai manusia sekalian, kenapa kalian bertepuk tangan. Tepuk tangan hanya untuk wanita. Jika terjadi sesuatu dalam shalat kalian, maka ucapkan, \"Subhanallah (Maha suci Allah).\""},"1166":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ الْأَعْمَشِ عَنْ الْمُسَيَّبِ بْنِ رَافِعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَخَرَجَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ رَافِعُو أَيْدِينَا فِي الصَّلَاةِ فَقَالَ مَا بَالُهُمْ رَافِعِينَ أَيْدِيَهُمْ فِي الصَّلَاةِ كَأَنَّهَا أَذْنَابُ الْخَيْلِ الشُّمُسِ اسْكُنُوا فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abtsar] dari [Al A'masy] dari [Al Musayyib bin Rafi'] dari [Tamim bin Tharafah] dari [Jabir bin Samurah] dia berkata; dia berkata; \"Rasulullah Shallallahu'alaihiwasallam menemui kami dan kami dalam keadaan mengangkat tangan saat shalat, maka beliau bersabda: 'Kenapa mereka? Mereka mengangkat tangan-tangan mereka saat shalat laksana ekor-ekor kuda liar (yang tidak bisa diam), Tenanglah kalian dalam shalat'.\""},"1167":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ مِسْعَرٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنَّا نُصَلِّي خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُسَلِّمُ بِأَيْدِينَا فَقَالَ مَا بَالُ هَؤُلَاءِ يُسَلِّمُونَ بِأَيْدِيهِمْ كَأَنَّهَا أَذْنَابُ خَيْلٍ شُمُسٍ أَمَا يَكْفِي أَحَدُهُمْ أَنْ يَضَعَ يَدَهُ عَلَى فَخِذِهِ ثُمَّ يَقُولَ السَّلَامُ عَلَيْكُمْ السَّلَامُ عَلَيْكُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Mis'ar] dari ['Ubaidullah bin Al Qibthiyyah] dari [Jabir bin Samurah] dia berkata; \"Kami pernah shalat di belakang Rasulullah Shallallahu'alaihiwasallam, lalu kami memberi salam dengan tangan-tangan kami, maka beliau bersabda: 'Kenapa mereka memberi salam dengan tangan-tangan mereka? Mereka laksana ekor-ekor kuda liar! Cukuplah salah seorang dari mereka meletakkan tangannya di atas pahanya kemudian mengucapkan, \"Assalamu 'alaikum, assalamu 'alaikum.\""},"1168":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ نَابِلٍ صَاحِبِ الْعَبَاءِ عَنْ ابْنِ عُمَرَ عَنْ صُهَيْبٍ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَمَرَرْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَرَدَّ عَلَيَّ إِشَارَةً وَلَا أَعْلَمُ إِلَّا أَنَّهُ قَالَ بِإِصْبَعِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Nabil] -sahabat Al 'Aba- dari [Ibnu 'Umar] dari [Shuhaib] sahabat Rasulullah Shallallahu'alaihiwasallam dia berkata; \"Aku pernah melewati Rasulullah Shallallahu'alaihiwasallam yang sedang shalat, lalu aku mengucapkan salam kepada beliau, dan beliau membalasnya dengan isyarat tangan. Setahuku beliau tidak mengucapkan apa-apa selain memberi isyarat dengan tangan. "},"1169":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ الْمَكِّيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زَيْدِ ابْنِ أَسْلَمَ قَالَ قَالَ ابْنُ عُمَرَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَسْجِدَ قُبَاءَ لِيُصَلِّيَ فِيهِ فَدَخَلَ عَلَيْهِ رِجَالٌ يُسَلِّمُونَ عَلَيْهِ فَسَأَلْتُ صُهَيْبًا وَكَانَ مَعَهُ كَيْفَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ إِذَا سُلِّمَ عَلَيْهِ قَالَ كَانَ يُشِيرُ بِيَدِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur Al Makkiy] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Zaid bin Aslam] dia berkata; [Ibnu 'Umar] berkata; \"Nabi Shallallahu'alaihiwasallam masuk ke dalam masjid Quba untuk shalat di dalamnya, lalu ada beberapa orang yang mengucapkan salam kepada beliau. Aku lalu bertanya kepada [Shuhaib] -ia saat itu bersama Rasulullah Shallallahu'alaihiwasallam-, 'Bagaimana Rasulullah Shallallahu'alaihiwasallam berbuat tatkala ada yang memberi salam kepadanya? ' la menjawab, \"Beliau Shallallahu'alaihiwasallam menjawab dengan isyarat tangannya.\""},"1170":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا وَهْبٌ يَعْنِي ابْنَ جَرِيرٍ قَالَ حَدَّثَنَا أَبِي عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ عَطَاءٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ عَمَّارِ بْنِ يَاسِرٍأَنَّهُ سَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَرَدَّ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Busysyar] dia berkata; telah menceritakan kepada kami [Wahab bin Jarir] dia berkata; [bapakku] telah menceritakan kepada kami dari [Qais bin Sa'ad] dari ['Atha] dari [Muhammad bin 'Ali] dari ['Ammar bin Yasir] bahwa ia pernah mengucapkan salam kepada Rasulullah Shallallahu'alaihiwasallam saat beliau sedang shalat, dan beliau Shallallahu'alaihiwasallam membalas salamnya."},"1171":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِحَاجَةٍ ثُمَّ أَدْرَكْتُهُ وَهُوَ يُصَلِّي فَسَلَّمْتُ عَلَيْهِ فَأَشَارَ إِلَيَّ فَلَمَّا فَرَغَ دَعَانِي فَقَالَ إِنَّكَ سَلَّمْتَ عَلَيَّ آنِفًا وَأَنَا أُصَلِّي وَإِنَّمَا هُوَ مُوَجَّهٌ يَوْمَئِذٍ إِلَى الْمَشْرِقِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam pernah mengutusku untuk suatu keperluan beliau, dan kudapati beliau sedang shalat. Aku mengucapkan salam kepada beliau dan beliau memberi isyarat kepadaku. Ketika selesai shalat beliau memanggilku dan berkata: 'Kamu tadi mengucapkan salam kepadaku sementara aku sedang shalat'. Ketika itu beliau menghadap timur.\""},"1172":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ هَاشِمٍ الْبَعْلَبَكِّيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبِ بْنِ شَابُورَ عَنْ عَمْرِو بْنِ الْحَارِثِ قَالَ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَبَعَثَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ وَهُوَ يَسِيرُ مُشَرِّقًا أَوْ مُغَرِّبًا فَسَلَّمْتُ عَلَيْهِ فَأَشَارَ بِيَدِهِ ثُمَّ سَلَّمْتُ عَلَيْهِ فَأَشَارَ بِيَدِهِ فَانْصَرَفْتُ فَنَادَانِي يَا جَابِرُ فَنَادَانِي النَّاسُ يَا جَابِرُ فَأَتَيْتُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَلَّمْتُ عَلَيْكَ فَلَمْ تَرُدَّ عَلَيَّ قَالَ إِنِّي كُنْتُ أُصَلِّي","id":"Telah mengabarkan kepada kami [Muhammad bin Hasyim Al Ba'labakiy] dia berkata; telah menceritakan kepada kami [Muhammad bin Syu'aib bin Syabur] dari ['Amr bin Al Harits] dia berkata; Telah mengabarkan kepadaku [Abu Az Zubair] dari [Jabir], dia berkata; \"Rasulullah Shallallahu'alaihiwasallam mengutusku, lalu aku datang kepadanya, dan beliau sedang berjalan ke timur atau barat, maka aku mengucapkan salam kepadanya dan beliau Shallallahu'alaihiwasallam memberi isyarat dengan tangannya. Kemudian aku mengucapkan salam kepadanya dan beliau Shallallahu'alaihiwasallam memberi isyarat dengan tangannya. Lalu aku pergi, namun beliau Shallallahu'alaihiwasallam memanggilku, 'Wahai Jabir'. Orang-orang pun ikut memanggilku, 'Wahai Jabir'. Lalu aku mendatanginya dan kukatakan, 'Wahai Rasulullah Shallallahu'alaihiwasallam, aku memberi salam kepada engkau tetapi engkau tidak membalasnya! ' Beliau Shallallahu'alaihiwasallam berkata: 'Aku sedang shalat\""},"1173":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَالْحُسَيْنُ بْنُ حُرَيْثٍ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْأَحْوَصِ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَ��ْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ فِي الصَّلَاةِ فَلَا يَمْسَحْ الْحَصَى فَإِنَّ الرَّحْمَةَ تُوَاجِهُهُ","id":"Telah mengkhabarkan kepada kami [Qutaibah bin Sa'id] dan [Al Husain bin Harits] -dan lafadz ini miliknya- dari [Sufyan] dari [Az Zuhri] dari [Abu Al Ahwash] dari [Abu Dzarr] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Apabila salah seorang diantara kalian shalat, jangan menghapus batu-batu kerikil kecil (di waktu sujud), karena hal itu akan menghalanginya dari mendapat Rahmat Allah.\""},"1174":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي مُعَيْقِيبٌأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ كُنْتَ لَا بُدَّ فَاعِلًا فَمَرَّةً","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdulah bin Al Mubarak] dari [Al Auza'i] dari [Yahya bin Abi Katsir] dia berkata; telah menceritakan kepadaku [Abu Salamah bin 'Abdurrahman] dia berkata; telah menceritakan kepada kami [Mu'aiqib] bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika engkau memang harus melakukannya, maka lakukanlah sekali saja.\""},"1175":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ وَشُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى وَهُوَ ابْنُ سَعِيدٍ الْقَطَّانُ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا بَالُ أَقْوَامٍ يَرْفَعُونَ أَبْصَارَهُمْ إِلَى السَّمَاءِ فِي صَلَاتِهِمْ فَاشْتَدَّ قَوْلُهُ فِي ذَلِكَ حَتَّى قَالَ لَيَنْتَهُنَّ عَنْ ذَلِكَ أَوْ لَتُخْطَفَنَّ أَبْصَارُهُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dan [Syu'aib bin Yusuf] dari [Yahya bin Sa'id Al Qaththan] dari [Ibnu Abu 'Arubah] dari [Qatadah] dari [Anas bin Malik] bahwasanya Rasulullah Shallallahu'alaihiwasallam bersabda: \"Kenapa orang-orang mengangkat pandangan ke langit saat shalat?\" Suara beliau meninggi ketika mengucapkan hal itu, hingga beliau berkata, \"Berhentilah dari hal itu, atau pandangan mereka akan hilang.\" "},"1176":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَنَّ رَجُلًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَدَّثَهُأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا كَانَ أَحَدُكُمْ فِي الصَّلَاةِ فَلَا يَرْفَعْ بَصَرَهُ إِلَى السَّمَاءِ أَنْ يُلْتَمَعَ بَصَرُهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin 'Abdullah] bahwasanya [seorang laki-laki] sahabat nabi Shallallahu'alaihiwasallam bercerita kepadanya ia mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Jika salah seorang dari kalian shalat, janganlah memandang ke langil (ke atas) dikhawatirkun pandangannya akan tersambar."},"1177":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ أَبَا الْأَحْوَصِ يُحَدِّثُنَا فِي مَجْلِسِ سَعِيدِ ابْنِ الْمُسَيَّبِ وَابْنُ الْمُسَيَّبِ جَالِسٌ أَنَّهُ سَمِعَ أَبَا ذَرٍّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ اللَّهُ عَزَّ وَجَلَّ مُقْبِلًا عَلَى الْعَبْدِ فِي صَلَاتِهِ مَا لَمْ يَلْتَفِتْ فَإِذَا صَرَفَ وَجْهَهُ انْصَرَفَ عَنْهُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Yunus] dari [Az Zuhri] dia berkata; aku mendengar [Abu Al Ahwash] menceritakan kepada kami di majlis Sa'id bin Al Musayyib dan Ibnu Al Musayyib waktu itu sedang duduk mendengar [Abu Dzarr] berkata; Rasululllah Shallallahu'alaihiwasallam bersabda: \"Allah Azza wa Jalla akan selalu menghadap seorang hamba ketika dia shalat selagi hamba tersebut tidak menoleh, apabila dia menoleh maka Allah pun berpaling darinya.\""},"1178":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا زَائِدَةُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الِالْتِفَاتِ فِي الصَّلَاةِ فَقَالَ اخْتِلَاسٌ يَخْتَلِسُهُ الشَّيْطَانُ مِنْ الصَّلَاةِأَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَشْعَثَ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِي عَطِيَّةَ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Zaidah] dari [Asy'ats bin Abu Asy Sya'tsa] dari [bapaknya] dari [Masruq] dari ['Aisyah] Radliyallahu'anha dia berkata; \"Aku bertanya kepada Rasulullah Shallallahu'alaihiwasallam tentang menoleh saat shalat, lalu beliau menjawab: 'Itu adalah pencopetan (perampasan) yang dilakukan oleh setan dari shalat'.\" Telah mengabarkan kepada kami Amr bin Ali dia berkata; Telah menceritakan kepada kami Abdurrahman dia berkata; Telah menceritakan Abul Ahwash dari Asy'ats dari Bapaknya dari Masruq dari Aisyah dari Nabi shallallahu 'alaihi wasallam dengan hadis yang semisal tadi. Telah mengabarkan kepada kami Amr bin Ali dia berkata; Telah menceritakan kepada kami Abdurrahman dia berkata; Telah menceritakan kepada kami Israil dari Asy'ats bin Abu Sya'tsa dari Abu Athiyyah dari Masruq dari Aisyah dari Nabi shallallahu 'alaihi wasallam dengan hadis seperti itu juga."},"1179":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ بْنِ هِلَالٍ قَالَ حَدَّثَنَا الْمُعَافَى بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا الْقَاسِمُ وَهُوَ ابْنُ مَعْنٍ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ أَبِي عَطِيَّةَ قَالَ قَالَتْ عَائِشَةُإِنَّ الِالْتِفَاتَ فِي الصَّلَاةِ اخْتِلَاسٌ يَخْتَلِسُهُ الشَّيْطَانُ مِنْ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala bin Hilal] dia berkata; telah menceritakan kepada kami [Al Mu'afa bin Sulaiman] dia berkata; telah menceritakan kepada kami [Al Qasim bin Ma'an] dari [Al A'masy] dari ['Umarah] dari [Abu 'Athiyyah] dia berkata; ['Aisyah'] berkata; \"Menoleh dalam shalat adalah pencopetan (perampasan) yang dilakukan oleh setan dari shalat.\""},"1180":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ قَالَاشْتَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّيْنَا وَرَاءَهُ وَهُوَ قَاعِدٌ وَأَبُو بَكْرٍ يُكَبِّرُ يُسْمِعُ النَّاسَ تَكْبِيرَهُ فَالْتَفَتَ إِلَيْنَا فَرَآنَا قِيَامًا فَأَشَارَ إِلَيْنَا فَقَعَدْنَا فَصَلَّيْنَا بِصَلَاتِهِ قُعُودًا فَلَمَّا سَلَّمَ قَالَ إِنْ كُنْتُمْ آنِفًا تَفْعَلُونَ فِعْلَ فَارِسَ وَالرُّومِ يَقُومُونَ عَلَى مُلُوكِهِمْ وَهُمْ قُعُودٌ فَلَا تَفْعَلُوا ائْتَمُّوا بِأَئِمَّتِكُمْ إِنْ صَلَّى قَائِمًا فَصَلُّوا قِيَامًا وَإِنْ صَلَّى قَاعِدًا فَصَلُّوا قُعُودًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Abu Az Zubair] dari [Jabir] dia berkata; \"Ketika Rasulullah Shallallahu'alaihiwasallam sakit, kami shalat di belakangnya dan beliau dalam keadaan duduk, sedangkan Abu Bakar memperdengarkan takbirnya kepada orang-orang, maka beliau menoleh kepada kami dan melihat kami dalam keadaan berdiri. Beliau lalu mengisyaratkan kepada kami agar kami shalat dengan duduk. Setelah salam (selesai) beliau bersabda: 'Jika kalian seperti tadi, maka kalian melakukan perbuatan orang-orang Persia dan Romawi; mereka berdiri kepada raja-raja mereka yang sedang duduk. Janganlah kalian melakukan hal itu. Ikutilah imam-imam kalian, jika ia shalat dengan berdiri maka shalatlah dengan berdiri, dan jika ia shalat dengan duduk maka shalatlah dengan duduk'.\""},"1181":{"ar":"أَخْبَرَنَا أَبُو عَمَّارٍ الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدٍ بْنُ أَبِي هِنْدٍ عَنْ ثَوْرِ بْنِ زَيْدٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَلْتَفِتُ فِي صَلَاتِهِ يَمِينًا وَشِمَالًا وَلَا يَلْوِي عُنُقَهُ خَلْفَ ظَهْرِهِ","id":"Telah mengabarkan kepada kami [Abu 'Ammar Al Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari ['Abdullah bin Sa'id bin Abu Hindun] dari [Tsaur bin Zaid] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam pernah menoleh ke kanan dan ke kiri dalam shalatnya, dan beliau tidak memutar lehernya ke belakang punggungnya.\""},"1182":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ سُفْيَانَ وَيَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ عَنْ مَعْمَرٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ ضَمْضَمِ بْنِ جَوْسٍ عَنْ أَبِي هُرَيْرَةَ قَالَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْأَسْوَدَيْنِ فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Sufyan] dan [Yazid bin Zurai'] dari [Ma'mar] dari [Yahya bin Abu Katsir] dari [Dhamdham bin Jaus] dari [Abu Hurairah] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam memerintahkan untuk membunuh aswadain (dua hewan hitam, ular dan kalajengking) saat shalat.\""},"1183":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ دَاوُدَ أَبُو دَاوُدَ قَالَ حَدَّثَنَا هِشَامٌ وَهُوَ ابْنُ أَبِي عَبْدِ اللَّهِ عَنْ مَعْمَرٍ عَنْ يَحْيَى عَنْ ضَمْضَمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْأَسْوَدَيْنِ فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Sulaiman bin Dawud Abu Dawud] dia berkata; telah menceritakan kepada kami [Hisyam bin Abu 'Abdullah] dari [Ma'mar] dari [Yahya] dari [Dhamdham] dari [Abu Hurairah] dia berkata: \"Rasulullah Shallallahu'alaihiwasallam memerintahkan untuk membunuh aswadain (dua hewan hitam, ular dan kalajengking) saat shalat.\""},"1184":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي وَهُوَ حَامِلٌ أُمَامَةَ فَإِذَا سَجَدَ وَضَعَهَا وَإِذَا قَامَ رَفَعَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Malik] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amr bin Sulaim] dari [Abu Qatadah] bahwa Rasulullah Shallallahu'alaihiwasallam shalat dengan menggendong Umamah, apabila sujud maka beliau meletakkannya, dan jika berdiri maka beliau mengangkatnya kembali."},"1185":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ بْنِ أَبِي سُلَيْمَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ أَبِي قَتَادَةَ قَالَرَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ النَّاسَ وَهُوَ حَامِلٌ أُمَامَةَ بِنْتَ أَبِي الْعَاصِ عَلَى عَاتِقِهِ فَإِذَا رَكَعَ وَضَعَهَا فَإِذَا فَرَغَ مِنْ سُجُودِهِ أَعَادَهَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Utsman bin Abi Sulaiman] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Amr bin Sulaim] dari [Abu Qatadah] dia berkata; \"Aku melihat Rasulullah Shallallahu'alaihiwasallam mengimami shalat manusia dengan menggendong Umamah binti Abu Al Ash di pundaknya. Jika ruku' maka beliau meletakkannya dan ketika selesai dari sujud maka beliau menggendongnya kembali.\""},"1186":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ وَرْدَانَ قَالَ حَدَّثَنَا بُرْدُ بْنُ سِنَانٍ أَبُو الْعَلَاءِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْاسْتَفْتَحْتُ الْبَابَ وَرَسُول�� اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي تَطَوُّعًا وَالْبَابُ عَلَى الْقِبْلَةِ فَمَشَى عَنْ يَمِينِهِ أَوْ عَنْ يَسَارِهِ فَفَتَحَ الْبَابَ ثُمَّ رَجَعَ إِلَى مُصَلَّاهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hatim bin Wardan] dia berkata; Telah menceritakan kepada kami [Burd bin Sinan Abu Al 'Alaa] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Aku membuka pintu dan Rasulullah Shallallahu'alaihiwasallam sedang shalat sunnah, sedangkan pintu-berada-di arah kiblat, lalu beliau berjalan ke kanan atau ke kirinya, lantas beliau membuka pintu kemudian kembali ke tempat shalatnya.\""},"1187":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ زَادَ ابْنُ الْمُثَنَّى فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Qatadah] dan [Muhammad bin Al Mutsanna] -dan lafad ini miliknya- mereka berdua berkatan; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi Shallallahu'alaihiwasallam, beliau bersabda: \"Bertasbih (mengucap subhanallah) adalah bagi laki-laki dan tepuk tangan adalah bagi perempuan.\" -Ibnu Mutsanna menambahkan; -saat shalat\"-."},"1188":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwasanya keduanya mendengar [Abu Hurairah] berkata; Rasulullah Shallallahu'alaihiwasallam bersabda: \"Bertasbih (mengucap subhanallah) adalah bagi laki-laki dan tepuk tangan bagi perempuan.\""},"1189":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْفُضَيْلُ بْنُ عِيَاضٍ عَنْ الْأَعْمَشِ ح وَأَنْبَأَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُلَيْمَانَ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Fudhail bin 'Iyadh] dari [Al A'masy] -lewat jalur periwayatan lain-- dan telah memberitakan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sulaiman Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu'alaihiwasallam bersabda; \"Bertasbih bagi laki-laki dan lepuk tangan bagi perempuan.\""},"1190":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَوْفٍ قَالَ حَدَّثَنِي مُحَمَّدٌ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ التَّسْبِيحُ لِلرِّجَالِ وَالتَّصْفِيقُ لِلنِّسَاءِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Auf] dia berkata; telah menceritakan kepadaku [Muhammad] dari [Abu Hurairah] dari Rasulullah Shallallahu'alaihiwasallam beliau bersabda; \"Bertasbih bagi laki-laki dan bertepuk tangan bagi perempuan.\""},"1191":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ الْمُغِيرَةِ عَنْ الْحَارِثِ الْعُكْلِيِّ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُجَيٍّ عَنْ عَلِيٍّ قَالَكَانَ لِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاعَةٌ آتِيهِ فِيهَا فَإِذَا أَتَيْتُهُ اسْتَأْذَنْتُ إِنْ وَجَدْتُهُ يُصَلِّي فَتَنَحْنَحَ دَخَلْتُ وَإِنْ وَجَدْتُهُ فَارِغًا أَذِنَ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Al Mughirah] dari [Al Harits Al 'Ukliy] dari [Abu Zur'ah bin 'Amr bin Jarir] dia berkata; telah menceritakan kepada kami ['Abdullah bin Nujayy] dari ['Ali] dia berkata; \"Aku mempunyai satu saat dari Rasulullah Shalallahu 'Alaihi Wa Sallam untuk menemuinya. Apabila aku menemuinya aku meminta izin terlebih dahulu. Jika beliau sedang shalat, maka beliau berdehem -sebagai tanda beliau merasa keberatan- aku masuk. Dan jika beliau sedang longgar, beliau mempersilahkanku.\""},"1192":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا ابْنُ عَيَّاشٍ عَنْ مُغِيرَةَ عَنْ الْحَارِثِ الْعُكْلِيِّ عَنْ ابْنِ نُجَيٍّ قَالَ قَالَ عَلِيٌّكَانَ لِي مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَدْخَلَانِ مَدْخَلٌ بِاللَّيْلِ وَمَدْخَلٌ بِالنَّهَارِ فَكُنْتُ إِذَا دَخَلْتُ بِاللَّيْلِ تَنَحْنَحَ لِي","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid] dia berkata; telah menceritakan kepada kami [Ibnu 'Ayyasy] dari [Mughirah] dari [Al Harits Al 'Ukliy] dari [Ibnu Nujayy] dia berkata; ['Ali] berkata; Aku mempunyai dua kesempatan dari Rasulullah Shalallahu 'Alaihi Wa Sallam untuk menemuinya. Yaitu kesempatan di malam hari dan kesempatan di siang hari. Apabila aku menemuinya di waktu malam, beliau berdehem kepadaku.\""},"1193":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ قَالَ حَدَّثَنِي شُرَحْبِيلُ يَعْنِي ابْنَ مُدْرِكٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ نُجَيٍّ عَنْ أَبِيهِ قَالَ قَالَ لِي عَلِيٌّكَانَتْ لِي مَنْزِلَةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ تَكُنْ لِأَحَدٍ مِنْ الْخَلَائِقِ فَكُنْتُ آتِيهِ كُلَّ سَحَرٍ فَأَقُولُ السَّلَامُ عَلَيْكَ يَا نَبِيَّ اللَّهِ فَإِنْ تَنَحْنَحَ انْصَرَفْتُ إِلَى أَهْلِي وَإِلَّا دَخَلْتُ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar] dia berkata; telah menceritakan kepada kami [Abu Usamah] dia berkata; telah menceritakan kepada kami [Syurahbil bin Mudrik] dia berkata; ['Abdullah bin Nujayyi] dari [bapaknya] dia berkata; ['Ali] berkata kepadaku; \"Aku mempunyai kedudukan di sisi Rasulullah Shalallahu 'Alaihi Wa Sallam yang tidak dimiliki oleh siapapun. Aku selalu menemuinya di waktu sahur dengan mengucapkan, 'Assalaamu 'Alaika ya Nabiyullah'. Apabila beliau berdehem, aku kembali kerumahku. Jika tidak, maka akupun masuk.\""},"1194":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ مُطَرِّفٍ عَنْ أَبِيهِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي وَلِجَوْفِهِ أَزِيزٌ كَأَزِيزِ الْمِرْجَلِ يَعْنِي يَبْكِي","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Hammad bin Salamah] dari [Tsabit Al Bannani] dari [Mutharrif] dari [bapaknya], dia berkata; \"Aku datang kepada Nabi Shallallahu'alaihiwasallam yang sedang shalat dan dalam dadanya terdengar suara seperti air yang mendidih dalam periuk - yakni: beliau menangis.\""},"1195":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ وَهْبٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي الدَّرْدَاءِ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَسَمِعْنَاهُ يَقُولُ أَعُوذُ بِاللَّهِ مِنْكَ ثُمَّ قَالَ أَلْعَنُكَ بِلَعْنَةِ اللَّهِ ثَلَاثًا وَبَسَطَ يَدَهُ كَأَنَّهُ يَتَنَاوَلُ شَيْئًا فَلَمَّا فَرَغَ مِنْ الصَّلَاةِ قُلْنَا يَا رَسُولَ اللَّهِ قَدْ سَمِعْنَاكَ تَقُولُ فِي الصَّلَاةِ شَيْئًا لَمْ نَسْمَعْكَ تَقُولُهُ قَبْلَ ذَلِكَ وَرَأَيْنَاكَ بَسَطْتَ يَدَكَ قَالَ إِنَّ عَدُوَّ اللَّهِ إِبْلِيسَ جَاءَ بِشِهَابٍ مِنْ نَارٍ لِيَجْعَلَهُ فِي وَجْهِي فَقُلْتُ أَعُوذُ بِاللَّهِ مِنْكَ ثَلَاثَ مَرَّاتٍ ثُمَّ قُلْتُ أَلْعَنُكَ بِلَعْنَةِ اللَّهِ فَلَمْ يَسْتَأْخِرْ ثَلَاثَ مَرَّاتٍ ثُمَّ أَرَدْتُ أَنْ آخُذَهُ وَاللَّهِ لَوْلَا دَعْوَةُ أَخِينَا سُلَيْمَانَ لَأَصْبَحَ مُوثَقًا بِهَا يَلْعَبُ بِهِ وِلْدَانُ أَهْلِ الْمَدِينَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dari [Ibnu Wahb] dari [Mu'awiyah bin Shalih] dia berkata; telah menceritakan kepada kami [Rabi'ah bin Yazid] dari [Abu Idris Al Khaulani] dari [Abu Ad Darda'] dia berkata; \"Rasulullah Shallallahu'alaihiwasallam berdiri untuk shalat, dan kami mendengar beliau mengucapkan, 'Aku berlindung kepada Allah darimu (syetan) '. Kemudian beliau juga mengucapkan, 'Aku melaknatmu dengan laknat Allah'. Beliau mengucapkannya tiga kali dengan menengadahkan tangannya seolah-olah beliau meminta sesuatu. Setelah selesai shalat kami berkata; 'Wahai Rasulullah Shallallahu'alaihiwasallam, kami mendengar engkau dalam shalat mengucapkan sesuatu yang belum pernah kami dengar sebelumnya dari engkau dan kami juga melihatmu menengadahkan tangan? ' Beliau Shallallahu'alaihiwasallam menjawab: \"Musuh Allah (syetan) datang dengan membawa bintang dari api untuk diletakkan di wajahku! Aku mengucapkan: \"Aku berlindung kepada Allah darimu (syetan) \" -tiga kali-. Aku juga mengucapkan; \"Aku melaknatmu (syetan) dengan laknat Allah.\" - juga tiga kali-. Kemudian aku ingin menangkapnya! Demi Allah, andaikan bukan karena doa saudaraku Sulaiman, maka pasti ia diikat untuk dipermainkan oleh anak-anak Madinah'.\""},"1196":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ وَقُمْنَا مَعَهُ فَقَالَ أَعْرَابِيٌّ وَهُوَ فِي الصَّلَاةِ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تَرْحَمْ مَعَنَا أَحَدًا فَلَمَّا سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْأَعْرَابِيِّ لَقَدْ تَحَجَّرْتَ وَاسِعًا يُرِيدُ رَحْمَةَ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari [Abu Salamah] bahwasanya [Abu Hurairah] berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam berdiri untuk shalat dan kami ikut berdiri dengannya, lalu ada seorang Badui yang berbicara dalam shalat; 'Ya Allah, kasihanilah aku dan Muhammad, janganlah Engkau kasihani seorangpun bersama kami! ' Setelah Rasulullah Shalallah 'Alaihi Wa Sallam mengucapkan salam, beliau bersabda kepada orang Badui tersebut: 'Engkau telah menyempitkan sesuatu yang luas! ' Maksudnya adalah rahmat Allah Azza wa Jalla.\""},"1197":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ الزُّهْرِيُّ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ أَحْفَظُهُ مِنَ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدٌ عَنْ أَبِي هُرَيْرَةَأَنَّ أَعْرَابِيًّا دَخَلَ الْمَسْجِدَ فَصَلَّى رَكْعَتَيْنِ ثُمَّ قَالَ اللَّهُمَّ ارْحَمْنِي وَمُحَمَّدًا وَلَا تَرْحَمْ مَعَنَا أَحَدًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ تَحَجَّرْتَ وَاسِعًا","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad bin 'Abdurrahman Az Zuhri] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; saya menghafalnya dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Sa'id] dari [Abu Hurairah] bahwa ada seorang Badui yang masuk ke masjid lalu shalat dua rakaat, kemudian mengucapkan; \"Ya Allah, kasihanilah aku dan Muhammad, dan jangan Engkau kasihani seorangpun bersama kami!\" Rasulullah Shalallah 'Alaihi Wa Sallam lalu bersabda: \"Engkau telah menyempitkan sesuatu yang luas.\""},"1198":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ هِلَالِ بْنِ أَبِي مَيْمُونَةَ قَالَ حَدَّثَنِي عَطَاءُ بْنُ يَسَارٍ عَنْ مُعَاوِيَةَ بْنِ الْحَكَمِ السَّلَمِيِّ قَا��َقُلْتُ يَا رَسُولَ اللَّهِ إِنَّا حَدِيثُ عَهْدٍ بِجَاهِلِيَّةٍ فَجَاءَ اللَّهُ بِالْإِسْلَامِ وَإِنَّ رِجَالًا مِنَّا يَتَطَيَّرُونَ قَالَ ذَاكَ شَيْءٌ يَجِدُونَهُ فِي صُدُورِهِمْ فَلَا يَصُدَّنَّهُمْ وَرِجَالٌ مِنَّا يَأْتُونَ الْكُهَّانَ قَالَ فَلَا تَأْتُوهُمْ قَالَ يَا رَسُولَ اللَّهِ وَرِجَالٌ مِنَّا يَخُطُّونَ قَالَ كَانَ نَبِيٌّ مِنْ الْأَنْبِيَاءِ يَخُطُّ فَمَنْ وَافَقَ خَطُّهُ فَذَاكَ قَالَ وَبَيْنَا أَنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ إِذْ عَطَسَ رَجُلٌ مِنْ الْقَوْمِ فَقُلْتُ يَرْحَمُكَ اللَّهُ فَحَدَّقَنِي الْقَوْمُ بِأَبْصَارِهِمْ فَقُلْتُ وَا ثُكْلَ أُمِّيَاهُ مَا لَكُمْ تَنْظُرُونَ إِلَيَّ قَالَ فَضَرَبَ الْقَوْمُ بِأَيْدِيهِمْ عَلَى أَفْخَاذِهِمْ فَلَمَّا رَأَيْتُهُمْ يُسَكِّتُونِي لَكِنِّي سَكَتُّ فَلَمَّا انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَانِي بِأَبِي وَأُمِّي هُوَ مَا ضَرَبَنِي وَلَا كَهَرَنِي وَلَا سَبَّنِي مَا رَأَيْتُ مُعَلِّمًا قَبْلَهُ وَلَا بَعْدَهُ أَحْسَنَ تَعْلِيمًا مِنْهُ قَالَ إِنَّ صَلَاتَنَا هَذِهِ لَا يَصْلُحُ فِيهَا شَيْءٌ مِنْ كَلَامِ النَّاسِ إِنَّمَا هُوَ التَّسْبِيحُ وَالتَّكْبِيرُ وَتِلَاوَةُ الْقُرْآنِ قَالَ ثُمَّ اطَّلَعْتُ إِلَى غُنَيْمَةٍ لِي تَرْعَاهَا جَارِيَةٌ لِي فِي قِبَلِ أُحُدٍ وَالْجَوَّانِيَّةِ وَإِنِّي اطَّلَعْتُ فَوَجَدْتُ الذِّئْبَ قَدْ ذَهَبَ مِنْهَا بِشَاةٍ وَأَنَا رَجُلٌ مِنْ بَنِي آدَمَ آسَفُ كَمَا يَأْسَفُونَ فَصَكَكْتُهَا صَكَّةً ثُمَّ انْصَرَفْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَعَظَّمَ ذَلِكَ عَلَيَّ فَقُلْتُ يَا رَسُولَ اللَّهِ أَفَلَا أَعْتِقُهَا قَالَ ادْعُهَا فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْنَ اللَّهُ عَزَّ وَجَلَّ قَالَتْ فِي السَّمَاءِ قَالَ فَمَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّهَا مُؤْمِنَةٌ فَاعْتِقْهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf] dia berkata; telah menceritakan kepada kami [Al Auza'i] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Hilal bin Abu Maimunah] dia berkata; telah menceritakan kepada kami ['Atha bin Yasar] dari [Mu'awiyah bin Al Hakam As Salami] dia berkata; bahwa ia pernah berkata kepada Rasulullah Shalallah 'Alaihi Wa Sallam; \"Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, kami baru saja meninggalkan masa Jahiliyah, lalu Allah menurunkan Islam dan beberapa orang dari kami melakukan thathayyur!\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Itu hanyalah bisikan hati, maka jangan menghalangi niatan mereka.\" Kami berkata; \"Di antara kita juga ada yang mendatangi dukun-dukun.\" Nabi Shallallallahu'alaihi wasallam berkata: \"Jangan kalian datangi mereka.\" la berkata; \"Wahai Rasulullah, di antara kita ada yang membuat garis ramal.\" Lalu Nabi berkata: \"Dulu juga ada salah satu nabi yang membuat garis petunjuk. Jadi barangsiapa garisnya sama dengan garis yang dibuat olehnya, maka hal itu boleh.\" Ketika kami bersama Rasulullah dalam suatu shalat, tiba-tiba ada seseorang yang bersin, maka aku spontan mengucapkan; \"Yarhamukallah (semoga Allah merahmati-Mu).\" Orang-orangpun melototiku, maka aku berkata; \"Celakalah kalian, kenapa kalian melototiku?\" la berkata; \"Lalu orang-orang menepukkan tangan ke paha mereka. Setelah aku lihat mereka menyuruhku diam yang (sebenarnya aku ingin mendebatnya), aku akhirnya diam. Setelah Rasulullah selesai shalat, beliau memanggiku - demi ibu dan bapakku yang menjadi jaminan - beliau tidak memukulku, tidak menghardikku, dan tidak mencelaku. Aku belum pernah melihat seorang guru pun sebelum ataupun setelah beliau yang pengajarannya lebih baik daripada beliau. Lantas Rasulullah sekedar bersabda; 'Shalat kita ini tidak boleh ada ucapan sesuatupun dari pembicaraan manusia. Shalat adalah bertasbih, bertakbir, dan membaca Al Qur'an.\" la berkata, \"Kemudian aku melihat kambingku yang digembalakan oleh seorang budak perempuanku di daerah antara Uhud dan Jawaniyyah, dan aku melihat seekor srigala membawa kabur salah satu kambing - aku seorang manusia yang kecewa sebagaimana umumnya orang yang kecewa - maka aku menampar budak itu sekali. Kemudian aku datang kepada Rasulullah dan mengabarkan hal itu. Beliau anggap perlakuanku itu keterlaluan, sehingga aku berkata; \"Bagaimana kalau dia kumerdekakan?\" Beliau menjawab: \"Panggillah dia.\" Lantas Rasulullah bersabda kepadanya: \"Di mana Allah 'azza wajalla?\" la - budak tersebut -menjawab; \"Di langit.\" Beliau bertanya lagi, \"Lalu siapa aku?\" la - budak tersebut-menjawab: \"Engkau utusan Allah.\" Beliau berkata: \"Dia perempuan yang beriman. maka merdekakanlah.\" "},"1199":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ قَالَ حَدَّثَنِي الْحَارِثُ بْنُ شُبَيْلٍ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكَانَ الرَّجُلُ يُكَلِّمُ صَاحِبَهُ فِي الصَّلَاةِ بِالْحَاجَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَزَلَتْ هَذِهِ الْآيَةُ{ حَافِظُوا عَلَى الصَّلَوَاتِ وَالصَّلَاةِ الْوُسْطَى وَقُومُوا لِلَّهِ قَانِتِينَ }فَأُمِرْنَا بِالسُّكُوتِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Isma'il bin Abu Khalid] dia berkata; telah menceritakan kepada kami [Al Harits bin Syubail] dari [Abu 'Amr Asy Syaibani] dari [Zaid bin Arqam] dia berkata; \"Pada masa Rasulullah Shalallah 'Alaihi Wa Sallam ada seorang laki-laki yang berbicara dalam shalat dengan temannya untuk suatu keperluan, lalu turunlah ayat ini, 'Peliharalah segala shalat(mu), dan (peliharalah) shalat wustha. Berdirilah karena Allah (dalam shalatmu) dengan khusyu'. (Qs. Al Baqarah (2): 238) Lalu kami disuruh diam (saat) shalat.\""},"1200":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا ابْنُ أَبِي غَنِيَّةَ وَاسْمُهُ يَحْيَى بْنُ عَبْدِ الْمَلِكِ وَالْقَاسِمُ بْنُ يَزِيدَ الْجَرْمِيُّ عَنْ سُفْيَانَ عَنْ الزُّبَيْرِ بْنِ عَدِيٍّ عَنْ كُلْثُومٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَهَذَا حَدِيثُ الْقَاسِمِ قَالَكُنْتُ آتِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يُصَلِّي فَأُسَلِّمُ عَلَيْهِ فَيَرُدُّ عَلَيَّ فَأَتَيْتُهُ فَسَلَّمْتُ عَلَيْهِ وَهُوَ يُصَلِّي فَلَمْ يَرُدَّ عَلَيَّ فَلَمَّا سَلَّمَ أَشَارَ إِلَى الْقَوْمِ فَقَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَعْنِي أَحْدَثَ فِي الصَّلَاةِ أَنْ لَا تَكَلَّمُوا إِلَّا بِذِكْرِ اللَّهِ وَمَا يَنْبَغِي لَكُمْ وَأَنْ تَقُومُوا لِلَّهِ قَانِتِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Ammar] dia berkata; telah menceritakan kepada kami [Ibnu Abu Ghaniyyah Yahya bin 'Abdul Malik] dan [Al Qasim bin Yazid Al Jarmi] dari [Sufyan] dari [Az Zubair bin 'Adiy] dari [Kultsum] dari ['Abdullah bin Mas'ud] dia berkata; \"Aku datang kepada Rasulullah Shalallah 'Alaihi Wa Sallam yang sedang shatat lalu memberi salam kepadanya, dan beliau membalas salamku. Disaat yang lain, aku datang kepada beliau yang sedang shalat, dan beliau tidak membalas salamku. Setelah salam, beliau mengisyaratkan kepada kaum lalu bersabda: 'Allah Azza wa Jalla telah menetapkan hukum perihal shalat yaitu, agar kalian jangan berbicara kecuali dzikir kepada Allah dan apa yang patut bagi kalian, serta agar kalian berdiri tegak kepada Allah dengan tunduk'.\""},"1201":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ عَنْ أَبِي وَائِلٍ عَنْ ابْنِ مَسْعُودٍ قَالَكُنَّا نُسَلِّمُ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَرُدُّ عَلَيْنَا السَّلَامَ حَتَّى قَدِمْنَا مِنْ أَرْضِ الْحَبَشَةِ فَسَلَّمْتُ عَلَيْهِ فَلَمْ يَرُدَّ عَلَيَّ فَأَخَذَنِي مَا قَرُبَ وَمَا بَعُدَ فَجَلَسْتُ حَتَّى إِذَا قَضَى الصَّلَاةَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُحْدِثُ مِنْ أَمْرِهِ مَا يَشَاءُ وَإِنَّهُ قَدْ أَحْدَثَ مِنْ أَمْرِهِ أَنْ لَا يُتَكَلَّمَ فِي الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim] dari [Abu Wa'il] dari [Ibnu Mas'ud] dia berkata; \"Kami pernah memberi salam kepada Rasulullah Shalallah 'Alaihi Wa Sallam, lalu beliau menjawab salam kami. Ketika kami tiba dari negeri Habasyah, aku\" memberi salam kepada beliau, namun beliau tidak menjawab salamku, \" lalu beliau memposisikanku pada jarak yang tidak terlalu dekat dan tidak terlalu jauh! Maka aku duduk hingga beliau selesai shalat, dan setelah itu beliau Shallallallahu'alaihi wasallam bersabda: 'Allah subhanahu wata'ala senantiasa menetapkan hukum yang di kehendaki-Nya, dan Dia telah menetapkan suatu hukum yang di kehendaki-Nya, - yaitu - jangan seorang pun berbicara saat shalat '.\""},"1202":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَ قَالَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ قَامَ فَلَمْ يَجْلِسْ فَقَامَ النَّاسُ مَعَهُ فَلَمَّا قَضَى صَلَاتَهُ وَنَظَرْنَا تَسْلِيمَهُ كَبَّرَ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Ibnu Syihab] dari ['Abdurrahman Al A'raj] dari ['Abdullah bin Buhainah] dia berkata; Rasulullah Shalallah 'Alaihi Wa Sallam shalat dua rakaat mengimami kami, lalu beliau berdiri dan tidak duduk (tasyahud), maka orang-orang ikut berdiri bersamanya. Setelah menyelesaikan shalatnya dan kami menunggu salamnya, beliau langsung takbir dan sujud dua kali dalam keadaan duduk sebelum salam, kemudian beliau salam. "},"1203":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ عَبْدِ اللَّهِ ابْنِ بُحَيْنَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ فِي الصَّلَاةِ وَعَلَيْهِ جُلُوسٌ فَسَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ قَبْلَ التَّسْلِيمِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari ['Abdurrahman bin Hurmuz] dari ['Abdullah bin Buhainah] dari Nabi Shallallahu'alaihi wasallam, bahwa beliau pernah berdiri pada shalat padahal mestinya ia duduk, dan beliau sujud dua kali saat duduk sebelum salam."},"1204":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ قَالَ أَبُو هُرَيْرَةَصَلَّى بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِحْدَى صَلَاتَيْ الْعَشِيِّ قَالَ قَالَ أَبُو هُرَيْرَةَ وَلَكِنِّي نَسِيتُ قَالَ فَصَلَّى بِنَا رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَانْطَلَقَ إِلَى خَشَبَةٍ مَعْرُوضَةٍ فِي الْمَسْجِدِ فَقَالَ بِيَدِهِ عَلَيْهَا كَأَنَّهُ غَضْبَانُ وَخَرَجَتْ السَّرَعَانُ مِنْ أَبْوَابِ الْمَسْجِدِ فَقَالُوا قُصِرَتْ الصَّلَاةُ وَفِي الْقَوْمِ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا فَهَابَاهُ أَنْ يُكَلِّمَاهُ وَفِي الْقَوْمِ رَجُلٌ فِي يَدَيْهِ طُولٌ قَالَ كَانَ يُسَمَّى ذَا الْيَدَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَنَسِيتَ أَمْ قُصِرَتْ الصَّلَاةُ قَالَ لَمْ أَنْسَ وَلَمْ تُقْصَرْ الصَّلَاةُ قَالَ وَقَالَ أَكَمَا قَالَ ذُو الْيَدَيْنِ قَالُوا نَعَمْ فَجَاءَ فَصَلَّى الَّذِي كَانَ تَرَكَهُ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَكَبَّرَ ثُمَّ كَبَّرَ ثُمَّ سَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ كَبَّرَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad bin Sirin] dia berkata; [Abu Hurairah] berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam mendirikan salah satu dari dua shalat senja(maghrib atau isyak) bersama kami-Abu Hurairah berkata; \"Akan tetapi aku lupa pastinya-. la meneruskan; \"Beliau Shallallallahu'alaihi wasallam shalat dua rakaat bersama kami, kemudian salam dan pergi ke papan yang terhampar di masjid. Rasulullah Shalallah 'Alaihi Wa Sallam lalu bersabda ke arah papan itu dengan telunjuknya, seolah-olah ia marah, maka orang-orang pun buru-buru keluar dari pintu-pintu masjid sambil berkata, 'Shalat telah diqashar'. Diantara mereka ada Abu Bakar dan Umar Radliyallahu'anhu, dan keduanya segan untuk berbicara kepada beliau Shallallalahu'alaihi wasallam. Disitu ada seseorang yang mempunyai tangan panjang, sehingga ia dijuluki dzul yadain (orang yang mempunyai tangan panjang). la berkata kepada Rasulullah Shalallah 'Alaihi Wa Sallam, 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, apakah engkau lupa ataukah engkau sengaja mengqashar shalat? ' Beliau menjawab: 'Aku tidak lupa dan aku juga tidak mengqashar shalat'. Lalu Rasulullah Shalallah 'Alaihi Wa Sallam bersabda kepada orang banyak, 'Apakah keadaannya seperti yang dikatakan oleh-, Dzul Yadain': \" Mereka menjawab, 'Ya'. Lalu beliau datang dan mengerjakan shalat yang ketinggalan lalu salam. kemudian takbir dan sujud seperti sujud biasanya atau lebih lama, kemudian mengangkat kepalanya dan bertakbir. Lalu bertakbir dan sujud lagi seperti sujud biasanya atau lebih lama, kemudian mengangkat kepalanya lalu bertakbir.\""},"1205":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْصَرَفَ مِنْ اثْنَتَيْنِ فَقَالَ لَهُ ذُو الْيَدَيْنِ أَقُصِرَتْ الصَّلَاةُ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالَ النَّاسُ نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى اثْنَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ كَبَّرَ فَسَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ ثُمَّ سَجَدَ مِثْلَ سُجُودِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Al Qasim] dari [Malik] dia berkata; telah menceritakan kepada kami [Ayyub] dari [Muhammad bin Sirin] dari [Abu Hurairah] \"Rasulullah Shalallah 'Alaihi Wa Sallam pernah pergi setelah selesai shalat dua raka'at, maka Dzul Yadain bertanya; 'Apakah shalat ini sengaja diqashar ataukah engkau lupa wahai Rasulullah Shalallah 'Alaihi Wa Sallam?\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Apakah benar Dzul Yadain ini?\" para sahabat menjawab, \"Ya\" Lalu Rasulullah Shalallah 'Alaihi Wa Sallam bangkit dan shalat dua raka'at lagi, kemudian beliau takbir dan sujud sebagaimana sujud yang biasa beliau lakukan atau lebih panjang lagi, kemudian bangkit dari sujud lalu sujud lagi seperti biasanya atau lebih panjang kemudian beliau bangkit lagi."},"1206":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ دَاوُدَ بْنِ الْحُصَيْنِ عَنْ أَبِي سُفْيَانَ مَوْلَى ابْنِ أَبِي أَحْمَدَ أَنَّهُ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْعَصْرِ فَسَلَّمَ فِي رَكْعَتَيْنِ فَقَامَ ذُو الْيَدَيْنِ فَقَالَ أَقُصِرَتْ الصَّلَاةُ يَا رَسُولَ اللَّهِ أَمْ نَسِيتَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُّ ذَلِكَ لَمْ يَكُنْ فَقَالَ قَدْ كَانَ بَعْضُ ذَلِكَ يَا رَسُولَ اللَّهِ فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى النَّاسِ فَقَالَ أَصَدَقَ ذُو الْيَدَيْنِ فَقَالُوا نَعَمْ فَأَتَمَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا بَقِيَ مِنْ الصَّلَاةِ ثُمَّ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ التَّسْلِيمِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Dawud bin Al Hushain] dari [Abu Sufyan] -budak Ibnu Abu Ahmad- bahwasanya dia berkata; aku mendengar [Abu Hurairah] berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam pernah shalat Ashar bersama kami, lalu beliau salam pada rakaat kedua. Dzul Yadain bangkit dan berkata; 'Apakah shalat ini di qashar wahai Rasulullah Shalallah 'Alaihi Wa Sallam, ataukah engkau lupa? ' Lalu Rasulullah Shalallah 'Alaihi Wa Sallam menjawab: 'Bukan karena semua itu'. Ia menegaskan lagi, 'Mungkin karena salah satunya wahai Rasulullah Shalallah 'Alaihi Wa Sallam? ' Lantas beliau Shallallallahu'alaihi wasallam menghadap kepada umatnya dan bersabda: 'Apakah Dzul Yadain benar? ' Mereka menjawab, 'Ya'. Lalu Rasulullah Shalallah 'Alaihi Wa Sallam menyempurnakan sisa shalatnya, kemudian sujud dua kali dan beliau dalam keadaan duduk setelah salam.\" "},"1207":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُحَدِّثُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الظُّهْرِ رَكْعَتَيْنِ ثُمَّ سَلَّمَ فَقَالُوا قُصِرَتْ الصَّلَاةُ فَقَامَ وَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Sulaiman bin 'Ubaidillah] dia berkata; telah menceritakan kepada kami [Bahz bin Asad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sa'd bin Ibrahim] bahwasanya ia mendengar [Abu Salamah] menceritakan dari [Abu Hurairah] bahwa Rasulullah mengerjakan shalat Zhuhur dua rakaat kemudian salam, maka mereka berkata; \"Shalat telah di qashar? ' Lalu Rasulullah Shalallah 'Alaihi Wa Sallam bangkit dan shalat dua rakaat, kemudian salam dan sujud dua kali."},"1208":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِمْرَانَ بْنِ أَبِي أَنَسٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمًا فَسَلَّمَ فِي رَكْعَتَيْنِ ثُمَّ انْصَرَفَ فَأَدْرَكَهُ ذُو الشِّمَالَيْنِ فَقَالَ يَا رَسُولَ اللَّهِ أَنُقِصَتْ الصَّلَاةُ أَمْ نَسِيتَ فَقَالَ لَمْ تُنْقَصْ الصَّلَاةُ وَلَمْ أَنْسَ قَالَ بَلَى وَالَّذِي بَعَثَكَ بِالْحَقِّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ قَالُوا نَعَمْ فَصَلَّى بِالنَّاسِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari ['Imran bin Abu Anas] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam suatu hari mengerjakan shalat dan beliau salam pada rakaat kedua kemudian pergi. Dzu Syimalain menjumpainya dan berkata kepada beliau; \"Apakah shalat ini dikurangi ataukah engkau lupa?\" Beliau Shallallallahu'alaihi wasallam menjawab: \"Shalat tidak dikurangi dan juga tidak lupa\". Dia berkata; ' \"Baik, demi Dzat yang telah mengutusmu dengan membawa kebenaran.\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Apakah Dzul Yadain benar?\" Mereka menjawab, \"Ya\". Lalu Rasulullah Shalallah 'Alaihi Wa Sallam shalat bersama orang-orang dua rakaat.\" "},"1209":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُوسَى الْفَرْوِيُّ قَالَ حَدَّثَنِي أَبُو ضَمْرَةَ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَسِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَلَّمَ فِي سَجْدَتَيْنِ فَقَالَ لَهُ ذُو الشِّمَالَيْنِ أَقُصِ��َتْ الصَّلَاةُ أَمْ نَسِيتَ يَا رَسُولَ اللَّهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَدَقَ ذُو الْيَدَيْنِ قَالُوا نَعَمْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَمَّ الصَّلَاةَ","id":"Telah mengabarkan kepada kami [Harun bin Musa Al Farwi] dia berkata; telah menceritakan kepada kami [Abu Dhamrah] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [Abu Salamah] dari [Abu Hurairah], dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam pernah lupa (dalam shalat), maka beliau salam ketika baru dua sujud. Dzu Syimalain bertanya; 'Apakah shalat ini di qashar ataukah engkau lupa wahai Rasulullah Shalallah 'Alaihi Wa Sallam?\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Apakah benar Dzul Yadain ini?\" para sahabat menjawab, \"Ya\" Lalu Rasulullah Shalallah 'Alaihi Wa Sallam bangkit untuk menyempurnakan shalatnya. "},"1210":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَأَبِي بَكْرِ بْنِ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ أَوْ الْعَصْرَ فَسَلَّمَ فِي رَكْعَتَيْنِ وَانْصَرَفَ فَقَالَ لَهُ ذُو الشِّمَالَيْنِ ابْنُ عَمْرٍو أَنُقِصَتْ الصَّلَاةُ أَمْ نَسِيتَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَقُولُ ذُو الْيَدَيْنِ فَقَالُوا صَدَقَ يَا نَبِيَّ اللَّهِ فَأَتَمَّ بِهِمْ الرَّكْعَتَيْنِ اللَّتَيْنِ نَقَصَأَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا بَكْرِ بْنَ سُلَيْمَانَ بْنِ أَبِي حَثْمَةَ أَخْبَرَهُ أَنَّهُ بَلَغَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى رَكْعَتَيْنِ فَقَالَ لَهُ ذُو الشِّمَالَيْنِ نَحْوَهُ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي هَذَا الْخَبَرَ سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ وَأَخْبَرَنِيهِ أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ وَأَبُو بَكْرِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ وَعُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah bin 'Abdurrahman] dan [Abu Bakr bin Sulaiman bin Abu Hatsmah] dari [Abu Hurairah], dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam shalat Zhuhur atau Ashar, dan beliau salam pada rakaat kedua lalu beranjak pergi, maka Dzu Syimalain Ibnu Amr berkata kepada beliau, 'Apakah shalat ini di qashar atuakah engkau lupa? ' Lalu Nabi Shallallallahu'alaihi wasallam bersabda: 'Apakah yang dikatakan Dzul Yadain (benar)? ' Para sahabat menjawab, 'Benar wahai Nabi Allah! ' Lantas beliau Shallallallahu'alaihi wasallam menyempurnakan dua rakaat yang ketinggalan. Telah mengabarkan kepada kami [Abu Daud] dia berkata; Telah menceritakan kepada kami [Ya'qub] dia berkata; Telah menceritakan kepada kami [Bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu Bakar bin Sulaiman bin Abu Hatsmah] Telah mengabarkan kepadanya, telah sampai kepadanya bahwa Rasulullah Shalallah 'Alaihi Wa Sallam shalat dua raka'at, lalu Dzul Syimalain berkata kepada kepada beliau sebagaimana Hadist diatas. [Ibnu Syihab] berkata; Telah mengabarkan kepadaku [Said bin Musayyab] tentang Hadist ini, dari [Abu Hurairah] dia berkata; dan telah mengabarkan kepadaku pula [Abu Salamah bin Abdurrahman] dan [Abu Bakar bin Abdurrahman bin Al Harits] dan [Ubaidullah bin Abdullah]."},"1211":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا شُعَيْبٌ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ عُقَيْلٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ وَأَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ وَابْنِ أَبِي حَثْمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَلَمْ يَسْجُدْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ قَبْلَ السَّلَامِ وَلَا بَعْدَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin 'Abdul Hakim] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; telah memberitakan kepada kami [Al Laits] dari ['Uqail] dia berkata; telah menceritakan kepadaku [Ibnu Syihab] dari [Sa'id] dan [Abu Salamah] dan [Abu Bakr bin 'Abdurrahman] dan [Ibnu Abu Hatsmah] dari [Abu Hurairah] dia berkata; pada waktu itu (kisah Dzul Yadain) Rasulullah Shalallah 'Alaihi Wa Sallam tidak sujud sebelum salam maupun sesudahnya."},"1212":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ قَالَ أَنْبَأَنَا اللَّيْثُ بْنُ سَعْدٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ يَوْمَ ذِي الْيَدَيْنِ سَجْدَتَيْنِ بَعْدَ السَّلَامِأَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ قَالَ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا عَمْرُو بْنُ الْحَارِثِ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad bin 'Amr] dia berkata; telah menceritakan kepada kami ['Abdullah bin Wahb] dia berkata; telah memberitakan kepada kami [Al Laits bin Sa'd] dari [Yazid bin Abu Habib] dari [Ja'far bin Rabi'ah] dari ['Irak bin Malik] dari [Abu Hurairah] bahwa pada peristiwa Dzul Yadain, Rasulullah Shalallah 'Alaihi Wa Sallam sujud dua kali setelah salam. Telah mengabarkan kepada kami [Amr bin Sawad bin Al Aswad] dia berkata; Telah mengabarkan kepada kami [Ibnu Wahab] dia berkata; Telah memberitakan kepada kami [Amr bin Al Harits] dia berkata; Telah menceritakan kepada kami [Qatadah] dari [Muhammad bin Sirin] dari [Abu Hurairah] dari Rasulullah Shalallah 'Alaihi Wa Sallam dengan Hadist seperti di atas."},"1213":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ وَحَدَّثَنِي ابْنُ عَوْنٍ وَخَالِدٌ الْحَذَّاءُ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَجَدَ فِي وَهْمِهِ بَعْدَ التَّسْلِيمِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman bin Sa'id bin Katsir bin Dinar] dia berkata; telah menceritakan kepada kami [Baqiyyah] dia berkata; telah menceritakan kepada kami [Syu'aib] dia berkata; dan telah menceritakan kepadaku [Ibnu 'Aun] dan [Khalid Al Hadza'] dari [Ibnu Sirin] dari [Abu Hurairah] bahwa setelah salam Nabi Shallallallahu'alaihi wasallam sujud ketika beliau ragu."},"1214":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ قَالَ أَخْبَرَنِي أَشْعَثُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ ابْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فَسَهَا فَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin 'Abdullah An Naisaburi] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Abdullah Al Anshari] dia berkata; telah mengabarkan kepadaku [Asy'ats] dari [Muhammad bin Sirin] dari [Khalid Al Hadza'] dari [Abu Qilabah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] bahwa Nabi Shallallallahu'alaihi wasallam shalat bersama mereka, lalu Rasulullah Shalallah 'Alaihi Wa Sallam lupa, maka beliau sujud dua kali kemudian salam. "},"1215":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَسَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثِ رَكَعَاتٍ مِنْ الْعَصْرِ فَدَخَلَ مَنْزِلَهُ فَقَامَ إِلَيْهِ رَجُلٌ يُقَالُ لَهُ الْخِرْبَاقُ فَقَالَ يَعْنِي نَقَصَتْ الصَّلَاةُ يَا رَسُولَ اللَّهِ فَخَرَجَ مُغْضَبًا يَجُرُّ رِدَاءَهُ فَقَالَ أَصَدَقَ قَالُوا نَعَمْ فَقَامَ فَصَلَّى تِلْكَ الرَّكْعَةَ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْهَا ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Abu Al Asy'ats] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Khalid Al Hadza'] dari [Abu Qilabah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam mengucapkan salam saat rakaat ketiga dalam shalat Ashar, lalu beliau masuk rumah. Kemudian ada seorang laki-laki yang disebut Al Khirbaq, dia berkata; 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, shalatnya kurang?! ' Kemudian beliau Shallallallahu'alaihi wasallam keluar dalam keadaan marah dengan menarik serbannya, lantas berkata: 'Apakah ia benar? ' para sahabat menjawab, 'Ya'. Kemudian beliau Shallallallahu'alaihi wasallam bangkit berdiri dan mengerjakan shalat satu rakaat, kemudian salam dan sujud dua kali, lalu beliau salam.\""},"1216":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ عَجْلَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيُلْغِ الشَّكَّ وَلْيَبْنِ عَلَى الْيَقِينِ فَإِذَا اسْتَيْقَنَ بِالتَّمَامِ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ قَاعِدٌ فَإِنْ كَانَ صَلَّى خَمْسًا شَفَعَتَا لَهُ صَلَاتَهُ وَإِنْ صَلَّى أَرْبَعًا كَانَتَا تَرْغِيمًا لِلشَّيْطَانِ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu 'Ajlan] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Bila salah seorang dari kalian ragu dalam shalatnya, maka hilangkan yang ragu dan pedomanilah yang diyakini. Bila ia yakin telah sempurna shalatnya, maka sujudlah dua kali dalam keadaan duduk, jika ia shalat lima rakaat maka (dua sujud tersebut) sebagai penggenapnya, dan jika ia shalat empat rakaat maka itu penghinaan bagi setan.\""},"1217":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ وَهُوَ ابْنُ أَبِي سَلَمَةَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا لَمْ يَدْرِ أَحَدُكُمْ صَلَّى ثَلَاثًا أَمْ أَرْبَعًا فَلْيُصَلِّ رَكْعَةً ثُمَّ يَسْجُدْ بَعْدَ ذَلِكَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ فَإِنْ كَانَ صَلَّى خَمْسًا شَفَعَتَا لَهُ صَلَاتَهُ وَإِنْ صَلَّى أَرْبَعًا كَانَتَا تَرْغِيمًا لِلشَّيْطَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz bin Abu Salamah] dari [Zaid bin Aslam] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Jika salah seorang dari kalian tidak tahu, apakah ia shalat tiga atau empat rakaat, maka shalatlah satu rakaat kemudian sujud dua kali dalam keadaan duduk, kalau ia shalat lima rakaat maka (dua sujud tersebut) sebagai penggenapnya, dan jika ia shalat empat rakaat maka itu penghinaan bagi setan.\" "},"1218":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مُفَضَّلٌ وَهُوَ ابْنُ مُهَلْهَلٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِيَرْفَعُهُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَتَحَرَّ الَّذِي يَرَى أَنَّهُ الصَّوَابُ فَيُتِمَّهُ ثُمَّ يَعْنِي يَسْجُدُ سَجْدَتَيْنِ وَلَمْ أَفْهَمْ بَعْضَ حُرُوفِهِ كَمَا أَرَدْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Mufadhdhal bin Muhalhal] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] dia menisbatkan hadits ini sampai kepada Nabi Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Jika salah seorang seorang dari kalian ragu dalam shalatnya, maka pedomanilah yang diyakini, yang dianggapnya benar, lalu sempurnakanlah, kemudian -yakni- sujudlah dua kali.\" Aku -perawi- tidak mengerti lagi kepastian redaksinya sebagaimana yang aku inginkan."},"1219":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا شَكَّ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَتَحَرَّ وَيَسْجُدْ سَجْدَتَيْنِ بَعْدَ مَا يَفْرُغُ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Waki'] dari [Mis'ar] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] dia berkata; Nabi Shallallallahu'alaihi wasallam bersabda: \"Jika salah seorang dari kalian ragu dalam shalatnya, maka pedomanilah yang diyakini, dan sujudlah dua kali setelah selesai.\""},"1220":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ سُلَيْمَانَ الْمُجَالِدِيُّ قَالَ حَدَّثَنَا الْفُضَيْلُ يَعْنِي ابْنَ عِيَاضٍ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةً فَزَادَ فِيهَا أَوْ نَقَصَ فَلَمَّا سَلَّمَ قُلْنَا يَا نَبِيَّ اللَّهِ هَلْ حَدَثَ فِي الصَّلَاةِ شَيْءٌ قَالَ وَمَا ذَاكَ فَذَكَرْنَا لَهُ الَّذِي فَعَلَ فَثَنَى رِجْلَهُ فَاسْتَقْبَلَ الْقِبْلَةَ فَسَجَدَ سَجْدَتَيْ السَّهْوِ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ لَوْ حَدَثَ فِي الصَّلَاةِ شَيْءٌ لَأَنْبَأْتُكُمْ بِهِ ثُمَّ قَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ فَأَيُّكُمْ شَكَّ فِي صَلَاتِهِ شَيْئًا فَلْيَتَحَرَّ الَّذِي يَرَى أَنَّهُ صَوَابٌ ثُمَّ يُسَلِّمْ ثُمَّ يَسْجُدْ سَجْدَتَيْ السَّهْوِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Isma'il bin Sulaiman Al Mujalidi] dia berkata; telah menceritakan kepada kami [Al Fudhail bin 'Iyadh] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam mengerjakan suatu shalat, lalu ia menambah atau mengurangi (rakaatnya), kemudian beliau salam. Kami bertanya; 'Wahai Nabi Allah, apakah ada cara baru dalam shalat? ' Rasulullah Shalallah 'Alaihi Wa Sallam balik bertanya, 'Apa itu? ' Kemudian kami menerangkan kepada beliau apa yang beliau perbuat, lalu beliau menekuk kakinya (untuk duduk) dan menghadap kiblat, kemudian sujud sahwi dua kali. Setelah itu beliau menghadapkan wajahnya kepada kami dan bersabda: 'Kalau ada cara baru dalam shalat, maka pasti kuberitahu kepada kalian.'Beliau melanjutkan sabdanya lagi: 'Aku adalah manusia biasa, aku lupa sebagaimana kalian juga lupa. Jadi siapa saja yang ragu dalam shalatnya maka hendaknya ia memilih yang dia yakini benar, kemudian salam dan sujud sahwi dua kali.\""},"1221":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ شُعْبَةَ قَالَ كَتَبَ إِلَيَّ مَنْصُورٌ وَقَرَأْتُهُ عَلَيْهِ وَسَمِعْتُهُ يُحَدِّثُ رَجُلًا عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى صَلَاةَ الظُّهْرِ ثُمَّ أَقْبَلَ عَلَيْهِمْ بِوَجْهِهِ فَقَالُوا أَحَدَثَ فِي الصَّلَاةِ حَدَثٌ قَالَ وَمَا ذَاكَ فَأَخْبَرُوهُ بِصَنِيعِهِ فَثَنَى رِجْلَهُ وَاسْتَقْبَلَ الْقِبْلَةَ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ سَلَّمَ ثُمَّ أَقْبَلَ عَلَيْهِمْ بِوَجْهِهِ فَقَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ فَإِذَا نَسِيتُ فَذَكِّرُونِي وَقَالَ لَوْ كَانَ حَدَثَ فِي الصَّلَاةِ حَدَثٌ أَنْبَأْتُكُمْ بِهِ وَقَالَ إِذَا أَوْهَمَ أَحَدُكُمْ فِي صَلَاتِهِ فَلْيَتَحَرَّ أَقْرَبَ ذَلِكَ مِنْ الصَّوَابِ ثُمَّ لِيُتِمَّ عَلَيْهِ ثُمَّ يَسْجُدْ سَجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Syu'bah] dia berkata; [Manshur] menulis kepadaku dan akupun membacakan dihadapannya, aku mendengar dia berkata dari seseorang dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam pernah shalat Zhuhur kemudian menghadap kepada jamaah. Lalu mereka berkata; \"Apakah ada sesuatu yang terjadi dalam shalat?\" Beliau menegaskan; \"Apa itu?\" Lalu mereka mengabarkan apa yang diperbuatnya. Beliau kemudian menekuk kakinya (untuk duduk) dan menghadap kiblat, lalu sujud dua kali. Setelah itu beliau menghadap kami, lantas bersabda: \"Aku adalah manusia biasa, aku lupa sebagaimana kalian juga lupa. Jika aku lupa maka ingatkanlah aku.\" Beliau bersabda lagi: \"Kalau terjadi sesuatu dalam shalat maka pasti kuberitahu kalian.\" Beliau melanjutkan sabdanya: \"Jika salah seorang dari kalian bimbang (ragu) dalam shalatnya, maka hendaklah memilih (meyakini) yang paling mendekati kebenaran, kemudian menyempurnakan, lantas sujud sahwi dua kali.\""},"1222":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ قَالَ سَمِعْتُ أَبَا وَائِلٍ يَقُولُ قَالَ عَبْدُ اللَّهِمَنْ أَوْهَمَ فِي صَلَاتِهِ فَلْيَتَحَرَّ الصَّوَابَ ثُمَّ يَسْجُدْ سَجْدَتَيْنِ بَعْدَ مَا يَفْرُغُ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Syu'bah] dari [Al Hakim] dia berkata; aku mendengar [Abu Wa'il] berkata; ['Abdullah] berkata; \"Barangsiapa yang ragu dalam shalatnya maka hendaklah meyakini yang mendekati kebenaran kemudian sujud dua kali setelah salam dalam keadaan duduk.\" "},"1223":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ عَوْنٍ عَنْ إِبْرَاهِيمَ قَالَكَانُوا يَقُولُونَ إِذَا أَوْهَمَ يَتَحَرَّى الصَّوَابَ ثُمَّ يَسْجُدُ سَجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu 'Aun] dari [Ibrahim] dia berkata; \"Mereka (para sahabat) berkata; 'Jika seseorang bimbang (dalam shalat), maka hendaklah meyakini yang mendekati kebenaran, kemudian sujud dua kali.\""},"1224":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ جُرَيْجٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مُسَافِعٍ عَنْ عُقْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَكَّ فِي صَلَاتِهِ فَلْيَسْجُدْ سَجْدَتَيْنِ بَعْدَ مَا يُسَلِّمُ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Ibnu Juraij] dia berkata; ['Abdullah bin Musafi'] berkata, dari ['Uqbah bin Muhammad bin Al Harits] dari ['Abdullah bin Ja'far] dia berkata; bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda; \"Barangsiapa bimbang dalam shalatnya, maka hendaklah sujud dua kali setelah salam.\""},"1225":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ أَنَّ مُصْعَبَ بْنَ شَيْبَةَ أَخْبَرَهُ عَنْ عُقْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَكَّ فِي صَلَاتِهِ فَلْيَسْجُدْ سَجْدَتَيْنِ بَعْدَ مَا يُسَلِّمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Hajjaj], berkata [Ibnu Juraij], telah mengabarkan kepadaku ['Abdullah bin Musafi'] bahwasanya [Mush'ab bin Syaibah] mengabarkan kepadanya, dari ['Uqbah bin Muhammad bin Al Harits] dari ['Abdullah bin Ja'far] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda; \"Barangsiapa bimbang dalam shalatnya, maka hendaklah sujud dua kali setelah salam.\""},"1226":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حَجَّاجٌ وَرَوْحٌ هُوَ ابْنُ عُبَادَةَ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُسَافِعٍ أَنَّ مُصْعَبَ بْنَ شَيْبَةَ أَخْبَرَهُ عَنْ عُقْبَةَ بْنِ مُحَمَّدِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ شَكَّ فِي صَلَاتِهِ فَلْيَسْجُدْ سَجْدَتَيْنِ قَالَ حَجَّاجٌ بَعْدَ مَا يُسَلِّمُ وَقَالَ رَوْحٌ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Hajjaj] dan [Rauh bin 'Ubadah] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Abdullah bin Musafi'] bahwasanya [Mush'ab bin Syaibah] mengabarkan kepadanya, dari ['Uqbah bin Muhammad bin Al Harits] dari ['Abdullah bin Ja'far] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda; \"Barangsiapa bimbang dalam shalatnya, maka hendaklah sujud dua kali Hajaj berkata; 'setelah salam.' Rauh berkata; 'dalam keadaan duduk.'"},"1227":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَدَكُمْ إِذَا قَامَ يُصَلِّي جَاءَهُ الشَّيْطَانُ فَلَبَسَ عَلَيْهِ صَلَاتَهُ حَتَّى لَا يَدْرِيَ كَمْ صَلَّى فَإِذَا وَجَدَ أَحَدُكُمْ ذَلِكَ فَلْيَسْجُدْ سَجْدَتَيْنِ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari [Abu Hurairah] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Sesungguhnya salah seorang diantara kalian apabila berdiri hendak shalat, maka syaithan mendatanginya, lalu ia mencampur adukan shalatnya hingga dia tidak tahu sudah berapa kali dia shalat. Jika salah seorang dari kalian mengalami hal tersebut, maka sujudlah dua kali dalam keadaan duduk.\""},"1228":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ خَمْسًا فَثَنَى رِجْلَهُ وَسَجَدَ سَجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -dan lafadz ini milik Ibnu Al Mutsanna- mereka berdua berkata; telah menceritakan kepada kami [Yahya] dari [Syu'bah] dari [Al Hakim] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam shalat zhuhur lima rakaat, maka beliau Shallallallahu'alaihi wasallam ditanya, 'Apakah shalat ditambah? Beliau Shallallallahu'alaihi wasallam berkata: 'Apa itu? ' Mereka menjawab, 'Engkau mengerjakan shalat lima rakaat! ' Lalu beliau menekuk kakinya dan sujud dua kali.\""},"1229":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا ابْنُ شُمَيْلٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ الْحَكَمِ وَمُغِيرَةُ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى بِهِمْ الظُّهْرَ خَمْسًا فَقَالُوا إِنَّكَ صَلَّيْتَ خَمْسًا فَسَجَدَ سَجْدَتَيْنِ بَعْدَ مَا سَلَّمَ وَهُوَ جَالِسٌ","id":"Telah mengabarkan kepada kami ['Ubdah bin 'Abdurrahim] dia berkata; telah memberitakan kepada kami [Ibnu Syumail] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Al Hakim] dan [Mughirah] dari [Ibrahim] dari [Alqamah] dari ['Abdullah] dari Nabi Shallallahu'alaihi wasallam, bahwa beliau pernah shalat zhuhur lima rakaat bersama para sahabat, maka para sahabat berkata; \"Engkau telah mengerjakan shalat lima rakaat! ' Lalu beliau sujud dua kali setelah salam sambil duduk."},"1230":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مُفَضَّلُ بْنُ مُهَلْهَلٍ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ بْنِ سُوَيْدٍ قَالَ صَلَّى عَلْقَمَةُ خَمْسًا فَقِيلَ لَهُ فَقَالَ مَا فَعَلْتُ قُلْتُ بِرَأْسِي بَلَى قَالَ وَأَنْتَ يَا أَعْوَرُ فَقُلْتُ نَعَمْ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ حَدَّثَنَا عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى خَمْسًا فَوَشْوَشَ الْقَوْمُ بَعْضُهُمْ إِلَى بَعْضٍ فَقَالُوا لَهُ أَزِيدَ فِي الصَّلَاةِ قَالَ لَا فَأَخْبَرُوهُ فَثَنَى رِجْلَهُ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ قَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Mufadhdhal bin Muhalhal] dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim bin Suwaid] dia berkata; \"Alqamah pernah shalat lima rakaat, maka ia ditanya tentang hal yang diperbuatnya. Ia menjawab; 'Aku tidak melakukan hal itu. Aku melakukannya sesuai dengan kepalaku (ingatanku) '. Ia (Alqamah) bertanya; 'Dan kamu wahai A'war? ' Lalu ia menjawab, 'Iya'. Lalu ia (Alqamah) melakukan sujud dua kali.\" Kemudian [Alqamah] menceritakan kepada kami dari [Abdullah], dari Nabi Shallallahu'alaihi wasallam, bahwa beliau pernah shalat lima rakaat, sehingga orang-orang saling berbisik, Mereka kemudian berkata kepada Nabi Shallallahu'alaihi wasallam, \"Apakah engkau menambah shalat ini?\" Beliau Shallallallahu'alaihi wasallam menjawab: \"Tidak\" Lalu mereka memberitahu beliau tentang hal itu. Setelah itu beliau duduk dan sujud dua kali, lantas bersabda: \"Aku manusia biasa, aku lupa sebagaimana kalian juga lupa.\""},"1231":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ مَالِكِ بْنِ مِغْوَلٍ قَالَ سَمِعْتُ الشَّعْبِيَّ يَقُولُسَهَا عَلْقَمَةُ بْنُ قَيْسٍ فِي صَلَاتِهِ فَذَكَرُوا لَهُ بَعْدَ مَا تَكَلَّمَ فَقَالَ أَكَذَلِكَ يَا أَعْوَرُ قَالَ نَعَمْ فَحَلَّ حُبْوَتَهُ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ وَقَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ وَسَمِعْتُ الْحَكَمَ يَقُولُ كَانَ عَلْقَمَةُ صَلَّى خَمْسًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Malik bin Mighwal] dia berkata; aku mendengar [Asy Sya'bi] berkata; \" [Alqamah bin Qais] pernah lupa saat shalat, maka orang-orang mengingatkannya setelah ia berbicara. Ia menegaskannya, 'Apakah demikian wahai A'war? ' Ia menjawab 'Ya'. Lalu ia melepas serbannya dan sujud sahwi dua kali. Kemudian ia berkata; 'Beginilah dulu Rasulullah Shalallah 'Alaihi Wa Sallam melakukannya'. Dan aku mendengar Al Hakam berkata bahwa Alqamah shalat lima rakaat.\" "},"1232":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ سُفْيَانَ عَنْ الْحَسَنِ بْنِ عُبَيْدِ اللَّهِ عَنْ إِبْرَاهِيمَ أَنَّ عَلْقَمَةَصَلَّى خَمْسًا فَلَمَّا سَلَّمَ قَالَ إِبْرَاهِيمُ بْنُ سُوَيْدٍ يَا أَبَا شِبْلٍ صَلَّيْتَ خَمْسًا فَقَالَ أَكَذَلِكَ يَا أَعْوَرُ فَسَجَدَ سَجْدَتَيْ السَّهْوِ ثُمَّ قَالَ هَكَذَا فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Sufyan] dari [Al Hasan bin 'Ubaidullah] dari [Ibrahim] bahwasanya ['Alqamah] shalat lima raka'at, setelah salam Ibrahim bin Suwaid berkata, \"Wahai Abu Syibl, engkau shalat lima rakaat.\" Ia berkata; \"Apakah demikian wahai A'war?\" Lalu ia sujud sahwi dua kali. Lantas ia berkata; \"Beginilah dulu Rasulullah Shalallah 'Alaihi Wa Sallam melakukannya.\" "},"1233":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ أَبِي بَكْرٍ النَّهْشَلِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى إِحْدَى صَلَاتَيْ الْعَشِيِّ خَمْسًا فَقِيلَ لَهُ أَزِيدَ فِي الصَّلَاةِ قَالَ وَمَا ذَاكَ قَالُوا صَلَّيْتَ خَمْسًا قَالَ إِنَّمَا أَنَا بَشَرٌ أَنْسَى كَمَا تَنْسَوْنَ وَأَذْكُرُ كَمَا تَذْكُرُونَ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ انْفَتَلَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Abu Bakr An Nahsyali] dari ['Abdurrahman bin Al Aswad] dari [Bapaknya] dari [Abdullah] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam pernah mengerjakan salah satu shalat Asyiyy (Maghrib atau Isya) lima rakaat, maka beliau lalu ditanya; \"Apakah shalat ini ditambah?\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Apa itu?\" Mereka menjawab, \"Engkau mengerjakan shalat lima rakaat!\" Setelah itu beliau bersabda: \"Aku adalah manusia biasa. Aku lupa sebagaimana kalian lupa dan aku ingat sebagaimana kalian ingat.\" Lalu beliau sujud dua kali lantas pergi. "},"1234":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ مُحَمَّدِ بْنِ يُوسُفَ مَوْلَى عُثْمَانَ عَنْ أَبِيهِ يُوسُفَأَنَّ مُعَاوِيَةَ صَلَّى أَمَامَهُمْ فَقَامَ فِي الصَّلَاةِ وَعَلَيْهِ جُلُوسٌ فَسَبَّحَ النَّاسُ فَتَمَّ عَلَى قِيَامِهِ ثُمَّ سَجَدَ سَجْدَتَيْنِ وَهُوَ جَالِسٌ بَعْدَ أَنْ أَتَمَّ الصَّلَاةَ ثُمَّ قَعَدَ عَلَى الْمِنْبَرِ فَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نَسِيَ شَيْئًا مِنْ صَلَاتِهِ فَلْيَسْجُدْ مِثْلَ هَاتَيْنِ السَّجْدَتَيْنِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Muhammad bin 'Ajlan] dari [Muhammad bin Yusuf] mantan budak 'Utsman dari Bapaknya - [Yusuf] - bahwasanya Mu'awiyah shalat di depannya, lalu Mu'awiyah berdiri yang seharusnya ia duduk, orang-orangpun mengucapkan 'subhanallah'. Maka Mu'awiyah menyempurnakan berdirinya kemudian dia sujud dua kali dalam keadaan duduk. selanjutnya [Mu'awiyah] naik mimbar dan berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa merasakan ada yang lupa dalam shalatnya, maka hendaklah dia bersujud sebagaimana sujud tadi.'"},"1235":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرٌو وَيُونُسُ وَاللَّيْثُ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ أَنَّ عَبْدَ اللَّهِ ابْنَ بُحَيْنَةَ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فِي الثِّنْتَيْنِ مِنْ الظُّهْرِ فَلَمْ يَجْلِسْ فَلَمَّا قَضَى صَلَاتَهُ سَجَدَ سَجْدَتَيْنِ كَبَّرَ فِي كُلِّ سَجْدَةٍ وَهُوَ جَالِسٌ قَبْلَ أَنْ يُسَلِّمَ وَسَجَدَهُمَا النَّاسُ مَعَهُ مَكَانَ مَا نَسِيَ مِنْ الْجُلُوسِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As Sarh] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku ['Amr] dan [Yunus] dan [Al Laits] bahwasanya [Ibnu Syihab] mengabarkan kepada mereka dari ['Abdurrahman Al A'raj] bahwasanya ['Abdullah bin Buhainah] berkata kepadanya bahwa Nabi Shallallallahu'alaihi wasallam pernah bangkit (berdiri) pada dua rakaat tanpa duduk (untuk tasyahud awal) saat zhuhur dan setelah selesai shalat beliau sujud dua kali sambil duduk dengan bertakbir pada setiap sujud tersebut sebelum salam. Orang-orangpun ikut sujud bersama dengannya sebagai ganti dari duduk yang lupa beliau lakukan."},"1236":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَمُحَمَّدُ بْنُ بَشَّارِ بُنْدَارٌ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ عَمْرِو بْنِ عَطَاءٍ عَنْ أَبِي حُمَيْدٍ السَّاعِدِيِّ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ فِي الرَّكْعَتَيْنِ اللَّتَيْنِ تَنْقَضِي فِيهِمَا الصَّلَاةُ أَخَّرَ رِجْلَهُ الْيُسْرَى وَقَعَدَ عَلَى شِقِّهِ مُتَوَرِّكًا ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad-Dauraqi] dan [Muhammad bin Basysyar Bundar] - dan lafadz ini baginya - mereka berdua berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami ['Abdul Hamid bin Ja'far] dia berkata; telah menceritakan kepada kami [Muhammad bin 'Amr bin 'Atha] dari [Abu Humaid As-Sa'idi] dia berkata; \"Nabi Shallallallahu'alaihi wasallam bila berada pada dua rakaat terakhir maka beliau mengakhirkan kaki kiri dan duduk tawaruk, kemudian salam.\" "},"1237":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ إِذَا افْتَتَحَ الصَّلَاةَ وَإِذَا رَكَعَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَإِذَا جَلَسَ أَضْجَعَ الْيُسْرَى وَنَصَبَ الْيُمْنَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَيَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى وَعَقَدَ ثِنْتَيْنِ الْوُسْطَى وَالْإِبْهَامَ وَأَشَارَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Kulaib] dari [Bapaknya] dari [Wa'il bin Hujr] dia berkata; \"Aku melihat Rasulullah Shalallah 'Alaihi Wa Sallam mengangkat kedua tangannya apabila hendak memulai shalat, hendak ruku' dan bangkit dari ruku' dan apabila beliau duduk, maka beliau menghamparkan kaki kiri dan menegakkan kaki kanan, meletakan tangan kanan diatas paha sebelah kanan dan tangan kiri di paha sebelah kiri dan melipat kedua jari tengah serta ibu jari, dengan mengisyaratkan telunjuknya."},"1238":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ الرَّقِّيُّ قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ يُوسُفَ الْفِرْيَابِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍأَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَلَسَ فِي الصَّلَاةِ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ ذِرَاعَيْهِ عَلَى فَخِذَيْهِ وَأَشَارَ بِالسَّبَّابَةِ يَدْعُو بِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Maimun Ar Riqqi] dia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf Al Firyabi] dia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Kulaib] dari [Bapaknya] dari [Wa'il bin Hujr] bahwa dia melihat Nabi Shallallallahu'alaihi wasallam duduk dalam shalat dengan menghamparkan kaki kiri dan meletakkan kedua lengannya diatas kedua pahannya, serta menunjuk dengan telunjuknya, beliau berdo'a dengannya."},"1239":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ أَنْبَأَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ عَنْ أَبِيهِ عَنْ وَائِلِ بْنِ حُجْرٍ قَالَ قُلْتُلَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَقْبَلَ الْقِبْلَةَ فَرَفَعَ يَدَيْهِ حَتَّى حَاذَتَا أُذُنَيْهِ ثُمَّ أَخَذَ شِمَالَهُ بِيَمِينِهِ فَلَمَّا أَرَادَ أَنْ يَرْكَعَ رَفَعَهُمَا مِثْلَ ذَلِكَ وَوَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ فَلَمَّا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ رَفَعَهُمَا مِثْلَ ذَلِكَ فَلَمَّا سَجَدَ وَضَعَ رَأْسَهُ بِذَلِكَ الْمَنْزِلِ مِنْ يَدَيْهِ ثُمَّ جَلَسَ فَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَحَدَّ مِرْفَقَهُ الْأَيْمَنَ عَلَى فَخِذِهِ الْيُمْنَى وَقَبَضَ ثِنْتَيْنِ وَحَلَّقَ وَرَأَيْتُهُ يَقُولُ هَكَذَا وَأَشَارَ بِشْرٌ بِالسَّبَّابَةِ مِنْ الْيُمْنَى وَحَلَّقَ الْإِبْهَامَ وَالْوُسْطَى","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah memberitakan kepada kami [Bisyr bin Al Mufadhdhal] dia berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dari [Bapaknya] dari [Wa'il bin Hujr] dia berkata; \"Sungguh Aku akan melihat bagaimana Rasulullah Shalallahu 'Alaihi Wa Sallam melaksanakan shalat. Beliau berdiri menghadap kiblat, lalu mengangkat kedua tangannya sejajar dengan kedua telinganya, kemudian memegang tangan kiri dengan tangan kanannya. Apabila hendak ruku beliau mengangkat kedua tangannya seperti hendak takbir. Ketika sujud, beliau meletakkan kepalanya sejajar dengan kedua tangannya. Kemudian beliau duduk dengan menghamparkan kaki kirinya, meletakkan tangan kiri di atas paha kiri, dan meletakkan siku lengan kanan diatas paha kanan. lalu beliau menggenggam kedua jari dan melingkarkannya. Aku melihat beliau berkata; 'Begini'. Bisyir mengisyaratkan dengan telunjuk kanannya dan melingkarkan ibu jari dan jari tengah."},"1240":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُسْلِمِ بْنِ أَبِي مَرْيَمَ شَيْخٌ مِنْ أَهْلِ الْمَدِينَةِ ثُمَّ لَقِيتُ الشَّيْخَ فَقَالَ سَمِعْتُ عَلِيَّ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُصَلَّيْتُ إِلَى جَنْبِ ابْنِ عُمَرَ فَقَلَّبْتُ الْحَصَى فَقَالَ لِي ابْنُ عُمَرَ لَا تُقَلِّبْ الْحَصَى فَإِنَّ تَقْلِيبَ الْحَصَى مِنْ الشَّيْطَانِ وَافْعَلْ كَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ قُلْتُ وَكَيْفَ رَأَيْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ قَالَ هَكَذَا وَنَصَبَ الْيُمْنَى وَأَضْجَعَ الْيُسْرَى وَوَضَعَ يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى وَيَدَهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَأَشَارَ بِالسَّبَّابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muslim bin Abu Maryam] -seorang Syaikh dari Madinah-, kemudian saya bertemu dengan syaikh, maka dia berkata; aku mendengar ['Ali bin 'Abdurrahman] berkata; aku shalat di belakang [Ibnu 'Umar] dan aku membalik-balikkan kerikil, lalu Ibnu Umar berkata kepadaku; \"Kenapa kamu membolak-balikkan kerikil, itu adalah perbuatan syaithan!. Lakukanlah sebagaimana yang telah aku lihat dari Rasulullah Shalallahu 'Alaihi Wa sallam. Aku berkata kepadanya; 'Bagaimana Rasulullah Shalallahu 'Alaihi Wasallam melakukannya? Ibnu Umar menjawab, begini; lalu dia menegakkan kaki kanan, dan menghamparkan kaki kiri, meletakkan tangan kanan diatas paha sebelah kanan dan tangan kiri di paha sebelah kiri dan mengisyaratkan dengan telunjuknya."},"1241":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ مُسْلِمِ بْنِ أَبِي مَرْيَمَ عَنْ عَلِيِّ بْنِ عَبْدِ الرَّحْمَنِ قَالَرَآنِي ابْنُ عُمَرَ وَأَنَا أَعْبَثُ بِالْحَصَى فِي الصَّلَاةِ فَلَمَّا انْصَرَفَ نَهَانِي وَقَالَ اصْنَعْ كَمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ قُلْتُ وَكَيْفَ كَانَ يَصْنَعُ قَالَ كَانَ إِذَا جَلَسَ فِي الصَّلَاةِ وَضَعَ كَفَّهُ الْيُمْنَى عَلَى فَخِذِهِ وَقَبَضَ يَعْنِي أَصَابِعَهُ كُلَّهَا وَأَشَارَ بِإِصْبَعِهِ الَّتِي تَلِي الْإِبْهَامَ وَوَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Muslim bin Abu Maryam] dari ['Ali bin 'Abdurrahman] dia berkata; \" [Ibnu Umar] melihatku sedang menggerak-gerakan kerikil saat beliau shalat. Setelah selesai shalat ia melarangku dengan berkata; 'Berbuatlah sebagaimana yang dilakukan Rasulullah Shalallah 'Alaihi Wa Sallam'. Aku berkata; 'Bagaimana Rasulullah Shalallah 'Alaihi Wa Sallam berbuat? ' Abdullah menjawab; 'Bila beliau duduk dalam shalat maka beliau meletakkan telapak tangan kanan diatas paha kanan dan menggenggam semua jari-jari, lalu berisyarat dengan jari telunjuk. Beliau juga meletakkan tangan kiri diatas paha kiri.\" "},"1242":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا عَاصِمُ بْنُ كُلَيْبٍ قَالَ حَدَّثَنِي أَبِي أَنَّ وَائِلَ بْنَ حُجْرٍ قَالَ قُلْتُلَأَنْظُرَنَّ إِلَى صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ يُصَلِّي فَنَظَرْتُ إِلَيْهِ فَوَصَفَ قَالَ ثُمَّ قَعَدَ وَافْتَرَشَ رِجْلَهُ الْيُسْرَى وَوَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخِذِهِ وَرُكْبَتِهِ الْيُسْرَى وَجَعَلَ حَدَّ مِرْفَقِهِ الْأَيْمَنِ عَلَى فَخِذِهِ الْيُمْنَى ثُمَّ قَبَضَ اثْنَتَيْنِ مِنْ أَصَابِعِهِ وَحَلَّقَ حَلْقَةً ثُمَّ رَفَعَ أُصْبُعَهُ فَرَأَيْتُهُ يُحَرِّكُهَا يَدْعُو بِهَا مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Zaidah] dia berkata; telah menceritakan kepada kami ['Ashim bin Kulaib] dia berkata; [bapakku] telah menceritakan kepadaku bahwasanya [Wa'il bin Hujr] berkata; \"Aku akan melihat cara shalat Rasulullah Shalallah 'Alaihi Wa Sallam. Kemudian aku melihat beliau Shallallallahu'alaihi wasallam shalat.\" -dia menyifatinya dengan berkata-; 'Beliau duduk diatas kaki kiri serta meletakkan telapak tangan kiri diatas paha dan lutut bagian kiri. Lalu beliau Shalallahu 'Alaihi Wa Sallam meletakkan siku lengan kanan diatas paha kanan, lalu menggenggam dua jari sehingga menjadi melingkar, kemudian beliau mengangkat telunjuknya, aku melihat beliau mengerak-gerakannya dan berdoa dengannya.\" (secara ringkas)."},"1243":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَلَسَ فِي الصَّلَاةِ وَضَعَ يَدَيْهِ عَلَى رُكْبَتَيْهِ وَرَفَعَ أُصْبُعَهُ الَّتِي تَلِي الْإِبْهَامَ فَدَعَا بِهَا وَيَدُهُ الْيُسْرَى عَلَى رُكْبَتِهِ بَاسِطُهَا عَلَيْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami ['Abdurrazzaq] dia berkata; telah memberitakan kepada kami [Ma'mar] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] bahwa apabila Rasulullah Shalallah 'Alaihi Wa Sallam duduk dalam shalat maka beliau meletakkan kedua tangan diatas lutut dan mengangkat jari telunjuk, lalu berdoa dengannya. Sedangkan tangan kiri dilututnya, dengan membentangkannya."},"1244":{"ar":"أَخْبَرَنَا أَيُّوبُ بْنُ مُحَمَّدٍ الْوَزَّانُ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي زِيَادٌ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُشِيرُ بِأُصْبُعِهِ إِذَا دَعَا وَلَا يُحَرِّكُهَاقَالَ ابْنُ جُرَيْجٍ وَزَادَ عَمْرٌو قَالَ أَخْبَرَنِي عَامِرُ بْنُ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو كَذَلِكَ وَيَتَحَامَلُ بِيَدِهِ الْيُسْرَى عَلَى رِجْلِهِ الْيُسْرَى","id":"Telah mengabarkan kepada kami [Ayyub bin Muhammad Al Wazzan] dia berkata; telah menceritakan kepada kami [Hajjaj], berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Ziyad] dari [Muhammad bin 'Ajlan] dari ['Amir bin 'Abdullah bin Az Zubair] dari ['Abdullah bin Az Zubair] bahwa Rasulullah shallallahu 'alaihi wasallam memberi isyarat dengan telunjuknya ketika berdo'a dan tidak menggerakkannya.\" [Ibnu Juraij] mengatakan; dan ['Amru] sedikit menambahkan, katanya; telah mengabarkan kepadaku ['Amir bin Abdullah bin Az Zubair] dari [Ayahnya] bahwa ia pernah melihat Nabi Shallallallahu'alaihi wasallam berdoa seperti itu juga dan meletakkan tangan kiri diatas kaki kirinya. "},"1245":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ الْمَوْصِلِيُّ عَنْ الْمُعَافَى عَنْ عِصَامِ بْنِ قُدَامَةَ عَنْ مَالِكٍ وَهُوَ ابْنُ نُمَيْرٍ الْخُزَاعِيُّ عَنْ أَبِيهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاضِعًا يَدَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى فِي الصَّلَاةِ وَيُشِيرُ بِأُصْبُعِهِ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Abdullah bin 'Ammar Al Maushili] dari [Al Mu'afa] dari ['Ashim bin Qudamah] dari [Malik bin Numair Al Khuza'i] dari [Bapaknya], dia berkata; \"Aku melihat Rasulullah Shalallah 'Alaihi Wa Sallam meletakkan tangan kanan diatas paha kanan dalam shalat, dan berisyarat dengan jarinya.\" "},"1246":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى قَالَ حَدَّثَنَا ابْنُ عَجْلَانَ عَنْ الْقَعْقَاعِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا كَانَ يَدْعُو بِأُصْبُعَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحِّدْ أَحِّدْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Shafwan bin 'Isa] dia berkata; telah menceritakan kepada kami [Ibnu 'Ajlan] dari [Al Qa'qa'] dari [Abu Shalih] dari [Abu Hurairah] bahwa ada seseorang yang berisyarat dengan dua jarinya, lalu Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"(Gunakan) satu jari, (gunakan) satu jari.\" "},"1247":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرِّمِيُّ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ سَعْدٍ قَالَمَرَّ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا أَدْعُو بِأَصَابِعِي فَقَالَ أَحِّدْ أَحِّدْ وَأَشَارَ بِالسَّبَّابَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak Al Mukharrimi] dia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Sa'ad] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam pernah melewatiku yang sedang berdoa dengan jari-jariku, lalu beliau Shallallallahu'alaihi wasallam bersabda: '(gunakan) satu jari, (gunakan) satu jari'. Beliau Shallallallahu'alaihi wasallam juga memberikan isyarat dengan jari telunjuk."},"1248":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى الصُّوفِيُّ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عِصَامُ بْنُ قُدَامَةَ الْجَدَلِيُّ قَالَ حَدَّثَنِي مَالِكُ بْنُ نُمَيْرٍ الْخُزَاعِيُّ مِنْ أَهْلِ الْبَصْرَةِ أَنَّ أَبَاهُ حَدَّثَهُأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدًا فِي الصَّلَاةِ وَاضِعًا ذِرَاعَهُ الْيُمْنَى عَلَى فَخِذِهِ الْيُمْنَى رَافِعًا أُصْبُعَهُ السَّبَّابَةَ قَدْ أَحْنَاهَا شَيْئًا وَهُوَ يَدْعُو","id":"Telah mengabarkan kepadaku [Ahmad bin Yahya Ash-Shufi] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dia berkata; telah menceritakan kepada kami ['Isham bin Qudamah Al Jadali] dia berkata; telah menceritakan kepadaku [Malik bin Numair Al Khuza'i] -dari penduduk Bashrah- bahwasanya [Bapaknya] menceritakan kepadanya, dia melihat Rasulullah Shalallah 'Alaihi Wa Sallam duduk dalam shalat dengan meletakan lengan kanannya di atas paha yang kanan, dan mengangkat telunjuknya dengan sedikit membengkokkannya sambil berdo'a.\""},"1249":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ ابْنِ عَجْلَانَ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا قَعَدَ فِي التَّشَهُّدِ وَضَعَ كَفَّهُ الْيُسْرَى عَلَى فَخِذِهِ الْيُسْرَى وَأَشَارَ بِالسَّبَّابَةِ لَا يُجَاوِزُ بَصَرُهُ إِشَارَتَهُ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari [Ibnu 'Ajlan] dari ['Amir bin 'Abdullah bin Az Zubair] dari [Bapaknya] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam apabila duduk saat tasyahud maka beliau meletakkan telapak tangan kiri diatas paha kiri serta menunjuk dengan jari telunjuknya, dan pandangannya tidak pernah melebihi telunjuknya."},"1250":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي اللَّيْثُ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيَنْتَهِيَنَّ أَقْوَامٌ عَنْ رَفْعِ أَبْصَارِهِمْ عِنْدَ الدُّعَاءِ فِي الصَّلَاةِ إِلَى السَّمَاءِ أَوْ لَتُخْطَفَنَّ أَبْصَارُهُمْ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amr bin As-Sarh] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Al Laits] dari [Ja'far bin Rabi'ah] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Berhentilah kaum-kaum itu dari mengangkat pandangan mereka keatas saat berdoa dalam shalat, atau pandangan mereka disambar.\""},"1251":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو عُبَيْدِ اللَّهِ الْمَخْزُومِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ وَمَنْصُورٌ عَنْ شَقِيقِ بْنِ سَلَمَةَ عَنْ ابْنِ مَسْعُودٍ قَالَكُنَّا نَقُولُ فِي الصَّلَاةِ قَبْلَ أَنْ يُفْرَضَ التَّشَهُّدُ السَّلَامُ عَلَى اللَّهِ السَّلَامُ عَلَى جِبْرِيلَ وَمِيكَائِيلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا هَكَذَا فَإِنَّ اللَّهَ عَزَّ وَجَلَّ هُوَ السَّلَامُ وَلَكِنْ قُولُوا التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Abdurrahman Abu 'Ubaidillah Al Makhzumi] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dan [Manshur] dari [Syaqiq bin Salamah] dari [Ibnu Mas'ud] dia berkata; \"Sebelum kami diwajibkan tasyahud, kami mengucapkan dalam shalat, 'Assalamu 'alallah, assalamu 'alaa Jibril, assalamu 'ala Mikail (keselamatan bagi Allah, keselamatan bagi Jibril, keselamatan bagi Mikail) '. Kemudian Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Janganlah kalian megucapkan hal itu, sesungguhnya Allah Azza wa Jalla adalah Assalam (Maha Pemberi Keselamatan). Ucapkanlah, \"At-tahiyatul lillahi wash-shalawatu wath-thayyibatu, as-salamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakatuh, as-salamu 'alaina wa 'ala 'ibadillahish-shalihin, asyhadu alla illaha illallah wa asyhadu anna muhammadan abduhu wa rasuluh (Penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan rahmat dan keberkahan terlimpahkan atasmu wahai Nabi, juga keselamatan surga terlimpahkan atas kami dari hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya).\" "},"1252":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدٍ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Humaid] dia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Thawus] dari [Ibnu 'Abbas] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam mengajarkan tasyahud kepada kami sebagaimana beliau mengajarkan surat Al Qur'an.\""},"1253":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا الْفُضَيْلُ وَهُوَ ابْنُ عِيَاضٍ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ هُوَ السَّلَامُ فَإِذَا قَعَدَ أَحَدُكُمْ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ لِيَتَخَيَّرْ بَعْدَ ذَلِكَ مِنْ الْكَلَامِ مَا شَاءَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Fudhail bin 'Iyadh] dari [Al A'masy] dari [Syaqiq] dari ['Abdullah] dia berkata; Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Allah Azza wa Jalla adalah As Salam (Maha Pemberi Keselamatan), jadi jika salah seorang dari kalian duduk maka ucapkan, \"At-tahiyatul lillahi wash-shalawatu wath-thayyibatu, as-salamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakatuh, as-salamu 'alaina wa 'ala 'ibadillahish-shalihin, asyhadu alla illaha illallah wa asyhadu anna muhammadan abduhu wa rasuluh (Penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan rahmat dan keberkahan terlimpahkan atasmu wahai Nabi, juga keselamatan surga terlimpahkan atas kami dari hamba-hamba Allah yang shaleh. Aku bersaksi bahwa tidak ada tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya) \" kemudian setelah itu ia boleh memilih doa yang dikehendaki. "},"1254":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ عَنْ قَتَادَةَ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ أَنَّ الْأَشْعَرِيَّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَنَا فَعَلَّمَنَا سُنَّتَنَا وَبَيَّنَ لَنَا صَلَاتَنَا فَقَالَ إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَأَقِيمُوا صُفُوفَكُمْ ثُمَّ لِيَؤُمَّكُمْ أَحَدُكُمْ فَإِذَا كَبَّرَ فَكَبِّرُوا وَإِذَا قَالَ وَلَا الضَّالِّينَ فَقُولُوا آمِينَ يُجِبْكُمْ اللَّهُ ثُمَّ إِذَا كَبَّرَ وَرَكَعَ فَكَبِّرُوا وَارْكَعُوا فَإِنَّ الْإِمَامَ يَرْكَعُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقُولُوا اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ قَالَ عَلَى لِسَانِ نَبِيِّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ إِذَا كَبَّرَ وَسَجَدَ فَكَبِّرُوا وَاسْجُدُوا فَإِنَّ الْإِمَامَ يَسْجُدُ قَبْلَكُمْ وَيَرْفَعُ قَبْلَكُمْ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتِلْكَ بِتِلْكَ وَإِذَا كَانَ عِنْدَ الْقَعْدَةِ فَلْيَكُنْ مِنْ قَوْلِ أَحَدِكُمْ أَنْ يَقُولَ التَّحِيَّاتُ الطَّيِّبَاتُ الصَّلَوَاتُ لِلَّهِ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] dari [Qatadah]. Dan (dari jalur periwayatan yang lain disebutkan;) Telah memberitakan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Hisyam] dia berkata; telah menceritakan kepada kami [Qatadah] dari [Yunus bin Jubair] dari [Hiththan bin 'Abdullah] bahwasanya [Al Asy'ari] berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam berkhutbah kepada kami dengan mengajarkan sunnah-sunnah dan menjelaskan cara shalat kami, beliau Shallallallahu'alaihi wasallam bersabda: \"Jika kalian hendak shalat, maka luruskan barisan kalian, kemudian salah seorang dari kalian menjadi imam. Bila ia (imam) bertakbir maka bertakbirlah kalian, dan bila ia mengucapkan, 'Waladl dlaalliin' maka ucapkan, 'Aamiin'. Jika imam takbir dan ruku', maka takbir dan rukulah kalian, sesungguhnya imam sujud sebelum kalian dan mengangkat (kepala dari sujud) sebelum kalian\"-lantas Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Gerakan-gerakan Imam itu harus kalian ikuti secara urut.\" -Jika ia mengucapkan, 'Sami'a Allahu liman hamidah (Allah mendengar orang yang memuji-Nya) ' maka ucapkan, 'Rabbana lakal hamdu (wahai Rabb kami segala puji untuk-Mu) ' sesungguhnya Allah berfirman melalui lisan Rasul-Nya, 'Allah maha mendengar orang yang memuji-Nya'. Kemudian jika imam takbir dan sujud maka takbir dan sujudlah, sesungguhnya imam sujud sebelum kalian dan mengangkat kepala dari sujud sebelum kalian.\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Itu dengan itu ' ('Gerakan-gerakan Imam itu harus kalian ikuti secara urut). Jika ia mengangkat (kepala dari sujud) maka angkatlah, dan jika ia dalam posisi duduk tahiyat maka ucapkan, \"At-tahiyatul lillahi wash-shalawatu wath-thayyibatu, as-salamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakatuh, as-salamu 'alaina wa 'ala 'ibadillahish-shalihin, asyhadu alla illaha illallah wa asyhadu anna muhammadan abduhu wa rasuluh (Penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan rahmat dan keberkahan terlimpahkan atasmu wahai Nabi, juga keselamatan surga terlimpahkan atas kami dari hamba-hamba Allah yang shaleh. Aku bersaksi bahwa tidak ada tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya) \" "},"1255":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا أَيْمَنُ ابْنُ نَابِلٍ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا التَّشَهُّدَ كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ بِسْمِ اللَّهِ وَبِاللَّهِ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَأَسْأَلُ اللَّهَ الْجَنَّةَ وَأَعُوذُ بِهِ مِنْ النَّارِقَالَ أَبُو عَبْد الرَّحْمَنِ لَا نَعْلَمُ أَحَدًا تَابَعَ أَيْمَنَ بْنَ نَابِلٍ عَلَى هَذِهِ الرِّوَايَةِ وَأَيْمَنُ عِنْدَنَا لَا بَأْسَ بِهِ وَالْحَدِيثُ خَطَأٌ وَبِاللَّهِ التَّوْفِيقُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Abu 'Ashim] dia berkata; telah menceritakan kepada kami [Aiman bin Nabil] dia berkata; telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir bin 'Abdullah] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam mengajari kami tasyahud sebagaimana mengajari kami surat dari Al Qur'an; \" Bismillah, wa billah \"At-tahiyatul lillahi wash-shalawatu wath-thayyibatu, as-salamu 'alaika ayyuhan-nabiyyu wa rahmatullahi wa barakatuh, as-salamu 'alaina wa 'ala 'ibadillahish-shalihin, asyhadu alla illaha illallah wa asyhadu anna muhammadan abduhu wa rasuluh, wa as alullahal jannata wa a'udzu bihi minannar. (Penghormatan, rahmat dan kebaikan hanya milik Allah. Semoga keselamatan rahmat dan keberkahan terlimpahkan atasmu wahai Nabi, juga keselamatan terlimpahkan atas kami dari hamba-hamba Allah yang shalih. Aku bersaksi bahwa tidak ada tuhan selain Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusan-Nya, dan saya meminta surge kepada Alalh dan berlindung kepada-Nya dari neraka) \" Abu Abdurrahman berkata; 'kami tidak mengetahui seorangpun yang mengikuti Aiman bin Nabil mengenai riwayat ini, menurut kami Aiman orangnya bisa dipertanggung jawabkan, Hadist ini salah. Hanya kepada Allah kita memohon taufiq."},"1256":{"ar":"أَخْبَرَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْحَكَمِ الْوَرَّاقُ قَالَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ سُفْيَانَ بْنِ سَعِيدٍ ح و أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ وَعَبْدُ الرَّزَّاقِ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ السَّائِبِ عَنْ زَاذَانَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِلَّهِ مَلَائِكَةً سَيَّاحِينَ فِي الْأَرْضِ يُبَلِّغُونِي مِنْ أُمَّتِي السَّلَامَ","id":"Telah mengabarkan kepada kami ['Abdul Wahhab bin 'Abdul Hakim Al Warraq] dia berkata; telah menceritakan kepada kami [Mu'adz bin Mu'adz] dari [Sufyan bin Sa'id]. -lewat jalur periwayatan lain- dan Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dan ['Abdurrazzaq] dari [Sufyan] dari ['Abdullah bin As Sa'ib] dari [Zadzan] dari ['Abdullah] dia berkata; Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Allah memiliki malaikat Sayyahiin (yang berkeliling) di bumi. Mereka menyampaikan salam dari umatku kepadaku.\""},"1257":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ الْكَوْسَجُ قَالَ أَنْبَأَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌ قَالَ قَدِمَ عَلَيْنَا سُلَيْمَانُ مَوْلَى الْحَسَنِ ابْنِ عَلِيٍّ زَمَنَ الْحَجَّاجِ فَحَدَّثَنَا عَنْ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ ذَاتَ يَوْمٍ وَالْبُشْرَى فِي وَجْهِهِ فَقُلْنَا إِنَّا لَنَرَى الْبُشْرَى فِي وَجْهِكَ فَقَالَ إِنَّهُ أَتَانِي الْمَلَكُ فَقَالَ يَا مُحَمَّدُ إِنَّ رَبَّكَ يَقُولُ أَمَا يُرْضِيكَ أَنَّهُ لَا يُصَلِّي عَلَيْكَ أَحَدٌ إِلَّا صَلَّيْتُ عَلَيْهِ عَشْرًا وَلَا يُسَلِّمُ عَلَيْكَ أَحَدٌ إِلَّا سَلَّمْتُ عَلَيْهِ عَشْرًا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur Al Kausaj] dia berkata; telah memberitakan kepada kami ['Affan] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami [Tsabit] dia berkata; datang kepada kami [Sulaiman] -mantan budak Al Hasan bin 'Ali pada masa Al Hajjaj-, maka dia menceritakan kepada kami dari ['Abdullah bin Abu Thalhah] dari [Bapaknya] bahwa pada suatu hari Rasulullah Shalallah 'Alaihi Wa Sallam datang dengan wajah yang berseri-seri, maka kami berkata kepadanya, \"Kami melihat wajahmu berseri-seri\". Kemudian beliau bersabda: \"Malaikat datang kepadaku, ia berkata kepadaku; 'Wahai Muhammad, Rabbmu berfirman, \"Tidaklah Allah menjadikanmu ridha kalau ada seseorang yang bershalawat kepadamu kecuali Aku juga bershalawat kepadanya sepuluh kali?. Tidak ada seorangpun yang menyampaikan salam kepadamu kecuali Aku juga menyampaikan salam kepadanya sepuluh kali.\" "},"1258":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ أَبِي هَانِئٍ أَنَّ أَبَا عَلِيٍّ الْجَنْبِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ فَضَالَةَ بْنَ عُبَيْدٍ يَقُولُسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يَدْعُو فِي صَلَاتِهِ لَمْ يُمَجِّدْ اللَّهَ وَلَمْ يُصَلِّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَجِلْتَ أَيُّهَا الْمُصَلِّي ثُمَّ عَلَّمَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَمِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي فَمَجَّدَ اللَّهَ وَحَمِدَهُ وَصَلَّى عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ادْعُ تُجَبْ وَسَلْ تُعْطَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Abu Hani'] bahwasanya [Abu 'Ali Al Janbi] menceritakan kepadanya bahwasanya dia mendengar [Fadhalah bin 'Ubaid] berkata; bahwa Rasulullah Shalallah 'Alaihi Wa Sallam mendengar seorang laki-laki berdoa usai shalat tanpa mengagungkan Allah tanpa bershalawat kepada Nabi Shallallahu'alaihi wasallam, maka Rasulullah Shalallah 'Alaihi Wa Sallam berkata kepadanya: wahai orang yang shalat 'kamu telah tergesa-gesa! kemudian mengajarkan mereka. Rasulullah Shalallah 'Alaihi Wa Sallam juga mendengar seseorang dalam doanya mengagungkan dan memuji Allah, serta bershalawat kepada Nabi Shallallahu'alaihi wasallam, maka Nabi Shallallallahu'alaihi wasallam lalu berkata: \"Berdoalah, maka kamu akan dikabulkan (doanya) dan mintalah, kamu akan diberi.\" "},"1259":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نُعَيْمِ بْنِ عَبْدِ اللَّهِ الْمُجْمِرِ أَنَّ مُحَمَّدَ بْنَ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَنْصَارِيَّ وَعَبْدُ اللَّهِ بْنُ زَيْدٍ الَّذِي أُرِيَ النِّدَاءَ بِالصَّلَاةِ أَخْبَرَهُ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ أَنَّهُ قَالَأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَجْلِسِ سَعْدِ بْنِ عُبَادَةَ فَقَالَ لَهُ بَشِيرُ بْنُ سَعْدٍ أَمَرَنَا اللَّهُ عَزَّ وَجَلَّ أَنْ نُصَلِّيَ عَلَيْكَ يَا رَسُولَ اللَّهِ فَكَيْفَ نُصَلِّ عَلَيْكَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى تَمَنَّيْنَا أَنَّهُ لَمْ يَسْأَلْهُ ثُمَّ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ فِي الْعَالَمِينَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَالسَّلَامُ كَمَا عَلِمْتُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] secara baca dan saya mendengarnya, lafadz ini darinya, dari [Ibnul Qasim] dia berkata; telah menceritakan kepadaku [Malik] dari [Nu'aim bin 'Abdullah Al Mujmir] bahwasanya [Muhammad bin 'Abdullah bin Zaid Al Anshari] dan 'Abdullah bin Zaid saat adzan dikumandangkan mengabarkan kepadanya dari [Abu Mas'ud Al Anshari] ia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam datang kepada kami di majelisnya Sa'd bin Ubadah, lalu Basyir bin Sa'ad berkata kepada beliau; 'Allah Azza wa Jalla memerintahkan kita untuk bershalawat kepadamu wahai Rasulullah Shalallah 'Alaihi Wa Sallam. Lantas bagaimanakah cara bershalawat kepadamu?\" Rasulullah Shalallah 'Alaihi Wa Sallam terdiam hingga kami menginginkan kalau saja tadi ia tidak bertanya kepadanya. Kemudian beliau Shallallallahu'alaihi wasallam bersabda: 'Ucapkanlah, \"ALLAHUMMA SHALLI 'ALA MUHAMMADIN WA'ALAA AALII MUHAMMAD, KAMAA SHALLAITA 'ALAA IBRAHIM. WABAARIK 'ALAA MUHAMMAD WA'ALAA AALI MUHAMMAD, KAMAA BARAKTA 'ALAA IBRAHIM FIL 'ALAMIINA INNAKA HAMIDUM-MAJIID (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim. Ya Allah, curahkanlah salam kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung). Lalu mengucapkan salam seperti yang engkau ketahui."},"1260":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ قَالَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بِشْرٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقِيلَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُمِرْنَا أَنْ نُصَلِّيَ عَلَيْكَ وَنُسَلِّمَ أَمَّا السَّلَامُ فَقَدْ عَرَفْنَاهُ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ","id":"Telah mengabarkan kepada kami [Ziyad bin Yahya] dia berkata; telah menceritakan kepada kami ['Abdul Wahhab bin 'Abdul Majid] dia berkata; telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad] dari ['Abdurrahman bin Bisyr] dari [Abu Mas'ud Al Anshari] dia berkata; \"Nabi Shallallallahu'alaihi wasallam pernah ditanya, 'Kami diperintahkan bershalawat dan mengucapkan salam kepadamu. Kami telah mengetahui cara mengucapkan salam, lalu bagaimana cara bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam bersabda: 'Ucapkanlah oleh kalian, \"ALLAHUMMA SHALLI 'ALA MUHAMMADIN, KAMA SHALLAITA 'ALAA IBRAHIM. WABAARIK 'ALAA MUHAMMAD, KAMA BARAKTA 'ALAA IBRAHIM (Ya Allah, curahkanlah kesejahteraan kepada Muhammad sebagaimana Engkau curahkan kesejahteraan kepada keluarga Ibrahim. Ya Allah, curahkanlah keberkahan kepada Muhammad sebagaiman Engkau curahkan keberkahan kepada keluarga Ibrahim).\" "},"1261":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ مِنْ كِتَابِهِ قَالَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَقُلْنَا يَا رَسُولَ اللَّهِ السَّلَامُ عَلَيْكَ قَدْ عَرَفْنَاهُ فَكَيْفَ الصَّلَاةُ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌقَالَ ابْنُ أَبِي لَيْلَى وَنَحْنُ نَقُولُ وَعَلَيْنَا مَعَهُمْ قَالَ أَبُو عَبْد الرَّحْمَنِ حَدَّثَنَا بِهِ مِنْ كِتَابِهِ وَهَذَا خَطَأٌ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria bin Dinar] dari bukunya dia berkata; telah menceritakan kepada kami [Husain bin 'Ali] dari [Zaidah] dari [Sulaiman] dari ['Amr bin Murrah] dari ['Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] dia berkata; \"Kami bertanya kepada Rasulullah Shalallah 'Alaihi Wa Sallam, 'Wahai Rasulullah, mengucapkan salam kepadamu telah kami ketahui, lalu bagaimana cara kami bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam menjawab: \"Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim. Wabaarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim fil 'alamiina innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim. Ya Allah, curahkanlah salam kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung). Ibnu Laila (perawi hadits) dan kami berkata; \"Dan curahkanlah kepada kami bersama mereka.\" Abu Abdurrahman berkata; 'Ia menceritakan kepada kami seperti ini dari bukunya, dan ini adalah salah.'"},"1262":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ سُلَيْمَانَ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَقُلْنَا يَا رَسُولَ اللَّهِ السَّلَامُ عَلَيْكَ قَدْ عَرَفْنَاهُ فَكَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌقَالَ عَبْدُ الرَّحْمَنِ وَنَحْنُ نَقُولُ وَعَلَيْنَا مَعَهُمْ قَالَ أَبُو عَبْد الرَّحْمَنِ وَهَذَا أَوْلَى بِالصَّوَابِ مِنْ الَّذِي قَبْلَهُ وَلَا نَعْلَمُ أَحَدًا قَالَ فِيهِ عَمْرُو بْنُ مُرَّةَ غَيْرَ هَذَا وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria] dia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Sulaiman] dari [Al Hakim] dari ['Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] dia berkata; \"Kami bertanya kepada Rasulullah Shalallah 'Alaihi Wa Sallam, 'Wahai Rasulullah, mengucapkan salam kepadamu telah kami ketahui, lalu bagaimana cara kami bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam menjawab: \"Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim wa 'alaa aalii Ibrahim. Innaka hamiidun-majiid. Wabaarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim wa 'alaa aalii Ibrahim innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada Ibrahim dan keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung. Ya Allah, curahkanlah salam kepada kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada Ibrahim dan keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\" Abdurrahman (perawi hadits ini) berkata; \"Kami berkata; 'Kami bersama mereka.\" Abu Abdurrahman berkata; 'Hadist ini lebih terpercaya kebenarannya, dibanding hadist sebelumnya. Dan tidak kami ketahui seorangpun yang meriwayatkan perkataan Amr bin Murrah selain Hadist ini. Wallahu Ta'ala A'lam.'"},"1263":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ عَنْ شُعْبَةَ عَنْ الْحَكَمِ عَنْ ابْنِ أَبِي لَيْلَى قَالَ قَالَ لِي كَعْبُ بْنُ عُجْرَةَأَلَا أُهْدِي لَكَ هَدِيَّةً قُلْنَا يَا رَسُولَ اللَّهِ قَدْ عَرَفْنَا كَيْفَ السَّلَامُ عَلَيْكَ فَكَيْفَ نُصَلِّي عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ اللَّهُمَّ بَارِكْ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah] dari [Syu'bah] dari [Al Hakim] dari [Ibnu Abu Laila] dia berkata; [Ka'b bin 'Ujrah] berkata kepadaku; bahwa Rasulullah Shalallah 'Alaihi Wa Sallam bersabda kepadaku; Maukah saya beri hadiah? ' Kami menjawab; 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, mengucapkan salam kepadamu telah kami ketahui, lalu bagaimana cara kami bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam menjawab: 'Ucapkanlah, \"Allahumma shalli 'ala Muhammadin wa aalii Muhammad, kamaa shallaita 'alaa aalii Ibrahim innaka hamidum-majid. Allahumma baarik 'alaa Muhammad wa aali Muhammad, kamaa barakta 'alaa aalii Ibrahim innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung. Ya Allah, curahkanlah salam kepada kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\""},"1264":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ بِشْرٍ قَالَ حَدَّثَنَا مُجَمِّعُ بْنُ يَحْيَى عَنْ عُثْمَانَ بْنِ مَوْهَبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِ قَالَقُلْنَا يَا رَسُولَ اللَّهِ كَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ وَآلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Muhammad bin Bisyr] dia berkata; telah menceritakan kepada kami [Mujammi' bin Yahya] dari ['Utsman bin Mauhab] dari [Musa bin Thalhah] dari [Bapaknya], dia berkata; \"Kami berkata; 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, bagaimana cara kami bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam menjawab: 'Ucapkanlah, \"Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim wa 'alaa aalii Ibrahim. Innaka hamidum-majiid. Wabaarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim wa 'alaa aalii Ibrahim innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada Ibrahim dan keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung. Ya Allah, curahkanlah salam kepada kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada Ibrahim dan keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\""},"1265":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا شَرِيكٌ عَنْ عُثْمَانَ بْنِ مَوْهَبٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِيهِأَنَّ رَجُلًا أَتَى نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَيْفَ نُصَلِّي عَلَيْكَ يَا نَبِيَّ اللَّهِ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ وَبَارِكْ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd] dia berkata; [pamanku] telah menceritakan kepadaku, dia berkata; telah menceritakan kepada kami [Syarik] dari ['Utsman bin Mauhab] dari [Musa bin Thalhah] dari [Bapaknya] bahwa ada seorang laki-laki yang datang kepada Nabi Shallallallahu'alaihi wasallam lalu bertanya kepada beliau; \"Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, bagaimana cara kami bershalawat kepadamu? ' Beliau Shallallallahu'alaihi wasallam menjawab: 'Ucapkanlah, \"Allahumma shalli 'ala Muhammadin wa'alaa aalii Muhammad, kamaa shallaita 'alaa Ibrahim Innaka hamidum-majiid. Wabaarik 'alaa Muhammad wa'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim innaka hamidum-majiid (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad sebagaimana Engkau curahkan kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung. Ya Allah, curahkanlah salam kepada kepada Muhammad dan keluarga Muhammad, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\""},"1266":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ يَحْيَى بْنِ سَعِيدٍ الْأُمَوِيُّ فِي حَدِيثِهِ عَنْ أَبِيهِ عَنْ عُثْمَانَ بْنِ حَكِيمٍ عَنْ خَالِدِ بْنِ سَلَمَةَ عَنْ مُوسَى بْنِ طَلْحَةَ قَالَ سَأَلْتُ زَيْدَ بْنَ خَارِجَةَ قَالَأَنَا سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ صَلُّوا عَلَيَّ وَاجْتَهِدُوا فِي الدُّعَاءِ وَقُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَعَلَى آلِ مُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin Yahya bin Sa'id Al Umawi] dalam haditsnya dari [Bapaknya] dari ['Utsman bin Hakim] dari [Khalid bin Salamah] dari [Musa bin Thalhah] dia berkata; aku bertanya kepada [Zaid bin Kharijah] lalu dia menjawab; \"Aku bertanya kepada Rasulullah Shalallah 'Alaihi Wa Sallam, maka beliau bersabda: \"Bershalawatlah kepada Rasulullah Shalallah 'Alaihi Wa Sallam, sungguhlah dalam berdoa, lalu ucapkanlah, 'ALLAHUMMA SHALLI 'ALA MUHAMMADIN WA'ALAA AALII MUHAMMAD' (Ya Allah, curahkanlah kesejahteraan kepada Muhammad dan keluarga Muhammad).\""},"1267":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ وَهُوَ ابْنُ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ خَبَّابٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقُلْنَا يَا رَسُولَ اللَّهِ السَّلَامُ عَلَيْكَ قَدْ عَرَفْنَاهُ فَكَيْفَ الصَّلَاةُ عَلَيْكَ قَالَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ عَبْدِكَ وَرَسُولِكَ كَمَا صَلَّيْتَ عَلَى إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَآلِ مُحَمَّدٍ كَمَا بَارَكْتَ عَلَى إِبْرَاهِيمَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr bin Mudhar] dari [Ibnul Had] dari ['Abdullah bin Khabbab] dari [Abu Sa'id Al Khudri] dia berkata; \"Kami bertanya kepada Rasulullah Shalallah 'Alaihi Wa Sallam, 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, kami telah mengetahui cara mengucapkan salam kepada engkau, lalu bagaimana cara bershalawat kepadamu? ' Lalu beliau Shallallallahu'alaihi wasallam bersabda: 'Ucapkanlah oleh kalian, \"Allahumma shalli 'alaa Muhammadin 'abdika wa rasulika, kamaa shallaita 'alaa Ibrahim. Wa barik 'alaa Muhammad wa 'alaa aali Muhammad, kamaa barakta 'alaa Ibrahim (Ya Allah, curahkanlah kesejahteraan kepada Muhammad, hamba dan Rasul-Mu, sebagaimana telah Engkau curahkan kesejahteraan kepada Ibrahim. Ya Allah, curahkanlah salam kepada Muhammad dan keluarganya, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim) \". "},"1268":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ قَالَ أَخْبَرَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّأَنَّهُمْ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ نُصَلِّي عَلَيْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُولُوا اللَّهُمَّ صَلِّ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ فِي حَدِيثِ الْحَارِثِ كَمَا صَلَّيْتَ عَلَى آلِ إِبْرَاهِيمَ وَبَارِكْ عَلَى مُحَمَّدٍ وَأَزْوَاجِهِ وَذُرِّيَّتِهِ قَالَا جَمِيعًا كَمَا بَارَكْتَ عَلَى آلِ إِبْرَاهِيمَ إِنَّكَ حَمِيدٌ مَجِيدٌقَالَ أَبُو عَبْد الرَّحْمَنِ أَنْبَأَنَا قُتَيْبَةُ بِهَذَا الْحَدِيثِ مَرَّتَيْنِ وَلَعَلَّهُ أَنْ يَكُونَ قَدْ سَقَطَ عَلَيْهِ مِنْهُ شَطْرٌ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dan [Al Harits bin Miskin] secara baca dan saya mendengarnya dari [Ibnul Qasim] telah menceritakan kepada kami [Malik] dari ['Abdullah bin Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Bapaknya] dari ['Amr bin Sulaim Az Zuraqi] dia berkata; telah mengabarkan kepadaku [Abu Humaid As Sa'idi] bahwasanya mereka berkata; \"Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, bagaimanakah cara kami bershalawat kepadamu?\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Ucapkanlah oleh kalian, 'Allahumma shalli 'alaa Muhammadin waazwajihi wa dzurriyyatihi, kamaa shallaita 'alaa aali Ibrahim. Wabarik 'alaa Muhammad wa azwajihi wa dzurriyyatihi, kamaa baarakta 'alaa Ibrahim innaka hamiidun-majid (Ya Allah, turunkanlah kesejahteraan kepada Muhammad dan istri-istrinya dan keturunannya, sebagaimana Engkau curahkan kesejahteraan kepada keluarga Ibrahim. Ya Allah, curahkanlah salam kepada Muhammad dan istri-istrinya serta keturunannya, sebagaimana Engkau curahkan salam kepada keluarga Ibrahim. Sesungguhnya Engkau Maha Terpuji Lagi Maha Agung).\" Abu Abdurrahman berkata; 'Qutaibah memberitahuku hadits ini dua kali, mungkin ada bagian yang hilang darinya.' "},"1269":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ يَعْنِي ابْنَ الْمُبَارَكِ قَالَ أَنْبَأَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ سُلَيْمَانَ مَوْلَى الْحَسَنِ بْنِ عَلِيٍّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ ذَاتَ يَوْمٍ وَالْبِشْرُ يُرَى فِي وَجْهِهِ فَقَالَ إِنَّهُ جَاءَنِي جِبْرِيلُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَا يُرْضِيكَ يَا مُحَمَّدُ أَنْ لَا يُصَلِّيَ عَلَيْكَ أَحَدٌ مِنْ أُمَّتِكَ إِلَّا صَلَّيْتُ عَلَيْهِ عَشْرًا وَلَا يُسَلِّمَ عَلَيْكَ أَحَدٌ مِنْ أُمَّتِكَ إِلَّا سَلَّمْتُ عَلَيْهِ عَشْرًا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah menceritakan kepada kami ['Abdullah bin Al Mubarak] dia berkata; telah memberitakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Sulaiman] budak Al Hasan bin 'Ali, dari ['Abdullah bin Abu Thalhah] dari [Bapaknya] bahwa pada suatu hari Rasulullah Shalallah 'Alaihi Wa Sallam datang dengan wajah berseri-seri. Kemudian beliau bersabda: \"Telah datang kepadaku malaikat Jibril, ia berkata kepadaku, \"Wahai Muhammad, tidakkah kamu ridha seseorang bershalawat kepadamu kecuali Aku juga bershalawat kepadanya sepuluh kali. Juga tidak ada lagi seorangpun yang mengucapkan salam kepadamu kecuali Aku juga mengucapkan salam kepadanya sepuluh kali.\" "},"1270":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَيَّ وَاحِدَةً صَلَّى اللَّهُ عَلَيْهِ عَشْرًا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Al 'Alaa] dari [Bapaknya] dari [Abu Hurairah] dari Nabi Shallallahu'alaihi wasallam, beliau bersabda: \"Barangsiapa bershalawat kepadaku satu kali, maka Allah akan mengucapkan shalawat kepadanya sepuluh kali.\""},"1271":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ بُرَيْدِ بْنِ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا أَنَسُ بْنُ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى عَلَيَّ صَلَاةً وَاحِدَةً صَلَّى اللَّهُ عَلَيْهِ عَشْرَ صَلَوَاتٍ وَحُطَّتْ عَنْهُ عَشْرُ خَطِيئَاتٍ وَرُفِعَتْ لَهُ عَشْرُ دَرَجَاتٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Muhammad bin Yusuf] dia berkata; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [Buraid bin Abu Maryam] dia berkata; telah menceritakan kepada kami [Anas bin Malik] dia berkata; Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Barangsiapa bershalawat kepadaku satu kali, maka Allah akan mengucapkan shalawat kepadanya sepuluh kali, dihapuskan darinya sepuluh kesalahan, dan ia diangkat sepuluh derajat untuknya.\""},"1272":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ وَعَمْرُو بْنُ عَلِيٍّ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُلَيْمَانُ الْأَعْمَشُ قَالَ حَدَّثَنِي شَقِيقٌ عَنْ عَبْدِ اللَّهِ قَالَكُنَّا إِذَا جَلَسْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الصَّلَاةِ قُلْنَا السَّلَامُ عَلَى اللَّهِ مِنْ عِبَادِهِ السَّلَامُ عَلَى فُلَانٍ وَفُلَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُولُوا السَّلَامُ عَلَى اللَّهِ فَإِنَّ اللَّهَ هُوَ السَّلَامُ وَلَكِنْ إِذَا جَلَسَ أَحَدُكُمْ فَلْيَقُلْ التَّحِيَّاتُ لِلَّهِ وَالصَّلَوَاتُ وَالطَّيِّبَاتُ السَّلَامُ عَلَيْكَ أَيُّهَا النَّبِيُّ وَرَحْمَةُ اللَّهِ وَبَرَكَاتُهُ السَّلَامُ عَلَيْنَا وَعَلَى عِبَادِ اللَّهِ الصَّالِحِينَ فَإِنَّكُمْ إِذَا قُلْتُمْ ذَلِكَ أَصَابَتْ كُلَّ عَبْدٍ صَالِحٍ فِي السَّمَاءِ وَالْأَرْضِ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ لِيَتَخَيَّرْ مِنْ الدُّعَاءِ بَعْدُ أَعْجَبَهُ إِلَيْهِ يَدْعُو بِهِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim Ad Dauraqi] dan ['Amru bin 'Ali] dan lafadz ini baginya, mereka berdua berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sulaiman Al A'masy] dia berkata; telah menceritakan kepada kami [Syaqiq] dari ['Abdullah] dia berkata; \"Jika kami duduk (tasyahud) bersama Rasulullah Shalallah 'Alaihi Wa Sallam dalam shalat, maka kami berkata; 'As-salamu 'alallaahi min 'ibaadihi, as-salaamu 'alaa fulan wa fulan (keselamatan bagi Allah dan hamba-Nya dan keselamatan bagi fulan dan fulan) '. Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Janganlah kalian berkata, \"As-salaamu 'alallah (semoga keselamatan atas Allah) karena Allah Azza wa Jalla adalah As-salam (Maha Pemberi Keselamatan), tetapi jika salah seorang dari kalian duduk maka ucapkanlah, \"At-tahiyyatu lillahi wash-shalawatu wa rahmatullahi wa barakatuh, as-salamu 'alainaa wa 'ala 'ibadillahish-shalihiin, - karena jika kalian mengucapkan demikian maka telah mengenai semua hamba shaleh yang ada di langit dan di bumi- asyhadu allaa ilaaha illallaah wa asyhadu anna Muhammadan abduhu wa rasuluh.\" Kemudian hendaklah memilih doa yang dia senangi dan berdoa dengannya.\" "},"1273":{"ar":"أَخْبَرَنَا عُبَيْدُ بْنُ وَكِيعِ بْنِ الْجَرَّاحِ أَخُو سُفْيَانَ بْنِ وَكِيعٍ قَالَ حَدَّثَنَا أَبِي عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَتْ أُمُّ سُلَيْمٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ عَلِّمْنِي كَلِمَاتٍ أَدْعُو بِهِنَّ فِي صَلَاتِي قَالَ سَبِّحِي اللَّهَ عَشْرًا وَاحْمَدِيهِ عَشْرًا وَكَبِّرِيهِ عَشْرًا ثُمَّ سَلِيهِ حَاجَتَكِ يَقُلْ نَعَمْ نَعَمْ","id":"Telah mengabarkan kepada kami ['Ubaid bin Waki' bin Al Jarrah] saudara Sufyan bin Waki', dia berkata; [bapakku] telah menceritakan kepada kami, dari ['Ikrimah bin 'Ammar] dari [Ishaq bin 'Abdullah bin Abu Thalhah] dari [Anas bin Malik] dia berkata; \"Ummu Sulaim datang kepada Nabi Shallallahu'alaihi wasallam, lalu berkata; 'Wahai Rasulullah Shalallah 'Alaihi Wa Sallam, ajari aku beberapa kalimat yang digunakan untuk berdoa saat shalat'. Beliau Shallallallahu'alaihi wasallam bersabda: 'Bertasbih (mengucapkan subhanallah) sepuluh kali, bertahmid (mengucapkan alhamdulillah) sepuluh kali, dan bertakbir (mengucapkan allahu akbar) sepuluh kali. Kemudian mintalah keperluanmu, maka Dia (Allah) akan berkata: 'Ya, ya\". "},"1274":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا خَلَفُ بْنُ خَلِيفَةَ عَنْ حَفْصِ بْنِ أَخِي أَنَسٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا يَعْنِي وَرَجُلٌ قَائِمٌ يُصَلِّي فَلَمَّا رَكَعَ وَسَجَدَ وَتَشَهَّدَ دَعَا فَقَالَ فِي دُعَائِهِ اللَّهُمَّ إِنِّي أَسْأَلُكَ بِأَنَّ لَكَ الْحَمْدَ لَا إِلَهَ إِلَّا أَنْتَ الْمَنَّانُ بَدِيعُ السَّمَاوَاتِ وَالْأَرْضِ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ يَا حَيُّ يَا قَيُّومُ إِنِّي أَسْأَلُكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَصْحَابِهِ تَدْرُونَ بِمَا دَعَا قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ دَعَا اللَّهَ بِاسْمِهِ الْعَظِيمِ الَّذِي إِذَا دُعِيَ بِهِ أَجَابَ وَإِذَا سُئِلَ بِهِ أَعْطَى","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Khalaf bin Khalifah] dari [Hafsh] keponakan Anas, dari [Anas bin Malik] dia berkata; \"Aku pernah duduk-duduk bersama Rasulullah Shalallah 'Alaihi Wa Sallam, dan ada seorang laki-laki yang sedang shalat. seusai ruku', sujud dan tasyahud ia lalu berdo'a. Ia memanjatkan doanya dengan mengucapkan; 'Ya Allah, aku meminta kepada-Mu dengan segala pujian bagi-Mu, tiada Dzat yang berhak disembah kecuali engkau, Dzat yang maha pemberi karunia dan pencipta langit serta bumi. Wahai Dzat pemilik keagungan dan kemuliaan. Wahai Dzat yang Maha Hidup lagi Maha Berdiri Sendiri, aku meminta kepada-Mu.\" Lalu Nabi shallallahu 'alaihi wasallam bersabda kepada para sahabatnya: 'Apakah kalian tahu dengan apa ia memanjatkan doanya? ' Mereka menjawab, 'Allah dan Rasul-Nya yang lebih mengetahui'. Lalu beliau bersabda: \"Demi Dzat yang jiwaku ada ditangan-Nya, ia memanjatkan doanya kepada Allah dengan menggunakan nama-Nya yang agung. Bila ada yang berdoa dengan nama tersebut, Allah mengabulkan dan jika ada yang meminta sesuatu dengan nama itu, Dia memberi.\" "},"1275":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَزِيدَ أَبُو بُرَيْدٍ الْبَصْرِيُّ عَنْ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ عَنْ ابْنِ بُرَيْدَةَ قَالَ حَدَّثَنِي حَنْظَلَةُ بْنُ عَلِيٍّ أَنَّ مِحْجَنَ بْنَ الْأَدْرَعِ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ الْمَسْجِدَ إِذَا رَجُلٌ قَدْ قَضَى صَلَاتَهُ وَهُوَ يَتَشَهَّدُ فَقَالَ اللَّهُمَّ إِنِّي أَسْأَلُكَ يَا أَللَّهُ بِأَنَّكَ الْوَاحِدُ الْأَحَدُ الصَّمَدُ الَّذِي لَمْ يَلِدْ وَلَمْ يُولَدْ وَلَمْ يَكُنْ لَهُ كُفُوًا أَحَدٌ أَنْ تَغْفِرَ لِي ذُنُوبِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ غُفِرَ لَهُ ثَلَاثًا","id":"Telah mengabarkan kepada kami ['Amr bin Yazid Abu Buraid Al Bashri] dari ['Abdush Shamad bin 'Abdul Warits] dia berkata; [bapakku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Husain Al Mu'allim] dari [Ibnu Buraidah] dia berkata; telah menceritakan kepada kami [Hanzhalah bin 'Ali] bahwasanya [Mahjan bin Al Adra'] menceritakan kepadanya; Rasulullah Shalallah 'Alaihi Wa Sallam masuk masjid, dan ternyata ada seorang yang sedang menyelesaikan shalatnya sambil berdoa dalam tasyahudnya, \"Ya Allah, aku memohon kepada-Mu dengan keberadaan-Mu Yang Maha Esa, Tunggal dan sebagai tempat bergantung, yang tidak melahirkan dan tidak dilahirkan, serta tidak ada bandingannya. Ampunilah dosa-dosaku. Sesungguhnya Engkau Maha Pengampun lagi Maha Penyayang.\" Rasulullah Shalallah 'Alaihi Wa Sallam lalu bersabda: \"Dia telah diampuni\". Beliau Shallallallahu'alaihi wasallam mengulanginya tiga kali."},"1276":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ أَبِي بَكْرٍ الصِّدِّيقِ رَضِيَ اللَّهُ عَنْهُمَاأَنَّهُ قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِّمْنِي دُعَاءً أَدْعُو بِهِ فِي صَلَاتِي قَالَ قُلْ اللَّهُمَّ إِنِّي ظَلَمْتُ نَفْسِي ظُلْمًا كَثِيرًا وَلَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ فَاغْفِرْ لِي مَغْفِرَةً مِنْ عِنْدِكَ وَارْحَمْنِي إِنَّكَ أَنْتَ الْغَفُورُ الرَّحِيمُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abul Khair] dari ['Abdullah bin 'Amr] dari [Abu Bakar Ash Shiddiq] radliallahu 'anhu bahwa ia pernah berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Ajari aku suatu doa yang dapat aku panjatkan dalam shalatku.\" Beliau Shallallallahu'alaihi wasallam bersabda: \"Ucapkanlah, Ya Allah, aku telah berbuat aniaya kepada diriku sendiri dengan aniaya yang besar, dan tidak ada yang mengampuni dosa-dosa selain Engkau, ampunilah aku dengan ampunan dari sisi-Mu, serta kasihinilah aku. Sesungguhnya Engkau Maha Pengampun lagi Maha Penyayang.\" "},"1277":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ حَيْوَةَ يُحَدِّثُ عَنْ عُقْبَةَ بْنِ مُسْلِمٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْحُبُلِيِّ عَنْ الصُّنَابِحِيِّ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَأَخَذَ بِيَدِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي لَأُحِبُّكَ يَا مُعَاذُ فَقُلْتُ وَأَنَا أُحِبُّكَ يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا تَدَعْ أَنْ تَقُولَ فِي كُلِّ صَلَاةٍ رَبِّ أَعِنِّي عَلَى ذِكْرِكَ وَشُكْرِكَ وَحُسْنِ عِبَادَتِكَ","id":"Telah mengabarkan kepada kami [Yunus bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; aku mendengar [Haiwah] menceritakan dari ['Uqbah bin Muslim] dari [Abu 'Abdurrahman Al Hubuli] dari [Ash Shunabihi] dari [Mu'adz bin Jabal] dia berkata; \"Rasulullah Shalallah 'Alaihi Wa Sallam memegang tanganku sambil berkata kepadaku: \"Aku mencintaimu wahai Mu'adz!\" Lalu aku juga berkata: 'Aku juga mencintai Engkau wahai Rasulullah Shalallah 'Alaihi Wa Sallam! ' Lalu beliau Shallallallahu'alaihi wasallam bersabda: 'Janganlah kau meninggalkan bacaan berikut ini setelah usai shalat.\"Ya Allah, bantulah aku untuk ingat dan bersyukur kepada-Mu, serta beribadah kepada-Mu dengan baik.\" "},"1278":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ أَبِي الْعَلَاءِ عَنْ شَدَّادِ بْنِ أَوْسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي صَلَاتِهِ اللَّهُمَّ إِنِّي أَسْأَلُكَ الثَّبَاتَ فِي الْأَمْرِ وَالْعَزِيمَةَ عَلَى الرُّشْدِ وَأَسْأَلُكَ شُكْرَ نِعْمَتِكَ وَحُسْنَ عِبَادَتِكَ وَأَسْأَلُكَ قَلْبًا سَلِيمًا وَلِسَانًا صَادِقًا وَأَسْأَلُكَ مِنْ خَيْرِ مَا تَعْلَمُ وَأَعُوذُ بِكَ مِنْ شَرِّ مَا تَعْلَمُ وَأَسْتَغْفِرُكَ لِمَا تَعْلَمُ","id":"Telah mengabarkan kepada kami [Abu Dawud] dia berkata; telah menceritakan kepada kami [Sulaiman bin Harb] dia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Sa'id Al Jurairi] dari [Abul 'Alaa] dari [Syaddad bin Aus] bahwa Rasulullah Shalallahu 'Alaihi Wasallam didalam shalatnya berdoa: \"Ya Allah, aku memohon keteguhan dalam menghadapi semua urusan, dan tekad yang kuat dalam mencari kebenaran, aku memohon kepada-Mu untuk senantiasa mensyukuri nikmat-Mu, aku memohon kepada-Mu hati yang selamat, lisan yang senantiasa jujur, aku memohon kepada-Mu dari kebaikan yang engkau ketahui dan aku berlindung kepada-Mu dari kejelekan yang engkau ketahui, aku memohon ampun-Mu terhadap segala kesalahan yang engkau ketahui."},"1279":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبيٍّ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِيهِ قَالَصَلَّى بِنَا عَمَّارُ بْنُ يَاسِرٍ صَلَاةً فَأَوْجَزَ فِيهَا فَقَالَ لَهُ بَعْضُ الْقَوْمِ لَقَدْ خَفَّفْتَ أَوْ أَوْجَزْتَ الصَّلَاةَ فَقَالَ أَمَّا عَلَى ذَلِكَ فَقَدْ دَعَوْتُ فِيهَا بِدَعَوَاتٍ سَمِعْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا قَامَ تَبِعَهُ رَجُلٌ مِنْ الْقَوْمِ هُوَ أُبَيٌّ غَيْرَ أَنَّهُ كَنَى عَنْ نَفْسِهِ فَسَأَلَهُ عَنْ الدُّعَاءِ ثُمَّ جَاءَ فَأَخْبَرَ بِهِ الْقَوْمَ اللَّهُمَّ بِعِلْمِكَ الْغَيْبَ وَقُدْرَتِكَ عَلَى الْخَلْقِ أَحْيِنِي مَا عَلِمْتَ الْحَيَاةَ خَيْرًا لِي وَتَوَفَّنِي إِذَا عَلِمْتَ الْوَفَاةَ خَيْرًا لِي اللَّهُمَّ وَأَسْأَلُكَ خَشْيَتَكَ فِي الْغَيْبِ وَالشَّهَادَةِ وَأَسْأَلُكَ كَلِمَةَ الْحَقِّ فِي الرِّضَا وَالْغَضَبِ وَأَسْأَلُكَ الْقَصْدَ فِي الْفَقْرِ وَالْغِنَى وَأَسْأَلُكَ نَعِيمًا لَا يَنْفَدُ وَأَسْأَلُكَ قُرَّةَ عَيْنٍ لَا تَنْقَطِعُ وَأَسْأَلُكَ الرِّضَاءَ بَعْدَ الْقَضَاءِ وَأَسْأَلُكَ بَرْدَ الْعَيْشِ بَعْدَ الْمَوْتِ وَأَسْأَلُكَ لَذَّةَ النَّظَرِ إِلَى وَجْهِكَ وَالشَّوْقَ إِلَى لِقَائِكَ فِي غَيْرِ ضَرَّاءَ مُضِرَّةٍ وَلَا فِتْنَةٍ مُضِلَّةٍ اللَّهُمَّ زَيِّنَّا بِزِينَةِ الْإِيمَانِ وَاجْعَلْنَا هُدَاةً مُهْتَدِينَ","id":"Telah mengabarkan kepada kami [Yahya bin Hubaib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami ['Atha bin As Saib] dari [Bapaknya], dia berkata; \" [Ammar bin Yasir] pernah shalat bersama (mengimami) kami, dan ia mempersingkat shalatnya. Lalu sebagian orang bertanya kepadanya, 'Engkau telah meringankan -mempersingkat- shalat? ' Ia menjawab, 'Dalam shalat tadi aku memanjatkan doa dengan doa yang kudengar dari Rasulullah Shalallah 'Alaihi Wa Sallam.' Lalu ia bangkit dan diikuti oleh seseorang -dia adalah Ubay, tetapi ia menyamarkan dirinya- lalu ia bertanya kepadanya tentang doa. Kemudian ia datang dan memberitahukan doa tersebut kepada kaumnya, 'Ya Allah dengan ilmu-Mu terhadap hal gaib dan kekuasaan-Mu atas makhluk, hidupkanlah aku selagi Engkau mengetahui bahwa hidup itu lebih baik bagiku, dan matikanlah aku jika Engkau mengetahui bahwa mati lebih baik bagiku. Ya Allah, aku memohon kepada-Mu rasa takut kepada-Mu saat nampak ataupun saat tidak nampak. Aku memohon kesederhanaan saat fakir dan kaya. Aku memohon kenikmatan tanpa habis dan kesenangan tanpa henti. Aku memohon keridhaan setelah adanya keputusan, dan kenyamanan hidup setelah mati dan kelezatan memandang kepada wajah-Mu serta keridhaan berjumpa dengan-Mu tanpa ada bahaya yang membahayakan dan tanpa fitnah yang menyesatkan. Ya Allah, hiasilah kami dengan hiasan iman dan jadikanlah kami orang yang menyampaikan hidayah dan yang mendapatkan hidayah.\" "},"1280":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي هَاشِمٍ الْوَاسِطِيِّ عَنْ أَبِي مِجْلَزٍ عَنْ قَيْسِ بْنِ عُبَادٍ قَالَصَلَّى عَمَّارُ بْنُ يَاسِرٍ بِالْقَوْمِ صَلَاةً أَخَفَّهَا فَكَأَنَّهُمْ أَنْكَرُوهَا فَقَالَ أَلَمْ أُتِمَّ الرُّكُوعَ وَالسُّجُودَ قَالُوا بَلَى قَالَ أَمَا إِنِّي دَعَوْتُ فِيهَا بِدُعَاءٍ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ اللَّهُمَّ بِعِلْمِكَ الْغَيْبَ وَقُدْرَتِكَ عَلَى الْخَلْقِ أَحْيِنِي مَا عَلِمْتَ الْحَيَاةَ خَيْرًا لِي وَتَوَفَّنِي إِذَا عَلِمْتَ الْوَفَاةَ خَيْرًا لِي وَأَسْأَلُكَ خَشْيَتَكَ فِي الْغَيْبِ وَالشَّهَادَةِ وَكَلِمَةَ الْإِخْلَاصِ فِي الرِّضَا وَالْغَضَبِ وَأَسْأَلُكَ نَعِيمًا لَا يَنْفَدُ وَقُرَّةَ عَيْنٍ لَا تَنْقَطِعُ وَأَسْأَلُكَ الرِّضَاءَ بِالْقَضَاءِ وَبَرْدَ الْعَيْشِ بَعْدَ الْمَوْتِ وَلَذَّةَ النَّظَرِ إِلَى وَجْهِكَ وَالشَّوْقَ إِلَى لِقَائِكَ وَأَعُوذُ بِكَ مِنْ ضَرَّاءَ مُضِرَّةٍ وَفِتْنَةٍ مُضِلَّةٍ اللَّهُمَّ زَيِّنَّا بِزِينَةِ الْإِيمَانِ وَاجْعَلْنَا هُدَاةً مُهْتَدِينَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim bin Sa'd] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Hasyim Al Wasithi] dari [Abu Mijlaz] dari [Qais bin 'Ubad] dia berkata; \" [Ammar bin Yasir] pernah shalat bersama kaumnya dan dia meringankannya, seolah-olah kaumnya mengingkarinya. Lalu ia berkata, \"Tidaklah aku telah menyempurnakan ruku dan sujud? ' Mereka menjawab, 'Ya'. Ia menjelaskannya, 'Aku saat itu memanjatkan doa yang dipergunakan Nabi Shallallallahu'alaihi wasallam dalam doanya, 'Ya Allah dengan ilmu-Mu terhadap hal gaib dan kekuasaan-Mu atas makhluk, hidupkanlah aku selagi Engkau mengetahui bahwa hidup itu lebih baik bagiku, dan matikanlah aku jika Engkau mengetahui bahwa mati lebih baik bagiku. Ya Allah, aku memohon kepada-Mu rasa takut kepada-Mu saat nampak atau saat tidak nampak. Aku memohon kalimat ikhlas saat ridla dan saat marah. Aku memohon kenikmatan tanpa habis dan kesenangan tanpa henti. Aku memohon keridhaan setelah adanya keputusan dan kenyamanan hidup setelah mati dan kelezatan memandang kepada wajah-Mu serta keridaan berjumpa dengan-Mu tanpa ada bahaya yang membahayakan dan tanpa fitnah yang menyesatkan. Ya Allah, hiasilah kami dengan hiasan iman dan jadikanlah kami orang yang menyampaikan hidayah dan yang mendapatkan hidayah.\" "},"1281":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ فَرْوَةَ بْنِ نَوْفَلٍ قَالَقُلْتُ لِعَائِشَةَ حَدِّثِينِي بِشَيْءٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِهِ فِي صَلَاتِهِ فَقَالَتْ نَعَمْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ شَرِّ مَا عَمِلْتُ وَمِنْ شَرِّ مَا لَمْ أَعْمَلْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Farwah bin Naufal] dia berkata; 'Aku berkata kepada [Aisyah], \"Beritahukanlah kepadaku doa yang dipanjatkan Rasulullah Shalallah 'Alaihi Wa Sallam dalam shalatnya.\" Ia menjawab; \"Ya, Rasulullah pernah memanjatkan doa, 'Ya Allah, aku berlindung kepada-Mu dari keburukan yang telah kuperbuat dan keburukan yang belum aku perbuat.\" "},"1282":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَذَابِ الْقَبْرِ فَقَالَ نَعَمْ عَذَابُ الْقَبْرِ حَقٌّ قَالَتْ عَائِشَةُ فَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةً بَعْدُ إِلَّا تَعَوَّذَ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] dari [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Asy'ats] dari [Bapaknya] dari [Masruq] dari ['Aisyah] radliallahu 'anha dia berkatas \"Aku pernah bertanya kepada Rasulullah Shalallah 'Alaihi Wa Sallam tentang adzab kubur, lalu Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: 'Ya, adzab kubur itu benar (adanya).\" Aisyah berkata, \"Setelah itu aku tidak melihat Rasulullah shallallahu 'alaihi wasallam mengerjakan suatu shalat kecuali berlindung dari adzab kubur sesudahnya.\" "},"1283":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا أَبِي عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو فِي الصَّلَاةِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ عَذَابِ الْقَبْرِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ وَأَعُوذُ بِكَ مِنْ فِتْنَةِ الْمَحْيَا وَالْمَمَاتِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْمَأْثَمِ وَالْمَغْرَمِ فَقَالَ لَهُ قَائِلٌ مَا أَكْثَرَ مَا تَسْتَعِيذُ مِنْ الْمَغْرَمِ فَقَالَ إِنَّ الرَّجُلَ إِذَا غَرِمَ حَدَّثَ فَكَذَبَ وَوَعَدَ فَأَخْلَفَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Utsman] dia berkata; [bapakku] telah menceritakan kepada kami, dari [Syu'aib] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair], ['Aisyah] mengabarkan kepadanya bahwa Rasulullah Shalallah 'Alaihi Wa Sallam dalam shalatnya memanjatkan doa: \"Ya Allah, aku berlindung kepadamu dari adzab kubur dan fitnah Dajjal serta fitnah kehidupan dan kematian. Ya Allah, aku berlindung kepadamu dari dosa dan utang.\" Lalu seseorang bertanya kepada beliau; \"Alangkah seringnya engkau berlindung dari utang!\" Lalu beliau Shallallallahu'alaihi wasallam bersabda: \"Jika seseorang berutang, maka ia bicara dan berdusta, juga berjanji lalu mengingkarinya.\" "},"1284":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَمَّارٍ الْمَوْصِلِيُّ عَنْ الْمُعَافَى عَنْ الْأَوْزَاعِيِّ ح وَأَنْبَأَنَا عَلِيُّ بْنُ خَشْرَمٍ عَنْ عِيسَى بْنِ يُونُسَ وَاللَّفْظُ لَهُ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ مُحَمَّدِ بْنِ أَبِي عَائِشَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا تَشَهَّدَ أَحَدُكُمْ فَلْيَتَعَوَّذْ بِاللَّهِ مِنْ أَرْبَعٍ مِنْ عَذَابِ جَهَنَّمَ وَعَذَابِ الْقَبْرِ وَفِتْنَةِ الْمَحْيَا وَالْمَمَاتِ وَمِنْ شَرِّ الْمَسِيحِ الدَّجَّالِ ثُمَّ يَدْعُو لِنَفْسِهِ بِمَا بَدَا لَهُ","id":"Telah mengabarkan kepadaku [Muhammad bin 'Abdullah bin 'Ammar Al Maushili] dari [Al Mu'afa] dari [Al Auza'i] dan diriwayatkan pula dari jalur lain, telah memberitakan kepada kami ['Ali bin Khasyram] dari ['Isa bin Yunus] dan lafadz ini miliknya, dari [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Muhammad bin Abu 'Aisyah] dia berkata; aku mendengar [Abu Hurairah] berkata; Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Bila salah seorang dari kalian tasyahud, maka berlindunglah dari empat hal, yaitu adzab neraka jahannam, adzab kubur, fitnah kehidupan dan kematian, serta dari jahatnya Dajjal.\" Kemudian hendaklah berdoa untuk dirinya dari apa yang diinginkannya."},"1285":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ فِي صَلَاتِهِ بَعْدَ التَّشَهُّدِ أَحْسَنُ الْكَلَامِ كَلَامُ اللَّهِ وَأَحْسَنُ الْهَدْيِ هَدْيُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari [Ja'far bin Muhammad] dari [Bapaknya] dari [Jabir] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam sesudah tasyahud berdoa dengan mengucapkan: \"Sebaik-baiknya perkataan adalah perkataan Allah dan sebaik-baik petunjuk adalah petunjuk Muhammad Shalallu 'Alaihi wa sallam.\" "},"1286":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مَالِكٌ وَهُوَ ابْنُ مِغْوَلٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ زَيْدِ بْنِ وَهْبٍ عَنْ حُذَيْفَةَأَنَّهُ رَأَى رَجُلًا يُصَلِّي فَطَفَّفَ فَقَالَ لَهُ حُذَيْفَةُ مُنْذُ كَمْ تُصَلِّي هَذِهِ الصَّلَاةَ قَالَ مُنْذُ أَرْبَعِينَ عَامًا قَالَ مَا صَلَّيْتَ مُنْذُ أَرْبَعِينَ سَنَةً وَلَوْ مِتَّ وَأَنْتَ تُصَلِّي هَذِهِ الصَّلَاةَ لَمِتَّ عَلَى غَيْرِ فِطْرَةِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَالَ إِنَّ الرَّجُلَ لَيُخَفِّفُ وَيُتِمُّ وَيُحْسِنُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Malik bin Mighwal] dari [Thalhah bin Musharrif] dari [Zaid bin Wahb] dari [Hudzaifah] bahwa ia pernah melihat seseorang shalat dengan menguranginya, maka Hudzaifah menegurnya, \"Sejak kapan kamu shalat seperti ini?\" Ia menjawab, \"Sejak empat puluh tahun!\" Hudzaifah bertanya, \"Kamu tidak shalat sejak empat puluh tahun. Seandainya kamu mati dalam keadaan shalat seperti ini, maka kamu pasti akan mati bukan diatas agama Muhammad Shalallahu 'Alaihi Wasallam.\" Kemudian ia menambahkan, \"Sesungguhnya orang itu benar-benar meringankan shalatnya dan menyempurnakannya, serta memperbaikinya.\""},"1287":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ عَلِيٍّ وَهُوَ ابْنُ يَحْيَى عَنْ أَبِيهِ عَنْ عَمٍّ لَهُ بَدْرِيٍّ أَنَّهُ حَدَّثَهُأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ فَصَلَّى وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُهُ وَنَحْنُ لَا نَشْعُرُ فَلَمَّا فَرَغَ أَقْبَلَ فَسَلَّمَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ أَقْبَلَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ مَرَّتَيْنِ أَوْ ثَلَاثًا فَقَالَ لَهُ الرَّجُلُ وَالَّذِي أَكْرَمَكَ يَا رَسُولَ اللَّهِ لَقَدْ جَهِدْتُ فَعَلِّمْنِي فَقَالَ إِذَا قُمْتَ تُرِيدُ الصَّلَاةَ فَتَوَضَّأْ فَأَحْسِنْ وُضُوءَكَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ فَكَبِّرْ ثُمَّ اقْرَأْ ثُمَّ ارْكَعْ فَاطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ قَاعِدًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ ثُمَّ افْعَلْ كَذَلِكَ حَتَّى تَفْرُغَ مِنْ صَلَاتِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari ['Ali bin Yahya] dari [Bapaknya] dari pamannya - [Badri] -, ia menceritakan bahwa seorang laki-laki masuk masjid lalu shalat. Ternyata Rasulullah Shalallah 'Alaihi Wa Sallam selalu memperhatikannya, tetapi kami tidak menyadarinya. Seusai shalat ia datang dengan memberi salam kepada Rasulullah Shalallah 'Alaihi Wa Sallam, lantas beliau bersabda kepadanya: \"Kembalilah dan shalatlah lagi karena engkau belum shalat.\" Iapun kembali lagi, kemudian menghadap kepada Rasulullah shallallahu 'alaihi wasallam lagi, namun beliau Shallallallahu'alaihi wasallam masih berkata: \"Kembalilah dan shalatlah lagi karena engkau belum shalat.\" Beliau mengulanginya sebanyak dua atau tiga kali. Kemudian orang tersebut berkata, \"Demi Dzat yang memuliakan engkau wahai Rasulullah Shalallah 'Alaihi Wa Sallam, aku telah bersungguh-sungguh. Maka ajarilah aku.\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Jika kamu hendak shalat, maka berwudhulah dan perbaikilah wudhumu. Kemudian berdiri dan menghadaplah kiblat. Lalu takbir dan bacalah (Al Qur'an). Kemudian ruku'lah hingga kamu tenang (thuma'ninah) dalam ruku'mu. Lalu bangkitlah dari ruku' hingga kamu berdiri tegak, kemudian sujudlah hingga kamu tenang (thuma'ninah) dalam sujudmu, lalu bangkitlah dari sujud. Kerjakanlah semuanya seperti itu hingga kamu selesai dari shalatmu.\" "},"1288":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ دَاوُدَ بْنِ قَيْسٍ قَالَ حَدَّثَنِي عَلِيُّ بْنُ يَحْيَى بْنِ خَلَّادِ بْنِ رَافِعِ بْنِ مَالِكٍ الْأَنْصَارِيُّ قَالَ حَدَّثَنِي أَبِي عَنْ عَمٍّ لَهُ بَدْرِيٍّ قَالَكُنْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا فِي الْمَسْجِدِ فَدَخَلَ رَجُلٌ فَصَلَّى رَكْعَتَيْنِ ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْمُقُهُ فِي صَلَاتِهِ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ قَالَ لَهُ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ فَرَجَعَ فَصَلَّى ثُمَّ جَاءَ فَسَلَّمَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ عَلَيْهِ السَّلَامَ ثُمَّ قَالَ ارْجِعْ فَصَلِّ فَإِنَّكَ لَمْ تُصَلِّ حَتَّى كَانَ عِنْدَ الثَّالِثَةِ أَوْ الرَّابِعَةِ فَقَالَ وَالَّذِي أَنْزَلَ عَلَيْكَ الْكِتَابَ لَقَدْ جَهِدْتُ وَحَرَصْتُ فَأَرِنِي وَعَلِّمْنِي قَالَ إِذَا أَرَدْتَ أَنْ تُصَلِّيَ فَتَوَضَّأْ فَأَحْسِنْ وُضُوءَكَ ثُمَّ اسْتَقْبِلْ الْقِبْلَةَ فَكَبِّرْ ثُمَّ اقْرَأْ ثُمَّ ارْكَعْ حَتَّى تَطْمَئِنَّ رَاكِعًا ثُمَّ ارْفَعْ حَتَّى تَعْتَدِلَ قَائِمًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ حَتَّى تَطْمَئِنَّ قَاعِدًا ثُمَّ اسْجُدْ حَتَّى تَطْمَئِنَّ سَاجِدًا ثُمَّ ارْفَعْ فَإِذَا أَتْمَمْتَ صَلَاتَكَ عَلَى هَذَا فَقَدْ تَمَّتْ وَمَا انْتَقَصْتَ مِنْ هَذَا فَإِنَّمَا تَنْتَقِصُهُ مِنْ صَلَاتِكَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Dawud bin Qais] dia berkata; telah menceritakan kepada kami ['Ali bin Yahya bin Khallad bin Rafi' bin Malik Al Anshari] dia berkata; [bapakku] telah menceritakan kepadaku dari pamannya - [Badri] -, dia berkata; \"Kami pernah duduk-duduk bersama Rasulullah Shalallah 'Alaihi Wa Sallam, dan tiba-tiba ada seorang laki-laki masuk ke dalam masjid, lalu shalat dua rakaat. Setelah itu dia datang kepada Rasulullah Shalallah 'Alaihi Wa Sallam sambil mengucapkan salam kepada beliau, padahal Rasulullah shallallahu 'alaihi wasallam telah memperhatikan shalatnya, setelah beliau menjawab salamnya beliau berkata: 'Kembalilah dan shalatlah lagi karena engkau belum shalat'. Iapun kembali shalat lagi, kemudian menghadap Rasulullah Shalallah 'Alaihi Wa Sallam lagi dengan mengucapkan salam kepada beliau Shallallahu'alaihi wasallam. Beliau membalas salamnya sambil berkata, 'Kembalilah dan shalatlah lagi karena engkau belum shalat'. Hingga pada jawaban yang ketiga atau keempat ia lalu berkata, 'Demi Dzat yang mengutus engkau dengan membawa Al Qur'an, aku telah bersungguh-sungguh dan bersemangat. Jadi perlihatkanlah kepadaku dan ajarilah aku.\" Rasulullah Shalallah 'Alaihi Wa Sallam bersabda: \"Jika kamu hendak shalat, maka berwudhulah dan perbaikilah wudhumu. Kemudian berdiri dan menghadaplah kiblat. Lalu takbir dan bacalah (Al Qur'an). Kemudian ruku'lah hingga kamu tenang (thuma'ninah) dalam ruku'mu. Lalu bangkitlah dari ruku' hingga kamu berdiri tegak, kemudian sujudlah hingga kamu tenang (thuma'ninah) dalam sujudmu. Setelah itu bangkitlah dari sujud hingga kamu tenang (thuma'ninah) dalam keadaan duduk. Jika kamu telah menyempurnakan shalatmu dengan cara seperti ini, maka telah sempurna shalatmu. Apa yang kamu kurangi dari itu maka akan mengurangi kesempurnaan shalatmu.\""},"1289":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ قَالَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ وَتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كُنَّا نُعِدُّ لَهُ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ لِمَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيَتَوَضَّأُ وَيُصَلِّي ثَمَانِ رَكَعَاتٍ لَا يَجْلِسُ فِيهِنَّ إِلَّا عِنْدَ الثَّامِنَةِ فَيَجْلِسُ فَيَذْكُرُ اللَّهَ عَزَّ وَجَلَّ وَيَدْعُو ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sa'id] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dia berkata; \"Aku pernah berkata kepada [Aisyah]; 'Wahai Ummul Mukminin, kabarkan kepadaku tentang shalat witir Rasulullah Shalallah 'Alaihi Wa Sallam! ' Ia lalu menerangkan, 'Kami mempersiapkan siwak dan air wudhunya. Allah membangunkan beliau kapan saja Dia menghendakinya di waktu malam. Kemudian beliau Shallallallahu'alaihi wasallam bersiwak dan berwudhu, lalu mengerjakan shalat delapan rakaat tanpa duduk, kecuali pada rakaat kedelapan. Beliau berdzikir dan berdoa kepada Allah Azza wa Jalla, lantas mengucapkan salam yang beliau biasa pendengarkan kepada kami.\""},"1290":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ دَاوُدَ الْهَاشِمِيَّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ وَهُوَ ابْنُ سَعْدٍ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ جَعْفَرٍ وَهُوَ ابْنُ الْمِسْوَرِ الْمَخْرَمِيُّ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنِي عَامِرُ بْنُ سَعْدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dia berkata; telah menceritakan kepada kami [Sulaiman bin Dawud Al Hasyimi] dia berkata; telah menceritakan kepada kami [Ibrahim bin Sa'd] dia berkata; telah menceritakan kepada kami ['Abdullah bin Ja'far bin Al Miswar Al Makhzumi] dari [Isma'il bin Muhammad] dia berkata; ['Amir bin Sa'd] menceritakan kepadakku dari [Bapaknya] bahwa Rasulullah Shalallah 'Alaihi Wa Sallam mengucapkan salam ke kanan dan ke kirinya."},"1291":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو عَامِرٍ الْعَقَدِيُّ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الْمَخْرَمِيُّ عَنْ إِسْمَعِيلَ بْنِ مُحَمَّدِ بْنِ سَعْدٍ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَكُنْتُ أَرَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ حَتَّى يُرَى بَيَاضُ خَدِّهِقَالَ أَبُو عَبْد الرَّحْمَنِ عَبْدُ اللَّهِ بْنُ جَعْفَرٍ هَذَا لَيْسَ بِهِ بَأْسٌ وَعَبْدُ اللَّهِ بْنُ جَعْفَرِ بْنِ نَجِيحٍ وَالِدُ عَلِيِّ بْنِ الْمَدِينِيِّ مَتْرُوكُ الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Abu 'Amir Al 'Aqadi] dia berkata; telah menceritakan kepada kami ['Abdullah bin Ja'far Al Makhzumi] dari [Isma'il bin Muhammad bin Sa'd] dari ['Amir bin Sa'd] dari [Sa'ad] dia berkata; \"Aku pernah melihat Rasulullah Shalallah 'Alaihi Wa Sallam mengucapkan salam ke kanan dan ke kiri hingga terlihat pipinya yang putih.\" Abu Abdurrahman berkata; Abdullah bin Ja'far adalah orang yang tidak bermasalah. Sedangkan Abdullah bin Ja'far bin Nujaih (bapaknya Ali bin Al Madini orangnya Matrukul Hadist (Hadistnya ditinggal)."},"1292":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ مِسْعَرٍ عَنْ عُبَيْدِ اللَّهِ ابْنِ الْقِبْطِيَّةِ قَالَ سَمِعْتُ جَابِرَ بْنَ سَمُرَةَ يَقُولُكُنَّا إِذَا صَلَّيْنَا خَلْفَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْنَا السَّلَامُ عَلَيْكُمْ السَّلَامُ عَلَيْكُمْ وَأَشَارَ مِسْعَرٌ بِيَدِهِ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ فَقَالَ مَا بَالُ هَؤُلَاءِ الَّذِينَ يَرْمُونَ بِأَيْدِيهِمْ كَأَنَّهَا أَذْنَابُ الْخَيْلِ الشُّمُسِ أَمَا يَكْفِي أَنْ يَضَعَ يَدَهُ عَلَى فَخِذِهِ ثُمَّ يُسَلِّمُ عَلَى أَخِيهِ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dari [Mis'ar] dari ['Ubaidillah bin Al Qibthiyyah] dia berkata; aku mendengar [Jabir bin Samurah] dia berkata; \"Jika kami shalat dibelakang Nabi Shallallahu 'Alahi Wa Sallam, maka kami mengucapkan, 'Assalamu 'alaikum, assalamu 'alaikum'. -Mis'ar (perawi) mengisyaratkan dengan tangannya, ke kanan dan ke kiri- lantas beliau Shallallahu 'Alahi Wa Sallam bersabda: 'Kenapa menjulurkan tangan-tangan mereka laksana ekor kuda liar? Mengapa ia tidak meletakkan tangannya diatas pahanya kemudian mengucapkan salam kepada saudaranya dari sebelah kanan dan kirinya?\""},"1293":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ قَالَ حَدَّثَنَا زُهَيْرٌ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ الْأَسْوَدِ وَعَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكَبِّرُ فِي كُلِّ خَفْضٍ وَرَفْعٍ وَقِيَامٍ وَقُعُودٍ وَيُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ حَتَّى يُرَى بَيَاضُ خَدِّهِوَرَأَيْتُ أَبَا بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا يَفْعَلَانِ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Mu'adz bin Mu'adz] dia berkata; telah menceritakan kepada kami [Zuhair] dari [Abu Ishaq] dari ['Abdurrahman bin Al Aswad] dari [Al Aswad] dan ['Alqamah] dari ['Abdullah] dia berkata; \"Aku melihat Rasulullah Shallallahu 'Alahi Wa Sallam bertakbir disetiap turun, bangun, berdiri, dan duduk. Beliau mengucapkan salam ke kanan dan ke kiri, 'Assalamu'alaikum wa rahmatullah, assalamu 'alaikum wa rahmatullah' hingga terlihat pipinya yang putih. Dan aku melihat Abu Bakar dan Umar Radliallah 'Anhuma melakukan yang demikian juga.\""},"1294":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ مُحَمَّدٍ الزَّعْفَرَانِيُّ عَنْ حَجَّاجٍ قَالَ ابْنُ جُرَيْجٍ أَنْبَأَنَا عَمْرُو بْنُ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَأَنَّهُ سَأَلَ عَبْدَ اللَّهِ بْنَ عُمَرَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اللَّهُ أَكْبَرُ كُلَّمَا وَضَعَ اللَّهُ أَكْبَرُ كُلَّمَا رَفَعَ ثُمَّ يَقُولُ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ عَنْ يَمِينِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ عَنْ يَسَارِهِ","id":"Telah mengabarkan kepada kami [Al Hasan bin Muhammad Az Za'farani] dari [Hajjaj], berkata [Ibnu Juraij]; telah memberitakan kepada kami ['Amr bin Yahya] dari [Muhammad bin Yahya bin Habban] dari pamannya [Wasi' bin Habban] bahwa ia pernah bertanya kepada [Abdullah bin Umar] tentang shalatnya Rasulullah Shallallahu 'Alahi Wa Sallam?\" Lalu ia menjawab bahwa Rasulullah mengucapkan Allahu akbar setiap ia turun dan Allahu akbar setiap ia bangun, kemudian mengucapkan, \"Assalamu'alaikum wa rahmatullah\" ke kanan dan \"Assalamu'alaikum wa rahmatullah\" ke kiri."},"1295":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ عَمْرِو بْنِ يَحْيَى عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ قَالَقُلْتُ لِابْنِ عُمَرَ أَخْبِرْنِي عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ كَانَتْ قَالَ فَذَكَرَ التَّكْبِيرَ قَالَ يَعْنِي وَذَكَرَ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ عَنْ يَمِينِهِ السَّلَامُ عَلَيْكُمْ عَنْ يَسَارِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz Ad Darawardi] dari ['Amr bin Yahya] dari [Muhammad bin Yahya bin Hibban] dari pamannya [Wasi' bin Habban] dia berkata; \"Aku bertanya kepada [Ibnu Umar], 'Kabarkanlah kepadaku tentang cara shalatnya Rasulullah Shallallahu 'Alahi Wa Sallam? ' Ia menjawab; 'Ia menyebutkan takbir, lantas mengucapkan, \"Assalamu'alaikum wa rahmatullah\" ke kanan dan \"Assalamu'alaikum wa rahmatullah\" ke kiri.\""},"1296":{"ar":"أَخْبَرَنَا زَيْدُ بْنُ أَخْزَمَ عَنْ ابْنِ دَاوُدَ يَعْنِي عَبْدَ اللَّهِ بْنَ دَاوُدَ الْخُرَيْبِيَّ عَنْ عَلِيِّ بْنِ صَالِحٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كَأَنِّي أَنْظُرُ إِلَى بَيَاضِ خَدِّهِ عَنْ يَمِينِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ وَعَنْ يَسَارِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ","id":"Telah mengabarkan kepada kami [Zaid bin Akhzam] dari [Ibnu Dawud 'Abdullah bin Dawud Al Khuraibi] dari ['Ali bin Shalih] dari [Abu Ishaq] dari [Abul Ahwash] dari ['Abdullah] dari Nabi Shallallahu 'Alahi Wa Sallam, dia berkata; \"Seolah-olah aku melihat pipinya yang putih disebelah kanannya -saat mengucapkan- assalamu'alaikum wa rahmatullah. Dan disebelah kirinya -saat mengucapkan- assalamu'alaikum wa rahmatullah."},"1297":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عُمَرَ بْنِ عُبَيْدٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَلِّمُ عَنْ يَمِينِهِ حَتَّى يَبْدُوَ بَيَاضُ خَدِّهِ وَعَنْ يَسَارِهِ حَتَّى يَبْدُوَ بَيَاضُ خَدِّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Umar bin 'Ubaid] dari [Abu Ishaq] dari [Abul Ahwash] dari ['Abdullah] dia berkata; \"Rasulullah Shallallahu 'Alahi Wa Sallam mengucapkan salam ke kanan hingga terlihat pipinya yang putih dan ke kiri hingga nampak pipinya yang putih.\""},"1298":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ وَعَنْ يَسَارِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ مِنْ هَاهُنَا وَبَيَاضُ خَدِّهِ مِنْ هَاهُنَا","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami ['Abdurrahman] dari [Sufyan] dari [Abu Ishaq] dari [Abul Ahwash] dari ['Abdullah] dari Nabi Shallallahu 'Alahi Wa Sallam, bahwa beliau Shallallahu 'Alahi Wa Sallam mengucapkan salam ke kanan dan ke kiri -dengan ucapan-, \"Assalamu'alaikum wa rahmatullah\" hingga nampak pipinya yang putih dari sebelah kanan dan kiri."},"1299":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ قَالَ أَنْبَأَنَا الْحُسَيْنُ بْنُ وَاقِدٍ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ وَأَبِي الْأَحْوَصِ قَالُوا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُسَلِّمُ عَنْ يَمِينِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ الْأَيْمَنِ وَعَنْ يَسَارِهِ السَّلَامُ عَلَيْكُمْ وَرَحْمَةُ اللَّهِ حَتَّى يُرَى بَيَاضُ خَدِّهِ الْأَيْسَرِ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami ['Ali bin Al Hasan bin Syaqiq] dia berkata; telah memberitakan kepada kami [Al Husain bin Waqid] dia berkata; telah menceritakan kepada kami [Abu Ishaq] dari ['Alqamah] dan [Al Aswad] dan [Abul Ahwash] mereka berkata; telah menceritakan kepada kami ['Abdullah bin Mas'ud] bahwasanya Rasulullah Shallallahu 'Alahi Wa Sallam mengucapkan salam ke kanan -dengan ucapan-, \"Assalamu'alaikum wa rahmatullah\" hingga terlihat pipi kanannya yang putih, lalu ke sebelah kirinya -dengan ucapan- \"Assalamu'alaikum wa rahmatullah\" hingga terlihat pipi kirinya yang putih. "},"1300":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ حَدَّثَنَا إِسْرَائِيلُ عَنْ فُرَاتٍ الْقَزَّازِ عَنْ عُبَيْدِ اللَّهِ وَهُوَ ابْنُ الْقِبْطِيَّةِ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكُنَّا إِذَا سَلَّمْنَا قُلْنَا بِأَيْدِينَا السَّلَامُ عَلَيْكُمْ السَّلَامُ عَلَيْكُمْ قَالَ فَنَظَرَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا شَأْنُكُمْ تُشِيرُونَ بِأَيْدِيكُمْ كَأَنَّهَا أَذْنَابُ خَيْلٍ شُمُسٍ إِذَا سَلَّمَ أَحَدُكُمْ فَلْيَلْتَفِتْ إِلَى صَاحِبِهِ وَلَا يُومِئْ بِيَدِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa] dia berkata; telah menceritakan kepada kami [Israil] dari [Furat Al Qazzaz] dari ['Ubaidullah bin Al Qibthiyyah] dari [Jabir bin Samurah] dia berkata; \"Aku shalat bersama Rasulullah shallallahu 'alaihi wasallam, dan jika salam maka kami mengucapkan, 'Assalamu'alaikum, assalamau'alaikum' dengan kedua tangan kami.\" Ia berkata; \"Lalu Rasulullah memandang kami sambil berkata: 'Kenapa kalian mengisyaratkan dengan kedua tangan kalian laksana ekor kuda liar? Bila salah seorang dari kalian mengucapkan salam, maka menolehlah ke temannya dan jangan mengisyaratkan dengan tangannya.\" "},"1301":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ أَخْبَرَهُ قَالَ أَخْبَرَنِي مَحْمُودُ بْنُ الرَّبِيعِ قَالَ سَمِعْتُ عِتْبَانَ بْنَ مَالِكٍ يَقُولُكُنْتُ أُصَلِّي بِقَوْمِي بَنِي سَالِمٍ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي قَدْ أَنْكَرْتُ بَصَرِي وَإِنَّ السُّيُولَ تَحُولُ بَيْنِي وَبَيْنَ مَسْجِدِ قَوْمِي فَلَوَدِدْتُ أَنَّكَ جِئْتَ فَصَلَّيْتَ فِي بَيْتِي مَكَانًا أَتَّخِذُهُ مَسْجِدًا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَفْعَلُ إِنْ شَاءَ اللَّهُ فَغَدَا عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ مَعَهُ بَعْدَ مَا اشْتَدَّ النَّهَارُ فَاسْتَأْذَنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ فَأَشَرْتُ لَهُ إِلَى الْمَكَانِ الَّذِي أُحِبُّ أَنْ يُصَلِّيَ فِيهِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْنَا خَلْفَهُ ثُمَّ سَلَّمَ وَسَلَّمْنَا حِينَ سَلَّمَ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah bin Al Mubarak] dari [Ma'mar] dari [Az Zuhri]; telah mengabarkan kepadanya, dia berkata; telah mengabarkan kepadaku [Mahmud bin Ar Rabi'] dia berkata; aku mendengar ['Itban bin Malik] berkata; \"Aku pernah shalat bersama kaumku -Bani Salim- lalu aku datang kepada Rasulullah Shallallahu 'Alahi Wa Sallam dan kukatakan kepadanya, 'penglihatanku sudah kabur, dan banjir menghalangiku antara aku dan masjid kaumku. Jadi aku ingin engkau datang dan shalat di rumahku, ditempat yang kujadikan sebagai masjid'. Lalu Nabi Shallallahu 'Alahi Wa Sallam bersabda: 'Aku akan melakukannya, Insya Allah'. Lalu Rasulullah Shallallahu 'Alahi Wa Sallam dan Abu Bakar Radliyallahu'anhu datang ke tempatku pada pertengahan siang, kemudian beliau Shallallahu 'Alahi Wa Sallam minta izin dan aku mengizinkannya. Belum sampai duduk, beliau bertanya kepadaku, 'Dibagian mana dari rumahmu yang kamu sukai untuk tempat shalatku? ' Lantas aku menunjukkan tempat yang kusukai untuk tempat shalat beliau Shallallahu 'Alahi Wa Sallam. Setelah itu beliau Shallallahu 'Alahi Wa Sallam berdiri dan kami berbaris dibelakangnya. Kemudian beliau Shallallahu 'Alahi Wa Sallam mengucapkan salam dan kami ikut mengucapkan salam tatkala beliau mengucapkan salam.\" "},"1302":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ بْنِ حَمَّادِ بْنِ سَعْدٍ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي ابْنُ أَبِي ذِئْبٍ وَعَمْرُو بْنُ الْحَارِثِ وَيُونُسُ بْنُ يَزِيدَ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُمْ عَنْ عُرْوَةَ قَالَتْ عَائِشَةُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيمَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً وَيُوتِرُ بِوَاحِدَةٍ وَيَسْجُدُ سَجْدَةً قَدْرَ مَا يَقْرَأُ أَحَدُكُمْ خَمْسِينَ آيَةً قَبْلَ أَنْ يَرْفَعَ رَأْسَهُوَبَعْضُهُمْ يَزِيدُ عَلَى بَعْضٍ فِي الْحَدِيثِ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Sulaiman bin Dawud bin Hammad bin Sa'd] dari [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Ibnu Abu Dzi'b] dan ['Amr bin Al Harits] dan [Yunus bin Yazid] bahwasanya [Ibnu Syihab] mengabarkan kepada mereka dari ['Urwah] dia berkata; ['Aisyah] berkata; \"Rasulullah Shallallahu 'Alahi Wa Sallam mengerjakan shalat sebelas rakaat diantara setelah shalat Isya sampai dengan shalat Fajar, dan shalat witir satu rakaat. Beliau sujud satu kali yang lamanya sama dengan seseorang dari kalian membaca lima puluh ayat Al Qur'an sebelum mengangkat kepalanya.\" Dan sebagian perawi lain ada yang menambahkannya dalam hadits ini. (Secara ringkas)."},"1303":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ حَفْصٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَ ثُمَّ تَكَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Hafsh] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] bahwa Nabi Shallallahu 'Alahi Wa Sallam mengucapkan salam lalu berbicara, dan setelah itu beliau sujud sahwi dua kali."},"1304":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ عَنْ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ عَنْ عِكْرِمَةَ بْنِ عَمَّارٍ قَالَ حَدَّثَنَا ضَمْضَمُ بْنُ جَوْسٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ وَهُوَ جَالِسٌ ثُمَّ سَلَّمَقَالَ ذَكَرَهُ فِي حَدِيثِ ذِي الْيَدَيْنِ","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dari ['Abdullah bin Al Mubarak] dari ['Ikrimah bin 'Ammar] dia berkata; telah menceritakan kepada kami [Dhamdham bin Jaus] dari [Abu Hurairah] bahwa Rasulullah Shallallahu 'Alahi Wa Sallam mengucapkan salam, kemudian ia sujud sahwi dua kali sambil duduk, kemudian mengucapkan salam.Ia (perawi) berkata; \"Ia menyebutkan pada hadits Dzul Yadain.\""},"1305":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى ثَلَاثًا ثُمَّ سَلَّمَ فَقَالَ الْخِرْبَاقُ إِنَّكَ صَلَّيْتَ ثَلَاثًا فَصَلَّى بِهِمْ الرَّكْعَةَ الْبَاقِيَةَ ثُمَّ سَلَّمَ ثُمَّ سَجَدَ سَجْدَتَيْ السَّهْوِ ثُمَّ سَلَّمَ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dia berkata; telah menceritakan kepada kami [Khalid] dari [Abu Qibalah] dari [Abu Al Muhallab] dari ['Imran bin Hushain] dia berkata; \"Rasulullah Shallallahu 'Alahi Wa Sallam shalat tiga rakaat, lantas salam. Kemudian Al Khirbaq berkata; 'Engkau shalat tiga rakaat'. Kemudian beliau Shallallahu 'Alahi Wa Sallam shalat satu rakaat yang ketinggalan bersama mereka, kemudian salam lalu sujud sahwi dua kali. Setelah itu beliau salam.\" "},"1306":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ هِلَالٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ ابْنِ عَازِبٍ قَالَرَمَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاتِهِ فَوَجَدْتُ قِيَامَهُ وَرَكْعَتَهُ وَاعْتِدَالَهُ بَعْدَ الرَّكْعَةِ فَسَجْدَتَهُ فَجِلْسَتَهُ بَيْنَ السَّجْدَتَيْنِ فَسَجْدَتَهُ فَجِلْسَتَهُ بَيْنَ التَّسْلِيمِ وَالِانْصِرَافِ قَرِيبًا مِنْ السَّوَاءِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami ['Amr bin 'Aun] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Hilal] dari ['Abdurrahman bin Abu Laila] dari [Al Barra' bin 'Azib] dia berkata; \"Aku memperhatikan shalatnya Rasulullah Shallallahu 'Alahi Wa Sallam, dan aku mendapati -lama- berdiri Rasulullah Shallallahu 'Alahi Wa Sallam saat shalat, ruku'nya, I'tidalnya setelah ruku', sujudnya dan duduknya diantara dua sujud, serta sujudnya dan duduknya diantara salam dan beranjaknya hampir sama (lamanya). "},"1307":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ أَخْبَرَتْنِي هِنْدُ بِنْتُ الْحَارِثِ الْفِرَاسِيَّةُ أَنَّ أُمَّ سَلَمَةَ أَخْبَرَتْهَاأَنَّ النِّسَاءَ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُنَّ إِذَا سَلَّمْنَ مِنْ الصَّلَاةِ قُمْنَ وَثَبَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ صَلَّى مِنْ الرِّجَالِ مَا شَاءَ اللَّهُ فَإِذَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ الرِّجَالُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus], [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Hindun binti Al Harits Al Firasiyyah] bahwasanya [Ummu Salamah] telah mengabarkan kepadanya; Para wanita pada masa Rasulullah Shallallahu 'Alahi Wa Sallam bila telah mengucapkan salam dari shalatnya maka mereka berdiri dan pulang ke rumah masing-masing, sedangkan Rasulullah Shallallahu 'Alahi Wa Sallam dan para sahabatnya (duduk). Apabila Rasulullah Shallallahu 'Alahi Wa Sallam berdiri maka mereka juga berdiri. "},"1308":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي يَعْلَى بْنُ عَطَاءٍ عَنْ جَابِرِ بْنِ يَزِيدَ بْنِ الْأَسْوَدِ عَنْ أَبِيهِأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الصُّبْحِ فَلَمَّا صَلَّى انْحَرَفَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepadaku [Ya'la bin 'Atha] dari [Jabir bin Yazid bin Al Aswad] dari [bapaknya] bahwa ia pernah shalat subuh bersama Rasulullah Shallallahu 'Alahi Wa Sallam, dan setelah shalat ia segera beranjak pergi. "},"1309":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي مَعْبَدٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّمَا كُنْتُ أَعْلَمُ انْقِضَاءَ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتَّكْبِيرِ","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid Al 'Askari] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan bin 'Uyainah] dari ['Amr bin Dinar] dari [Abu Ma'bad] dari [Ibnu 'Abbas] dia berkata; \"Aku orang yang paling tahu tentang akhir shalatnya Rasulullah Shallallahu 'Alahi Wa Sallam dengan takbir.\" "},"1310":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ اللَّيْثِ عَنْ حُنَيْنِ بْنِ أَبِي حَكِيمٍ عَنْ عَلِيِّ بْنِ رَبَاحٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَأَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ أَقْرَأَ الْمُعَوِّذَاتِ دُبُرَ كُلِّ صَلَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dari [Al Laits] dari [Hunain bin Abu Hakim] dari ['Ali bin Rabah] dari ['Uqbah bin 'Amir] dia berkata; \"Rasulullah Shallallahu 'Alahi Wa Sallam memerintahkanku membaca surah mu'awwidzat pada setiap selesai shalat.\""},"1311":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ أَبِي عَمْرٍو الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي شَدَّادٌ أَبُو عَمَّارٍ أَنَّ أَبَا أَسْمَاءَ الرَّحَبِيَّ حَدَّثَهُ أَنَّهُ سَمِعَ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا انْصَرَفَ مِنْ صَلَاتِهِ اسْتَغْفَرَ ثَلَاثًا وَقَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتُ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Abu 'Amr Al Auza'i] dia berkata; telah menceritakan kepadaku [Syaddad Abu 'Ammar] bahwasanya [Abu Asma Ar Rahabi] menceritakan kepadanya bahwasanya ia mendengar [Tsauban] -hamba sahaya Rasulullah Shallallahu 'Alahi Wa Sallam- Rasulullah Shallallahu 'Alahi Wa Sallam jika selesai shalat maka beliau beristighfar tiga kali, lalu bersabda: \"Ya Allah, Engkau Maha Pemberi Selamat dan dari-Mu-lah keselamatan. Maha Suci Engkau wahai pemilik keluhuran dan kemuliaan.\" "},"1312":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى وَمُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ عَنْ خَالِدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَلَّمَ قَالَ اللَّهُمَّ أَنْتَ السَّلَامُ وَمِنْكَ السَّلَامُ تَبَارَكْتَ يَا ذَا الْجَلَالِ وَالْإِكْرَامِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dan [Muhammad bin Ibrahim bin Shudran] dari [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ashim] dari ['Abdullah bin Al Harits] dari ['Aisyah] radliallahu 'anha bahwa jika Rasulullah Shallallahu 'Alahi Wa Sallam telah salam maka beliau mengucapkan: \"Ya Allah, Engkaulah Maha Pemberi Keselamatan dan dariMu-lah keselamatan. Maha Suci Engkau wahai pemilik keluhuran dan kemuliaan.\" "},"1313":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ شُجَاعٍ الْمَرُّوذِيُّ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْحَجَّاجِ بْنِ أَبِي عُثْمَانَ قَالَ حَدَّثَنِي أَبُو الزُّبَيْرِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الزُّبَيْرِيُحَدِّثُ عَلَى هَذَا الْمِنْبَرِ وَهُوَ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَلَّمَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا حَوْلَ وَلَا قُوَّةَ إِلَّا بِاللَّهِ لَا إِلَهَ إِلَّا اللَّهُ لَا نَعْبُدُ إِلَّا إِيَّاهُ أَهْلَ النِّعْمَةِ وَالْفَضْلِ وَالثَّنَاءِ الْحَسَنِ لَا إِلَهَ إِلَّا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ","id":"Telah mengabarkan kepada kami [Muhammad bin Syujja' Al Marrudzi] dia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah] dari [Al Hajjaj bin Abu 'Utsman] dia berkata; telah menceritakan kepadaku [Abu Az Zubair] dia berkata; \"Aku mendengar [Abdullah bin Zubair] bercerita diatas mimbar ini, dia berkata; 'Jika Rasulullah Shallallahu 'Alahi Wa Sallam selesai mengucapkan salam, maka beliau Shallallahu 'Alahi Wa Sallam memanjatkan doa -yang artinya- 'Tiada Dzat yang berhak disembah kecuali Allah, tidak ada sekutu bagi-Nya. Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu, tiada daya dan kekuatan kecuali dengan pertolongan Allah. Tiada Dzat yang berhak disembah kecuali Allah. Kita tidak beribadah kecuali dengan-Nya yang mempunyai segala nikmat dan keutamaan serta pujian yang luhur. Tiada Dzat yang berhak disembah kecuali Allah dengan memurnikan ketaatan kepada-Nya, walaupun orang-orang kafir membenci.\" "},"1314":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدَةُ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِي الزُّبَيْرِ قَالَكَانَ عَبْدُ اللَّهِ بْنُ الزُّبَيْرِ يُهَلِّلُ فِي دُبُرِ الصَّلَاةِ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ لَا إِلَهَ إِلَّا اللَّهُ وَلَا نَعْبُدُ إِلَّا إِيَّاهُ لَهُ النِّعْمَةُ وَلَهُ الْفَضْلُ وَلَهُ الثَّنَاءُ الْحَسَنُ لَا إِلَهَ إِلَّا اللَّهُ مُخْلِصِينَ لَهُ الدِّينَ وَلَوْ كَرِهَ الْكَافِرُونَ ثُمَّ يَقُولُ ابْنُ الزُّبَيْرِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُهَلِّلُ بِهِنَّ فِي دُبُرِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Abdah] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Abu Az Zubair] dia berkata; \"Abdullah bin Zubair selalu bertahlil ketika selesai shalat, dengan mengucapkan, Tiada Dzat yang berhak disembah kecuali Allah, tidak ada sekutu bagi-Nya. Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu, Tiada Dzat yang berhak disembah kecuali Allah. Kita tidak beribadah kecuali dengan-Nya yang mempunyai segala nikmat dan keutamaan serta pujian yang luhur. Tiada Dzat yang berhak disembah kecuali Allah dengan memurnikan ketaatan kepada-Nya, walaupun orang-orang kafir membenci.\" Kemudian [Ibnu Zubair] berkata; \"Rasulullah Shallallahu 'Alahi Wa Sallam selalu bertahlil dengan kalimat ini ketika selesai shalat.\""},"1315":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ سَمِعْتُهُ مِنْ عَبْدَةَ بْنِ أَبِي لُبَابَةَ وَسَمِعْتُهُ مِنْ عَبْدِ الْمَلِكِ بْنِ أَعْيَنَ كِلَاهُمَا سَمِعَهُ مِنْ وَرَّادٍ كَاتِبِ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَكَتَبَ مُعَاوِيَةُ إِلَى الْمُغِيرَةِ بْنِ شُعْبَةَ أَخْبِرْنِي بِشَيْءٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى الصَّلَاةَ قَالَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan] dia berkata; aku mendengarnya dari ['Abdah bin Abu Lubabah] dan dari ['Abdul Malik bin A'yan] keduanya mendengar dari [Warrad] -seorang juru tulis Al Mughirah bin Syu'bah- dia berkata; Mu'awiyah menulis surat kepada [Al Mughirah bin Syu'bah]; 'kabarkan kepadaku tentang sesuatu yang engkau dengar dari Rasulullah Shallallahu 'Alahi Wa Sallam', Lalu ia menjawab; \"Bila Rasulullah Shallallahu 'Alahi Wa Sallam selesai shalat, maka beliau Shallallahu 'Alahi Wa Sallam mengucapkan -doa yang artinya-: 'Tiada Dzat yang berhak disembah selain Allah, tiada sekutu bagi-Nya. Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu. Ya Allah, tiada yang bisa menghalangi apa yang Engkau berikan dan tiada yang bisa memberi apa yang Engkau halangi. Tidaklah bermanfaat kekayaan dan harta benda dari-Mu bagi pemiliknya.\" "},"1316":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ الْمُسَيَّبِ أَبِي الْعَلَاءِ عَنْ وَرَّادٍ قَالَكَتَبَ الْمُغِيرَةُ بْنُ شُعْبَةَ إِلَى مُعَاوِيَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ دُبُرَ الصَّلَاةِ إِذَا سَلَّمَ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ اللَّهُمَّ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] dia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Al Musayyab Abul Ala'] dari [Warrad] dia berkata; [Al Mughirah bin Syu'bah] menulis surat kepada Mu'awiyah bahwa Rasulullah Shallallahu 'Alahi Wa Sallam ketika selesai shalat, setelah salam senantiasa mengucapkan, 'Tiada Dzat yang berhak disembah selain Allah, tiada sekutu bagi-Nya. Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu. Ya Allah, tiada yang bisa menghalangi apa yang Engkau berikan dan tiada yang bisa memberi apa yang Engkau halangi. Tidaklah bermanfaat kekayaan dan harta benda dari-Mu bagi pemiliknya.\" "},"1317":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ الْمُجَالِدِيُّ قَالَ أَنْبَأَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا الْمُغِيرَةُ وَذَكَرَ آخَرَ ح وَأَنْبَأَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا غَيْرُ وَاحِدٍ مِنْهُمْ الْمُغِيرَةُ عَنْ الشَّعْبِيِّ عَنْ وَرَّادٍ كَاتِب الْمُغِيرَة��أَنَّ مُعَاوِيَةَ كَتَبَ إِلَى الْمُغِيرَةِ أَنْ اكْتُبْ إِلَيَّ بِحَدِيثٍ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَتَبَ إِلَيْهِ الْمُغِيرَةُ إِنِّي سَمِعْتُهُ يَقُولُ عِنْدَ انْصِرَافِهِ مِنْ الصَّلَاةِ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ لَهُ الْمُلْكُ وَلَهُ الْحَمْدُ وَهُوَ عَلَى كُلِّ شَيْءٍ قَدِيرٌ ثَلَاثَ مَرَّاتٍ","id":"Telah mengabarkan kepada kami [Al Hasan bin Isma'il Al Mujalidi] dia berkata; telah memberitakan kepada kami [Husyaim] dia berkata; telah memberitakan kepada kami [Al Mughirah] dan yang lain menyebutkan dari jalur lainnya, telah memberitakan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Husyaim] dia berkata; telah memberitakan kepada kami tidak hanya satu orang salah satunya adalah [Al Mughirah] dari [Asy Sya'bi] dari [Warrad] -juru tulis Al Mughirah- bahwasanya Mu'awiyah menulis surat kepada Al Mughirah untuk menuliskan kepadanya hadits yang dia dengar dari Rasulullah Shallallahu 'Alahi Wa Sallam maka [Al Mughirah] menulis; \"Aku mendengar Rasulullah ketika selesai shalat, mengucapkan: 'Tiada Dzat yang berhak disembah selain Allah, tiada sekutu bagi-Nya. Dia yang mempunyai kekuasaan dan segala pujian. Dia Maha Kuasa atas segala sesuatu. Sebanyak tiga kali."},"1318":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ الصَّاغَانِيُّ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ الْخُزَاعِيُّ مَنْصُورُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا خَلَّادُ بْنُ سُلَيْمَانَ قَالَ أَبُو سَلَمَةَ وَكَانَ مِنْ الْخَائِفِينَ عَنْ خَالِدِ بْنِ أَبِي عِمْرَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَلَسَ مَجْلِسًا أَوْ صَلَّى تَكَلَّمَ بِكَلِمَاتٍ فَسَأَلَتْهُ عَائِشَةُ عَنْ الْكَلِمَاتِ فَقَالَ إِنْ تَكَلَّمَ بِخَيْرٍ كَانَ طَابِعًا عَلَيْهِنَّ إِلَى يَوْمِ الْقِيَامَةِ وَإِنْ تَكَلَّمَ بِغَيْرِ ذَلِكَ كَانَ كَفَّارَةً لَهُ سُبْحَانَكَ اللَّهُمَّ وَبِحَمْدِكَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ishaq Ash Shaghani] dia berkata; telah menceritakan kepada kami [Abu Salamah Al Khuza'i Manshur bin Salamah] dia berkata; telah menceritakan kepada kami [Khallad bin Sulaiman], -Abu Salamah berkomentar (tentang Khallad); Dia termasuk orang yang penakut- dari [Khalid bin 'Imran] dari ['Urwah] dari ['Aisyah] bahwa Rasulullah Shallallahu 'Alahi Wa Sallam apabila duduk disuatu majelis atau ketika shalat maka beliau mengucapkan beberapa kalimat. Lalu aku bertanya kepada Aisyah tentang kalimat tersebut, dan dia menjawab; \"Jika bicara baik maka itu sebagai tanda (stempel) sampai hari kiamat dan jika bicara yang tidak baik maka itu sebagai kafarat/penghapusnya: 'Subhaanakallahumma wa bihamdika astaghfiruka wa atuubu ilaika (Ya Allah, Maha Suci Engkau dan segala pujian bagi-Mu. Aku mohon ampunan dan bertaubat kepada-Mu).\" "},"1319":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَعْلَى قَالَ حَدَّثَنَا قُدَامَةُ عَنْ جَسْرَةَ قَالَتْ حَدَّثَتْنِي عَائِشَةُ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَتْ عَلَيَّ امْرَأَةٌ مِنْ الْيَهُودِ فَقَالَتْ إِنَّ عَذَابَ الْقَبْرِ مِنْ الْبَوْلِ فَقُلْتُ كَذَبْتِ فَقَالَتْ بَلَى إِنَّا لَنَقْرِضُ مِنْهُ الْجِلْدَ وَالثَّوْبَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الصَّلَاةِ وَقَدْ ارْتَفَعَتْ أَصْوَاتُنَا فَقَالَ مَا هَذَا فَأَخْبَرْتُهُ بِمَا قَالَتْ فَقَالَ صَدَقَتْ فَمَا صَلَّى بَعْدَ يَوْمِئِذٍ صَلَاةً إِلَّا قَالَ فِي دُبُرِ الصَّلَاةِ رَبَّ جِبْرِيلَ وَمِيكَائِيلَ وَإِسْرَافِيلَ أَعِذْنِي مِنْ حَرِّ النَّارِ وَعَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Ya'la] dia berkata; telah menceritakan kepada kami [Qudamah] dari [Jasrah] dia berkata; telah menceritakan kepadaku ['Aisyah] Radliallah anha, dia berkata; \"Seorang wanita Yahudi menemuiku dan berkata; 'Adzab kubur itu bisa terjadi karena air kencing (yang tidak sempurna disucikan), aku pun berkata; 'Kamu berdusta! ' dia berkata; 'Benar, bahkan jika salah kami siap untuk memotong kulit dan pakaian kami. Kemudian Rasulullah shallallahu 'alaihi wasallam keluar hendak shalat, beliau mendengar suara kami yang keras, maka beliau bertanya: 'Ada apa ini? Lalu aku memberitahu apa yang dia katakan, Nabipun bersabda: 'dia (orang Yahudi) benar. Maka setelah itu beliau tidaklah melaksanakan shalat kecuali beliau mengucapkan di akhir shalatnya: 'Ya Allah pemelihara Jibril dan Mikail dan Israfil, lindungilah aku dari panasnya api neraka dan adzab kubur.'"},"1320":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي حَفْصُ بْنُ مَيْسَرَةَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ عَطَاءِ بْنِ أَبِي مَرْوَانَ عَنْ أَبِيهِأَنَّ كَعْبًا حَلَفَ لَهُ بِاللَّهِ الَّذِي فَلَقَ الْبَحْرَ لِمُوسَى إِنَّا لَنَجِدُ فِي التَّوْرَاةِ أَنَّ دَاوُدَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا انْصَرَفَ مِنْ صَلَاتِهِ قَالَ اللَّهُمَّ أَصْلِحْ لِي دِينِي الَّذِي جَعَلْتَهُ لِي عِصْمَةً وَأَصْلِحْ لِي دُنْيَايَ الَّتِي جَعَلْتَ فِيهَا مَعَاشِي اللَّهُمَّ إِنِّي أَعُوذُ بِرِضَاكَ مِنْ سَخَطِكَ وَأَعُوذُ بِعَفْوِكَ مِنْ نِقْمَتِكَ وَأَعُوذُ بِكَ مِنْكَ لَا مَانِعَ لِمَا أَعْطَيْتَ وَلَا مُعْطِيَ لِمَا مَنَعْتَ وَلَا يَنْفَعُ ذَا الْجَدِّ مِنْكَ الْجَدُّ قَالَ وَحَدَّثَنِي كَعْبٌ أَنَّ صُهَيْبًا حَدَّثَهُ أَنَّ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُهُنَّ عِنْدَ انْصِرَافِهِ مِنْ صَلَاتِهِ","id":"Telah mengabarkan kepada kami ['Amru bin Sawwad bin Al Aswad bin 'Amru] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Hafsh bin Maisarah] dari [Musa bin 'Uqbah] dari ['Atha` bin Abu Marwan] dari [Ayahnya] bahwa Ka'ab bersumpah kepadanya; \"Demi Allah yang telah membelah laut untuk Musa, sungguh kami mendapatkan dalam Taurat bahwa Nabi Daud -Nabiyullah semoga shallawat dan salam tercurah baginya- apabila selesai shalat, dia mengucapkan; 'Ya Allah perbaikilah bagiku agamaku yang Engkau telah menjadikannya bagiku sebagai pelindung, dan perbaikilah duniaku yang Engkau telah menjadikannya sebagai tempat hidupku. Ya Allah aku berlindung dengan keridlaan-Mu dari kemurkaan-Mu, aku berlindung dengan ampunan-Mu dari siksa-Mu, aku berlindung kepada-Mu dari (siksa) -Mu. Ya Allah, tiada yang bisa menghalangi apa yang Engkau berikan dan tiada yang bisa memberi apa yang Engkau halangi. Tidaklah bermanfaat kekayaan dan harta benda bagi pemiliknya, dari-Mu lah segala kekayaan.\" Dan telah menceritakan kepadaku [Ka'ab] bahwa [Shuhaiban] telah menceritakannya bahwa Muhammad shallallahu 'alaihi wasallam juga membacanya ketika usai mengerjakan shalat (yaitu setelah salam -pent).\""},"1321":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُثْمَانَ الشَّحَّامِ عَنْ مُسْلِمِ بْنِ أَبِي بَكْرَةَ قَالَكَانَ أَبِي يَقُولُ فِي دُبُرِ الصَّلَاةِ اللَّهُمَّ إِنِّي أَعُوذُ بِكَ مِنْ الْكُفْرِ وَالْفَقْرِ وَعَذَابِ الْقَبْرِ فَكُنْتُ أَقُولُهُنَّ فَقَالَ أَبِي أَيْ بُنَيَّ عَمَّنْ أَخَذْتَ هَذَا قُلْتُ عَنْكَ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُهُنَّ فِي دُبُرِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dari ['Utsman Asy Syahham] dari [Muslim bin Abu Bakrah] dia berkata; [Bapakku] ketika selesai shalat mengucapkan (doa); 'Ya Allah, aku berlindung kepada-Mu dari kekufuran, kefakiran, dan adzab kubur'. Aku juga mengucapkannya, lalu Bapakku berkata; 'Wahai anakku, dari siapa kamu mengambil ini? ' Aku menjawab; 'Darimu'. bapakku kemudian berkata; 'Rasulullah Shallallahu 'Alahi Wa Sallam senantiasa mengucapkannya setiap selesai shalat.\" "},"1322":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَلَّتَانِ لَا يُحْصِيهِمَا رَجُلٌ مُسْلِمٌ إِلَّا دَخَلَ الْجَنَّةَ وَهُمَا يَسِيرٌ وَمَنْ يَعْمَلُ بِهِمَا قَلِيلٌ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَوَاتُ الْخَمْسُ يُسَبِّحُ أَحَدُكُمْ فِي دُبُرِ كُلِّ صَلَاةٍ عَشْرًا وَيَحْمَدُ عَشْرًا وَيُكَبِّرُ عَشْرًا فَهِيَ خَمْسُونَ وَمِائَةٌ فِي اللِّسَانِ وَأَلْفٌ وَخَمْسُ مِائَةٍ فِي الْمِيزَانِ وَأَنَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُهُنَّ بِيَدِهِ وَإِذَا أَوَى أَحَدُكُمْ إِلَى فِرَاشِهِ أَوْ مَضْجَعِهِ سَبَّحَ ثَلَاثًا وَثَلَاثِينَ وَحَمِدَ ثَلَاثًا وَثَلَاثِينَ وَكَبَّرَ أَرْبَعًا وَثَلَاثِينَ فَهِيَ مِائَةٌ عَلَى اللِّسَانِ وَأَلْفٌ فِي الْمِيزَانِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيُّكُمْ يَعْمَلُ فِي كُلِّ يَوْمٍ وَلَيْلَةٍ أَلْفَيْنِ وَخَمْسَ مِائَةِ سَيِّئَةٍ قِيلَ يَا رَسُولَ اللَّهِ وَكَيْفَ لَا نُحْصِيهِمَا فَقَالَ إِنَّ الشَّيْطَانَ يَأْتِي أَحَدَكُمْ وَهُوَ فِي صَلَاتِهِ فَيَقُولُ اذْكُرْ كَذَا اذْكُرْ كَذَا وَيَأْتِيهِ عِنْدَ مَنَامِهِ فَيُنِيمُهُ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] dia berkata; telah menceritakan kepada kami [Hammad] dari ['Atha bin As Saib] dari [bapaknya] dari ['Abdullah bin 'Amru] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda, \"Ada dua perkara yang jika dilakukan oleh orang muslim maka ia masuk surga. Kedua perkara tersebut ringan, namun jarang yang mengamalkannya.\" Abdullah bin 'Amru melanjutkan, \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda lagi: 'Shalat lima waktu lalu setiap selesai shalat bertasbih sepuluh kali, bertahmid sepuluh kali, dan bertakbir sepuluh kali. Semua hal tersebut bernilai seratus lima puluh di lisan dan seribu lima ratus di mizan (timbangan amal di akhirat). Aku melihat Rasulullah Shalallahu 'Alaihi Wa Sallam menghitung dzikir dengan jari-jarinya, lalu bersabda: 'Jika kalian hendak menuju kasur atau tempat tidur, hendaklah bertasbih tiga puluh tiga kali, bertahmid tiga puluh tiga kali, serta bertakbir tiga puluh empat kali, maka hal itu bernilai seratus kali di lisan dan seribu di mizan.\" Abdullah bin Amru melanjutkan lagi, \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Siapakah diantara kalian yang berbuat dua ribu lima ratus kejelekan setiap siang dan malam hari? ' Lalu beliau Shalallahu 'Alaihi Wa Sallam ditanya, 'Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, bagaimana kami tidak menghitungnya? ' Beliau Shalallahu 'Alaihi Wa Sallam menjawab: 'Syetan mendatangi kalian yang sedang shalat sambil membisikkan, \"Ingatlah ini dan ingatlah itu\". Syetan juga datang ketika tidurnya dan membiusnya.\""},"1323":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ سَمُرَةَ عَنْ أَسْبَاطٍ قَالَ حَدَّثَنَا عَمْرُو بْنُ قَيْسٍ عَنْ الْحَكَمِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعَقِّبَاتٌ لَا يَخِيبُ قَائِلُهُنَّ يُسَبِّحُ اللَّهَ فِي دُبُرِ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَيَحْمَدُهُ ثَلَاثًا وَثَلَاثِينَ وَيُكَبِّرُهُ أَرْبَعًا وَثَلَاثِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Samurah] dari [Asbath] dia berkata; telah menceritakan kepada kami ['Amr bin Qais] dari [Al Hakim] dari ['Abdurrahman bin Abu Laila] dari [Ka'b bin 'Ujrah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Ada beberapa dzikir setelah shalat yang tidak merugikan bagi orang yang mengucapkannya, yaitu setiap selesai shalat bertasbih kepada Allah tiga puluh tiga kali, bertahmid kepada Allah tiga puluh tiga kali, serta bertakbir kepada Allah tiga puluh empat kali.\" "},"1324":{"ar":"أَخْبَرَنَا مُوسَى بْنُ حِزَامٍ التِّرْمِذِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ ابْنِ إِدْرِيسَ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ كَثِيرِ ابْنِ أَفْلَحَ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَأُمِرُوا أَنْ يُسَبِّحُوا دُبُرَ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَيَحْمَدُوا ثَلَاثًا وَثَلَاثِينَ وَيُكَبِّرُوا أَرْبَعًا وَثَلَاثِينَ فَأُتِيَ رَجُلٌ مِنْ الْأَنْصَارِ فِي مَنَامِهِ فَقِيلَ لَهُ أَمَرَكُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُسَبِّحُوا دُبُرَ كُلِّ صَلَاةٍ ثَلَاثًا وَثَلَاثِينَ وَتَحْمَدُوا ثَلَاثًا وَثَلَاثِينَ وَتُكَبِّرُوا أَرْبَعًا وَثَلَاثِينَ قَالَ نَعَمْ قَالَ فَاجْعَلُوهَا خَمْسًا وَعِشْرِينَ وَاجْعَلُوا فِيهَا التَّهْلِيلَ فَلَمَّا أَصْبَحَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ اجْعَلُوهَا كَذَلِكَ","id":"Telah mengabarkan kepada kami [Musa bin Hizam At Tirmidzi] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Ibnu Idris] dari [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Katsir bin Aflah] dari [Zaid bin Tsabit] dia berkata; \"Setiap selesai shalat mereka disuruh bertasbih kepada Allah tiga puluh tiga kali, bertahmid kepada Allah tiga puluh tiga kali, serta bertakbir kepada Allah tiga puluh empat kali. Kemudian ada seorang laki-laki Anshar yang bermimpi bahwa ada yang berkata kepadanya; 'Apakah Rasulullah Shalallahu 'Alaihi Wa Sallam menyuruh kalian bertasbih kepada Allah tiga puluh tiga kali, bertahmid kepada Allah tiga puluh tiga kali, serta bertakbir kepada Allah tiga puluh empat kali setiap selesai shalat? ' Ia menjawab, 'Ya'. Lalu ia mengatakan lagi, \"Maka jadikanlah dua puluh lima kali, dan jadikanlah juga ada kalimat tahlil!\" Lalu pagi harinya ia datang kepada Nabi Shallallahu 'Alahi Wa Sallam dan menceritakan hal itu kepadanya, lantas Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Jadikanlah seperti itu.\""},"1325":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْكَرِيمِ أَبُو زُرْعَةَ الرَّازِيُّ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ قَالَ حَدَّثَنِي عَلِيُّ بْنُ الْفُضَيْلِ بْنِ عِيَاضٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ أَبِي رَوَّادٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَجُلًا رَأَى فِيمَا يَرَى النَّائِمُ قِيلَ لَهُ بِأَيِّ شَيْءٍ أَمَرَكُمْ نَبِيُّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَمَرَنَا أَنْ نُسَبِّحَ ثَلَاثًا وَثَلَاثِينَ وَنَحْمَدَ ثَلَاثًا وَثَلَاثِينَ وَنُكَبِّرَ أَرْبَعًا وَثَلَاثِينَ فَتِلْكَ مِائَةٌ قَالَ سَبِّحُوا خَمْسًا وَعِشْرِينَ وَاحْمَدُوا خَمْسًا وَعِشْرِينَ وَكَبِّرُوا خَمْسًا وَعِشْرِينَ وَهَلِّلُوا خَمْسًا وَعِشْرِينَ فَتِلْكَ مِائَةٌ فَلَمَّا أَصْبَحَ ذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْعَلُوا كَمَا قَالَ الْأَنْصَارِيُّ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin 'Abdul Karim Abu Zur'ah Ar Razi] dia berkata; telah menceritakan kepada kami [Ahmad bin 'Abdullah bin Yunus] dia berkata; telah menceritakan kepadaku ['Ali bin Al Fudhail bin 'Iyadh] dari ['Abdul 'Aziz bin Abu Rawwad] dari [Nafi'] dari [Ibnu 'Umar] bahwa ada seseorang yang bermimpi, dan ia ditanya, \"Dengan apa Nabi Shalallahu 'Alaihi Wa Sallam memerintahkan kalian? ' Ia menjawab; \"Beliau Shalallahu 'Alaihi Wa Sallam memerintahkan kami bertasbih tiga puluh tiga kali, bertahmid tiga puluh tiga kali, serta bertakbir tiga puluh empat kali, setiap selesai shalat, maka itulah seratus (jumlahnya). Ia berkata; \"Bertasbihlah dua puluh lima kali, bertahmidlah dua puluh lima kali, bertakbirlah dua puluh lima kali, serta bertahlillah dua puluh lima kali, maka itulah seratus (jumlahnya) Pagi harinya dia menceritakan hal itu kepada Nabi Shalallahu 'Alaihi Wa Sallam, lalu beliau Shalallahu 'Alaihi Wa Sallam bersabda: \"Lakukanlah sebagaimana yang dikatakan oleh orang Anshar ini.\""},"1326":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى آلِ طَلْحَةَ قَالَ سَمِعْتُ كُرَيْبًا عَنْ ابْنِ عَبَّاسٍ عَنْ جُوَيْرِيَةَ بِنْتِ الْحَارِثِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ عَلَيْهَا وَهِيَ فِي الْمَسْجِدِ تَدْعُو ثُمَّ مَرَّ بِهَا قَرِيبًا مِنْ نِصْفِ النَّهَارِ فَقَالَ لَهَا مَا زِلْتِ عَلَى حَالِكِ قَالَتْ نَعَمْ قَالَ أَلَا أُعَلِّمُكِ يَعْنِي كَلِمَاتٍ تَقُولِينَهُنَّ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ عَدَدَ خَلْقِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ رِضَا نَفْسِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ زِنَةَ عَرْشِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ سُبْحَانَ اللَّهِ مِدَادَ كَلِمَاتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin 'Abdurrahman] -budak keluarga Thalhah- dia berkata; aku mendengar [Kuraib] dari [Ibnu 'Abbas] dari [Juwairiyyah bintu Al Harits] bahwa Nabi Shalallahu 'Alaihi Wa Sallam pernah melewatinya dan ia sedang berdoa di masjid. Kemudian beliau Shalallahu 'Alaihi Wa Sallam melewatinya lagi ketika menjelang Zhuhur pada pertengahan siang, lantas beliau bersabda kepadanya: \"Kamu masih dalam posisimu semula?\" Ia menjawab, \"Ya\". Lalu beliau Shalallahu 'Alaihi Wa Sallam meneruskan sabdanya: \"Maukah aku ajarkan tentang suatu kalimat yang bisa kamu ucapkan? -yang artinya- Maha suci Allah sejumlah bilangan mahluk-Nya, Maha suci Allah sejumlah bilangan mahluk-Nya, Maha suci Allah sejumlah bilangan mahluk-Nya, Maha suci Allah dengan keridlaan diri-Nya, Maha suci Allah dengan keridlaan diri-Nya, Maha suci Allah dengan keridlaan diri-Nya, Maha suci Allah (seberat) timbangan 'Arsy-Nya', Maha suci Allah (seberat) timbangan 'Arsy-Nya', Maha suci Allah (seberat) timbangan 'Arsy-Nya', Maha suci Allah sebanyak kalimat-Nya, Maha suci Allah sebanyak kalimat-Nya, Maha suci Allah sebanyak kalimat-Nya.\" "},"1327":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَتَّابٌ هُوَ ابْنُ بَشِيرٍ عَنْ خُصَيْفٍ عَنْ عِكْرِمَةَ وَمُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ الْفُقَرَاءُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّ الْأَغْنِيَاءَ يُصَلُّونَ كَمَا نُصَلِّي وَيَصُومُونَ كَمَا نَصُومُ وَلَهُمْ أَمْوَالٌ يَتَصَدَّقُونَ وَيُنْفِقُونَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتُمْ فَقُولُوا سُبْحَانَ اللَّهِ ثَلَاثًا وَثَلَاثِينَ وَالْحَمْدُ لِلَّهِ ثَلَاثًا وَثَلَاثِينَ وَاللَّهُ أَكْبَرُ ثَلَاثًا وَثَلَاثِينَ وَلَا إِلَهَ إِلَّا اللَّهُ عَشْرًا فَإِنَّكُمْ تُدْرِكُونَ بِذَلِكَ مَنْ سَبَقَكُمْ وَتَسْبِقُونَ مَنْ بَعْدَكُمْ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami ['Attab bin Basyir] dari [Khushaif] dari ['Ikrimah] dan [Mujahid] dari [Ibnu 'Abbas] dia berkata; \"Orang-orang fakir mendatangi Nabi shallallahu 'alaihi wasallam lalu mereka berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, orang-orang kaya shalat seperti kami shalat, mereka puasa sebagaimana kami puasa, dan mereka mempunyai kelebihan dari hartanya yang dapat mereka sedekahkan. Lalu Nabi shallallahu 'alaihi wasallam bersabda: 'Apabila kalian telah mengerjakan shalat maka ucapkanlah 'Subhaanallah' tigapuluh tiga kali, 'Alhamdulillah' tigapuluh tiga kali, 'Allahu Akbar' tigapuluh tiga kali, dan Laailaaha Illallah sepuluh kali maka dengan semua itu kalian dapat mengejar orang-orang yang telah mendahului kalian dan mendahului orang-orang setelah kalian."},"1328":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَفْصِ بْنِ عَبْدِ اللَّهِ النَّيْسَابُورِيُّ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ يَعْنِي ابْنَ طَهْمَانَ عَنْ الْحَجَّاجِ بْنِ الْحَجَّاجِ عَنْ أَبِي الزُّبَيْرِ عَنْ أَبِي عَلْقَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ سَبَّحَ فِي دُبُرِ صَلَاةِ الْغَدَاةِ مِائَةَ تَسْبِيحَةٍ وَهَلَّلَ مِائَةَ تَهْلِيلَةٍ غُفِرَتْ لَهُ ذُنُوبُهُ وَلَوْ كَانَتْ مِثْلَ زَبَدِ الْبَحْرِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh bin 'Abdullah An Naisaburi] dia berkata; [bapakku] telah menceritakan kepadaku, dia berkata; telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Al Hajjaj bin Al Hajjaj] dari [Abu Az Zubair] dari [Abu 'Alqamah] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu 'Alahi Wa Sallam bersabda: \"Barangsiapa ketika setiap selesai shalat Subuh bertasbih dan bertahlil seratus kali, dosanya akan diampuni, walaupun (banyaknya) laksana buih di lautan.\""},"1329":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ وَالْحُسَيْنُ بْنُ مُحَمَّدٍ الذَّارِعُ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا عَثَّامُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُ التَّسْبِيحَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la Ash-Shan'ani] dan [Al Husain bin Muhammad Adz-Dzari'] -dan lafadz ini miliknya- mereka berdua berkata; telah menceritakan kepada kami ['Atstsam bin 'Ali] dia berkata; telah menceritakan kepada kami [Al A'masy] dari ['Atha bin As Saib] dari [bapaknya] dari ['Abdullah bin 'Amru] dia berkata; \"Aku melihat Rasulullah Shallallahu 'Alahi Wa Sallam bertasbih dengan menggunakan jarinya -untuk menghitung jumlah tasbihnya.-\" "},"1330":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا بَكْرٌ وَهُوَ ابْنُ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُجَاوِرُ فِي الْعَشْرِ الَّذِي فِي وَسَطِ الشَّهْرِ فَإِذَا كَانَ مِنْ حِينِ يَمْضِي عِشْرُونَ لَيْلَةً وَيَسْتَقْبِلُ إِحْدَى وَعِشْرِينَ يَرْجِعُ إِلَى مَسْكَنِهِ وَيَرْجِعُ مَنْ كَانَ يُجَاوِرُ مَعَهُ ثُمَّ إِنَّهُ أَقَامَ فِي شَهْرٍ جَاوَرَ فِيهِ تِلْكَ اللَّيْلَةَ الَّتِي كَانَ يَرْجِعُ فِيهَا فَخَطَبَ النَّاسَ فَأَمَرَهُمْ بِمَا شَاءَ اللَّهُ ثُمَّ قَالَ إِنِّي كُنْتُ أُجَاوِرُ هَذِهِ الْعَشْرَ ثُمَّ بَدَا لِي أَنْ أُجَاوِرَ هَذِهِ الْعَشْرَ الْأَوَاخِرَ فَمَنْ كَانَ اعْتَكَفَ مَعِي فَلْيَثْبُتْ فِي مُعْتَكَفِهِ وَقَدْ رَأَيْتُ هَذِهِ اللَّيْلَةَ فَأُنْسِيتُهَا فَالْتَمِسُوهَا فِي الْعَشْرِ الْأَوَاخِرِ فِي كُلِّ وَتْرٍ وَقَدْ رَأَيْتُنِي أَسْجُدُ فِي مَاءٍ وَطِينٍقَالَ أَبُو سَعِيدٍ مُطِرْنَا لَيْلَةَ إِحْدَى وَعِشْرِينَ فَوَكَفَ الْمَسْجِدُ فِي مُصَلَّى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَظَرْتُ إِلَيْهِ وَقَدْ انْصَرَفَ مِنْ صَلَاةِ الصُّبْحِ وَوَجْهُهُ مُبْتَلٌّ طِينًا وَمَاءً","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Bakr bin Mudlar] dari [Ibnul Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Sa'id Al Khudri] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam beri'tikaf pada tanggal sepuluh di pertengahan bulan (Ramadhan), dan bila telah lewat dua puluh malam dan menjelang dua puluh satu maka beliau kembali ke rumahnya. Orang yang beri'tikaf dengannya juga ikut kembali. Kemudian beliau bangun malam di bulan tersebut dan beri'tikaf di malam yang ia pulang saat itu. Lalu beliau memberikan ceramah kepada orang-orang dan memerintahkan mereka dengan apa yang Allah kehendaki, kemudian beliau Shalallahu 'Alaihi Wa Sallam bersabda: 'Aku I'tikaf pada sepuluh malam ini, kemudian nampak bagiku untuk I'tikaf pada sepuluh terakhir. Barangsiapa I'tikaf bersamaku, maka tetaplah ia ditempat I'tikafnya, dan aku melihat malam ini kemudian aku dilupakan, maka carilah (lailatul qadar) pada sepuluh terakhir tiap malam ganjil. Aku melihat diriku sujud diatas air dan lumpur.\" Abu Sa'id berkata; \"Pada malam dua puluh satu kami diguyur hujan, dan masjid (Nabawi) saat itu bocor tepat pada tempat shalatnya Rasulullah Shalallahu 'Alaihi Wa Sallam. Lalu aku melihatnya dan beliau telah usai dari shalat Subuh dengan wajah berlumpur dan berair.\""},"1331":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الْفَجْرَ قَعَدَ فِي مُصَلَّاهُ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bila shalat fajar, beliau tetap duduk ditempat shalatnya hingga matahari terbit.\" "},"1332":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا زُهَيْرٌ وَذَكَرَ آخَرَ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَقُلْتُ لِجَابِرِ بْنِ سَمُرَةَ كُنْتَ تُجَالِسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى الْفَجْرَ جَلَسَ فِي مُصَلَّاهُ حَتَّى تَطْلُعَ الشَّمْسُ فَيَتَحَدَّثُ أَصْحَابُهُ يَذْكُرُونَ حَدِيثَ الْجَاهِلِيَّةِ وَيُنْشِدُونَ الشِّعْرَ وَيَضْحَكُونَ وَيَتَبَسَّمُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Zuhair] dan dia juga menyebutkan selainnya dari [Simak bin Harb] dia berkata; \"Aku pernah bertanya kepada [Jabir bin Samurah], 'Apakah engkau pernah duduk bersama Rasulullah Shallallahu 'Alahi Wa Sallam? ' Ia menjawab, 'Ya. Bila Rasulullah Shallallahu 'Alahi Wa Sallam shalat fajar, maka beliau duduk ditempat shalatnya hingga matahari terbit. Para sahabat bercerita tentang cerita-cerita jahiliyah, membacakan syair, dan tertawa, sedangkan Rasulullah Shallallahu 'Alahi Wa Sallam hanya tersenyum.\" "},"1333":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ السُّدِّيِّ قَالَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ كَيْفَ أَنْصَرِفُ إِذَا صَلَّيْتُ عَنْ يَمِينِي أَوْ عَنْ يَسَارِي قَالَ أَمَّا أَنَا فَأَكْثَرُ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْصَرِفُ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [As Suddi] dia berkata; aku bertanya kepada [Anas bin Malik], 'Bagaimana cara beranjak jika aku sudah selesai shalat? Dari sebelah kanan atau sebelah kiri? ' Ia menjawab; 'Aku sering melihat Rasulullah Shallallahu 'Alahi Wa Sallam beranjak pergi dari sebelah kanan.\""},"1334":{"ar":"أَخْبَرَنَا أَبُو حَفْصٍ عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ الْأَسْوَدِ قَالَ قَالَ عَبْدُ اللَّهِلَا يَجْعَلَنَّ أَحَدُكُمْ لِلشَّيْطَانِ مِنْ نَفْسِهِ جُزْءًا يَرَى أَنَّ حَتْمًا عَلَيْهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكْثَرَ انْصِرَافِهِ عَنْ يَسَارِهِ","id":"Telah mengabarkan kepada kami [Abu Hafsh 'Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Al A'masy] dari ['Umarah] dari [Al Aswad] dia berkata; ['Abdullah] berkata; \"Janganlah salah seorang dari kalian memberi bagian untuk syaithan pada dirinya, yaitu dengan mengharuskan seseorang untuk tidak beranjak dari shalat kecuali dari sebelah kanannya, sebab aku sendiri melihat Rasulullah Shallallahu 'Alahi Wa Sallam sering beranjak dari sebelah kirinya.\""},"1335":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا بَقِيَّةُ قَالَ حَدَّثَنَا الزُّبَيْدِيُّ أَنَّ مَكْحُولًا حَدَّثَهُ أَنَّ مَسْرُوقَ بْنَ الْأَجْدَعِ حَدَّثَهُ عَنْ عَائِشَةَ قَالَتْرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَشْرَبُ قَائِمًا وَقَاعِدًا وَيُصَلِّي حَافِيًا وَمُنْتَعِلًا وَيَنْصَرِفُ عَنْ يَمِينِهِ وَعَنْ شِمَالِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Baqiyyah] dia berkata; telah menceritakan kepada kami [Az Zubaidi], telah menceritakan kepadanya [Makhul] telah menceritakan kepadanya, [Masruq bin Al Azda'] dari ['Aisyah] dia berkata; \"Aku melihat Rasulullah Shallallahu 'Alahi Wa Sallam minum sambil berdiri, atau sambil duduk. Beliau mengerjakan shalat tanpa alas kaki, dan kadang memakai sandal. Beliau Shalallahu 'Alaihi Wa Sallam juga beranjak dari sebelah kanannya, atau dari sebelah kirinya.\" "},"1336":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ أَنْبَأَنَا عِيسَى بْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النِّسَاءُ يُصَلِّينَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْفَجْرَ فَكَانَ إِذَا سَلَّمَ انْصَرَفْنَ مُتَلَفِّعَاتٍ بِمُرُوطِهِنَّ فَلَا يُعْرَفْنَ مِنْ الْغَلَسِ","id":"Telah mengabarkan kepada kami ['Ali bin Khasyram] dia berkata; telah memberitakan kepada kami ['Isa bin Yunus] dari [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Para wanita shalat fajar bersama Rasulullah Shalallahu 'Alaihi Wa Sallam, dan bila beliau mengucapkan salam maka para wanita segera pulang seraya mengikatkan kain di kepalanya. Lalu mereka kembali -pulang- tanpa bisa dikenali karena masih gelap.\" "},"1337":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْمُخْتَارِ ابْنِ فُلْفُلٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ ثُمَّ أَقْبَلَ عَلَيْنَا بِوَجْهِهِ فَقَالَ إِنِّي إِمَامُكُمْ فَلَا تُبَادِرُونِي بِالرُّكُوعِ وَلَا بِالسُّجُودِ وَلَا بِالْقِيَامِ وَلَا بِالِانْصِرَافِ فَإِنِّي أَرَاكُمْ مِنْ أَمَامِي وَمِنْ خَلْفِي ثُمَّ قَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَوْ رَأَيْتُمْ مَا رَأَيْتُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا قُلْنَا مَا رَأَيْتَ يَا رَسُولَ اللَّهِ قَالَ رَأَيْتُ الْجَنَّةَ وَالنَّارَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami ['Ali bin Mushar] dari [Al Mukhtar bin Fulful] dari [Anas bin Malik] dia berkata; \"Suatu hari Rasulullah Shalallahu 'Alaihi Wa Sallam bersama kami, kemudian beliau menghadap kami lalu bersabda: 'Aku adalah imam kalian, maka janganlah kalian mendahuluiku saat ruku', sujud, berdiri, dan saat aku beranjak dari shalat. Sesungguhnya aku melihat kalian dari arah depan dan balakang.\" Kemudian beliau menambahkan, 'Demi Dzat yang jiwaku ada ditangan-Nya, seandainya kalian dapat melihat apa yang aku lihat, maka kalian pasti akan sedikit tertawa dan banyak menangis'. Kami bertanya, 'Apa yang engkau lihat wahai Rasulullah Shalallahu 'Alaihi Wa Sallam? ' Beliau menjawab: 'Aku melihat surga dan neraka.\""},"1338":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ وَهُوَ ابْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ أَبِي ذَرٍّ قَالَصُمْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَمَضَانَ فَلَمْ يَقُمْ بِنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَقِيَ سَبْعٌ مِنْ الشَّهْرِ فَقَامَ بِنَا حَتَّى ذَهَبَ نَحْوٌ مِنْ ثُلُثِ اللَّيْلِ ثُمَّ كَانَتْ سَادِسَةٌ فَلَمْ يَقُمْ بِنَا فَلَمَّا كَانَتْ الْخَامِسَةُ قَامَ بِنَا حَتَّى ذَهَبَ نَحْوٌ مِنْ شَطْرِ اللَّيْلِ قُلْنَا يَا رَسُولَ اللَّهِ لَوْ نَفَلْتَنَا قِيَامَ هَذِهِ اللَّيْلَةِ قَالَ إِنَّ الرَّجُلَ إِذَا صَلَّى مَعَ الْإِمَامِ حَتَّى يَنْصَرِفَ حُسِبَ لَهُ قِيَامُ لَيْلَةٍ قَالَ ثُمَّ كَانَتْ الرَّابِعَةُ فَلَمْ يَقُمْ بِنَا فَلَمَّا بَقِيَ ثُلُثٌ مِنْ الشَّهْرِ أَرْسَلَ إِلَى بَنَاتِهِ وَنِسَائِهِ وَحَشَدَ النَّاسَ فَقَامَ بِنَا حَتَّى خَشِينَا أَنْ يَفُوتَنَا الْفَلَاحُ ثُمَّ لَمْ يَقُمْ بِنَا شَيْئًا مِنْ الشَّهْرِقَالَ دَاوُدُ قُلْتُ مَا الْفَلَاحُ قَالَ السُّحُورُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dia berkata; telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Al Walid bin 'Abdurrahman] dari [Jubair bin Nufair] dari [Abu Dzarr] dia berkata; \"Kami puasa Ramadlan bersama Rasulullah Shalallahu 'Alaihi Wa Sallam. Rasulullah Shalallahu 'Alaihi Wa Sallam tidak bangun (shalat malam) bersama kami hingga tinggal tujuh hari dari bulan Ramadhan, lalu beliau bangun bersama kami hingga sepertiga malam. Kemudian pada malam keenam akhir Ramadhan, beliau tidak bangun (shalat malam). Setelah malam kelima beliau bangun (shalat malam) bersama kami hingga hampir lewat separuh malam. Lalu kami berkata kepada beliau, 'Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, bagaimana jika engkau ikut shalat sunah bersama kami malam ini? ' Beliau menjawab, \"Jika seseorang shalat bersama imam hingga usai, berarti ia telah menegakkan shalat malam.\" Ia berkata lagi, \"Pada malam keempat (menjelang berakhirnya Ramadhan) beliau tidak bangun (shalat malam) bersama kami. Setelah tinggal sepertiga dari bulan (Ramadhan) beliau mengutus seseorang kepada anak-anak perempuannya dan para istrinya, serta mengumpulkan orang-orang, lalu beliau shalat bersama kami hingga kami khawatir kehilangan waktu falah. Beliau tidak melakukan itu lagi pada bulan Ramadhan.\" Daud berkata; aku bertanya, apakah yang di maksud dengan falah? Al Walid menjawab; yaitu waktu sahur."},"1339":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ بَكَّارٍ الْحَرَّانِيُّ قَالَ حَدَّثَنَا بِشْرُ بْنُ السَّرِيِّ عَنْ عُمَرَ بْنِ سَعِيدِ بْنِ أَبِي حُسَيْنٍ النَّوْفَلِيِّ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ بِالْمَدِينَةِ ثُمَّ انْصَرَفَ يَتَخَطَّى رِقَابَ النَّاسِ سَرِيعًا حَتَّى تَعَجَّبَ النَّاسُ لِسُرْعَتِهِ فَتَبِعَهُ بَعْضُ أَصْحَابِهِ فَدَخَلَ عَلَى بَعْضِ أَزْوَاجِهِ ثُمَّ خَرَجَ فَقَالَ إِنِّي ذَكَرْتُ وَأَنَا فِي الْعَصْرِ شَيْئًا مِنْ تِبْرٍ كَانَ عِنْدَنَا فَكَرِهْتُ أَنْ يَبِيتَ عِنْدَنَا فَأَمَرْتُ بِقِسْمَتِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Bakkar Al Harrani] dia berkata; telah menceritakan kepada kami [Bisyr bin As Sari] dari ['Umar bin Sa'id bin Abu Husain An Naufali] dari [Ibnu Abu Mulaikah] dari ['Uqbah bin Al Harits] dia berkata; \"Aku shalat Ashar bersama Rasulullah Shallallahu 'Alahi Wa Sallam di Madinah, kemudian beliau melangkahi pundak jamaah dengan cepat hingga orang-orang keheranan karena sangat cepatnya. Sebagian sahabat ada yang mengikutinya. Beliau menemui sebagian istrinya, lalu keluar sambil berkata: 'Aku teringat emas yang ada padaku saat aku shalat Ashar. Aku tidak suka barang tersebut menginap di tempatku, maka aku menyuruh untuk dibagikan.\" "},"1340":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ عَنْ هِشَامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ يَوْمَ الْخَنْدَقِ بَعْدَ مَا غَرَبَتْ الشَّمْسُ جَعَلَ يَسُبُّ كُفَّارَ قُرَيْشٍ وَقَالَ يَا رَسُولَ اللَّهِ مَا كِدْتُ أَنْ أُصَلِّيَ حَتَّى كَادَتْ الشَّمْسُ تَغْرُبُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَاللَّهِ مَا صَلَّيْتُهَا فَنَزَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى بُطْحَانَ فَتَوَضَّأَ لِلصَّلَاةِ وَتَوَضَّأْنَا لَهَا فَصَلَّى الْعَصْرَ بَعْدَ مَا غَرَبَتْ الشَّمْسُ ثُمَّ صَلَّى بَعْدَهَا الْمَغْرِبَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dan [Muhammad bin 'Abdul A'la] mereka berdua berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dari [Hisyam] dari [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman] dari [Jabir bin 'Abdullah] bahwasa 'Umar bin Al Khaththab saat perang Khandaq -setelah matahari terbenam- mencela orang-orang kafir Quraisy, dia berkata kepada Rasulullah Shallallahu 'Alahi Wa Sallam, \"Wahai Rasulullah Shallallahu 'Alahi Wa Sallam, aku belum shalat hingga matahari hampir terbenam!\" Lalu Rasulullah Shallallahu 'Alahi Wa Sallam menjawab; \"Demi Allah, aku juga belum shalat!\" Kemudian aku bersama Rasulullah Shallallahu 'Alahi Wa Sallam turun ke Buthhan untuk mengambil air wudhu dan shalat. Beliau shalat Ashar setelah matahari terbenam, kemudian shalat Maghrib.\" "},"1341":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيُّ قَالَ حَدَّثَ��َا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ وَابْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُونَ السَّابِقُونَ بَيْدَ أَنَّهُمْ أُوتُوا الْكِتَابَ مِنْ قَبْلِنَا وَأُوتِينَاهُ مِنْ بَعْدِهِمْ وَهَذَا الْيَوْمُ الَّذِي كَتَبَ اللَّهُ عَزَّ وَجَلَّ عَلَيْهِمْ فَاخْتَلَفُوا فِيهِ فَهَدَانَا اللَّهُ عَزَّ وَجَلَّ لَهُ يَعْنِي يَوْمَ الْجُمُعَةِ فَالنَّاسُ لَنَا فِيهِ تَبَعٌ الْيَهُودُ غَدًا وَالنَّصَارَى بَعْدَ غَدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Abdurrahman Al Makhzumi] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dan [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah Shallallahu 'Alahi Wa Sallam bersabda: 'Kita orang-orang terakhir dari -generasi- yang terdahulu. Mereka (orang-orang sebelum kita) Telah diberi kitab sebelum kita dan kita diberi kitab setelah mereka. Dan hari ini, yang Allah Azza wa Jalla tetapkan bagi mereka untuk berkumpul, justeru mereka berselisih tentangnya, kemudian Allah Azza wa Jalla memberi petunjuk kepada kita pada hari Jum'at, maka manusia mengikuti kita pada hari tersebut, sementara orang-orang Yahudi besok (Sabtu) dan orang Nasrani lusa (Minggu)."},"1342":{"ar":"أَخْبَرَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ وَعَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَضَلَّ اللَّهُ عَزَّ وَجَلَّ عَنْ الْجُمُعَةِ مَنْ كَانَ قَبْلَنَا فَكَانَ لِلْيَهُودِ يَوْمُ السَّبْتِ وَكَانَ لِلنَّصَارَى يَوْمُ الْأَحَدِ فَجَاءَ اللَّهُ عَزَّ وَجَلَّ بِنَا فَهَدَانَا لِيَوْمِ الْجُمُعَةِ فَجَعَلَ الْجُمُعَةَ وَالسَّبْتَ وَالْأَحَدَ وَكَذَلِكَ هُمْ لَنَا تَبَعٌ يَوْمَ الْقِيَامَةِ وَنَحْنُ الْآخِرُونَ مِنْ أَهْلِ الدُّنْيَا وَالْأَوَّلُونَ يَوْمَ الْقِيَامَةِ الْمَقْضِيُّ لَهُمْ قَبْلَ الْخَلَائِقِ","id":"Telah mengabarkan kepada kami [Washil bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Ibnu Fudhail] dari [Abu Malik Al Asyja'i] dari [Abu Hazim] dari [Abu Hurairah] dan dari [Rib'i bin Hirasy] dari [Hudzaifah] mereka berdua berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Allah Azza wa Jalla tidak menghadiahkan hari jumat kepada orang-orang sebelum kita, sehingga orang-orang Yahudi memperoleh hari Sabtu, dan orang-orang Nasrani memperoleh hari Ahad. Kemudian Allah Azza wa Jalla membawa kita dan memberi petunjuk kepada kita untuk memperoleh hari jumat, Sehingga jadilah yang Ia tetapkan hari suci yaitu hari Jum'at, Sabtu dan Ahad. Mereka (Yahudi dan Nasrani) mengikuti kita pada hari kiamat, sementara kita adalah orang terkahir dari penduduk dunia dan orang-orang pertama pada hari kiamat. Hal itu diputuskan bagi mereka sebelum makhluk-makhluk.\" "},"1343":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ عَبِيدَةَ بْنِ سُفْيَانَ الْحَضْرَمِيِّ عَنْ أَبِي الْجَعْدِ الضَّمْرِيِّ وَكَانَتْ لَهُ صُحْبَةٌعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ تَرَكَ ثَلَاثَ جُمَعٍ تَهَاوُنًا بِهَا طَبَعَ اللَّهُ عَلَى قَلْبِهِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Muhammad bin 'Amr] dari ['Abidah bin Sufyan Al Hadhrami] dari [Abul Ja'd Adh-Dhamri] -dia pernah menemani Rasulullah Shalallahu 'Alaihi Wa Sallam- dari Nabi Shalallahu 'Alaihi Wa Sallam, beliau Shalallahu 'Alaihi Wa Sallam bersabda: \"Barangsiapa meninggalkan shalat Jum'at selama tiga kali karena meremehkan, Allah menutup hatinya.\" "},"1344":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا أَبَانُ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ الْحَضْرَمِيِّ بْنِ لَاحِقٍ عَنْ زَيْدٍ عَنْ أَبِي سَلَّامٍ عَنْ الْحَكَمِ بْنِ مِينَاءَ أَنَّهُ سَمِعَ ابْنَ عَبَّاسٍ وَابْنَ عُمَرَ يُحَدِّثَانِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَهُوَ عَلَى أَعْوَادِ مِنْبَرِهِ لَيَنْتَهِيَنَّ أَقْوَامٌ عَنْ وَدْعِهِمْ الْجُمُعَاتِ أَوْ لَيَخْتِمَنَّ اللَّهُ عَلَى قُلُوبِهِمْ وَلَيَكُونُنَّ مِنْ الْغَافِلِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] dia berkata; telah menceritakan kepada kami [Habban] dia berkata; telah menceritakan kepada kami [Aban] dia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Al Hadhrami bin Lahiq] dari [Zaid] dari [Abu Sallam] dari [Al Hakam bin Mina] bahwasanya ia mendengar [Ibnu 'Abbas] dan [Ibnu 'Umar] menceritakan bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda -beliau di atas mimbar kayunya- \"Kaum-kaum itu tetap saja menghentikan kewajiban (shalat) Jum'at-nya, atau Allah menutup hati mereka dan menjadikannya orang-orang yang lalai!.\" "},"1345":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنِي الْمُفَضَّلُ بْنُ فَضَالَةَ عَنْ عَيَّاشِ بْنِ عَبَّاسٍ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَوَاحُ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah mengabarkan kepadaku [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dia berkata; telah menceritakan kepadaku [Al Mufadhdhal bin Fadhalah] dari ['Ayyasy bin 'Abbas] dari [Bukair bin Al Asyaj] dari [Nafi'] dari [Ibnu 'Umar] dari [Hafshah] -istri Nabi Shalallahu 'Alaihi Wa Sallam- bahwa Nabi Shallallahu 'Alahi Wa Sallam bersabda: \"Mendatangi shalat Jum'at hukumnya wajib bagi setiap (muslim) yang sudah baligh (dewasa).\" "},"1346":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ قُدَامَةَ بْنِ وَبَرَةَ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَرَكَ الْجُمُعَةَ مِنْ غَيْرِ عُذْرٍ فَلْيَتَصَدَّقْ بِدِينَارٍ فَإِنْ لَمْ يَجِدْ فَبِنِصْفِ دِينَارٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Yazid bin Harun] dia berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Qudamah bin Wabarah] dari [Samurah bin Jundub] dia berkata; Rasulullah Shalallahu 'Alaihi Wa sallam bersabda: \"Barangsiapa yang meninggalkan shalat jum'at tanpa ada udzur (alasan yang dibenarkan), hendaklah dia bersedekah dengan satu dinar, jika dia tidak bisa maka dengan setengah dinar."},"1347":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ الْأَعْرَجُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ عَلَيْهِ السَّلَام وَفِيهِ أُدْخِلَ الْجَنَّةَ وَفِيهِ أُخْرِجَ مِنْهَا","id":"Telah mengabarkan kepada kami [Suwaid bin Nashr] dia berkata; telah memberitakan kepada kami ['Abdullah] dari [Yunus] dari [Az Zuhri] dia berkata; telah menceritakan kepada kami ['Abdurrahman Al A'raj] bahwasanya ia mendengar [Abu Hurairah] berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Hari terbaik ketika matahari terbit adalah hari Jum'at. hari itu Nabi Adam dicipta, hari itu dia dimasukkan ke surga, dan hari itu pula ia dikeluarkan dari surga.\" "},"1348":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ أَفْضَلِ أَيَّامِكُمْ يَوْمَ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ عَلَيْهِ السَّلَام وَفِيهِ قُبِضَ وَفِيهِ النَّفْخَةُ وَفِيهِ الصَّعْقَةُ فَأَكْثِرُوا عَلَيَّ مِنْ الصَّلَاةِ فَإِنَّ صَلَاتَكُمْ مَعْرُوضَةٌ عَلَيَّ قَالُوا يَا رَسُولَ اللَّهِ وَكَيْفَ تُعْرَضُ صَلَاتُنَا عَلَيْكَ وَقَدْ أَرَمْتَ أَيْ يَقُولُونَ قَدْ بَلِيتَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ قَدْ حَرَّمَ عَلَى الْأَرْضِ أَنْ تَأْكُلَ أَجْسَادَ الْأَنْبِيَاءِ عَلَيْهِمْ السَّلَام","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dia berkata; telah menceritakan kepada kami [Husain Al Ju'fi] dari ['Abdurrahman bin Yazid bin Jabir] dari [Abul Asy'ats Ash Shan'ani] dari [Aus bin Aus] dari Nabi Shalallahu 'Alaihi Wa Sallam beliau bersabda: \"Hari kalian yang paling utama adalah hari Jum'at -karena- pada hari itu Nabi Adam dicipta, pada hari itu beliau diwafatkan, pada hari itu ditiupnya terompet (menjelang kiamat), dan pada hari (mereka) dijadikan pingsan. Maka perbanyaklah shalawat kepadaku -karena- shalawat kalian disampaikan kepadaku.\" Mereka (para sahabat) berkata; \"Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, bagaimana mungkin shalawat kami bisa disampaikan kepada engkau, sedangkan engkau telah meninggal? -atau mereka berkata; \"Telah hancur (tulangnya) \"- Beliau Shalallahu 'Alaihi Wa Sallam lalu berkata: \"Allah Azza wa Jalla mengharamkan tanah untuk memakan jasad para Nabi 'Alaihimus Salam.\" "},"1349":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ سَعِيدَ بْنَ أَبِي هِلَالٍ وَبُكَيْرَ بْنَ الْأَشَجِّ حَدَّثَاهُ عَنْ أَبِي بَكْرِ بْنِ الْمُنْكَدِرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغُسْلُ يَوْمَ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ وَالسِّوَاكُ وَيَمَسُّ مِنْ الطِّيبِ مَا قَدَرَ عَلَيْهِ إِلَّا أَنَّ بُكَيْرًا لَمْ يَذْكُرْ عَبْدَ الرَّحْمَنِ وَقَالَ فِي الطِّيبِ وَلَوْ مِنْ طِيبِ الْمَرْأَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari ['Amr bin Al Harits] bahwasanya [Sa'id bin Abu Hilal] dan [Bukair bin Al Asyaj] menceritakan kepadanya dari [Abu Bakar bin Al Munkadir] dari ['Amr bin Sulaim] dari ['Abdurrahman Bin Abu Sa'id] dari [bapaknya] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Mandi pada hari Jum'at -hukumnya- wajib bagi setiap orang yang sudah bermimpi (baligh), juga bersiwak dan memakai wewangian secukupnya.\" Tetapi dari jalur lain Bukair tidak menyebutkan nama Abdurrahman dan mengenai wewangian dia berkata; walaupun dengan wewangian yang biasa dipakai perempuan.'"},"1350":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Apabila salah seorang dari kalian menghadiri shalat Jum'at, hendaklah mandi (terlebih dahulu).\""},"1351":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Shafwan bin Sulaim] dari ['Atha bin Yasar] dari [Abu Sa'id Al Khudri] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Mandi pada hari Jum'at -hukumnya- wajib bagi orang yang baligh (dewasa).\" "},"1352":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى كُلِّ رَجُلٍ مُسْلِمٍ فِي كُلِّ سَبْعَةِ أَيَّامٍ غُسْلُ يَوْمٍ وَهُوَ يَوْمُ الْجُمُعَةِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; telah menceritakan kepada kami [Bisyr] dia berkata; telah menceritakan kepada kami [Dawud bin Abu Hind] dari [Abu Az Zubair] dari [Jabir] dia berkata; Rasulullah Shallallahu 'Alahi Wa Sallam bersabda: \"Setiap laki-laki muslim pada tiap tujuh hari wajib mandi dalam satu harinya, yaitu pada hari Jum'at.\" "},"1353":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ عَنْ الْوَلِيدِ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْعَلَاءِ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدِ بْنِ أَبِي بَكْرٍأَنَّهُمْ ذَكَرُوا غُسْلَ يَوْمِ الْجُمُعَةِ عِنْدَ عَائِشَةَ فَقَالَتْ إِنَّمَا كَانَ النَّاسُ يَسْكُنُونَ الْعَالِيَةَ فَيَحْضُرُونَ الْجُمُعَةَ وَبِهِمْ وَسَخٌ فَإِذَا أَصَابَهُمْ الرَّوْحُ سَطَعَتْ أَرْوَاحُهُمْ فَيَتَأَذَّى بِهَا النَّاسُ فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَوَ لَا يَغْتَسِلُونَ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dari [Al Walid] dia berkata; telah menceritakan kepada kami ['Abdullah bin Al 'Ala] bahwasanya ia mendengar [Al Qasim bin Muhammad bin Abu Bakr], mereka menyebutkan tentang mandi pada hari Jum'at kepada [Aisyah], ia berkata, \"Orang-orang yang tinggal ditempat tinggi (bukit) menghadiri shalat Jum'at dalam keadaan kotor, sehingga bila ada tiupan angin maka baunya menyebar dan mengganggu orang lain. Hal tersebut diberitahukan kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, maka beliau Shalallahu 'Alaihi Wa Sallam bersabda: \"Kenapa mereka tidak mandi.\" "},"1354":{"ar":"أَخْبَرَنَا أَبُو الْأَشْعَثِ عَنْ يَزِيدَ بْنِ زُرَيْعٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ يَوْمَ الْجُمُعَةِ فَبِهَا وَنِعْمَتْ وَمَنْ اغْتَسَلَ فَالْغُسْلُ أَفْضَلُقَالَ أَبُو عَبْد الرَّحْمَنِ الْحَسَنُ عَنْ سَمُرَةَ كِتَابًا وَلَمْ يَسْمَعْ الْحَسَنُ مِنْ سَمُرَةَ إِلَّا حَدِيثَ الْعَقِيقَةِ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats] dari [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Al Hasan] dari [Samurah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Barangsiapa berwudhu pada hari Jum'at, maka itu baik, dan barangsiapa mandi -pada hari Jum'at- maka itu lebih utama.\" Abu Abdurrahman berkata; dari Al Hasan dari Samurah lewat tulisan, karena Al Hasan belum pernah mendengar langsung dari Samurah kecuali Hadist tentang 'aqiqah. Wallahu Ta'ala? lam."},"1355":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ وَهَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارِ بْنِ بِلَالٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا أَبُو مُسْهِرٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَبْدِ الْعَزِيزِ عَنْ يَحْيَى بْنِ الْحَارِثِ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَسَّلَ وَاغْتَسَلَ وَغَدَا وَابْتَكَرَ وَدَنَا مِنْ الْإِمَامِ وَلَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ عَمَلُ سَنَةٍ صِيَامُهَا وَقِيَامُهَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur] dan [Harun bin Muhammad bin Bakkar bin Bilal] -dan lafadz ini miliknya- mereka berdua berkata; telah menceritakan kepada kami [Abu Mushir] dia berkata; telah menceritakan kepada kami [Sa'id bin 'Abdul 'Aziz] dari [Yahya bin Al Harits] dari [Abul Asy'ats Ash-Shan'ani] dari [Aus bin Aus] dari Nabi Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Barangsiapa menggauli istrinya dan mandi, lalu ia segera berangkat (ke masjid) sedini mungkin serta mendekat kepada imam, dan ia tidak melakukan hal yang sia-sia, setiap langkahnya laksana amalan satu tahun disertai puasa dan shalat malamnya.\""},"1356":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَأَى حُلَّةً فَقَالَ يَا رَسُولَ اللَّهِ لَوْ اشْتَرَيْتَ هَذِهِ فَلَبِسْتَهَا يَوْمَ الْجُمُعَةِ وَلِلْوَفْدِ إِذَا قَدِمُوا عَلَيْكَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَلْبَسُ هَذِهِ مَنْ لَا خَلَاقَ لَهُ فِي الْآخِرَةِ ثُمَّ جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلُهَا فَأَعْطَى عُمَرَ مِنْهَا حُلَّةً فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ كَسَوْتَنِيهَا وَقَدْ قُلْتَ فِي حُلَّةِ عُطَارِدٍ مَا قُلْتَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ أَكْسُكَهَا لِتَلْبَسَهَا فَكَسَاهَا عُمَرُ أَخًا لَهُ مُشْرِكًا بِمَكَّةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari ['Abdullah bin 'Umar] bahwa Umar bin Khattab melihat kain sutera, maka ia berkata, \"Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, bagaimana kalau membeli ini dan mengenakannya saat hari Jum'at, juga saat ada utusan yang datang kepadamu?\" Beliau Shalallahu 'Alaihi Wa Sallam lalu bersabda: \"Ini hanya dipakai oleh orang yang tidak mempunyai bagian pada hari akhir.\" Kemudian dia (Umar) datang lagi kepada Rasulullah Shalallahu 'Alaihi Wa Sallam seperti semula, lalu Rasulullah Shalallahu 'Alaihi Wa Sallam memberikan sutera tersebut kepadanya. Umar lalu berkata; \"Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, apakah engkau memerintahkanku agar memakainya, padahal engkau telah mengatakan (larangan) tentang sutera mewah itu?\" Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Aku memberimu bukan untuk dipakai.\" Lalu Umar memberikannya kepada saudaranya di Makkah yang masih musyrik. "},"1357":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ سَوَّارٍ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنَا خَالِدٌ عَنْ سَعِيدٍ عَنْ أَبِي بَكْرِ بْنِ الْمُنْكَدِرِ أَنَّ عَمْرَو بْنَ سُلَيْمٍ أَخْبَرَهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْغُسْلَ يَوْمَ الْجُمُعَةِ عَلَى كُلِّ مُحْتَلِمٍ وَالسِّوَاكَ وَأَنْ يَمَسَّ مِنْ الطِّيبِ مَا يَقْدِرُ عَلَيْهِ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Al Hasan bin Sawwar] dia berkata; telah menceritakan kepada kami [Al Laits] dia berkata; telah menceritakan kepada kami [Khalid] dari [Sa'id] dari [Abu Bakr bin Al Munkadir] bahwasanya ['Amru bin Sulaim] mengabarkan kepadanya dari ['Abdurrahman bin Abu Sa'id] dari [bapaknya] dari Rasulullah Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Mandi pada hari Jum'at wajib atas setiap orang yang baligh, juga siwak serta memakai parfum sesuai yang dimilikinya.\""},"1358":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ أَنَّهُ سَمِعَ أَبَا الْأَشْعَثِ حَدَّثَهُ أَنَّهُ سَمِعَ أَوْسَ بْنَ أَوْسٍ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ وَغَسَلَ وَغَدَا وَابْتَكَرَ وَمَشَى وَلَمْ يَرْكَبْ وَدَنَا مِنْ الْإِمَامِ وَأَنْصَتَ وَلَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ عَمَلُ سَنَةٍ","id":"Telah mengabarkan kepadaku ['Amr bin 'Utsman bin Sa'id bin Katsir] dia berkata; telah menceritakan kepada kami [Al Walid] dari ['Abdurrahman bin Yazid bin Jabir] bahwasanya ia mendengar [Abul Asy'ats] menceritakan kepadanya ia mendengar [Aus bin Aus] -sahabat Rasulullah Shalallahu 'Alaihi Wa Sallam- berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Barangsiapa mandi pada hari Jum'at dan berwudhu, lalu sedini mungkin berangkat dengan berjalan kaki tidak naik kendaraan, dan mendekat kepada imam lalu ia diam tanpa berbuat perbuatan yang sia-sia, tiap langkahnya laksana amalan (ibadah) satu tahun.\""},"1359":{"ar":"أَخْبَرَنَا نَصْرُ بْنُ عَلِيِّ بْنِ نَصْرٍ عَنْ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ الْأَغَرِّ أَبِي عَبْدِ اللَّهِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ قَعَدَتْ الْمَلَائِكَةُ عَلَى أَبْوَابِ الْمَسْجِدِ فَكَتَبُوا مَنْ جَاءَ إِلَى الْجُمُعَةِ فَإِذَا خَرَجَ الْإِمَامُ طَوَتْ الْمَلَائِكَةُ الصُّحُفَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُهَجِّرُ إِلَى الْجُمُعَةِ كَالْمُهْدِي بَدَنَةً ثُمَّ كَالْمُهْدِي بَقَرَةً ثُمَّ كَالْمُهْدِي شَاةً ثُمَّ كَالْمُهْدِي بَطَّةً ثُمَّ كَالْمُهْدِي دَجَاجَةً ثُمَّ كَالْمُهْدِي بَيْضَةً","id":"Telah mengabarkan kepada kami [Nashr bin 'Ali bin Nashr] dari ['Abdul A'la] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Aghar Abu 'Abdullah] dari [Abu Hurairah] bahwa Nabi Shalallahu 'Alaihi Wa Sallam bersabda: \"Bila datang hari Jum'at, para malaikat duduk di pintu-pintu masjid untuk mencatat siapa yang menghadiri shalat Jum'at. Bila imam telah keluar (berkhutbah), maka malaikat menutup lembaran-lembarannya (buku catatan amal kebaikan).\" Abu Hurairah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Orang yang bersegera ke masjid seperti orang yang berkurban dengan seekor unta, yang datang setelahnya seperti berkurban dengan seekor sapi, orang yang datang setelahnya seperti berkurban dengan seekor kambing, yang datang setelahnya seperti berkurban dengan seekor bebek, yang datang setelahnya seperti berkurban dengan seekor ayam, dan yang datang setelahnya seperti berkurban dengan sebutir telur.\" "},"1360":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ كَانَ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِ الْمَسْجِدِ مَلَائِكَةٌ يَكْتُبُونَ النَّاسَ عَلَى مَنَازِلِهِمْ الْأَوَّلَ فَالْأَوَّلَ فَإِذَا خَرَجَ الْإِمَامُ طُوِيَتْ الصُّحُفُ وَاسْتَمَعُوا الْخُطْبَةَ فَالْمُهَجِّرُ إِلَى الصَّلَاةِ كَالْمُهْدِي بَدَنَةً ثُمَّ الَّذِي يَلِيهِ كَالْمُهْدِي بَقَرَةً ثُمَّ الَّذِي يَلِيهِ كَالْمُهْدِي كَبْشًا حَتَّى ذَكَرَ الدَّجَاجَةَ وَالْبَيْضَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] -sampai kepada Nabi Shalallahu 'Alaihi Wa Sallam- \"Pada hari Jum'at tiap-tiap pintu masjid ada malaikatnya yang mencatat orang-orang sesuai posisi mereka, yang pertama kemudian selanjutnya. Bila imam keluar (dari rumah lalu masuk masjid) maka malaikat menutup lembaran-lembarannya. Lalu mereka mendengarkan khutbah, maka orang yang bersegera ke masjid seperti orang yang berkurban dengan seekor unta, kemudian yang datang selanjutnya seperti orang yang berkurban dengan seekor sapi, lalu yang datang setelahnya seperti orang yang berkurban dengan seekor kambing.. hingga beliau menyebutkan ayam dan telur.\" "},"1361":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَقْعُدُ الْمَلَائِكَةُ يَوْمَ الْجُمُعَةِ عَلَى أَبْوَابِ الْمَسْجِدِ يَكْتُبُونَ النَّاسَ عَلَى مَنَازِلِهِمْ فَالنَّاسُ فِيهِ كَرَجُلٍ قَدَّمَ بَدَنَةً وَكَرَجُلٍ قَدَّمَ بَقَرَةً وَكَرَجُلٍ قَدَّمَ شَاةً وَكَرَجُلٍ قَدَّمَ دَجَاجَةً وَكَرَجُلٍ قَدَّمَ عُصْفُورًا وَكَرَجُلٍ قَدَّمَ بَيْضَةً","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] dia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dia berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] dari Rasulullah Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Para malaikat duduk di pintu-pintu masjid untuk mencatat orang-orang sesuai kedudukan mereka. Ada yang laksana berkurban dengan seekor unta, ada yang laksana berkurban dengan seekor sapi, ada yang laksana berkurban dengan seekor ayam, ada yang laksana berkurban dengan seekor burung, ada yang laksana berkurban dengan sebutir telur.\""},"1362":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ سُمَيٍّ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ غُسْلَ الْجَنَابَةِ ثُمَّ رَاحَ فَكَأَنَّمَا قَرَّبَ بَدَنَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّانِيَةِ فَكَأَنَّمَا قَرَّبَ بَقَرَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّالِثَةِ فَكَأَنَّمَا قَرَّبَ كَبْشًا وَمَنْ رَاحَ فِي السَّاعَةِ الرَّابِعَةِ فَكَأَنَّمَا قَرَّبَ دَجَاجَةً وَمَنْ رَاحَ فِي السَّاعَةِ الْخَامِسَةِ فَكَأَنَّمَا قَرَّبَ بَيْضَةً فَإِذَا خَرَجَ الْإِمَامُ حَضَرَتْ الْمَلَائِكَةُ يَسْتَمِعُونَ الذِّكْرَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Sumayya] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Barangsiapa mandi pada hari Jum'at sebagaimana mandi janabat, kemudian berangkat (ke masjid), ia laksana berkurban dengan seekor unta, barangsiapa yang berangkat di urutan kedua, ia seperti orang yang berkurban dengan seekor sapi. Lalu orang yang datang pada urutan ketiga, seperti orang yang berkurban dengan seekor kambing, orang yang datang pada urutan keempat seperti orang yang berkurban dengan seekor ayam, dan yang datang urutan kelima seperti orang yang berkurban dengan sebutir telur. Jika imam keluar (berkhutbah) maka para malaikat datang untuk mendengarkan khutbah.\""},"1363":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ الْجُلَاحِ مَوْلَى عَبْدِ الْعَزِيزِ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَوْمُ الْجُمُعَةِ اثْنَتَا عَشْرَةَ سَاعَةً لَا يُوجَدُ فِيهَا عَبْدٌ مُسْلِمٌ يَسْأَلُ اللَّهَ شَيْئًا إِلَّا آتَاهُ إِيَّاهُ فَالْتَمِسُوهَا آخِرَ سَاعَةٍ بَعْدَ الْعَصْرِ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad bin 'Amr] dan [Al Harits bin Miskin] secara baca dan aku mendengarnya, lafazh ini darinya, dari [Ibnu Wahb] dari ['Amr bin Al Harits] dari [Al Julah] -budak 'Abdul 'Aziz- bahwasanya ia mendengar [Abu Salamah bin 'Abdurrahman] menceritakan kepadanya dari [Jabir bin 'Abdullah] dari Rasulullah Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Pada hari Jum'at ada dua belas jam, dan tak ada seorang hamba pun yang meminta sesuatu kepada Allah pada jam-jam itu kecuali Allah akan memberinya. Jadi, carilah waktu tersebut pada akhir waktu Ashar.\" "},"1364":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا حَسَنُ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَرْجِعُ فَنُرِيحُ نَوَاضِحَنَا قُلْتُ أَيَّةَ سَاعَةٍ قَالَ زَوَالُ الشَّمْسِ","id":"Telah mengabarkan kepadaku [Harun bin 'Abdullah] dia berkata; telah menceritakan kepadaku [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Hasan bin 'Ayyasy] dia berkata; telah menceritakan kepada kami [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin 'Abdullah] dia berkata; \"Kami pernah shalat Jum'at bersama Rasulullah Shalallahu 'Alaihi Wa Sallam, kemudian kami pulang untuk mengistirahatkan hewan-hewan -yang kami pakai- kerja. Aku bertanya, \"Pada saat kapan?\" Ia menjawab, 'Ketika matahari tergelincir.\" "},"1365":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ عَنْ يَعْلَى بْنِ الْحَارِثِ قَالَ سَمِعْتُ إِيَاسَ بْنَ سَلَمَةَ بْنِ الْأَكْوَعِ يُحَدِّثُ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ ثُمَّ نَرْجِعُ وَلَيْسَ لِلْحِيطَانِ فَيْءٌ يُسْتَظَلُّ بِهِ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dia berkata; telah memberitakan kepada kami ['Abdurrahman] dari [Ya'la bin Al Harits] dia berkata; aku mendengar [Iyas bin Salamah bin Al Akwa'] menceritakan dari [bapaknya] dia berkata; \"Kami shalat Jum'at bersama Rasulullah Shallallahu 'Alahi Wa Sallam, kemudian kami pulang, dan tembok sudah tidak mempunyai bayangan untuk berteduh.\""},"1366":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي السَّائِبُ بْنُ يَزِيدَأَنَّ الْأَذَانَ كَانَ أَوَّلُ حِينَ يَجْلِسُ الْإِمَامُ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ فَلَمَّا كَانَ فِي خِلَافَةِ عُثْمَانَ وَكَثُرَ النَّاسُ أَمَرَ عُثْمَانُ يَوْمَ الْجُمُعَةِ بِالْأَذَانِ الثَّالِثِ فَأُذِّنَ بِهِ عَلَى الزَّوْرَاءِ فَثَبَتَ الْأَمْرُ عَلَى ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku [As Saib bin Yazid] bahwa pada masa Rasulullah Shalallahu 'Alaihi Wa Sallam, Abu Bakar, dan Umar, adzan pertama -pada hari Jum'at - dilakukan ketika imam telah duduk diatas mimbar, Sedangkan pada masa Utsman jumlah manusia telah bertambah banyak, sehingga Usman perintahkan pada hari Jum'at untuk adzan yang ketiga, lalu dikumandangkan di Zaura'. Dan hal ini menjadi tradisi yang terus dilestarikan. "},"1367":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ السَّائِبَ بْنَ يَزِيدَ أَخْبَرَهُ قَالَإِنَّمَا أَمَرَ بِالتَّأْذِينِ الثَّالِثِ عُثْمَانُ حِينَ كَثُرَ أَهْلُ الْمَدِينَةِ وَلَمْ يَكُنْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرُ مُؤَذِّنٍ وَاحِدٍ وَكَانَ التَّأْذِينُ يَوْمَ الْجُمُعَةِ حِينَ يَجْلِسُ الْإِمَامُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Ya'qub] dia berkata; [bapakku] telah menceritakan kepada kami dari [Shalih] dari [Ibnu Syihab] bahwasanya [As Saib bin Yazid] mengabarkan kepadanya dia berkata; \"Yang menyuruh adzan tiga kali adalah Utsman, saat penduduk Madinah bertambah banyak. Sedangkan pada masa Rasulullah Shalallahu 'Alaihi Wa Sallam hanya satu adzan, dan adzan pada hari Jum'at dikumandangkan ketika imam telah duduk.\""},"1368":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ عَنْ السَّائِبِ بْنِ يَزِيدَ قَالَكَانَ بِلَالٌ يُؤَذِّنُ إِذَا جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فَإِذَا نَزَلَ أَقَامَ ثُمَّ كَانَ كَذَلِكَ فِي زَمَنِ أَبِي بَكْرٍ وَعُمَرَ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dari [bapaknya] dari [Az Zuhri] dari [As Saib bin Yazid] dia berkata; \"Bilal mengumandangkan adzan saat Rasulullah Shalallahu 'Alaihi Wa Sallam telah duduk diatas mimbarnya, pada hari Jum'at. Bila beliau turun, ia segera menegakkan shalat, begitu pula pada zaman Abu Bakar dan Umar Radliallahu? nhuma.\" "},"1369":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا جَاءَ أَحَدُكُمْ وَقَدْ خَرَجَ الْإِمَامُ فَلْيُصَلِّ رَكْعَتَيْنِقَالَ شُعْبَةُ يَوْمَ الْجُمُعَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Amr bin Dinar] dia berkata; aku mendengar [Jabir bin 'Abdullah] berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda, 'Apabila salah seorang dari kalian datang (ke masjid) pada hari Jum'at, padahal imam telah keluar (untuk berkhutbah), shalatlah dua rakaat.\""},"1370":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ أَنَّ أَبَا الزُّبَيْرِ أَخْبَرَهُ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ يَسْتَنِدُ إِلَى جِذْعِ نَخْلَةٍ مِنْ سَوَارِي الْمَسْجِدِ فَلَمَّا صُنِعَ الْمِنْبَرُ وَاسْتَوَى عَلَيْهِ اضْطَرَبَتْ تِلْكَ السَّارِيَةُ كَحَنِينِ النَّاقَةِ حَتَّى سَمِعَهَا أَهْلُ الْمَسْجِدِ حَتَّى نَزَلَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَنَقَهَا فَسَكَتَتْ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] bahwasanya [Abu Az Zubair] mengabarkan kepadanya bahwasanya ia mendengar [Jabir bin 'Abdullah] berkata; \"Pada awal mulanya Rasulullah Shalallahu 'Alaihi Wa Sallam apabila menyampaikan khutbah, beliau bersandar ke batang pohon kurma yang termasuk tiang masjid. Setelah dibuatkan mimbar dan beliau jadikan tempat berdiri, merintihlah pohon kurma tersebut seperti suara rintihan unta betina, hingga didengar oleh orang-orang yang ada di masjid. Rasulullah Shalallahu 'Alaihi Wa Sallam lantas menghampirinya, memeluknya, maka ia pun terdiam.\" "},"1371":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَدَخَلَ الْمَسْجِدَ وَعَبْدُ الرَّحْمَنِ ابْنُ أُمِّ الْحَكَمِ يَخْطُبُ قَاعِدًا فَقَالَ انْظُرُوا إِلَى هَذَا يَخْطُبُ قَاعِدًا وَقَدْ قَالَ اللَّهُ عَزَّ وَجَلَّ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","id":"Telah mengabarkan kepada kami [Ahmad bin 'Abdullah bin Al Hakam] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari ['Amr bin Murrah] dari [Abu 'Ubaidah] dari [Ka'b bin 'Ujrah] dia berkata; \"Aku masuk ke masjid, dan Abdurrahman bin Ummu Hakam sedang khutbah sambil duduk.\" Lalu Ka'ab berkata; \"Lihatlah orang ini yang sedang khutbah sambil duduk! Padahal Allah Azza wa Jalla berfirman: \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhutbah) '. (Qs. Al Jumu'ah (62): 11).\""},"1372":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنِي عُمَرُ بْنُ عَبْدِ الْوَاحِدِ قَالَ سَمِعْتُ يَحْيَى بْنَ الْحَارِثِ يُحَدِّثُ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ أَوْسِ بْنِ أَوْسٍ الثَّقَفِيِّعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَسَّلَ وَاغْتَسَلَ وَابْتَكَرَ وَغَدَا وَدَنَا مِنْ الْإِمَامِ وَأَنْصَتَ ثُمَّ لَمْ يَلْغُ كَانَ لَهُ بِكُلِّ خُطْوَةٍ كَأَجْرِ سَنَةٍ صِيَامِهَا وَقِيَامِهَا","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dia berkata; telah menceritakan kepadaku ['Umar bin 'Abdul Wahid] dia berkata; aku mendengar [Yahya bin Al Harits] menceritakan dari [Abul Asy'ats Ash-Shan'ani] dari [Aus bin Aus Ats-Tsaqafi] dari Nabi Shalallahu 'Alaihi Wa Sallam beliau bersabda: \"Barangsiapa menggauli istrinya dan mandi pada hari Jum'at, lalu pergi sedini mungkin dan mendekat kepada imam, serta ia tidak melakukan hal yang sia-sia, setiap langkahnya laksana ibadah satu tahun, berikut puasa dan shalat malamnya.\""},"1373":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ مُعَاوِيَةَ بْنَ صَالِحٍ عَنْ أَبِي الزَّاهِرِيَّةِ عَنْ عَبْدِ اللَّهِ بْنِ بُسْرٍ قَالَكُنْتُ جَالِسًا إِلَى جَانِبِهِ يَوْمَ الْجُمُعَةِ فَقَالَ جَاءَ رَجُلٌ يَتَخَطَّى رِقَابَ النَّاسِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيْ اجْلِسْ فَقَدْ آذَيْتَ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; aku mendengar [Mu'awiyah bin Shalih] dari [Abu Az Zahiriyah] dari ['Abdullah bin Busr] dia berkata; \"Aku pernah duduk disampingnya pada hari Jum'at, lalu ia berkata; 'Ada seorang laki-laki datang dengan melangkahi pundak orang-orang (jamaah), maka Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'Duduklah, kamu telah mengganggu.\""},"1374":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ وَيُوسُفُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُجَاءَ رَجُلٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فَقَالَ لَهُ أَرَكَعْتَ رَكْعَتَيْنِ قَالَ لَا قَالَ فَارْكَعْ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dan [Yusuf bin Sa'id] -dan lafadz ini miliknya- mereka berdua berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku ['Amr bin Dinar] bahwasanya ia mendengar [Jabir bin 'Abdullah] berkata; \"Ada seorang laki-laki datang, sementara Nabi Shalallahu 'Alaihi Wa Sallam sedang berada diatas mimbar pada hari Jum'at, maka beliau bertanya: 'Sudahkah kamu shalat dua rakaat? ' Ia menjawab, 'Belum'. Beliau bersabda: 'Shalatlah'."},"1375":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ لِصَاحِبِهِ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ أَنْصِتْ فَقَدْ لَغَا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi Shalallahu 'Alaihi Wa Sallam, beliau bersabda: \"Barangsiapa pada hari Jum'at berkata kepada temannya, \"Diamlah\" padahal imam sedang khutbah, ia telah berbuat sia-sia.\""},"1376":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ إِبْرَاهِيمَ بْنِ قَارِظٍ وَعَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُمَا حَدَّثَاهُ أَنَّ أَبَا هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَ","id":"Telah mengabarkan kepada kami ['Abdul Malik bin Syu'aib bin Al Laits bin Sa'd] dia berkata; [bapakku] telah menceritakan kepadaku dari [kakekku] dia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab] dari ['Umar bin 'Abdul 'Aziz] dari ['Abdullah bin Ibrahim bin Qarizh] dan dari [Sa'id bin Al Musayyab] mereka berdua menceritakan kepadanya, bahwa [Abu Hurairah] berkata; \"Aku mendengar Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: 'jika kamu berkata kepada temanmu; \"Diamlah\" padahal imam sedang khutbah, ia telah berbuat sia-sia.\""},"1377":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي مَعْشَرٍ زِيَادِ بْنِ كُلَيْبٍ ع��نْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ الْقَرْثَعِ الضَّبِّيِّ وَكَانَ مِنْ الْقُرَّاءِ الْأَوَّلِينَ عَنْ سَلْمَانَ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ رَجُلٍ يَتَطَهَّرُ يَوْمَ الْجُمُعَةِ كَمَا أُمِرَ ثُمَّ يَخْرُجُ مِنْ بَيْتِهِ حَتَّى يَأْتِيَ الْجُمُعَةَ وَيُنْصِتُ حَتَّى يَقْضِيَ صَلَاتَهُ إِلَّا كَانَ كَفَّارَةً لِمَا قَبْلَهُ مِنْ الْجُمُعَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Abu Ma'syar Ziyad bin Kulaib] dari [Ibrahim] dari ['Alqamah] dari [Al Qartsa' Adh Dhabi] dan dia termasuk generasi pertama para Qurra', dari [Salman] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda bersabda kepadaku: 'Tidak ada seorangpun yang bersuci pada hari Jum'at sebagaimana yang diperintahkan, lalu keluar dari rumahnya hingga datang ke masjid, kemudian diam hingga selesai shalat, melainkan itu semua akan menjadi kafarat (penghapus) bagi dosanya satu Jum'at sebelumnya'.\""},"1378":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ يُحَدِّثُ عَنْ أَبِي عُبَيْدَةَ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَّمَنَا خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا وَسَيِّئَاتِ أَعْمَالِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ }{ يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَاءً وَاتَّقُوا اللَّهَ الَّذِي تَسَاءَلُونَ بِهِ وَالْأَرْحَامَ إِنَّ اللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا }{ يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا }قَالَ أَبُو عَبْد الرَّحْمَنِ أَبُو عُبَيْدَةَ لَمْ يَسْمَعْ مِنْ أَبِيهِ شَيْئًا وَلَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَلَا عَبْدُ الْجَبَّارِ بْنُ وَائِلِ بْنِ حُجْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; aku mendengar [Abu Ishaq] menceritakan dari [Abu 'Ubaidah] dari ['Abdullah] dari Nabi Shalallahu 'Alaihi Wa Sallam. Abdullah berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam telah mengajarkan Khutbah Hajah kepada kami, yaitu, 'Segala puji bagi Allah, kita memohon pertolongan dan ampunan kepadanya, berlindung kepadanya dari kejahatan jiwa kami dan kejelekan perbuatan-perbuatan kami. Barang siapa yang diberikan petunjuk oleh Allah, maka tidak akan ada yang bisa menyesatkannya. Barangsiapa yang telah Allah sesatkan, maka tidak akan ada yang bisa memberinya petunjuk. Aku bersaksi tiada tuhan (yang berhak disembah) kecuali Allah, dan aku bersaksi bahwa Muhammad adalah hamba dan utusannya'. Kemudian beliau membaca tiga ayat berikut ini: 'Wahai orang-orang yang beriman, bertakwalah kepada Allah dengan sebenar-benar takwa kepadanya, dan janganlah kamu mati melainkan dalam keadaan beragama Islam'. (Qs. Ali 'Imran (3): 102). 'Hai kalian manusia, bertakwalah kepada tuhanmu yang telah menciptakanmu dari diri yang satu, dan daripadanya Allah menciptakan istrinya, dan daripada keduanya Allah memperkembangbiakan laki-laki dan perempuan yang banyak, dan bertakwalah kepada Allah dengan (mempergunakan) nama-Nya kamu saling meminta satu dengan yang lain, dan (periharalah) hubungan Silaturrahim. Sesungguhnya Allah selalu menjaga dan mengawasimu'.\"(Qs. An-Nisaa'(4): 1). 'Hai orang-orang yang beriman, bertakwalah kepada Allah dan katakanlah perkataan yang benar'.\"(Qs. Al Ahzaab (33): 70). Abu Abdurrahman berkata; Abu Ubaidah tidak pernah mendengar dari Bapaknya sedikitpun, demikian juga Abdurrahman bin Abdullah bin Mas'ud dan Abdul Jabbar bin Wa'il bin Hujr. "},"1379":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا رَاحَ أَحَدُكُمْ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam berkhutbah kepada kami, 'Apabila salah seorang dari kalian hendak pergi shalat jum'at, hendaklah dia mandi'.\""},"1380":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ إِبْرَاهِيمَ بْنِ نَشِيطٍ أَنَّهُ سَأَلَ ابْنَ شِهَابٍ عَنْ الْغُسْلِ يَوْمَ الْجُمُعَةِ فَقَالَ سُنَّةٌ وَقَدْ حَدَّثَنِي بِهِ سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكَلَّمَ بِهَا عَلَى الْمِنْبَرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Ibrahim bin Nasyith] bahwasanya dia bertanya kepada [Ibnu Syihab] mengenai mandi pada hari Jum'at, maka dia menjawab; itu adalah sunnah dan sungguh telah menceritakan kepadaku [Salim bin 'Abdullah] dari [bapaknya] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam mengatakannya diatas mimbar."},"1381":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَهُوَ قَائِمٌ عَلَى الْمِنْبَرِ مَنْ جَاءَ مِنْكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْقَالَ أَبُو عَبْد الرَّحْمَنِ مَا أَعْلَمُ أَحَدًا تَابَعَ اللَّيْثَ عَلَى هَذَا الْإِسْنَادِ غَيْرَ ابْنِ جُرَيْجٍ وَأَصْحَابُ الزُّهْرِيِّ يَقُولُونَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ بَدَلَ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Abdullah bin 'Abdullah] dari ['Abdullah bin 'Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: -diatas mimbar-, \"Barang siapa hendak berangkat Shalat Jum'at, maka mandilah.\" Abu Abdurrahman berkata; 'Tidak seorang pun dalam hal ini yang mengikuti Al Laits selain [Ibnu Juraij], dan [para sahabat]. [Az Zuhri] mengatakan; dari [Salim bin Abdullah] dari [Bapaknya] sebagai pengganti Abdullah bin Abdullah bin Umar."},"1382":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ عَجْلَانَ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُجَاءَ رَجُلٌ يَوْمَ الْجُمُعَةِ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ بِهَيْئَةٍ بَذَّةٍ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَّيْتَ قَالَ لَا قَالَ صَلِّ رَكْعَتَيْنِ وَحَثَّ النَّاسَ عَلَى الصَّدَقَةِ فَأَلْقَوْا ثِيَابًا فَأَعْطَاهُ مِنْهَا ثَوْبَيْنِ فَلَمَّا كَانَتْ الْجُمُعَةُ الثَّانِيَةُ جَاءَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَحَثَّ النَّاسَ عَلَى الصَّدَقَةِ قَالَ فَأَلْقَى أَحَدَ ثَوْبَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَ هَذَا يَوْمَ الْجُمُعَةِ بِهَيْئَةٍ بَذَّةٍ فَأَمَرْتُ النَّاسَ بِالصَّدَقَةِ فَأَلْقَوْا ثِيَابًا فَأَمَرْتُ لَهُ مِنْهَا بِثَوْبَيْنِ ثُمَّ جَاءَ الْآنَ فَأَمَرْتُ النَّاسَ بِالصَّدَقَةِ فَأَلْقَى أَحَدَهُمَا فَانْتَهَرَهُ وَقَالَ خُذْ ثَوْبَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Yazid] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu 'Ajlan] dari ['Iyadh bin 'Abdullah] dia berkata; aku mendengar [Abu Sa'id Al Khudri] berkata; \"Pada hari Jum'at, ada seseorang datang ke masjid dengan lusuh; ketika Rasulullah shallallahu 'alaihi wasallam khutbah, Rasulullah shallallahu 'alaihi wasallam menegurnya, 'Apakah kamu sudah Shalat? ' Ia menjawab, 'belum'. Lalu Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: 'Shalatlah dua rakaat'. Kemudian beliau menganjurkan orang-orang untuk sedekah. Orang-orang pun segera melemparkan baju-bajunya, lalu beliau memberikan kepadanya dua baju. Pada hari Jum'at berikutnya datang lagi, dan saat itu Rasulullah shallallahu 'alaihi wasallam juga sedang khutbah, dan beliau shallallahu 'alaihi wasallam menganjurkan untuk sedekah.\" Abu Sa'id Al Khudri berkata, \"lalu ia (laki-laki tersebut) melemparkan salah satu bajunya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: 'Orang ini datang pada hari Jum'at dengan penampilan yang lusuh, aku menyuruh orang-orang untuk bersedekah, maka mereka melemparkan baju. Dan aku perintahkan agar memberinya dua baju. Kemudian sekarang dia dia datang lagi, dan aku menyuruh orang-orang untuk bersedekah, namun ia melemparkan salah satu bajunya'. Rasulullah shallallahu 'alaihi wasallam menghardiknya sambil berkata, 'Ambil bajumu! '"},"1383":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ جَاءَ رَجُلٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّيْتَ قَالَ لَا قَالَ قُمْ فَارْكَعْ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amr bin Dinar] dari [Jabir bin 'Abdullah] dia berkata; \"Pada saat Rasulullah shallallahu 'alaihi wasallam Khutbah pada hari Jum'at tiba-tiba ada seorang laki-laki yang datang, lalu beliau bersabda: 'Apakah kamu sudah shalat? ' ia menjawab; 'Belum'. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: 'Berdiri dan shalatlah.'\""},"1384":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو مُوسَى إِسْرَائِيلُ بْنُ مُوسَى قَالَ سَمِعْتُ الْحَسَنَ يَقُولُ سَمِعْتُ أَبَا بَكْرَةَ يَقُولُلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ وَالْحَسَنُ مَعَهُ وَهُوَ يُقْبِلُ عَلَى النَّاسِ مَرَّةً وَعَلَيْهِ مَرَّةً وَيَقُولُ إِنَّ ابْنِي هَذَا سَيِّدٌ وَلَعَلَّ اللَّهَ أَنْ يُصْلِحَ بِهِ بَيْنَ فِئَتَيْنِ مِنْ الْمُسْلِمِينَ عَظِيمَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Abu Musa Isra'il bin Musa] dia berkata; aku mendengar [Al Hasan] berkata; aku mendengar [Abu Bakrah] berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam di atas mimbar, dan Hasan bersamanya. Beliau kadang menghadap manusia, dan kadang menghadap ke arah Hasan, lalu bersabda: 'Cucuku ini adalah Sayyid (Pemimpin). Semoga Allah mendamaikan dua kelompok besar kaum muslimin dengan perantaranya'.\""},"1385":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا هَارُونُ بْنُ إِسْمَعِيلَ قَالَ حَدَّثَنَا عَلِيٌّ وَهُوَ ابْنُ الْمُبَارَكِ عَنْ يَحْيَى عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ ابْنَةِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْحَفِظْتُ ق وَالْقُرْآنِ الْمَجِيدِ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; telah menceritakan kepada kami [Harun bin Isma'il] dia berkata; telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya] dari [Muhammad bin 'Abdurrahman] dari [Bintu Haritsah bin An Nu'man] dia berkata; \"Aku hafal surat Qaaf Wal Qura'anil Majid dari lisan Rasulullah shallallahu 'alaihi wasallam saat itu beliau sedang berada di atas mimbar pada hari Jum'at.\""},"1386":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ حُصَيْنٍأَنَّ بِشْرَ بْنَ مَرْوَانَ رَفَعَ يَدَيْهِ يَوْمَ الْجُمُعَةِ عَلَى الْمِنْبَرِ فَسَبَّهُ عُمَارَةُ بْنُ رُوَيْبَةَ الثَّقَفِيُّ وَقَالَ مَا زَادَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى هَذَا وَأَشَارَ بِإِصْبَعِهِ السَّبَّابَةِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Hushain] bahwasanya Bisyr bin Marwan mengangkat tangannya pada hari Jum'at diatas mimbar, maka ['Umarah bin Ruwaibah Ats-Tsaqafi] mencelanya dan berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak lebih dari ini.\" Ia mengisyaratkan dengan telunjuknya."},"1387":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَجَاءَ الْحَسَنُ وَالْحُسَيْنُ رَضِي�� اللَّهُ عَنْهُمَا وَعَلَيْهِمَا قَمِيصَانِ أَحْمَرَانِ يَعْثُرَانِ فِيهِمَا فَنَزَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَطَعَ كَلَامَهُ فَحَمَلَهُمَا ثُمَّ عَادَ إِلَى الْمِنْبَرِ ثُمَّ قَالَ صَدَقَ اللَّهُ{ إِنَّمَا أَمْوَالُكُمْ وَأَوْلَادُكُمْ فِتْنَةٌ }رَأَيْتُ هَذَيْنِ يَعْثُرَانِ فِي قَمِيصَيْهِمَا فَلَمْ أَصْبِرْ حَتَّى قَطَعْتُ كَلَامِي فَحَمَلْتُهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul 'Aziz] dia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Husain bin Waqid] dari ['Abdullah bin Buraidah] dari [bapaknya] dia berkata; Rasulullah shallallahu 'alaihi wasallam sedang khutbah, lalu datang Hasan dan Husain radliallahu 'anhuma yang memakai baju merah. Keduanya lalu terjatuh, Rasulullah shallallahu 'alaihi wasallam turun dari mimbar dan menggendong keduanya lalu kembali ke mimbar dengan berkata: \"Maha benar Allah atas firman-Nya: 'Sesungguhnya hartamu dan anak-anakmu hanyalah sebagai cobaan'. (Qs. Al Anfaal (8): 28). Aku melihat kedua anak ini terjatuh dalam kedua bajunya, maka aku tidak sabar hingga aku memotong pembicaraanku lalu aku menggendong keduanya.\""},"1388":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ غَزْوَانَ قَالَ أَنْبَأَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي يَحْيَى بْنُ عُقَيْلٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ أَبِي أَوْفَى يَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُكْثِرُ الذِّكْرَ وَيُقِلُّ اللَّغْوَ وَيُطِيلُ الصَّلَاةَ وَيُقَصِّرُ الْخُطْبَةَ وَلَا يَأْنَفُ أَنْ يَمْشِيَ مَعَ الْأَرْمَلَةِ وَالْمِسْكِينِ فَيَقْضِيَ لَهُ الْحَاجَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul 'Aziz bin Ghazwan] dia berkata; telah memberitakan kepada kami [Al Fadhl bin Musa] dari [Al Husain bin Waqid] dia berkata; telah menceritakan kepadaku [Yahya bin 'Uqail] dia berkata; aku mendengar ['Abdullah bin Abu Aufa] berkata; \"Rasulullah shallallahu 'alaihi wasallam selalu memperbanyak dzikir dan sedikit melakukan perbuatan sia-sia. Beliau juga memperpanjang shalat dan mempersingkat khutbah, serta tidak sungkan untuk berjalan bersama para janda dan orang-orang miskin lalu memenuhi kebutuhannya.\""},"1389":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَجَالَسْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَا رَأَيْتُهُ يَخْطُبُ إِلَّا قَائِمًا وَيَجْلِسُ ثُمَّ يَقُومُ فَيَخْطُبُ الْخُطْبَةَ الْآخِرَةَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Syarik] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Aku pernah duduk bersama Rasulullah shallallahu 'alaihi wasallam dan aku tidak pernah melihatnya khutbah kecuali dengan berdiri, lalu duduk, kemudian berdiri lagi untuk khutbah yang terakhir.\""},"1390":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ الْخُطْبَتَيْنِ وَهُوَ قَائِمٌ وَكَانَ يَفْصِلُ بَيْنَهُمَا بِجُلُوسٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadladlal] dia berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari ['Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam menyampaikan dua khutbah sambil berdiri, dan memisahkan keduanya dengan duduk."},"1391":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ قَالَ حَدَّثَنَا إِسْرَائِيلُ قَالَ حَدَّثَنَا سِمَاكٌ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ قَائِمًا ثُمَّ يَقْعُدُ قِعْدَةً لَا يَتَكَلَّمُ ثُمَّ يَقُومُ فَيَخْطُبُ خُطْبَةً أُخْرَى فَمَنْ حَدَّثَكُمْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ قَاعِدًا فَقَدْ كَذَبَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Bazi'] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Isra'il] dia berkata; telah menceritakan kepada kami [Simak] dari [Jabir bin Samurah] dia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam khutbah pada hari Jum'at dalam keadaan berdiri, kemudian duduk sejenak tanpa berbicara, lalu berdiri lagi untuk menyampaikan khutbah yang terakhir. Barangsiapa menceritakan kepadamu bahwa Rasulullah shallallahu 'alaihi wasallam menyampaikan khutbah dalam keadaan duduk, ia berdusta.\""},"1392":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ وَيَقْرَأُ آيَاتٍ وَيَذْكُرُ اللَّهَ عَزَّ وَجَلَّ وَكَانَتْ خُطْبَتُهُ قَصْدًا وَصَلَاتُهُ قَصْدًا","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dari ['Abdurrahman] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Simak] dari [Jabir bin Samurah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyampaikan khutbah dalam keadaan berdiri, kemudian duduk, lalu berdiri dan membaca beberapa ayat serta berdzikir kepada Allah Azza wa Jalla. Khutbah beliau sederhana (tidak lama dan tidak sebentar) dan shalatnya juga sederhana (tidak lama dan tidak sebentar)."},"1393":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَلِيِّ بْنِ مَيْمُونٍ قَالَ حَدَّثَنَا الْفِرْيَابِيُّ قَالَ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْزِلُ عَنْ الْمِنْبَرِ فَيَعْرِضُ لَهُ الرَّجُلُ فَيُكَلِّمُهُ فَيَقُومُ مَعَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى يَقْضِيَ حَاجَتَهُ ثُمَّ يَتَقَدَّمُ إِلَى مُصَلَّاهُ فَيُصَلِّي","id":"Telah mengabarkan kepadaku [Muhammad bin 'Ali bin Maimun] dia berkata; telah menceritakan kepada kami [Al Firyabi] dia berkata; telah menceritakan kepada kami [Jarir bin Hazim] dari [Tsabit Al Bannani] dari [Anas] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah turun dari mimbar, tiba-tiba seseorang menghadangnya dan berbicara kepada beliau, lalu Nabi shallallahu 'alaihi wasallam mengajaknya berbicara dan menyelesaikan kebutuhannya, setelah itu beliau maju ketempat shalatnya dan shalat."},"1394":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ قَالَ عُمَرُصَلَاةُ الْجُمُعَةِ رَكْعَتَانِ وَصَلَاةُ الْفِطْرِ رَكْعَتَانِ وَصَلَاةُ الْأَضْحَى رَكْعَتَانِ وَصَلَاةُ السَّفَرِ رَكْعَتَانِ تَمَامٌ غَيْرُ قَصْرٍ عَلَى لِسَانِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ أَبُو عَبْد الرَّحْمَنِ عَبْدُ الرَّحْمَنِ بْنُ أَبِي لَيْلَى لَمْ يَسْمَعْ مِنْ عُمَرَ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Syarik] dari [Zubaid] dari ['Abdurrahman bin Abu Laila] dia berkata; ['Umar] berkata; \"Shalat Jum'at dua raka'at, shalat Idul Fitri dua raka'at, dan shalat Safar dua raka'at. Itu semua adalah sempurna, bukan qashar (diringkas) menurut lisan Rasulullah shallallahu 'alaihi wasallam.\" Abu Abdurrahman berkata; Abdurrahman bin Abu Laila tidak mendengar dari Umar."},"1395":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى الصَّنْعَانِيُّ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي مُخَوَّلٌ قَالَ سَمِعْتُ مُسْلِمًا الْبَطِينَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ يَوْمَ الْجُمُعَةِ فِي صَلَا��ِ الصُّبْحِ الم تَنْزِيلُ وَ هَلْ أَتَى عَلَى الْإِنْسَانِ وَفِي صَلَاةِ الْجُمُعَةِ بِسُورَةِ الْجُمُعَةِ وَالْمُنَافِقِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la Ash-Shan'ani] dia berkata; telah menceritakan kepada kami [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah mengabarkan kepadaku [Makhawwal] dia berkata; Aku mendengar [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at saat shalat Subuh membaca Alif Lam Mim Tanziil (surat As-Sajadah) dan Hal Ataa 'Alal Insaan (surah Al Insaan). Sedangkan pada shalat Jum'at beliau membaca surah Al Jumu'ah dan surah Al Munaafiquun."},"1396":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ قَالَ أَخْبَرَنِي مَعْبَدُ بْنُ خَالِدٍ عَنْ زَيْدِ بْنِ عُقْبَةَ عَنْ سَمُرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dia berkata; telah mengabarkan kepadaku [Ma'bad bin Khalid] dari [Zaid bin 'Uqbah] dari [Samurah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam membaca surah Al A'laa dan Al Ghaasyiyah dalam shalat Jum'at.\""},"1397":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ الضَّحَّاكَ بْنَ قَيْسٍ سَأَلَ النُّعْمَانَ بْنَ بَشِيرٍ مَاذَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ يَوْمَ الْجُمُعَةِ عَلَى إِثْرِ سُورَةِ الْجُمُعَةِ قَالَ كَانَ يَقْرَأُ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Dhamrah bin Sa'id] dari ['Ubaidullah bin 'Abdullah] bahwasanya Adh Dhahhak bin Qais bertanya kepada [An Nu'man bin Basyir] \"Apa yang dibaca Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at, sesudah membaca surah Al Jumu'ah?\" Ia menjawab: \"Beliau membaca surah Al Ghaasyiyah (Hal ataaka hadiitsul ghasyiyah).\""},"1398":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ أَنَّ إِبْرَاهِيمَ بْنَ مُحَمَّدِ بْنِ الْمُنْتَشِرِ أَخْبَرَهُ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْجُمُعَةِ بِسَبِّحْ اسْمَ رَبِّكَ الْأَعْلَى وَ هَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ وَرُبَّمَا اجْتَمَعَ الْعِيدُ وَالْجُمُعَةُ فَيَقْرَأُ بِهِمَا فِيهِمَا جَمِيعًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] bahwasanya [Ibrahim bin Muhammad bin Al Muntasyir] mengabarkan kepadanya, dia berkata; Aku mendengar [bapakku] menceritakan dari [Habib bin Salim] dari [An Nu'man bin Basyir] dia berkata; Dalam shalat Jum'at, Rasulullah shallallahu 'alaihi wasallam membaca surah Al A'laa dan Al Ghasyiyah. Kadang hari raya bertepatan pada hari Jum'at, maka beliau membaca surah tersebut dalam kedua shalat tersebut.\""},"1399":{"ar":"أَخْبَرَنَا قُتَيْبَةُ وَمُحَمَّدُ بْنُ مَنْصُورٍ وَاللَّفْظُ لَهُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَدْرَكَ مِنْ صَلَاةِ الْجُمُعَةِ رَكْعَةً فَقَدْ أَدْرَكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dan [Muhammad bin Manshur] -dan lafadz ini miliknya- dari [Sufyan] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa yang mendapatkan satu raka'at shalat jum'at maka ia telah mendapatkan shalat jum'at tersebut.\""},"1400":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ الْجُمُعَةَ فَلْيُصَلِّ بَعْدَهَا أَرْبَعًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami [Jarir] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian mengerjakan shalat Jum'at, hendaklah dia shalat setelahnya empat raka'at.\""},"1401":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يُصَلِّي بَعْدَ الْجُمُعَةِ حَتَّى يَنْصَرِفَ فَيُصَلِّيَ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Nafi'] dari [Ibnu 'Umar] Bahwa Rasulullah shallallahu 'alaihi wasallam tidak mengerjakan shalat setelah shalat jum'at hingga beliau pulang lalu shalat dua raka'at."},"1402":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ فِي بَيْتِهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdurrazzaq] dia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [bapaknya], dia berkata; \"Rasulullah shallallahu 'alaihi wasallam shalat dua raka'at di rumahnya setelah shalat Jum'at.\""},"1403":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ عَنْ يَزِيدَ وَهُوَ ابْنُ هَارُونَ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ يُطِيلُ فِيهِمَا وَيَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ","id":"Telah mengabarkan kepada kami ['Abdah bin 'Abdullah] dari [Yazid bin Harun] dia berkata; telah memberitakan kepada kami [Syu'bah] dari [Ayyub] dari [Nafi'] dari [Ibnu 'Umar] bahwa dia shalat dua raka'at setelah shalat jum'at, dan dia memanjangkan shalatnya. Ibnu Umar berkata; Rasulullah shallallahu 'alaihi wasallam mengerjakan demikian."},"1404":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَيْتُ الطُّورَ فَوَجَدْتُ ثَمَّ كَعْبًا فَمَكَثْتُ أَنَا وَهُوَ يَوْمًا أُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُحَدِّثُنِي عَنْ التَّوْرَاةِ فَقُلْتُ لَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُهْبِطَ وَفِيهِ تِيبَ عَلَيْهِ وَفِيهِ قُبِضَ وَفِيهِ تَقُومُ السَّاعَةُ مَا عَلَى الْأَرْضِ مِنْ دَابَّةٍ إِلَّا وَهِيَ تُصْبِحُ يَوْمَ الْجُمُعَةِ مُصِيخَةً حَتَّى تَطْلُعَ الشَّمْسُ شَفَقًا مِنْ السَّاعَةِ إِلَّا ابْنَ آدَمَ وَفِيهِ سَاعَةٌ لَا يُصَادِفُهَا مُؤْمِنٌ وَهُوَ فِي الصَّلَاةِ يَسْأَلُ اللَّهَ فِيهَا شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ فَقَالَ كَعْبٌ ذَلِكَ يَوْمٌ فِي كُلِّ سَنَةٍ فَقُلْتُ بَلْ هِيَ فِي كُلِّ جُمُعَةٍ فَقَرَأَ كَعْبٌ التَّوْرَاةَ ثُمَّ قَالَ صَدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ فِي كُلِّ جُمُعَةٍفَخَرَجْتُ فَلَقِيتُ بَصْرَةَ بْنَ أَبِي بَصْرَةَ الْغِفَارِيَّ فَقَالَ مِنْ أَيْنَ جِئْتَ قُلْتُ مِنْ الطُّورِ قَالَ لَوْ لَقِيتُكَ مِنْ قَبْلِ أَنْ تَأْتِيَهُ لَمْ تَأْتِهِ قُلْتُ لَهُ وَلِمَ قَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تُعْمَلُ الْمَطِيُّ إِلَّا إِلَى ثَلَاثَةِ مَسَاجِدَ الْمَسْجِدِ الْحَرَامِ وَمَسْجِدِي وَمَسْجِدِ بَيْتِ الْمَقْدِسِ فَلَقِيتُ عَبْدَ اللَّهِ بْنَ سَلَامٍ فَقُلْتُ لَوْ رَأَيْتَنِي خَرَجْتُ إِلَى الطُّورِ فَلَقِيتُ كَعْبًا فَمَكَثْتُ أَنَا وَهُوَ يَوْمًا أُحَدِّثُهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَيُحَدِّثُنِي عَنْ التَّوْرَاةِ فَقُلْتُ لَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ فِيهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُهْبِطَ وَفِيهِ تِيبَ عَلَيْهِ وَفِيهِ قُبِضَ وَفِيهِ تَقُومُ السَّاعَةُ مَا عَلَى الْأَرْضِ مِنْ دَابَّةٍ إِلَّا وَهِيَ تُصْبِحُ يَوْمَ الْجُمُعَةِ مُصِيخَةً حَتَّى تَطْلُعَ الشَّمْسُ شَفَقًا مِنْ السَّاعَةِ إِلَّا ابْنَ آدَمَ وَفِيهِ سَاعَةٌ لَا يُصَادِفُهَا عَبْدٌ مُؤْمِنٌ وَهُوَ فِي الصَّلَاةِ يَسْأَلُ اللَّهَ شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ قَالَ كَعْبٌ ذَلِكَ يَوْمٌ فِي كُلِّ سَنَةٍ فَقَالَ عَبْدُ اللَّهِ بْنُ سَلَامٍ كَذَبَ كَعْبٌ قُلْتُ ثُمَّ قَرَأَ كَعْبٌ فَقَالَ صَدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ فِي كُلِّ جُمُعَةٍ فَقَالَ عَبْدُ اللَّهِ صَدَقَ كَعْبٌ إِنِّي لَأَعْلَمُ تِلْكَ السَّاعَةَ فَقُلْتُ يَا أَخِي حَدِّثْنِي بِهَا قَالَ هِيَ آخِرُ سَاعَةٍ مِنْ يَوْمِ الْجُمُعَةِ قَبْلَ أَنْ تَغِيبَ الشَّمْسُ فَقُلْتُ أَلَيْسَ قَدْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يُصَادِفُهَا مُؤْمِنٌ وَهُوَ فِي الصَّلَاةِ وَلَيْسَتْ تِلْكَ السَّاعَةَ صَلَاةٌ قَالَ أَلَيْسَ قَدْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى وَجَلَسَ يَنْتَظِرُ الصَّلَاةَ لَمْ يَزَلْ فِي صَلَاتِهِ حَتَّى تَأْتِيَهُ الصَّلَاةُ الَّتِي تُلَاقِيهَا قُلْتُ بَلَى قَالَ فَهُوَ كَذَلِكَ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Bakr bin Mudhar] dari [Ibnul Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] dia berkata; \"Aku pernah datang ke (bukit) Thur dan aku mendapati Ka'ab di sana. Lalu aku dan dia menginap di sana selama satu hari. Aku menceritakan hadits dari Rasulullah Shalallahu 'Alaihi Wa Sallam kepadanya, sementara dia menceritakan Taurat kepadaku. Aku berkata kepadanya 'Rasulullah Shalallahu 'Alaihi Wa Sallam pernah bersabda: \"Sebaik-baik hari selama matahari terbit adalah hari Jum'at. Pada hari itu nabi Adam diciptakan, pada hari itu beliau diturunkan, pada hari itu beliau diterima taubatnya, pada hari itu pula beliau wafat, dan pada hari itu pula kiamat akan terjadi. Semua hewan di muka bumi berada di pagi hari Jum'at dalam keadaan mengoptimalkan pendengarannya hingga terbitnya matahari karena takut akan datangnya hari kiamat kecuali manusia. Pada hari Jum 'at ada suatu waktu yang tidaklah seorang mukmin pun yang berdoa ketika shalatnya meminta sesuatu kepada Allah bertepatan waktu itu, kecuali Allah akan mengabulkannya\".' Ka'ab lalu berkata; 'Waktu itu hanya ada dalam satu hari di setiap tahun'. Lalu kukatakan, 'Bahkan waktu itu ada pada setiap hari Jum'at'. Lantas Ka'ab membaca Taurat. Kemudian berkata; 'Rasulullah Shalallahu 'Alaihi Wa Sallam benar, hari itu ada pada setiap hari Jum'at'. Lalu aku keluar dan berjumpa dengan [Bashrah bin Abu Bashrah Al Ghifari], dan dia berkata; 'Kamu datang dari mana? ' Aku menjawab, 'Dari thur'. Ia berkata; 'Kalau saja aku berjumpa denganmu sebelum kamu datang ke Thur, maka kamu tidak akan mendatanginya'. Aku bertanya kepadanya; 'Mengapa bisa begitu? ' Ia menjelaskan; 'Aku pernah mendengar Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Tidak dipersiapkan kendaraan (perjalanan) kecuali ketiga masjid, yaitu Masjidil Haram, masjidku ini, dan masjid Baitul Maqdis\". Aku juga berjumpa dengan Abdullah bin Salam, kukatakan bahwa aku keluar dari Thur dan berjumpa dengan Ka'ab, lalu aku dan dan dia menginap di sana selama satu hari, dan aku menceritakan hadits dari Rasulullah Shalallahu 'Alaihi Wa Sallam kepadanya, sedangkan dia menceritakan Taurat kepadaku, kemudian aku berkata kepadanya bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam pernah bersabda: 'Sebaik-baik hari matahari terbit adalah hari Jum'at. Pada hari itu nabi Adam diciptakan, pada hari itu beliau diturunkan, pada hari itu beliau diterima taubatnya, pada hari itu beliau wafat, dan pada hari itu pula kiamat terjadi. Semua hewan di muka bumi berada di pagi hari Jum'at dalam keadaan mengoptimalkan pendengarannya hingga terbitnya matahari kecuali manusia. Di hari Jum'at ada suatu waktu, yang ketika itu tidaklah seorang mukmin pun yang berdoa di dalam shalatnya dan meminta sesuatu kepada Allah bertepatan dengan waktu itu kecuali Allah akan mengabulkannya\".'Ka'ab lalu berkata, 'Waktu ada pada satu hari di setiap tahun'. [Abdullah bin Salam] kemudian mengatakan bahwa Ka'ab telah berdusta, maka kukatakan bahwa Ka'ab membaca Taurat kemudian berkata, 'Rasulullah benar, hari itu ada pada setiap Jum'at'. kemudian Abdullah bin Salam berkata, 'Ka'ab benar, dan aku sangat mengetahui tentang waktu itu! Aku memohon kepadanya, 'Wahai saudaraku, beritakanlah hal itu kepadaku? ' Ia menjawab, 'Waktu itu adalah waktu terakhir pada hari Jum'at, sebelum matahari terbenam'. Kemudian aku menyanggahnya dengan bertanya, Bukankah kamu mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Tidaklah seorang mukmin berdoa bertepatan dengan waktu tersebut dalam shalatnya?\" Bukankah waktu itu adalah saat masih shalat? ' dia menjawab dengan bertanya juga, 'Bukankah kamu juga mendengar Rasulullah Shallallahu'alaihiwasallam bersabda: \"Barangsiapa shalat lalu duduk untuk menunggu shalat, maka ia senantiasa dihitung dalam keadaan shalat hingga datang waktu shalat berikutnya?\" 'Aku menjawab 'Ya'. Ia berkata, 'Maka hal tersebut juga seperti itu.'"},"1405":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ خَالِدٍ عَنْ رَبَاحٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدٌ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ فِي الْجُمُعَةِ سَاعَةً لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ يَسْأَلُ اللَّهَ فِيهَا شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ","id":"Telah mengabarkan kepadaku [Muhammad bin Yahya bin 'Abdullah] dia berkata; telah menceritakan kepada kami [Ahmad bin Hanbal] dia berkata; telah menceritakan kepada kami [Ibrahim bin Khalid] dari [Rabah] dari [Ma'mar] dari [Az Zuhri] dia berkata; telah menceritakan kepadaku [Sa'id] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Pada hari Jum'at ada suatu waktu yang bila seorang muslim meminta sesuatu kepada Allah bertepatan dengan waktu tersebut, Allah pasti memberinya.\""},"1406":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجُمُعَةِ سَاعَةً لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ قَائِمٌ يُصَلِّي يَسْأَلُ اللَّهَ عَزَّ وَجَلَّ شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُ قُلْنَا يُقَلِّلُهَا يُزَهِّدُهَاقَالَ أَبُو عَبْد الرَّحْمَنِ لَا نَعْلَمُ أَحَدًا حَدَّثَ بِهَذَا الْحَدِيثِ غَيْرَ رَبَاحٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ إِلَّا أَيُّوبَ بْنَ سُوَيْدٍ فَإِنَّهُ حَدَّثَ بِهِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ وَأَيُّوبُ بْنُ سُوَيْدٍ مَتْرُوكُ الْحَدِيثِ","id":"Telah mengabarkan kepada kami ['Amru bin Zurarah] dia berkata; telah memberitakan kepada kami [Isma'il] dari [Ayyub] dari [Muhammad] dari [Abu Hurairah] dia berkata; bahwa Abu Al Qasim shallallahu 'alaihi wasallam bersabda: \"Pada hari Jum'at ada waktu yang bila ada seorang muslim shalat dan meminta sesuatu kepada Allah bertepatan dengan waktu itu, Allah Azza wa Jaalla pasti memberinya.\" Abu Abdurrahman berkata; 'Kami tidak mengetahui seorangpun yang menceritakan Hadist ini selain Rabah dari Ma'mar dari Az Zuhri. Juga Ayyub bin Suwaid yang menceritakan hal ini dari Yunus dari Az Zuhri dari Sa? d dan Abu Salamah. Ayyub bin Suwaid orangnya matrukul Hadist."},"1407":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ أَمِنَ النَّاسُ فَقَالَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah memberitakan kepada kami ['Abdullah bin Idris] dia berkata; telah memberitakan kepada kami [Ibnu Juraij] dari [Ibnu Abu 'Ammar] dari ['Abdullah bin Babaih] dari [Ya'la bin Umayyah] dia berkata;? ku pernah bertanya kepada ['Umar bin Al Khaththab] tentang ayat, 'Tidaklah apa-apa bagi kalian untuk mengqashar/meringkas shalat jika kalian takut (khawatir) diserang orang-orang kafir'. (Qs. An-Nisaa' (4): 101), bukankah sekarang manusia sudah merasa aman?!\" Lalu Umar menjawab, \"Aku juga heran seperti kamu, dan aku juga pernah bertanya kepada Rasulullah shallallahu 'alaihi wasallam seperti itu? Beliau menjawab: 'Itu sedekah yang Allah sedekahkan kepada kalian, maka terimalah sedekah-Nya'.\""},"1408":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أُمَيَّةَ بْنِ عَبْدِ اللَّهِ بْنِ خَالِدٍأَنَّهُ قَالَ لِعَبْدِ اللَّهِ بْنِ عُمَرَ إِنَّا نَجِدُ صَلَاةَ الْحَضَرِ وَصَلَاةَ الْخَوْفِ فِي الْقُرْآنِ وَلَا نَجِدُ صَلَاةَ السَّفَرِ فِي الْقُرْآنِ فَقَالَ لَهُ ابْنُ عُمَرَ يَا ابْنَ أَخِي إِنَّ اللَّهَ عَزَّ وَجَلَّ بَعَثَ إِلَيْنَا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا نَعْلَمُ شَيْئًا وَإِنَّمَا نَفْعَلُ كَمَا رَأَيْنَا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Abdullah bin Abu Bakr bin 'Abdurrahman] dari ['Umayyah bin 'Abdullah bin Khalid] bahwasanya ia pernah berkata kepada ['Abdullah bin 'Umar]; \"Kami telah mendapati shalat saat mukim dan shalat saat takut (perang) di dalam Al Qur'an, tetapi kami tidak mendapati di dalamnya tentang shalat dalam perjalanan (safar)?\" Ibnu Umar lalu berkata kepadanya; \"Wahai saudaraku, Allah Azza wa Jalla telah mengutus Muhammad shallallahu 'alaihi wasallam dalam keadaan kita tidak mengetahui apa-apa, dan kita tidak melakukan apa-apa selain apa yang dilakukan oleh Muhammad shallallahu 'alaihi wasallam.\""},"1409":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ ابْنِ سِيرِينَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ لَا يَخَافُ إِلَّا رَبَّ الْعَالَمِينَ يُصَلِّي رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Husyaim] dari [Manshur bin Zadzan] dari [Ibnu Sirin] dari [Ibnu 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam keluar dari Makkah menuju Madinah tanpa takut kecuali kepada Tuhan semesta alam, dan beliau mengerjakan shalat dua raka'at."},"1410":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ قَالَكُنَّا نَسِيرُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ مَكَّةَ وَالْمَدِينَةِ لَا نَخَافُ إِلَّا اللَّهَ عَزَّ وَجَلَّ نُصَلِّي رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad] dari [Ibnu 'Abbas] dia berkata; \"Kami pernah bepergian bersama Rasulullah shallallahu 'alaihi wasallam di antara Makkah dan Madinah tanpa takut kecuali kepada Allah Azza wa Jalla, lalu kami shalat dua raka'at."},"1411":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بْنِ خُمَيْرٍ قَالَ سَمِعْتُ حَبِيبَ بْنَ عُبَيْدٍ يُحَدِّثُ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ ابْنِ السِّمْطِ قَالَرَأَيْتُ عُمَرَ بْنَ الْخَطَّابِ يُصَلِّي بِذِي الْحُلَيْفَةِ رَكْعَتَيْنِ فَسَأَلْتُهُ عَنْ ذَلِكَ فَقَالَ إِنَّمَا أَفْعَلُ كَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [An Nadhr bin Syumail] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Yazid bin Khumair] dia berkata; Aku mendengar [Habib bin 'Ubaid] menceritakan dari [Jubair bin Nufair] dari [Ibnu As Simthi] dia berkata; \"Aku melihat [Umar bin Khaththab] shalat dua raka'at di Dzilhulaifah, maka aku tanyakan tentang hal itu lalu dia menjawab; Aku tidak melakukannya melainkan hanya karena aku melihat Rasulullah shallallahu 'alaihi wasallam melakukannya'.\""},"1412":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَحْيَى بْنِ أَبِي إِسْحَقَ عَنْ أَنَسٍ قَالَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَلَمْ يَزَلْ يَقْصُرُ حَتَّى رَجَعَ فَأَقَامَ بِهَا عَشْرًا","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Yahya bin Abu Ishaq] dari [Anas] dia berkata; \"Aku pernah berangkat bersama Rasulullah shallallahu 'alaihi wasallam dari Madinah menuju Makkah, dan beliau senantiasa mengqashar/meringkas shalat hingga beliau kembali. Kemudian beliau menetap di Makkah selama sepuluh hari.\""},"1413":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَلِيِّ بْنِ الْحَسَنِ بْنِ شَقِيقٍ قَالَ أَبِي أَنْبَأَنَا أَبُو حَمْزَةَ وَهُوَ السُّكَّرِيُّ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السَّفَرِ رَكْعَتَيْنِ وَمَعَ أَبِي بَكْرٍ رَكْعَتَيْنِ وَمَعَ عُمَرَ رَكْعَتَيْنِ رَضِيَ اللَّهُ عَنْهُمَا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ali bin Al Hasan bin Syaqiq]; berkata [bapakku]; telah memberitakan kepada kami [Abu Hamzah As Sukkari] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari ['Abdullah] dia berkata; \"Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Aku juga shalat dua raka'at ketika bersama Abu Bakar Radliallahu? nhu dan juga ketika bersama Umar Radliallahu? nhuma."},"1414":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ وَهُوَ ابْنُ حَبِيبٍ عَنْ شُعْبَةَ عَنْ زُبَيْدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ عُمَرَ قَالَصَلَاةُ الْجُمُعَةِ رَكْعَتَانِ وَالْفِطْرِ رَكْعَتَانِ وَالنَّحْرِ رَكْعَتَانِ وَالسَّفَرِ رَكْعَتَانِ تَمَامٌ غَيْرُ قَصْرٍ عَلَى لِسَانِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan bin Habib] dari [Syu'bah] dari [Zubaid] dari ['Abdurrahman bin Abu Laila] dari ['Umar] dia berkata; \"Shalat Jum'at dua raka'at, shalat Idul Fitri dua raka'at, shalat Idul Adha dua raka? t, dan juga safar dua raka'at. Itu semua (dilaksanakan) sempurna bukan qashar, menurut lisan Nabi shallallahu 'alaihi wasallam.\""},"1415":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدٌ عَنْ أَيُّوبَ وَهُوَ ابْنُ عَائِذٍ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ أَبِي الْحَجَّاجِ عَنْ ابْنِ عَبَّاسٍ قَالَفُرِضَتْ صَلَاةُ الْحَضَرِ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعًا وَصَلَاةُ السَّفَرِ رَكْعَتَيْنِ وَصَلَاةُ الْخَوْفِ رَكْعَةً","id":"Telah mengabarkan kepadaku [Muhammad bin Wahb] dia berkata; telah menceritakan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepadaku [Abu 'Abdurrahim] dia berkata; telah menceritakan kepadaku [Zaid] dari [Ayyub bin 'Aidz] dari [Bukair bin Al Akhnas] dari [Mujahid Abul Hajjaj] dari [Ibnu 'Abbas] dia berkata; \"Shalat empat raka'at diwajibkan bagi yang bermukim, melalui lisan Nabi shallallahu 'alaihi wasallam. Adapun shalat safar adalah dua raka'at dan shalat Khauf dilaksanakan satu raka'at.\""},"1416":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ مَاهَانَ قَالَ حَدَّثَنَا الْقَاسِمُ بْنُ مَالِكٍ عَنْ أَيُّوبَ بْنِ عَائِذٍ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ اللَّهَ عَزَّ وَجَلَّ فَرَضَ الصَّلَاةَ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَضَرِ أَرْبَعًا وَفِي السَّفَرِ رَكْعَتَيْنِ وَفِي الْخَوْفِ رَكْعَةً","id":"Telah mengabarkan kepada kami [Ya'qub bin Mahan] dia berkata; telah menceritakan kepada kami [Al Qasim bin Malik] dari [Ayyub bin 'Aidz] dari [Bukair bin Al Akhnas] dari [Mujahid] dari [Ibnu 'Abbas] dia berkata; \"Allah Azza wa Jalla mewajibkan shalat empat raka'at melalui lisan Nabi shallallahu 'alaihi wasallam saat mukim. Ketika dalam perjalanan dua raka'at dan ketika dalam keadaan khauf (takut) satu raka'at.\""},"1417":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى فِي حَدِيثِهِ عَنْ خَالِدِ بْنِ الْحَارِثِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ مُوسَى وَهُوَ ابْنُ سَلَمَةَ قَالَقُلْتُ لِابْنِ عَبَّاسٍ كَيْفَ أُصَلِّي بِمَكَّةَ إِذَا لَمْ أُصَلِّ فِي جَمَاعَةٍ قَالَ رَكْعَتَيْنِ سُنَّةَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul A'la] dalam haditsnya dari [Khalid bin Al Harits] dia berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dia berkata; Aku mendengar [Musa bin Salamah] berkata; \"Aku berkata kepada [Ibnu Abbas], 'Bagaimana cara kami shalat di Makkah bila aku tidak shalat berjama'ah? ' Ia menjawab, \"Dua raka'at. Itulah sunnah Abu Al Qasim shallallahu 'alaihi wasallam'.\""},"1418":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ قَالَ حَدَّثَنَا قَتَادَةُ أَنَّ مُوسَى بْنَ سَلَمَةَ حَدَّثَهُمْأَنَّهُ سَأَلَ ابْنَ عَبَّاسٍ قُلْتُ تَفُوتُنِي الصَّلَاةُ فِي جَمَاعَةٍ وَأَنَا بِالْبَطْحَاءِ مَا تَرَى أَنْ أُصَلِّيَ قَالَ رَكْعَتَيْنِ سُنَّةَ أَبِي الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Sa'id] dia berkata; telah menceritakan kepada kami [Qatadah] bahwasanya [Musa bin Salamah] menceritakan kepada meraka bahwa dia pernah bertanya kepada [Ibnu Abbas], \"Aku berkata, 'Aku ketinggalan -shalat- berjama'ah saat di Bathha', maka apa pendapatmu tentang caraku mengerjakan shalat? ' Ia menjawab; 'Shalat dua raka'at. Itu adalah Sunnah Abu Al Qasim shallallahu 'alaihi wasallam'.\""},"1419":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ وَهْبٍ الْخُزَاعِيِّ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى آمَنَ مَا كَانَ النَّاسُ وَأَكْثَرَهُ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abul Ahwash] dari [Abu Ishaq] dari [Haritsah bin Wahb Al Khuza'i] dia berkata; \"Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Mina -saat itu kondisi manusia sangat aman dan banyak-.\""},"1420":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا أَبُو إِسْحَقَ ح وَأَنْبَأَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ أَخْبَرَنِي أَبُو إِسْحَقَ عَنْ حَارِثَةَ بْنِ وَهْبٍ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى أَكْثَرَ مَا كَانَ النَّاسُ وَآمَنَهُ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Syu'bah] dia berkata; telah menceritakan kepada kami [Abu Ishaq]. Dan diriwayatkan pula dari jalur lain, telah memberitakan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah mengabarkan kepadaku [Abu Ishaq] dari [Haritsah bin Wahb] dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat dua raka'at bersama kami di Mina, saat itu kondisi manusia sangat banyak dan aman.\""},"1421":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ بُكَيْرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي سُلَيْمَانَ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى وَمَعَ أَبِي بَكْرٍ وَعُمَرَ رَكْعَتَيْنِ وَمَعَ عُثْمَانَ رَكْعَتَيْنِ صَدْرًا مِنْ إِمَارَتِهِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Bukair] dari [Muhammad bin 'Abdullah bin Abu Sulaiman] dari [Anas bin Malik] ia berkata; \"Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam di Mina. Juga pernah bersama Abu Bakar, Umar, dan Utsman pada awal pemerintahannya.\""},"1422":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ الْأَعْمَشِ قَالَ حَدَّثَنَا إِبْرَاهِيمُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ ح وَأَنْبَأَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُ قَالَصَلَّيْتُ بِمِنًى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul Wahid] dari [Al A'masy] dia berkata; telah menceritakan kepada kami [Ibrahim] dia berkata; aku mendengar ['Abdurrahman bin Yazid] dan diriwayatkan pula dari jalur lain, telah memberitakan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dari ['Abdullah radliallahu 'anhu] dia berkata; \"Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Mina.\""},"1423":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ خَشْرَمٍ قَالَ حَدَّثَنَا عِيسَى عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَصَلَّى عُثْمَانُ بِمِنًى أَرْبَعًا حَتَّى بَلَغَ ذَلِكَ عَبْدَ اللَّهِ فَقَالَ لَقَدْ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Ali bin Khusyram] dia berkata; telah menceritakan kepada kami ['Isa] dari [Al A'masy] dari [Ibrahim] dari ['Abdurrahman bin Yazid] dia berkata; \"Aku pernah shalat empat raka'at bersama Utsman di Mina. Hal tersebut sampai kepada [Abdullah], maka ia berkata; 'Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam'.\""},"1424":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ أَنْبَأَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِوَمَعَ أَبِي بَكْرٍ رَضِيَ اللَّهُ عَنْهُ رَكْعَتَيْنِ وَمَعَ عُمَرَ رَضِيَ اللَّهُ عَنْهُ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id] dia berkata; telah memberitakan kepada kami [Yahya] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu 'Umar] dia berkata; \"Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Mina. Aku juga shalat dua raka'at bersama Abu Bakar Radliallahu? nhu dan Umar Radliallahu? nhu.\""},"1425":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِوَصَلَّاهَا أَبُو بَكْرٍ رَكْعَتَيْنِ وَصَلَّاهَا عُمَرُ رَكْعَتَيْنِ وَصَلَّاهَا عُثْمَانُ صَدْرًا مِنْ خِلَافَتِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Umar] dari [bapaknya] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat dua raka'at di Mina. Abu Bakar dan Umar juga shalat dua raka'at di tempat tersebut, serta Utsman pada awal pemerintahannya.\""},"1426":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ فَكَانَ يُصَلِّي بِنَا رَكْعَتَيْنِ حَتَّى رَجَعْنَا قُلْتُ هَلْ أَقَامَ بِمَكَّةَ قَالَ نَعَمْ أَقَمْنَا بِهَا عَشْرًا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dia berkata; telah menceritakan kepada kami [Yazid] dia berkata; telah memberitakan kepada kami [Yahya bin Abu Ishaq] dari [Anas bin Malik] dia berkata; \"Kami pernah berangkat bersama Rasulullah shallallahu 'alaihi wasallam dari Madinah ke Makkah, dan beliau mengerjakan shalat dua raka'at hingga kami pulang.\" Saya bertanya, \"Apakah beliau bermukim di Makkah?\" Anas menjawab; \"Ya, kami menetap di Makkah selama sepuluh hari."},"1427":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ الْبَصْرِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ بِمَكَّةَ خَمْسَةَ عَشَرَ يُصَلِّي رَكْعَتَيْنِ رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Al Aswad Al Bashri] dia berkata; telah menceritakan kepada kami [Muhammad bin Rabi'ah] dari ['Abdul Humaid bin Ja'far] dari [Yazid bin Abu Habib] dari ['Irak bin Malik] dari ['Ubaidullah bin 'Abdullah] dari [Ibnu 'Abbas] Rasulullah shallallahu 'alaihi wasallam pernah menetap di Makkah selama lima belas hari (hari) dan beliau mengerjakan shalat dua raka'at, dua raka'at."},"1428":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْمَلِكِ بْنِ زَنْجُوَيْهِ عَنْ عَبْدِ الرَّزَّاقِ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي إِسْمَعِيلُ بْنُ مُحَمَّدِ بْنِ سَعْدٍ أَنَّ حُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ السَّائِبَ بْنَ يَزِيدَ أَخْبَرَهُ أَنَّهُ سَمِعَ الْعَلَاءَ بْنَ الْحَضْرَمِيِّ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْكُثُ الْمُهَاجِرُ بَعْدَ قَضَاءِ نُسُكِهِ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdul Malik bin Zanjuwaih] dari ['Abdurrazzaq] dari [Ibnu Juraij] dia berkata; telah mengabarkan kepadaku [Isma'il bin Muhammad bin Sa'ad] telah mengabarkan kepadanya [Humaid bin 'Abdurrahman] telah mengabarkan kepadanya [As Saib bin Yazid] bahwasa ia mendengar [Al 'Ala bin Al Hadhrami] berkata; Rasulullah bersabda: \"Orang yang hijrah menetap (di Makkah) selama tiga hari setelah selesai melaksanakan ibadah haji.\""},"1429":{"ar":"أَخْبَرَنَا أَبُو عَبْد الرَّحْمَنِ قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ فِي حَدِيثِهِ عَنْ سُفْيَانَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ حُمَيْدٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْعَلَاءِ بْنِ الْحَضْرَمِيِّ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمْكُثُ الْمُهَاجِرُ بِمَكَّةَ بَعْدَ نُسُكِهِ ثَلَاثًا","id":"Telah mengabarkan kepada kami Abu 'Abdurrahman, berkata [Al Harits bin Miskin]; secara baca dan aku mendengar Hadistnya dari [Sufyan] dari ['Abdurrahman bin Humaid] dari [As Saib bin Yazid] dari [Al 'Ala bin Al Hadhrami] dia berkata; bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang hijrah menetap di Makkah selama tiga hari setelah melaksanakan ibadah haji.\""},"1430":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى الصُّوفِيُّ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْعَلَاءُ بْنُ زُهَيْرٍ الْأَزْدِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّهَا اعْتَمَرَتْ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْمَدِينَةِ إِلَى مَكَّةَ حَتَّى إِذَا قَدِمَتْ مَكَّةَ قَالَتْ يَا رَسُولَ اللَّهِ بِأَبِي أَنْتَ وَأُمِّي قَصَرْتَ وَأَتْمَمْتُ وَأَفْطَرْتَ وَصُمْتُ قَالَ أَحْسَنْتِ يَا عَائِشَةُ وَمَا عَابَ عَلَيَّ","id":"Telah mengabarkan kepadaku [Ahmad bin Yahya Ash Shufi] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dia berkata; telah menceritakan kepada kami [Al 'Alaa bin Zuhair Al Azdi] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Al Aswad] dari ['Aisyah] bahwasanya ia melaksanakan umrah bersama Rasulullah Shalallahu 'Alaihi Wa Sallam dari Madinah ke Makkah. Tatkala sampai di Makkah Aisyah berkata; Wahai Rasulullah, demi Bapak dan Ibuku, bagaimana engkau mengqashar shalat padahal aku menyempurnakan shalatku, dan engkau berbuka sedangkan aku berpuasa? Rasulullah Shalallahu 'Alaihi Wa sallam menjawab: Engkau telah berbuat baik wahai ' Aisyah, namun aku pun tidak tercela."},"1431":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْعَلَاءُ بْنُ زُهَيْرٍ قَالَ حَدَّثَنَا وَبَرَةُ بْنُ عَبْدِ الرَّحْمَنِ قَالَكَانَ ابْنُ عُمَرَ لَا يَزِيدُ فِي السَّفَرِ عَلَى رَكْعَتَيْنِ لَا يُصَلِّي قَبْلَهَا وَلَا بَعْدَهَا فَقِيلَ لَهُ مَا هَذَا قَالَ هَكَذَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ","id":"Telah mengabarkan kepadaku [Ahmad bin Yahya] dia berkata; telah menceritakan kepada kami [Abu Nu'aim] dia berkata; telah menceritakan kepada kami [Al 'Ala bin Zuhair] dia berkata; telah menceritakan kepada kami [Wabarah bin 'Abdurrahman] dia berkata; \"Shalat Ibnu Umar dalam Safar (perjalanan) tidak pernah melebihi dua raka'at, dan dia tidak mengerjakan shalat sunnah sesudah maupun sebelumnya. Lalu [Ibnu Umar] ditanya, \"Apa ini? ' Ia menjawab; 'Begitulah, aku melihat Rasulullah shallallahu 'alaihi wasallam melakukannya'.\""},"1432":{"ar":"أَخْبَرَنِي نُوحُ بْنُ حَبِيبٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عِيسَى بْنُ حَفْصِ بْنِ عَاصِمٍ قَالَ حَدَّثَنِي أَبِي قَالَكُنْتُ مَعَ ابْنِ عُمَرَ فِي سَفَرٍ فَصَلَّى الظُّهْرَ وَالْعَصْرَ رَكْعَتَيْنِ ثُمَّ انْصَرَفَ إِلَى طِنْفِسَةٍ لَهُ فَرَأَى قَوْمًا يُسَبِّحُونَ قَالَ مَا يَصْنَعُ هَؤُلَاءِ قُلْتُ يُسَبِّحُونَ قَالَ لَوْ كُنْتُ مُصَلِّيًا قَبْلَهَا أَوْ بَعْدَهَا لَأَتْمَمْتُهَا صَحِبْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ لَا يَزِيدُ فِي السَّفَرِ عَلَى الرَّكْعَتَيْنِ وَأَبَا بَكْرٍ حَتَّى قُبِضَ وَعُمَرَ وَعُثْمَانَ رَضِيَ اللَّهُ عَنْهُمْ كَذَلِكَ","id":"Telah mengabarkan kepadaku [Nuh bin Habib] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; telah menceritakan kepada kami ['Isa bin Hafsh bin 'Ashim] dia berkata; [bapakku] telah menceritakan kepadaku, dia berkata; \"Aku pernah bersama [Ibnu Umar] dalam suatu perjalanan. Dia mengerjakan shalat Zhuhur dan Ashar dua raka'at, kemudian pergi ke tikarnya. Setelah itu ia melihat suatu kaum yang sedang bertasbih, maka dia berkata, 'Apa yang sedang mereka perbuat? ' Aku menjawab, 'Mereka sedang bertasbih'. Dia berkata lagi, 'Seandainya aku shalat sebelum dan sesudahnya, maka aku pasti menyempurnakannya. Aku pernah menemani Rasulullah shallallahu 'alaihi wasallam, dan beliau dalam perjalanan tidak pernah shalat lebih dari dua raka'at. Begitu pula Abu Bakar hingga wafat, Umar, serta Utsman Radliallahu? nhum'.\""},"1433":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ تَعَالَى لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّ اللَّهَ عَزَّ وَجَلَّ يُخَوِّفُ بِهِمَا عِبَادَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Hammad] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Matahari dan Bulan adalah dua tanda dari tanda-tanda kebesaran Allah Ta'ala. Keduanya tidak mengalami gerhana karena kematian atau kelahiran seseorang, tetapi Allah Azza wa Jalla menakut-nakuti hamba-Nya dengan keduanya'.\""},"1434":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ هُوَ الْمُغِيرَةُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا أَبُو مَسْعُودٍ الْجُرَيْرِيُّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَبَيْنَا أَنَا أَتَرَامَى بِأَسْهُمٍ لِي بِالْمَدِينَةِ إِذْ انْكَسَفَتْ الشَّمْسُ فَجَمَعْتُ أَسْهُمِي وَقُلْتُ لَأَنْظُرَنَّ مَا أَحْدَثَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كُسُوفِ الشَّمْسِ فَأَتَيْتُهُ مِمَّا يَلِي ظَهْرَهُ وَهُوَ فِي الْمَسْجِدِ فَجَعَلَ يُسَبِّحُ وَيُكَبِّرُ وَيَدْعُو حَتَّى حُسِرَ عَنْهَا قَالَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Abdullah bin Al Mubarak] dia berkata; telah menceritakan kepada kami [Abu Hasyim Al Mughirah bin Salamah] dia berkata; telah menceritakan kepada kami [Wuhaib] dia berkata; telah menceritakan kepada kami [Abu Mas'ud Al Jurairi] dari [Hayyan bin 'Umari] dia berkata; telah menceritakan kepada kami ['Abdurrahman bin Samurah] dia berkata; \"Ketika aku melemparkan anak panahku di Madinah, tiba-tiba terjadi gerhana Matahari, maka aku mengumpulkan anak panah tersebut lalu berkata; 'Aku akan memperhatikan apa yang diperbuat oleh Rasulullah shallallahu 'alaihi wasallam saat terjadi gerhana Matahari'. Aku mendatangi beliau dari belakangnya ketika beliau di Masjid. Beliau bertasbih, bertakbir, dan berdo'a hingga selesai gerhana.\" Ia berkata; \"kemudian beliau berdiri dan Shalat dua rakaat dengan empat kali sujud.\""},"1435":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ تَعَالَى فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dari ['Umar bin Al Harits] bahwasanya ['Abdurrahman bin Al Qasim] menceritakan kepadanya dari [bapaknya] dari ['Abdullah bin 'Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Matahari dan bulan tidak akan terjadi karena kelahiran atau kematian seseorang, tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah Ta'ala. Jika kalian melihat kedua gerhana tersebut maka Shalatlah.\""},"1436":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ إِسْمَعِيلَ قَالَ حَدَّثَنِي قَيْسٌ عَنْ أَبِي مَسْعُودٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; telah menceritakan kepada kami [Yahya] dari [Isma'il] dia berkata; telah menceritakan kepadaku [Qais] dari [Abu Mas'ud] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Matahari dan bulan tidak akan terjadi karena kelahiran atau kematian seseorang, tetapi keduanya adalah dua tanda diantara tanda-tanda kebesaran Allah Azza wa Jalla. Jika kalian melihat kedua gerhana tersebut, maka Shalatlah.\""},"1437":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ كَامِلٍ الْمَرْوَزِيُّ عَنْ هُشَيْمٍ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ عَزَّ وَجَلَّ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا حَتَّى تَنْجَلِيَ","id":"Telah mengabarkan kepada kami [Muhammad bin Kamil Al Marwazi] dari [Husyaim] dari [Yunus] dari [Al Hasan] dari [Abu Bakrah] dia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: 'Matahari dan bulan tidak akan terjadi karena kelahiran atau kematian seseorang, tetapi keduanya adalah dua tanda diantara tanda-tanda kebesaran Allah Azza wa Jalla. Jika kalian melihat kedua gerhana tersebut, maka Shalatlah hingga terang lagi'.\""},"1438":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا أَشْعَثُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَكُنَّا جُلُوسًا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَسَفَتْ الشَّمْسُ فَوَثَبَ يَجُرُّ ثَوْبَهُ فَصَلَّى رَكْعَتَيْنِ حَتَّى انْجَلَتْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dan [Muhammad bin 'Abdul A'la] mereka berdua berkata; telah menceritakan kepada kami [Khalid] dia berkata; telah menceritakan kepada kami [Asy'ats] dari [Al Hasan] dari [Abu Bakrah] dia berkata; \"ketika kami duduk bersama Nabi shallallahu 'alaihi wasallam, tiba-tiba terjadi gerhana Matahari. Beliau lalu beranjak sambil menarik bajunya, kemudian mengerjakan Shalat hingga terang kembali.\""},"1439":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُنَادِيًا يُنَادِي أَنْ الصَّلَاةَ جَامِعَةً فَاجْتَمَعُوا وَاصْطَفُّوا فَصَلَّى بِهِمْ أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami ['Amru bin 'Utsman bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \" Telah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, lalu Nabi shallallahu 'alaihi wasallam memerintahkan mu'adzin untuk menyeru 'Ash Shalatu Jami'ah' (marilah kita bersama tegakkan shalat), maka orang-orang berkumpul dan menyusun barisan, kemudian beliau shalat dua rakaat bersama mereka, dengan empat kali ruku' dan empat kali sujud.\""},"1440":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدِ بْنِ خَلِيٍّ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَسَفَتْ الشَّمْسُ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَامَ فَكَبَّرَ وَصَفَّ النَّاسُ وَرَاءَهُ فَاسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَ","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid bin Khali] dia berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [bapaknya] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] bahwasanya ['Aisyah] -istri Nabi shallallahu 'alaihi wasallam- berkata; \"-Ketika- terjadi gerhana pada masa Rasulullah shallallahu 'alaihi wasallam, beliau keluar menuju Masjid, kemudian berdiri dan bertakbir, maka orang-orang membuat shaf di belakang beliau. Beliau shalat empat kali ruku' dan empat kali sujud, sementara gerhana telah terang (usai) sebelum beliau selesai shalat.\""},"1441":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ عَنْ إِسْمَعِيلَ ابْنِ عُلَيَّةَ قَالَ حَدَّثَنَا سُفْيَانُ الثَّوْرِيُّ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عِنْدَ كُسُوفِ الشَّمْسِ ثَمَانِيَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍوَعَنْ عَطَاءٍ مِثْلُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dari [Isma'il bin 'Ulayyah] dia berkata; telah menceritakan kepada kami [Sufyan Ats-Tsauri] dari [Habib bin Abu Tsabit] dari [Thawus] dari [Ibnu 'Abbas] bahwa ketika terjadi gerhana Matahari Rasulullah Shalallahu 'Alaihi Wa sallam shalat dengan delapan kali ruku dan empat kali sujud. Dari [Atha] juga demikian."},"1442":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنَا حَبِيبُ بْنُ أَبِي ثَابِتٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى فِي كُسُوفٍ فَقَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ سَجَدَ وَالْأُخْرَى مِثْلُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Yahya] dari [Sufyan] dia berkata; telah menceritakan kepada kami [Habib bin Abu Tsabit] dari [Thawus] dari [Ibnu 'Abbas] dari Nabi Shalallahu 'Alaihi Wa Sallam, bahwa ketika terjadi gerhana beliau shalat. Beliau membaca ayat kemudian ruku, lalu membaca lagi kemudian ruku, lalu membaca lagi kemudian ruku, lalu membaca lagi kemudian ruku, setelah itu beliau sujud. Pada raka'at selanjutnya beliau melakukan seperti itu juga."},"1443":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ نَمِرٍ وَهُوَ عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ عَنْ الزُّهْرِيِّ عَنْ كَثِيرِ بْنِ عَبَّاسٍ ح وَأَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي كَثِيرُ بْنُ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى يَوْمَ كَسَفَتْ الشَّمْسُ أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami ['Amru bin 'Utsman bin Sa'id] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Ibnu Namir 'Abdurrahman bin Namir] dari [Az Zuhri] dari [Katsir bin 'Abbas]. Demikian juga diriwayatkan dari jalur lain, telah mengabarkan kepadaku ['Amru bin 'Utsman] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Al Auza'i] dari [Az Zuhri] dia berkata; telah mengabarkan kepadaku [Katsir bin 'Abbas] dari ['Abdullah bin 'Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat pada hari terjadinya gerhana Matahari dengan empat kali ruku' dan empat kali sujud dalam dua rakaat."},"1444":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ قَالَ أَخْبَرَنِي ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يُحَدِّثُ قَالَ حَدَّثَنِي مَنْ أُصَدِّقُ فَظَنَنْتُ أَنَّهُ يُرِيدُ عَائِشَةَ أَنَّهَا قَالَتْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ بِالنَّاسِ قِيَامًا شَدِيدًا يَقُومُ بِالنَّاسِ ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ فَرَكَعَ رَكْعَتَيْنِ فِي كُلِّ رَكْعَةٍ ثَلَاثَ رَكَعَاتٍ رَكَعَ الثَّالِثَةَ ثُمَّ سَجَدَ حَتَّى إِنَّ رِجَالًا يَوْمَئِذٍ يُغْشَى عَلَيْهِمْ حَتَّى إِنَّ سِجَالَ الْمَاءِ لَتُصَبُّ عَلَيْهِمْ مِمَّا قَامَ بِهِمْ يَقُولُ إِذَا رَكَعَ اللَّهُ أَكْبَرُ وَإِذَا رَفَعَ رَأْسَهُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَلَمْ يَنْصَرِفْ حَتَّى تَجَلَّتْ الشَّمْسُ فَقَامَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنْ آيَتَانِ مِنْ آيَاتِ اللَّهِ يُخَوِّفُكُمْ بِهِمَا فَإِذَا كَسَفَا فَافْزَعُوا إِلَى ذِكْرِ اللَّهِ عَزَّ وَجَلَّ حَتَّى يَنْجَلِيَا","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Ibnu 'Ulayyah] dia berkata; Telah mengabarkan kepadaku [Ibnu Juraij] dari ['Atha] dia berkata; Aku mendengar ['Ubaid bin 'Umair] bercerita, dia berkata; Telah menceritakan kepadaku orang yang aku percayai, -aku mengira dia adalah [Aisyah] - dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari. Maka Nabi shallallahu 'alaihi wasallam shalat bersama orang-orang dengan berdiri yang lama sekali, lalu beliau ruku', berdiri lagi, ruku lagi, berdiri lagi lalu ruku lagi. Beliau mengerjakan shalat dua raka'at dimana setiap rakaat tiga kali ruku'. Beliau ruku pada ketiga kalinya, lalu sujud. Beberapa orang ketika itu jatuh tidak sadarkan diri, karena lamanya beliau berdiri bersama mereka, sehingga dituangkan air seember keatas tubuh mereka. Apabila beliau ruku' maka beliau mengucapkan Allahu Akbar, dan apabila beliau bangkit dari ruku beliau mengucapkan: 'Sami'allah huliman hamidah'. Beliau tidak bangkit sampai matahari terang kembali. Lalu beliau berdiri, bertahmid dan memuji Allah kemudian bersabda: 'Matahari dan bulan tidak terjadi gerhana karena kematian atau kelahiran seseorang akan tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah Ta'ala, yang dengannya Allah memberi peringatan kepada kalian. Apabila keduanya mengalami gerhana maka segeralah kalian mengingat Allah Azza Wa Jalla (Shalat) hingga terang kembali.'"},"1445":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ فِي صَلَاةِ الْآيَاتِ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى سِتَّ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍقُلْتُ لِمُعَاذٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا شَكَّ وَلَا مِرْيَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [Bapakku] telah menceritakan kepadaku dari [Qatadah] -mengenai shalat gerhana- dari ['Atha] dari ['Ubaid bin 'Umair] dari ['Aisyah] bahwasanya Nabi shallallahu 'alaihi wasallam shalat dengan enam kali ruku' dan empat kali sujud. Aku berkata kepada Mua'adz, Apakah ini dari Nabi shallallahu 'alaihi wasallam? Dia menjawab; 'Tidak diragukan lagi.'"},"1446":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَكَبَّرَ وَصَفَّ النَّاسُ وَرَاءَهُ فَاقْتَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ قَامَ فَاقْتَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ سَجَدَ ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ فَاسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَ ثُمَّ قَامَ فَخَطَبَ النَّاسَ فَأَثْنَى عَلَى اللَّهِ عَزَّ وَجَلَّ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ تَعَالَى لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا حَتَّى يُفْرَجَ عَنْكُمْ وَقَالَ رَسُولُ اللَّه صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ فِي مَقَامِي هَذَا كُلَّ شَيْءٍ وُعِدْتُمْ لَقَدْ رَأَيْتُمُونِي أَرَدْتُ أَنْ آخُذَ قِطْفًا مِنْ الْجَنَّةِ حِينَ رَأَيْتُمُونِي جَعَلْتُ أَتَقَدَّمُ وَلَقَدْ رَأَيْتُ جَهَنَّمَ يَحْطِمُ بَعْضُهَا بَعْضًا حِينَ رَأَيْتُمُونِي تَأَخَّرْتُ وَرَأَيْتُ فِيهَا ابْنَ لُحَيٍّ وَهُوَ الَّذِي سَيَّبَ السَّوَائِبَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dari [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah] dia berkata; \"Pada masa hidup Rasulullah shallallahu 'alaihi wasallam, terjadi gerhana matahari. Beliau berdiri dan bertakbir, lalu orang-orang menyusun barisan di belakangnya. Beliau membaca bacaan yang panjang. Kemudian beliau bertakbir lalu ruku' dengan ruku' yang lama pula, lalu mengangkat kepalanya sambil mengucapkan; 'Sami' Allahu Liman Hamidah, Rabbana Wa Lakal Hamdu'. Kemudian beliau bangun lalu membaca bacaan yang panjang, namun lebih pendek dari yang pertama. Kemudian bertakbir dan ruku' dengan ruku' yang lama, namun lebih pendek dari yang pertama. Lalu beliau mengucapkan; 'Sami' Allahu Liman Hamidah, Rabbana Wa Lakal Hamdu', kemudian sujud. Selanjutnya Rasulullah shallallahu 'alaihi wasallam juga melakukan hal yang seperti itu pada rakaat berikutnya, maka lengkaplah menjadi empat kali ruku dan empat kali sujud. Dan matahari pun telah terang kembali sebelum beliau bangkit. Kemudian beliau berdiri dan menyampaikan khutbah kepada orang-orang. Beliau memuji Allah Azza Wa Jalla dengan sesuatu yang telah menjadi hak-Nya, lalu bersabda: 'Matahari dan bulan adalah dua tanda dari kebesaran Allah Ta'ala. Keduanya tidak terjadi gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat gerhana tersebut, maka shalatlah hingga disingkapkan (diperlihatkan) kembali'. Lalu Rasulullah shallallahu 'alaihi wasallam melanjutkan sabdanya: 'Pada tempatku ini aku melihat semua yang dijanjikan kepada kalian. Kalian telah melihat bahwa aku ingin memetik sesuatu dari surga ketika kalian melihat aku maju. Sungguh aku telah melihat neraka Jahannam bertumpang tindih sebagiannya pada sebagian lagi ketika kalian melihatku mundur, dan aku melihat Abu Luhaiy bersada disana, dan dia adalah orang yang membiarkan unta Saibah'.\""},"1447":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنُودِيَ الصَّلَاةُ جَامِعَةٌ فَاجْتَمَعَ النَّاسُ فَصَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, lalu diserukan; 'Ash-Shalatu Jami'ah' (mari kita dirikan shalat bersama), maka manusia berkumpul. Lalu beliau shalat bersama mereka empat ruku' dan empat sujud dalam dua rakaat.\""},"1448":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَسَجَدَ ثُمَّ فَعَلَ ذَلِكَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَادْعُوا اللَّهَ عَزَّ وَجَلَّ وَكَبِّرُوا وَتَصَدَّقُوا ثُمَّ قَالَ يَا أُمَّةَ مُحَمَّدٍ مَا مِنْ أَحَدٍ أَغْيَرُ مِنْ اللَّهِ عَزَّ وَجَلَّ أَنْ يَزْنِيَ عَبْدُهُ أَوْ تَزْنِيَ أَمَتُهُ يَا أُمَّةَ مُحَمَّدٍ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, maka Rasulullah shallallahu 'alaihi wasallam shalat bersama orang-orang. Beliau berdiri dan memperlama berdirinya, kemudian ruku' dan memperlama ruku'nya. Kemudian bangkit lagi dan memperlama berdirinya, namun lebih pendek daripada yang pertama. Lalu ruku' dan memperlama ruku'nya, namun lebih pendek dari ruku' yang pertama. Kemudian mengangkat (kepalanya dari ruku'), lalu sujud. Beliau juga melakukan hal tersebut pada raka'at berikutnya. Beliau lalu beranjak, dan matahari telah terang kembali. Kemudian beliau berkhutbah di hadapan orang-orang. Beliau memuji dan menyanjung-Nya, lalu bersabda: 'Matahari dan bulan adalah dua tanda diantara tanda-tanda kebesaran Allah Ta'ala. Keduanya tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat dua gerhana tersebut, maka berdoalah kepada Allah Azza wa Jalla, bertakbir, lalu bersedekahlah'. Kemudian ia melanjutkan sabdanya: 'Wahai umat Muhammad! Tidak ada seorangpun yang melebihi cemburu dari Allah Azza wa Jalla bila ada hambanya yang berzina. Wahai umat Muhammad! Demi Allah, kalau kalian mengetahui apa yang aku ketahui, pasti kalian akan sedikit tertawa dan sering menangis.\""},"1449":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ عَمْرَةَ حَدَّثَتْهُ أَنَّ عَائِشَةَ حَدَّثَتْهَاأَنَّ يَهُودِيَّةً أَتَتْهَا فَقَالَتْ أَجَارَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ قَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ إِنَّ النَّاسَ لَيُعَذَّبُونَ فِي الْقُبُورِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِذًا بِاللَّهِ قَالَتْ عَائِشَةُ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مَخْرَجًا فَخَسَفَتْ الشَّمْسُ فَخَرَجْنَا إِلَى الْحُجْرَةِ فَاجْتَمَعَ إِلَيْنَا نِسَاءٌ وَأَقْبَلَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ ضَحْوَةً فَقَامَ قِيَامًا طَوِيلًا ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ دُونَ رُكُوعِهِ ثُمَّ سَجَدَ ثُمَّ قَامَ الثَّانِيَةَ فَصَنَعَ مِثْلَ ذَلِكَ إِلَّا أَنَّ رُكُوعَهُ وَقِيَامَهُ دُونَ الرَّكْعَةِ الْأُولَى ثُمَّ سَجَدَ وَتَجَلَّتْ الشَّمْسُ فَلَمَّا انْصَرَفَ قَعَدَ عَلَى الْمِنْبَرِ فَقَالَ فِيمَا يَقُولُ إِنَّ النَّاسَ يُفْتَنُونَ فِي قُبُورِهِمْ كَفِتْنَةِ الدَّجَّالِ قَالَتْ عَائِشَةُ كُنَّا نَسْمَعُهُ بَعْدَ ذَلِكَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dari [Ibnu Wahab] dari ['Amru bin Al Harits] dari [Yahya bin Sa'id] bahwasanya ['Amrah] menceritakan kepadanya bahwasanya ['Aisyah] menceritakan kepadanya bahwa ada orang Yahudi datang kepadanya, lalu ia berkata kepadanya; \"Semoga Allah melindungimu dari siksa kubur!\" Kemudian Aisyah berkata kepada Rasulullah shallallahu 'alaihi wasallam: \"Wahai Rasulullah shallallahu 'alaihi wasallam menjawab: 'Wahai Rasulullah shallallahu 'alaihi wasallam, apakah pada saat didalam kubur manusia akan disiksa? ' Rasulullah shallallahu 'alaihi wasallam menjawab: 'Berlindunglah kepada Allah! ' Aisyah berkata; 'Lalu Nabi shallallahu 'alaihi wasallam keluar, -ternyata- terjadi gerhana matahari, maka kami masuk ke kamar, dan para wanita berkumpul kepada kami. Rasulullah shallallahu 'alaihi wasallam muncul dengan menghadap kepada kami, dan hal itu saat waktu Dluha.' Lalu beliau berdiri lama, kemudian ruku' dengan ruku' yang lama juga. Lalu mengangkat kepalanya dan berdiri tapi lebih singkat dari berdiri yang pertama. Kemudian ruku' lebih singkat dari ruku' yang pertama, lalu sujud. Kemudian berdiri yang kedua dan melakukan hal yang sama, kecuali ruku' dan berdirinya lebih singkat dari yang pertama, kemudian sujud, dan matahari telah terang kembali. Setelah selesai beliau duduk di atas mimbar, lalu bersabda: 'Manusia diuji dalam kubur mereka, seperti fitnah Dajjal'.\"Lalu Aisyah berkata; 'Kami mendengar beliau meminta perlindungan dari siksa kubur setelah itu.'"},"1450":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ هُوَ الْأَنْصَارِيُّ قَالَ سَمِعْتُ عَمْرَةَ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُجَاءَتْنِي يَهُودِيَّةٌ تَسْأَلُنِي فَقَالَتْ أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ فَلَمَّا جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ يَا رَسُولَ اللَّهِ أَيُعَذَّبُ النَّاسُ فِي الْقُبُورِ فَقَالَ عَائِذًا بِاللَّهِ فَرَكِبَ مَرْكَبًا يَعْنِي وَانْخَسَفَتْ الشَّمْسُ فَكُنْتُ بَيْنَ الْحُجَرِ مَعَ نِسْوَةٍ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَرْكَبِهِ فَأَتَى مُصَلَّاهُ فَصَلَّى بِالنَّاسِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِيَامَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ قَامَ قِيَامًا أَيْسَرَ مِنْ قِيَامِهِ الْأَوَّلِ ثُمَّ رَكَعَ أَيْسَرَ مِنْ رُكُوعِهِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ أَيْسَرَ مِنْ قِيَامِهِ الْأَوَّلِ ثُمَّ رَكَعَ أَيْسَرَ مِنْ رُكُوعِهِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ أَيْسَرَ مِنْ قِيَامِهِ الْأَوَّلِ فَكَانَتْ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ فَقَالَ إِنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ كَفِتْنَةِ الدَّجَّالِ قَالَتْ عَائِشَةُ فَسَمِعْتُهُ بَعْدَ ذَلِكَ يَتَعَوَّذُ مِنْ عَذَابِ الْقَبْرِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id Al Anshari] dia berkata; Aku mendengar ['Amrah] berkata; Aku mendengar ['Aisyah] berkata; Ada seorang Yahudi datang kepadaku, lalu berkata; \"Semoga Allah melindungimu dari siksa kubur\". Setelah Rasulullah shallallahu 'alaihi wasallam datang, aku berkata kepadanya'Wahai Rasulullah shallallahu 'alaihi wasallam, apakah pada saat di dalam kubur manusia akan disiksa? ' Rasulullah shallallahu 'alaihi wasallam menjawab: \"Berlindunglah kepada Allah!\" Lalu beliau naik kendaraannya, kemudian terjadi gerhana matahari. Aku sedang di kamar bersama para wanita, lalu Rasulullah shallallahu 'alaihi wasallam datang dari kendaraannya dan masuk ke tempat shalatnya, kemudian shalat bersama orang-orang. Lantas beliau berdiri, kemudian ruku' dalam waktu yang lama. Lalu mengangkat kepalanya dan berdiri dalam waktu yang lama. Kemudian beliau ruku' dalam waktu yang lama, lalu beliau mengangkat kepalanya dan berdiri dalam waktu yang lama. Kemudian sujud dalam waktu yang lama, dan berdiri lagi tetapi lebih singkat dari berdirinya yang pertama. Lalu ruku' dengan ruku' yang lebih singkat dari ruku' yang pertama, kemudian mengangkat kepalanya dan berdiri lagi tapi lebih singkat dari berdiri yang pertama. Kemudian ruku' lagi yang lebih singkat dari ruku' yang pertama, kemudian mengangkat kepalanya dan berdiri tapi lebih ringan dari yang pertama. Shalatnya empat kali ruku' dan empat kali sujud, dan matahari telah terang. Setelah itu beliau bersabda: ' kalian akan diuji dalam kubur, seperti fitnah Dajjal. Lalu Aisyah berkata; 'Kami mendengar beliau memohon perlindungan dari siksa kubur setelah itu.'"},"1451":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ الرَّحِيمِ قَالَ أَنْبَأَنَا ابْنُ عُيَيْنَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي كُسُوفٍ فِي صُفَّةِ زَمْزَمَ أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ","id":"Telah mengabarkan kepada kami ['Abdah bin 'Abdurrahim] dia berkata; Telah memberitakan kepada kami [Ibnu 'Uyainah] dari [Yahya bin Sa'id] dari ['Amrah] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam Shalat gerhana di beranda sumur Zamzam dengan empat kali ruku' dan empat kali sujud."},"1452":{"ar":"أَخْبَرَنِي مَحْمُودُ بْنُ خَالِدٍ عَنْ مَرْوَانَ قَالَ حَدَّثَنِي مُعَاوِيَةُ بْنُ سَلَّامٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَ فَنُودِيَ الصَّلَاةُ جَامِعَةٌ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالنَّاسِ رَكْعَتَيْنِ وَسَجْدَةً ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ وَسَجْدَةًقَالَتْ عَائِشَةُ مَا رَكَعْتُ رُكُوعًا قَطُّ وَلَا سَجَدْتُ سُجُودًا قَطُّ كَانَ أَطْوَلَ مِنْهُ خَالَفَهُ مُحَمَّدُ بْنُ حِمْيَرَ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dari [Marwan] dia berkata; Telah menceritakan kepadaku [Mu'awiyah bin Sallam] dia berkata; Telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah bin 'Abdurrahman] dari ['Abdullah bin 'Amru] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari. Beliau memerintahkan untuk menyeru dengan kalimat; 'Ash Shalatul Jami'ah (mari kita tegakkan shalat bersama-sama). Lalu Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat dua kali ruku' dan dua kali sujud dengan orang-orang. Kemudian beliau berdiri dan shalat dengan satu kali sujud. Lalu Aisyah berkata; 'Aku belum pernah melakukan ruku' dan sujud yang lebih lama darinya'.\" Muhammad bin Humair menyelisihinya."},"1453":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ عُثْمَانَ قَالَ حَدَّثَنَا ابْنُ حِمْيَرَ عَنْ مُعَاوِيَةَ بْنِ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي طُعْمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكَسَفَتْ الشَّمْسُ فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ وَسَجْدَتَيْنِ ثُمَّ قَامَ فَرَكَعَ رَكْعَتَيْنِ وَسَجْدَتَيْنِ ثُمَّ جُلِّيَ عَنْ الشَّمْسِ وَكَانَتْ عَائِشَةُ تَقُولُ مَا سَجَدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُجُودًا وَلَا رَكَعَ رُكُوعًا أَطْوَلَ مِنْهُخَالَفَهُ عَلِيُّ بْنُ الْمُبَارَكِ","id":"Telah mengabarkan kepada kami [Yahya bin 'Utsman] dia berkata; Telah menceritakan kepada kami [Ibnu Hamir] dari [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] dari [Abu Thu'mah] dari ['Abdullah bin 'Amru] dia berkata; \"Saat matahari mengalami gerhana, Rasulullah shallallahu 'alaihi wasallam shalat dua kali ruku' dan dua kali sujud, kemudian bangun lagi dan ruku' lagi dua kali serta sujud dua kali. Setelah itu matahari terang.\" Saat itu Aisyah berkata; 'Rasulullah shallallahu 'alaihi wasallam belum pernah sujud dan ruku' yang lebih lama darinya.' Ali bin Al Mubarak menyelisihinya."},"1454":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ إِسْحَقَ قَالَ حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو حَفْصَةَ مَوْلَى عَائِشَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهُ أَنَّهُلَمَّا كَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَوَضَّأَ وَأَمَرَ فَنُودِيَ أَنَّ الصَّلَاةَ جَامِعَةٌ فَقَامَ فَأَطَالَ الْقِيَامَ فِي صَلَاتِهِ قَالَتْ عَائِشَةُ فَحَسِبْتُ قَرَأَ سُورَةَ الْبَقَرَةِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ مِثْلَ مَا قَامَ وَلَمْ يَسْجُدْ ثُمَّ رَكَعَ فَسَجَدَ ثُمَّ قَامَ فَصَنَعَ مِثْلَ مَا صَنَعَ رَكْعَتَيْنِ وَسَجْدَةً ثُمَّ جَلَسَ وَجُلِّيَ عَنْ الشَّمْسِ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ishaq] dia berkata; Telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar-Rabi'] dia berkata; Telah menceritakan kepada kami ['Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] dia berkata; Telah menceritakan kepadaku [Abu Hafshah] -budak 'Aisyah- bahwasanya ['Aisyah] mengabarkan kepadanya bahwa pada masa Rasulullah shallallahu 'alaihi wasallam terjadi gerhana matahari, maka beliau berwudlu lalu memerintahkan untuk menyeru, 'Ash-Shalatul Jami'ah'. Lalu beliau berdiri dan memperlama berdirinya saat shalat.\" Kemudian Aisyah berkata; 'Aku memperkirakan beliau membaca surah Al-Baqarah, kemudian beliau ruku' dengan ruku' yang lama, lalu mengucapakan Sami' Allahu Liman Hamidah. Kemudian beliau berdiri seperti berdirinya semula tanpa sujud, lalu ruku' lagi dan sujud lagi. Kemudian berdiri dan berbuat seperti yang diperbuat pada dua ruku' dan satu kali sujud yang pertama. Lantas beliau duduk, sedangkan matahari telah terang.'"},"1455":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ اللَّهِ بْنِ عَبْدِ الْعَظِيمِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ سَبَلَانُ قَالَ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ الْمُهَلّ��بِيُّ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَصَلَّى لِلنَّاسِ فَأَطَالَ الْقِيَامَ ثُمَّ رَ��َعَ فَأَطَالَ الرُّكُوعَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ وَهُوَ دُونَ السُّجُودِ الْأَوَّلِ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ وَفَعَلَ فِيهِمَا مِثْلَ ذَلِكَ ثُمَّ سَجَدَ سَجْدَتَيْنِ يَفْعَلُ فِيهِمَا مِثْلَ ذَلِكَ حَتَّى فَرَغَ مِنْ صَلَاتِهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَافْزَعُوا إِلَى ذِكْرِ اللَّهِ عَزَّ وَجَلَّ وَإِلَى الصَّلَاةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaidullah bin 'Abdul 'Azhim] dia berkata; Telah menceritakan kepadaku [Ibrahim Sabalan] dia berkata; Telah menceritakan kepada kami ['Abbad bin 'Abbad Al Muhallabi] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Abu Hurairah] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, lalu Rasulullah shalat bersama orang orang. Beliau berdiri dan memperlama berdirinya, kemudian ruku' dan memperlama ruku'nya. Kemudian bangkit lagi dan memperlama berdirinya, namun lebih singkat dari berdiri yang pertama. Kemudian ruku' dan memperlama ruku'nya, namun lebih singkat dari ruku' yang pertama. Kemudian sujud dan memperlama sujudnya, lalu mengangkat (kepalanya dari ruku'), lalu sujud namun lebih singkat dari sujud yang pertama. Kemudian berdiri shalat dua rakaat. Beliau melakukan hal yang lama pada rakaat berikutnya, sampai selesai shalatnya. Setelah itu Beliau bersabda: 'Matahari dan bulan adalah dua tanda diantara tanda-tanda kebesaran Allah Ta'ala. Keduanya tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat kedua gerhana tersebut, maka segeralah berdzikir kepada Allah Azza wa Jalla dan kerjakanlah shalat '.\""},"1456":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ بْنِ هِلَالٍ قَالَ حَدَّثَنَا الْحُسَيْنُ بْنُ عَيَّاشٍ قَالَ حَدَّثَنَا زُهَيْرٌ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ قَيْسٍ قَالَ حَدَّثَنِي ثَعْلَبَةُ بْنُ عَبَّادٍ الْعَبْدِيُّ مِنْ أَهْلِ الْبَصْرَةِأَنَّهُ شَهِدَ خُطْبَةً يَوْمًا لِسَمُرَةَ بْنِ جُنْدُبٍ فَذَكَرَ فِي خُطْبَتِهِ حَدِيثًا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمُرَةُ بْنُ جُنْدُبٍ بَيْنَا أَنَا يَوْمًا وَغُلَامٌ مِنْ الْأَنْصَارِ نَرْمِي غَرَضَيْنِ لَنَا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كَانَتْ الشَّمْسُ قِيدَ رُمْحَيْنِ أَوْ ثَلَاثَةٍ فِي عَيْنِ النَّاظِرِ مِنْ الْأُفُقِ اسْوَدَّتْ فَقَالَ أَحَدُنَا لِصَاحِبِهِ انْطَلِقْ بِنَا إِلَى الْمَسْجِدِ فَوَاللَّهِ لَيُحْدِثَنَّ شَأْنُ هَذِهِ الشَّمْسِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي أُمَّتِهِ حَدَثًا قَالَ فَدَفَعْنَا إِلَى الْمَسْجِدِ قَالَ فَوَافَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ خَرَجَ إِلَى النَّاسِ قَالَ فَاسْتَقْدَمَ فَصَلَّى فَقَامَ كَأَطْوَلِ قِيَامٍ قَامَ بِنَا فِي صَلَاةٍ قَطُّ مَا نَسْمَعُ لَهُ صَوْتًا ثُمَّ رَكَعَ بِنَا كَأَطْوَلِ رُكُوعٍ مَا رَكَعَ بِنَا فِي صَلَاةٍ قَطُّ مَا نَسْمَعُ لَهُ صَوْتًا ثُمَّ سَجَدَ بِنَا كَأَطْوَلِ سُجُودٍ مَا سَجَدَ بِنَا فِي صَلَاةٍ قَطُّ لَا نَسْمَعُ لَهُ صَوْتًا ثُمَّ فَعَلَ ذَلِكَ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ قَالَ فَوَافَقَ تَجَلِّي الشَّمْسِ جُلُوسَهُ فِي الرَّكْعَةِ الثَّانِيَةِ فَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَشَهِدَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَشَهِدَ أَنَّهُ عَبْدُ اللَّهِ وَرَسُولُهُ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala bin Hilal] dia berkata; Telah menceritakan kepada kami [Al Husain bin 'Ayyasy] dia berkata; Telah menceritakan kepada kami [Zuhair] dia berkata; Telah menceritakan kepada kami [Al Aswad bin Qais] dia berkata; Telah menceritakan kepadaku [Tsa'labah bin 'Abbad Al 'Abdi] -dari penduduk Bashrah- bahwasanya suatu hari ia menyaksikan khutbah [Samurah bin Jundub], didalam khutbahnya dia menyebutkan sebuah Hadits dari Rasulullah shallallahu 'alaihi wasallam, dia berkata; \"Tatkala kami dan seorang anak kecil melemparkan tombak kami pada dua sasaran di masa Rasulullah, tiba-tiba matahari -yang kelihatannya berada seukuran dua tombak atau tiga tombak- diatas kami berwarna hitam. Lalu salah seorang diantara kami berkata; 'Mari kita pergi ke masjid bersama kami, demi Allah kita akan melihat Rasulullah shallallahu 'alaihi wasallam dalam menyikapi keadaan seperti ini. Samurah berkata; 'Maka kami pun ingin pergi ke masjid'. Dia berkata lagi; 'Kami mendapatkan Rasulullah shallallahu 'alaihi wasallam sedang keluar menuju sekumpulan manusia. Kemudian beliau maju, lalu shalat dengan memperlama berdirinya, sepertinya shalat ini yang paling paling panjang beliau lakukan bersama kami, dan kami tidak mendengar suara dari beliau. Kemudian beliau ruku' dengan ruku' yang panjang dan kami tidak mendengar suara dari beliau, kemudian beliau sujud dengan sujud yang panjang yang belum pernah beliau lakukan sebelumnya bersama kami, dan kamipun tidak mendengar suara dari beliau. Dan beliau melakukan hal yang sama pada raka'at kedua. Dia berkata; 'Duduk beliau pada raka'at kedua bersamaan dengan terangnya matahari.' Kemudian beliau mengucapkan salam dan memuji Allah, bersaksi bahwa tiada ilah yang berhak disembah selainNya dan bersaksi bahwa beliau utusanNya. (secara ringkas)."},"1457":{"ar":"و أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا عَمْرُو بْنُ عَاصِمٍ أَنَّ جَدَّهُ عُبَيْدَ اللَّهِ بْنَ الْوَازِعِ حَدَّثَهُ قَالَ حَدَّثَنَا أَيُّوبُ السَّخْتِيَانِيُّ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ بْنِ مُخَارِقٍ الْهِلَالِيِّ قَالَكَسَفَتْ الشَّمْسُ وَنَحْنُ إِذْ ذَاكَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ فَخَرَجَ فَزِعًا يَجُرُّ ثَوْبَهُ فَصَلَّى رَكْعَتَيْنِ أَطَالَهُمَا فَوَافَقَ انْصِرَافُهُ انْجِلَاءَ الشَّمْسِ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ مِنْ ذَلِكَ شَيْئًا فَصَلُّوا كَأَحْدَثِ صَلَاةٍ مَكْتُوبَةٍ صَلَّيْتُمُوهَا","id":"Dan telah mengabarkan kepada kami [Ibrahim bin Ya'qub] dia berkata; Telah menceritakan kepada kami ['Amru bin 'Ashim] bahwasanya kakeknya ['Ubaidullah bin Al Wazi'] menceritakan kepadanya, dia berkata; Telah menceritakan kepada kami [Ayyub As Sakhtiyani] dari [Abu Qilabah] dari [Qabishah bin Mukhariq Al Hilali] dia berkata; Telah terjadi gerhana matahari dan pada waktu itu kami berada di Madinah bersama Rasulullah shallallahu 'alaihi wasallam. Maka beliau keluar dengan rasa takut sambil menarik bajunya, lalu shalat dua raka'at dengan memanjangkan keduanya. Beliau selesai shalat bersamaan dengan terangnya matahari kembali. Lalu beliau memuji Allah kemudian berkata: \"Matahari dan bulan adalah dua tanda dari tanda-tanda kebesaran Allah keduanya tidak mengalami gerhana karena kematian seseorang atau kelahiran seseorang, apabila kalian melihat yang demikian, maka shalatlah seperti shalat wajib yang kalian lakukan.\""},"1458":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُعَاذٌ وَهُوَ ابْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ الْهِلَالِيِّأَنَّ الشَّمْسَ انْخَسَفَتْ فَصَلَّى نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ رَكْعَتَيْنِ حَتَّى انْجَلَتْ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْخَسِفَانِ لِمَوْتِ أَحَدٍ وَلَكِنَّهُمَا خَلْقَانِ مِنْ خَلْقِهِ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ يُحْدِثُ فِي خَلْقِهِ مَا شَاءَ وَإِنَّ اللَّهَ عَزَّ وَجَلَّ إِذَا تَجَلَّى لِشَيْءٍ مِنْ خَلْقِهِ يَخْشَعُ لَهُ فَأَيُّهُمَا حَدَثَ فَصَلُّوا حَتَّى يَنْجَلِيَ أَوْ يُحْدِثَ اللَّهُ أَمْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dia berkata; Telah menceritakan kepada kami [Mu'adz bin Hisyam] dia berkata; [Bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Abu Qilabah] dari [Qabishah Al Hilali], matahari mengalami gerhana maka Nabi Shallalahu 'Alaihi Wa Sallam shalat dua raka'at dua raka'at hingga matahari terang kembali. Kemudian beliau bersabda: \" Matahari dan bulan tidak mengalami gerhana karena kematian seseorang akan tetapi keduanya adalah dua tanda dari tanda-tanda kebesaran Allah. Allah Azza Wa Jalla berbuat sesuatu terhadap ciptaan-Nya sesuai dengan kehendak-NYA. Dan Dia apabila menampakkan sebagian dari ciptaan-NYA maka akan membuat takut kepada-NYA, mana saja di antara keduanya mengalami gerhana maka shalatlah kalian hingga terang kembali atau Allah memutuskan perkara.\""},"1459":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ مُعَاذِ بْنِ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ أَبِي قِلَابَةَ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا خَسَفَتْ الشَّمْسُ وَالْقَمَرُ فَصَلُّوا كَأَحْدَثِ صَلَاةٍ صَلَّيْتُمُوهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Mu'adz bin Hisyam] dia berkata; [Bapakku] telah menceritakan kepadaku dari [Qatadah] dari [Abu Qilabah] dari [An Nu'man bin Basyir] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila matahari dan bulan mengalami gerhana maka shalatlah kalian sebagaimana shalat wajib yang kalian lakukan.\""},"1460":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَخَسَفَتْ الشَّمْسُ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا قَرَأَ نَحْوًا مِنْ سُورَةِ الْبَقَرَةِ قَالَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ عَزَّ وَجَلَّ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ قَالَ إِنِّي رَأَيْتُ الْجَنَّةَ أَوْ أُرِيتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا لِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ يَكْفُرْنَ بِاللَّهِ قَالَ يَكْفُرْنَ الْعَشِيرَ وَيَكْفُرْنَ الْإِحْسَانَ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dia berkata; Telah menceritakan kepada kami [Ibnul Qasim] dari [Malik] dia berkata; Telah menceritakan kepadaku [Zaid bin Aslam] dari ['Atha bin Yasar] dari ['Abdullah bin 'Abbas] dia berkata; \"Telah terjadi gerhana matahari, maka Rasulullah shallallahu 'alaihi wasallam shalat bersama orang-orang. Beliau berdiri lama dengan membaca surat yang sepadan dengan surah Al Baqarah.\" Kemudian Abdullah berkata lagi; 'Kemudian beliau ruku' dengan ruku' yang lama, lalu mengangkat kepalanya dan berdiri (lagi), tapi lebih singkat dari yang pertama. Kemudian ruku' dengan ruku' yang lama tapi lebih singkat dari ruku' yang pertama. Lalu beliau mengangkat (kepalanya) dan berdiri lagi dengan lama, namun lebih singkat dari yang pertama. Kemudian beliau ruku' dengan ruku' yang lama, namun lebih singkat dari ruku' yang pertama. Lalu beliau sujud dan pergi sedangkan matahari telah terang. Setelah itu beliau shallallahu 'alaihi wasallam bersabda: 'Matahari dan Bulan adalah dua tanda diantara tanda-tanda kebesaran Allah Ta'ala. Keduanya tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat gerhana tersebut, maka berdzikirlah kepada Allah Azza Wa Jalla.' Para sahabat berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, kami melihat engkau menggapai sesuatu pada posisimu ini, kemudian kami melihatmu juga mundur? ' Beliau bersabda: 'Aku melihat surga -atau diperlihatkan kepadaku surga. Seandainya aku mengambil sesuatu dari surga, maka kamu pasti akan memakannya, lalu tak akan tersisa lagi dunia ini. Aku juga melihat neraka. Aku belum melihat pandangan yang lebih menakutkan dari ini dan aku melihat kebanyakan penghuninya adalah wanita.' Para sahabat berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, kenapa bisa begitu? ' Beliau menjawab: 'Karena kekufuran mereka'. -Dalam riwayat lain: Karena mereka kufur kepada Allah? - Beliau meneruskan lagi: 'Mereka juga kufur terhadap kebaikan suami dan kufur terhadap kebaikan. Seandainya kamu berbuat baik kepada salah seorang dari mereka (wanita) sepanjang masa, Lalu dia melihat suatu (keburukan) pada dirimu', Maka dia akan berkata: 'Aku tidak melihat suatu kebaikanpun pada dirimu! '"},"1461":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْوَلِيدُ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ أَنَّهُ سَمِعَ الزُّهْرِيَّ يُحَدِّثُ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى أَرْبَعَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍ وَجَهَرَ فِيهَا بِالْقِرَاءَةِ كُلَّمَا رَفَعَ رَأْسَهُ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; Telah memberitakan kepada kami [Al Walid] dia berkata; Telah menceritakan kepada kami ['Abdurrahman bin Namir] bahwasanya ia mendengar [Az Zuhri] bercerita dari ['Urwah] dari ['Aisyah] Rasulullah shallallahu 'alaihi wasallam, bahwa beliau pernah shalat (gerhana) dengan empat kali ruku' dan empat kali sujud. Beliau juga mengeraskan bacaannya. Tiap kali beliau mengangkat kepalanya, beliau mengucapkan: 'Sami'allahu Liman Hamidah, Rabbana Wa Lakal Hamdu (Allah mendengar siapa yang memuji-Nya, wahai Tuhan kami, segala puji untuk-Mu) '.\""},"1462":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ ابْنِ عَبَّادٍ رَجُلٍ مِنْ بَنِي عَبْدِ الْقَيْسِ عَنْ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِمْ فِي كُسُوفِ الشَّمْسِ لَا نَسْمَعُ لَهُ صَوْتًا","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] dia berkata; Telah menceritakan kepada kami [Abu Nu'aim] dia berkata; Telah menceritakan kepada kami [Sufyan] dari [Al Aswad bin Qais] dari [Ibnu 'Abbad] -seorang laki-laki dari Bani 'Abdul Qais- dari [Samurah] bahwa Nabi Shalallahu 'Alaihi Wa Sallam shalat bersama mereka ketika terjadi gerhana matahari dan kami tidak mendengar suaranya.\""},"1463":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْمِسْوَرِ الزُّهْرِيُّ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَأَطَالَ قَالَ شُعْبَةُ وَأَحْسَبُهُ قَالَ فِي السُّجُودِ نَحْوَ ذَلِكَ وَجَعَلَ يَبْكِي فِي سُجُودِهِ وَيَنْفُخُ وَيَقُولُ رَبِّ لَمْ تَعِدْنِي هَذَا وَأَنَا أَسْتَغْفِرُكَ لَمْ تَعِدْنِي هَذَا وَأَنَا فِيهِمْ فَلَمَّا صَلَّى قَالَ عُرِضَتْ عَلَيَّ الْجَنَّةُ حَتَّى لَوْ مَدَدْتُ يَدِي تَنَاوَلْتُ مِنْ قُطُوفِهَا وَعُرِضَتْ عَلَيَّ النَّارُ فَجَعَلْتُ أَنْفُخُ خَشْيَةَ أَنْ يَغْشَاكُمْ حَرُّهَا وَرَأَيْتُ فِيهَا سَارِقَ بَدَنَتَيْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَأَيْتُ فِيهَا أَخَا بَنِي دُعْدُعٍ سَارِقَ الْحَجِيجِ فَإِذَا فُطِنَ لَهُ قَالَ هَذَا عَمَلُ الْمِحْجَنِ وَرَأَيْتُ فِيهَا امْرَأَةً طَوِيلَةً سَوْدَاءَ تُعَذَّبُ فِي هِرَّةٍ رَبَطَتْهَا فَلَمْ تُطْعِمْهَا وَلَمْ تَسْقِهَا وَلَمْ تَدَعْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ حَتَّى مَاتَتْ وَإِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا انْكَسَفَتْ إِحْدَاهُمَا أَوْ قَالَ فَعَلَ أَحَدُهُمَا شَيْئًا مِنْ ذَلِكَ فَاسْعَوْا إِلَى ذِكْرِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami ['Abdullah bin Muhammad bin 'Abdurrahman bin Al Miswar Az Zuhri] dia berkata; telah menceritakan kepada kami [Ghundar] dari [Syu'bah] dari ['Atha bin As Saib] dari [bapaknya] dari ['Abdullah bin 'Amru] dia berkata; \"Saat terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, beliau mengerjakan shalat. Beliau memperlama berdirinya, kemudian ruku' dan memperlama ruku'nya, kemudian berdiri lagi dan memperlama berdirinya.\" Syu'bah (perawi) berkata; \"Aku mengira bahwa dia mengatakan tentang sujud Rasulullah shallallahu 'alaihi wasallam juga demikian. Beliau menangis saat sujud dan meniup sambil mengucapkan, 'Wahai Rabbku, ini jangan terjadi sedangkan kami masih memohon ampun kepada-Mu! Janganlah hal ini terjadi di saat aku masih berada di tengah-tengah mereka! ' Setelah selesai shalat beliau bersabda: 'Surga diperlihatkan kepadaku, hingga kalau tanganku dijulurkan maka aku pasti bisa memetik sesuatu darinya. Neraka juga telah diperlihatkan kepadaku, maka aku meniupnya karena khawatir panasnya akan menimpa kalian. Di dalamnya aku melihat seorang pencuri dua unta betina Rasulullah shallallahu 'alaihi wasallam dan melihat saudaranya Bani Du'du', orang yang mencuri orang yang haji, dan jika ia ditanya tentang curiannya maka ia berkata; \"Ini perbuatan tongkat \". Aku juga melihat seorang perempuan yang tinggi dan hitam, yang disiksa karena seekor kucing yang diikatnya, tanpa memberinya makan dan minum, serta tidak membiarkannya mencari makan sendiri dari serangga-serangga bumi, sehingga akhirnya kucing itu mati'. Beliau bersabda: `Matahari dan bulan tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat salah satunya - atau beliau berkata: Salah satunya mengalami gerhana maka segeralah berdzikir kepada Allah Azza wa Jalla '.\""},"1464":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ عَنْ الْوَلِيدِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ نَمِرٍ أَنَّهُ سَأَلَ الزُّهْرِيَّ عَنْ سُنَّةِ صَلَاةِ الْكُسُوفِ فَقَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَسَفَتْ الشَّمْسُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَنَادَى أَنْ الصَّلَاةَ جَامِعَةً فَاجْتَمَعَ النَّاسُ فَصَلَّى بِهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ ثُمَّ قَرَأَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا مِثْلَ قِيَامِهِ أَوْ أَطْوَلَ ثُمَّ رَفَعَ رَأْسَهُ وَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ كَبَّرَ فَسَجَدَ سُجُودًا طَوِيلًا مِثْلَ رُكُوعِهِ أَوْ أَطْوَلَ ثُمَّ كَبَّرَ فَرَفَعَ رَأْسَهُ ثُمَّ كَبَّرَ فَسَجَدَ ثُمَّ كَبَّرَ فَقَامَ فَقَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْأُولَى ثُمَّ كَبَّرَ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَرَأَ قِرَاءَةً طَوِيلَةً وَهِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى فِي الْقِيَامِ الثَّانِي ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ كَبَّرَ فَرَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ كَبَّرَ فَسَجَدَ أَدْنَى مِنْ سُجُودِهِ الْأَوَّلِ ثُمَّ تَشَهَّدَ ثُمَّ سَلَّمَ فَقَامَ فِيهِمْ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْخَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَأَيُّهُمَا خُسِفَ بِهِ أَوْ بِأَحَدِهِمَا فَافْزَعُوا إِلَى اللَّهِ عَزَّ وَجَلَّ بِذِكْرِ الصَّلَاةِ","id":"Telah mengabarkan kepada kami ['Amru bin 'Utsman bin Sa'id bin Katsir] dari [Al Walid] dari ['Abdurrahman bin Namir] bahwasanya ia bertanya kepada [Az Zuhri] mengenai sunnah shalat Kusuf, maka dia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] dari ['Aisyah] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, beliau berwudlu lalu memerintahkan untuk menyeru, \"Ash-shalaatu Jami'ah.\"Orang-orang pun segera berkumpul, dan Rasulullah shalat bersama mereka. Beliau takbir, kemudian membaca bacaan yang lama. Beliau takbir lagi, kemudian ruku' dengan ruku' yang lama, seperti lamanya berdiri atau lebih. Kemudian beliau mengangkat kepalanya dari ruku' sambil mengucapkan: \"Sami'allahu liman hamidah.\" Kemudian beliau membaca bacaan yang lama, namun lebih pendek dari yang pertama. Lalu takbir lagi, kemudian ruku' dengan ruku' yang lama, namun lebih pendek dari yang pertama. Kemudian mengangkat kepalanya dari ruku' sambil mengucapkan, \"Sami'allahu liman hamidah.\" Kemudian takbir lagi dan sujud dengan sujud yang lama, seperti lamanya ruku' atau lebih. Kemudian takbir dan mengangkat kepalanya, lalu takbir dan sujud lagi, kemudian takbir lagi dan berdiri dengan membaca bacaan yang panjang, namun lebih pendek dari yang pertama. Kemudian takbir lagi dan ruku' dengan ruku' yang lama, namun lebih pendek dari yang pertama. Kemudian mengangkat kepalanya dari ruku' sambil mengucapkan, \"Sami'allahu liman hamidah.\" Kemudian beliau membaca bacaan yang panjang, namun lebih pendek dari yang pertama saat berdiri yang kedua. Kemudian beliau takbir lalu ruku' dengan ruku' yang panjang, namun masih lebih pendek dari ruku' yang pertama. Kemudian takbir lagi dan mengangkat kepalanya sambil mengucapkan, \"Sami'allahu liman hamidah.\" Lalu takbir lagi dan sujud lagi dengan sujud yang lebih pendek dari yang pertama, kemudian tasyahhud (membaca dua kalimat syahadat) dan mengucapkan salam. Setelah itu beliau bangkit ketengah-tengah mereka dan memuji Allah. lalu bersabda: \"Matahari dan bulan tidak mengalami gerhana karena kematian atau kelahiran seseorang, tetapi keduanya adalah tanda diantara tanda-tanda kebesaran Allah. Jadi mana saja dari keduanya mengalami gerhana, maka segeralah mengingat Allah Azza wa Jalla dengan shalat.\""},"1465":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا مُوسَى بْنُ دَاوُدَ قَالَ حَدَّثَنَا نَافِعُ بْنُ عُمَرَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْكُسُوفِ فَقَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ سَجَدَ فَأَطَالَ السُّجُودَ ثُمَّ رَفَعَ ثُمَّ انْصَرَفَ","id":"Telah mengabarkan kepadaku [Ibrahim bin Ya'qub] dia berkata; telah menceritakan kepada kami [Musa bin Dawud] dia berkata; telah menceritakan kepada kami [Nafi' bin 'Umar] dari [Ibnu Abu Mulaikah] dari [Asma binti Abu Bakr] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam pernah shalat saat terjadi gerhana. Beliau berdiri dan memperlama berdirinya kemudian ruku' dan memperlama ruku'nya. Kemudian bangkit lagi dan memperlama berdirinya. Kemudian ruku' dan memperlama ruku'nya. lalu mengangkat (kepalanya dari ruku') dan sujud dalam waktu yang lama, kemudian mengangkat kepalanya dari sujud, dan sujud lagi dengan sujud yang lama juga. Kemudian beliau berdiri dan memperlama berdirinya, kemudian ruku' dan memperlama ruku'nya. Lalu bangkit lagi dan memperlama berdirinya. Kemudian ruku' dan memperlama ruku'nya, lalu mengangkat (kepalanya dari ruku') dan sujud dalam waktu yang lama, kemudian mengangkat kepalanya dari sujud. Kemudian sujud lagi dengan sujud yang lama juga, lalu mengangkatnya, kemudian selesai (salam).\""},"1466":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ عَنْ ابْنِ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ يَحْيَى بْنِ سَعِيدٍ أَنَّ عَمْرَةَ حَدَّثَتْهُ أَنَّ عَائِشَةَ قَالَتْإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مَخْرَجًا فَخُسِفَ بِالشَّمْسِ فَخَرَجْنَا إِلَى الْحُجْرَةِ فَاجْتَمَعَ إِلَيْنَا نِسَاءٌ وَأَقْبَلَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ ضَحْوَةً فَقَامَ قِيَامًا طَوِيلًا ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ دُونَ رُكُوعِهِ ثُمَّ سَجَدَ ثُمَّ قَامَ الثَّانِيَةَ فَصَنَعَ مِثْلَ ذَلِكَ إِلَّا أَنَّ قِيَامَهُ وَرُكُوعَهُ دُونَ الرَّكْعَةِ الْأُولَى ثُمَّ سَجَدَ وَتَجَلَّتْ الشَّمْسُ فَلَمَّا انْصَرَفَ قَعَدَ عَلَى الْمِنْبَرِ فَقَالَ فِيمَا يَقُولُ إِنَّ النَّاسَ يُفْتَنُونَ فِي قُبُورِهِمْ كَفِتْنَةِ الدَّجَّالِ مُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dari [Ibnu Wahb] dari ['Amru bin Al Harits] dari [Yahya bin Sa'id] bahwasanya ['Amrah] menceritakan kepadanya bahwasanya ['Aisyah] berkata; \"Nabi shallallahu 'alaihi wasallam pernah keluar tiba-tiba terjadi gerhana matahari. Kami lalu keluar menuju kamar, dan para wanita berkumpul di sekitar kami. Rasulullah shallallahu 'alaihi wasallam datang kepada kami, dan saat itu pada waktu Dluha. Lalu beliau berdiri lama, kemudian ruku' dengan ruku' yang lama, lalu mengangkat kepalanya dan berdiri lagi tapi lebih singkat dari berdiri yang pertama. Kemudian ruku' dengan ruku' yang lebih singkat dari ruku' yang pertama, lalu sujud. Kemudian berdiri yang kedua, dan melakukan hal yang sama, namun ruku' dan berdirinya lebih pendek dari rakaat pertama. Kemudian sujud, dan matahari telah terang kembali. Setelah selesai beliau duduk di atas mimbar lalu bersabda: 'Manusia diuji dalam kubur mereka, seperti fitnah Dajjal '.\" (secara ringkas)."},"1467":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدَةُ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَصَلَّى فَأَطَالَ الْقِيَامَ جِدًّا ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ جِدًّا ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ جِدًّا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ فَفَرَغَ مِنْ صَلَاتِهِ وَقَدْ جُلِّيَ عَنْ الشَّمْسِ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَصَلُّوا وَتَصَدَّقُوا وَاذْكُرُوا اللَّهَ عَزَّ وَجَلَّ وَقَالَ يَا أُمَّةَ مُحَمَّدٍ إِنَّهُ لَيْسَ أَحَدٌ أَغْيَرَ مِنْ اللَّهِ عَزَّ وَجَلَّ أَنْ يَزْنِيَ عَبْدُهُ أَوْ أَمَتُهُ يَا أُمَّةَ مُحَمَّدٍ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَضَحِكْتُمْ قَلِيلًا وَلَبَكَيْتُمْ كَثِيرًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami ['Abdah] dia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [bapaknya] dari ['Aisyah] dia berkata; \"Pada masa Rasulullah Shalallahu 'Alaihi Wa Sallam pernah terjadi gerhana matahari, lalu Rasulullah berdiri dan shalat. Beliau berdiri lama sekali. kemudian ruku' dan ruku'nya lama sekali. Lalu bangkit lagi dan memperlama berdirinya, namun lebih singkat dari berdiri yang pertama, kemudian ruku' dan memperlama ruku'nya, namun lebih singkat dari ruku' yang pertama. Kemudian ia mengangkat (kepalanya dari ruku') dan sujud. Lalu beliau melakukan hal tersebut pada rakaat berikutnya. Kemudian beliau beranjak dan matahari telah terang kembali. Setelah itu beliau berkhutbah kepada manusia; Beliau memuji Allah dan menyanjung-Nya; lalu bersabda: 'Matahari dan bulan tidak mengalami gerhana karena kematian atau kelahiran seseorang. Jika kalian melihat kedua gerhana tersebut, maka shalatlah, bersedakahlah dan berdzikirlah kepada Allah'. Kemudian beliau melanjutkan sabdanya: `Wahai umat Muhammad! Tidak ada seorangpun yang lebih cemburu dari Allah Azza wa Jalla bila ada hamba-Nya yang berzina atau ada hamba perempuan-Nya yang berzina. Wahai umat Muhammad! Demi Allah, seandainya kalian mengetahui apa yang aku ketahui, maka kalian pasti akan sedikit tertawa dan banyak menangis '.\""},"1468":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عَنْ سُفْيَانَ عَنْ الْأَسْوَدِ بْنِ قَيْسٍ عَنْ ثَعْلَبَةَ بْنِ عَبَّادٍ عَنْ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ حِينَ انْكَسَفَتْ الشَّمْسُ فَقَالَ أَمَّا بَعْدُ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] dia berkata; telah menceritakan kepada kami [Abu Dawud Al Ja'fari] dari [Sufyan] dari [Al Aswad bin Qais] dari [Tsa'labah bin 'Abbad] dari [Samurah]; \"Nabi Shalallahu 'Alaihi Wa Sallam berkhutbah ketika terjadi gerhana matahari dengan mengucapkan: 'Amma Ba'du'."},"1469":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا يُونُسُ عَنْ الْحَسَنِ عَنْ أَبِي بَكْرَةَ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْكَسَفَتْ الشَّمْسُ فَقَامَ إِلَى الْمَسْجِدِ يَجُرُّ رِدَاءَهُ مِنْ الْعَجَلَةِ فَقَامَ إِلَيْهِ النَّاسُ فَصَلَّى رَكْعَتَيْنِ كَمَا يُصَلُّونَ فَلَمَّا انْجَلَتْ خَطَبَنَا فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ يُخَوِّفُ بِهِمَا عِبَادَهُ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ فَإِذَا رَأَيْتُمْ كُسُوفَ أَحَدِهِمَا فَصَلُّوا وَادْعُوا حَتَّى يَنْكَشِفَ مَا بِكُمْ","id":"Telah mengabarkan kepada kami ['Amru bin 'Ali] dia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] dia berkata; telah menceritakan kepada kami [Yunus] dari [Al Hasan] dari [Abu Bakrah] dia berkata; \"Kami berada di samping Rasulullah shallallahu 'alaihi wasallam, tiba-tiba terjadi gerhana matahari, maka beliau segera berdiri menuju masjid, dan menarik selendangnya karena tergesa-gesa. Lalu orang-orang pun segera berdiri di sisinya dan beliau mengerjakan shalat dua rakaat sebagaimana mereka juga melakukannya. Setelah matahari terang, beliau berkhutbah di hadapan kami seraya bersabda: \"Matahari dan bulan tidak mengalami gerhana karena kematian atau kelahiran seseorang, tetapi keduanya merupakan tanda diantara tanda-tanda kebesaran Allah untuk menakut-nakuti hamba-Nya. Jika kalian melihat kedua gerhana tersebut, maka shalatlah dan berdoalah hingga gerhana tersingkap dari kalian (nampak kembali).\""},"1470":{"ar":"أَخْبَرَنَا مُوسَى بْنُ عَبْدِ الرَّحْمَنِ الْمَسْرُوقِيُّ عَنْ أَبِي أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَخَسَفَتْ الشَّمْسُ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزِعًا يَخْشَى أَنْ تَكُونَ السَّاعَةُ فَقَامَ حَتَّى أَتَى الْمَسْجِدَ فَقَامَ يُصَلِّي بِأَطْوَلِ قِيَامٍ وَرُكُوعٍ وَسُجُودٍ مَا رَأَيْتُهُ يَفْعَلُهُ فِي صَلَاتِهِ قَطُّ ثُمَّ قَالَ إِنَّ هَذِهِ الْآيَاتِ الَّتِي يُرْسِلُ اللَّهُ لَا تَكُونُ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّ اللَّهَ يُرْسِلُهَا يُخَوِّفُ بِهَا عِبَادَهُ فَإِذَا رَأَيْتُمْ مِنْهَا شَيْئًا فَافْزَعُوا إِلَى ذِكْرِهِ وَدُعَائِهِ وَاسْتِغْفَارِهِ","id":"Telah mengabarkan kepada kami [Musa bin 'Abdurrahman Al Masruqi] dari [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dia berkata; \"Saat terjadi gerhana matahari Nabi shallallahu 'alaihi wasallam berdiri dengan rasa takut, beliau khawatir akan terjadi kiamat. Beliau mendatangi masjid, lalu berdiri, ruku', dan sujud dengan waktu yang lama. Aku belum pernah melihat beliau melakukan hal itu dalam shalatnya. Kemudian beliau bersabda: \"Ini adalah tanda-tanda kebesaran Allah yang Dia kirimkan bukan karena kematian ataupun kelahiran seseorang, telapi Allah mengirimnya untuk menakut-nakuti hamba-Nya. Jika kalian melihatnya, maka segeralah berdzikir dan berdoa serta meminta ampunan kepada-Nya.\""},"1471":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْمَوَاشِي وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ عَزَّ وَجَلَّ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمُطِرْنَا مِنْ الْجُمُعَةِ إِلَى الْجُمُعَةِ فَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ وَانْقَطَعَتْ السُّبُلُ وَهَلَكَتْ الْمَوَاشِي فَقَالَ اللَّهُمَّ عَلَى رُءُوسِ الْجِبَالِ وَالْآكَامِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ فَانْجَابَتْ عَنْ الْمَدِينَةِ انْجِيَابَ الثَّوْبِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dari [Malik] dari [Syarik bin 'Abdullah bin Abu Namir] dari [Anas bin Malik] dia berkata; \"Ada seorang lelaki datang kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, lalu berkata; 'Wahai Rasulullah, binatang ternak telah binasa dan jalan-jalan telah terputus, maka berdoalah kepada Allah Azza wa Jalla. Kemudian Rasulullah shallallahu 'alaihi wasallam berdoa, maka turunlah hujan dari hari Jum'at ke Jum'at berikutnya.\" Lalu datang seorang lelaki kepada Rasulullah Shalallahu 'Alaihi Wa Sallam dan berkata; ' Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, rumah-rumah telah hancur. jalan-jalan telah terputus, dan binatang ternak telah binasa'. Kemudian Rasulullah Shalallahu 'Alaihi Wa Sallam berdoa: ' Ya Allah, turunkan hujan itu di atas puncak gunung, bukit, di tengah-tengah lembah, serta di tempat tumbuhnya pepohonan'. Maka awan pun menjauh dari Madinah bagaikan lepasnya baju (dari badan).\""},"1472":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا الْمَسْعُودِيُّ عَنْ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ قَالَ سُفْيَانُ فَسَأَلْتُ عَبْدَ اللَّهِ بْنَ أَبِي بَكْرٍ فَقَالَ سَمِعْتُهُ مِنْ عَبَّادِ بْنِ تَمِيمٍ يُحَدِّثُ أَبِي أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ الَّذِي أُرِيَ النِّدَاءَ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى يَسْتَسْقِي فَاسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ رِدَاءَهُ وَصَلَّى رَكْعَتَيْنِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا غَلَطٌ مِنْ ابْنِ عُيَيْنَةَ وَعَبْدُ اللَّهِ بْنُ زَيْدٍ الَّذِي أُرِيَ النِّدَاءَ هُوَ عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَبْدِ رَبِّهِ وَهَذَا عَبْدُ اللَّهِ بْنُ زَيْدِ بْنِ عَاصِمٍ","id":"Telah mengabarkan kepadaku [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepada kami [Al Mas'udi] dari [Abu Bakr bin 'Amru bin Hazm] dari ['Abbad bin Tamim], [Sufyan] berkata; 'Aku bertanya kepada ['Abdullah bin Abu Bakr] lalu dia menjawab; 'Aku mendengarnya dari ['Abbad bin Tamim]; Bapakku menceritakan bahwa ['Abdullah bin Zaid] -orang yang bermimpi tentang adzan-berkata; \" Rasulullah Shalallahu 'Alaihi Wa Sallam suatu hari keluar menuju tempat shalat untuk meminta hujan. Beliau menghadap kiblat dan membalik selendangnya, lalu shalat dua rakaat.\" Abu Abdurrahman berkata; \"Ini kesalahan dari Ibnu Uyainah, Abdullah bin Zaid yang mimpi tentang adzan- adalah Abdullah bin Zaid bin Abdu Rabbih, sedangkan ini adalah Abdullah bin Zaid bin Ashim.\""},"1473":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ هِشَامِ بْنِ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ كِنَانَةَ عَنْ أَبِيهِ قَالَأَرْسَلَنِي فُلَانٌ إِلَى ابْنِ عَبَّاسٍ أَسْأَلُهُ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الِاسْتِسْقَاءِ فَقَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَضَرِّعًا مُتَوَاضِعًا مُتَبَذِّلًا فَلَمْ يَخْطُبْ نَحْوَ خُطْبَتِكُمْ هَذِهِ فَصَلَّى رَكْعَتَيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] dan [Muhammad bin Al Mutsanna] dari ['Abdurrahman] dari [Sufyan] dari [Hisyam bin Ishaq bin 'Abdullah bin Kinanah] dari [Bapaknya] dia berkata; \"Seseorang mengutusku menemui [Ibnu Abbas], dan aku bertanya kepadanya tentang cara shalat Istisqa' Rasulullah Shalallahu 'Alaihi Wa Sallam?, maka ia menjawab; 'Rasulullah Shalallahu 'Alaihi Wa Sallam keluar dengan merendahkan diri, tawadlu, serta berpakaian sederhana. Beliau tidak berkhutbah seperti kalian. Lalu beliau shalat dua rakaat'.\""},"1474":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى وَعَلَيْهِ خَمِيصَةٌ سَوْدَاءُ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami ['Abdul 'Aziz] dari ['Umarah bin Ghaziyyah] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam memohon hujan, dan beliau mengenakan pakaian hitam."},"1475":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدِ بْنِ مُحَمَّدٍ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ هِشَامِ بْنِ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ كِنَانَةَ عَنْ أَبِيهِ قَالَسَأَلْتُ ابْنَ عَبَّاسٍ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الِاسْتِسْقَاءِ فَقَالَ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَبَذِّلًا مُتَوَاضِعًا مُتَضَرِّعًا فَجَلَسَ عَلَى الْمِنْبَرِ ��َلَمْ يَخْطُبْ خُطْبَتَكُمْ هَذِهِ وَلَكِنْ لَمْ يَزَلْ فِي الدُّعَاءِ وَالتَّضَرُّعِ وَالتَّكْبِيرِ وَصَلَّى رَكْعَتَيْنِ كَمَا كَانَ يُصَلِّي فِي الْعِيدَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid bin Muhammad] dia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Hisyam bin Ishaq bin 'Abdullah bin Kinanah] dari [Bapaknya] dia berkata; \"Aku bertanya kepada [Ibnu 'Abbas] tentang cara shalat Istisqa' Rasulullah Shalallahu 'Alaihi Wa Sallam, maka ia menjawab; 'Rasulullah Shalallahu 'Alaihi Wa Sallam keluar dengan berpakaian sederhana dan tawadlu, serta merendahkan diri. Lalu beliau duduk di atas mimbar dan tidak berkhutbah seperti kalian, namun beliau senantiasa berdoa dan merendahkan diri serta bertakbir. Kemudian shalat dua rakaat sebagaimana beliau shalat pada dua hari raya'.\""},"1476":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا الْوَلِيدُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ أَنَّ عَمَّهُ حَدَّثَهُأَنَّهُ خَرَجَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَسْقِي فَحَوَّلَ رِدَاءَهُ وَحَوَّلَ لِلنَّاسِ ظَهْرَهُ وَدَعَا ثُمَّ صَلَّى رَكْعَتَيْنِ فَقَرَأَ فَجَهَرَ","id":"Telah mengabarkan kepadaku ['Amru bin 'Utsman] dia berkata; telah menceritakan kepada kami [Al Walid] dari [Ibnu Abu Dzi'b] dari [Az Zuhri] dari ['Abbad bin Tamim], [pamannya] menceritakan kepadanya bahwa dia pernah berangkat bersama Rasulullah Shalallahu 'Alaihi Wa Sallam untuk memohon hujan. Beliau memindahkan posisi selendangnya dan membalik punggungnya (membelakangi) manusia. Kemudian berdoa dan shalat dua rakaat. Beliau membaca (ayat Al Qur'an) dengan suara yang keras.\""},"1477":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى وَصَلَّى رَكْعَتَيْنِ وَقَلَبَ رِدَاءَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Sufyan] dari ['Abdullah bin Abu Bakr] dari ['Abbad bin Tamim] dari [pamannya], bahwa Nabi Shalallahu 'Alaihi Wa Sallam pernah meminta hujan, Beliau shalat dua raka'at serta membalik selendangnya."},"1478":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّهُ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ زَيْدٍ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَسْقَى وَحَوَّلَ رِدَاءَهُ حِينَ اسْتَقْبَلَ الْقِبْلَةَ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Malik] dari ['Abdullah bin Abu Bakr] bahwasanya ia mendengar ['Abbad bin Tamim] berkata; \"Aku mendengar ['Abdullah bin Zaid] berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam keluar, lalu Beliau meminta hujan dan merubah posisi selendangnya saat menghadap kiblat.\""},"1479":{"ar":"أَخْبَرَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ أَبُو تَقِيٍّ الْحِمْصِيُّ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الِاسْتِسْقَاءِ اسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ الرِّدَاءَ وَرَفَعَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Hisyam bin 'Abdul Malik Abu Taqiyyul Himshi] dia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Syu'aib] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [pamannya] bahwasanya ia pernah melihat Rasulullah Shalallahu 'Alaihi Wa Sallam menghadap kiblat saat meminta hujan dan membalik selendangnya, serta mengangkat kedua tangannya."},"1480":{"ar":"أَخْبَرَنِي شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى بْنِ سَعِيدٍ الْقَطَّانِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ الدُّعَاءِ إِلَّا فِي الِاسْتِسْقَاءِ فَإِنَّهُ كَانَ يَرْفَعُ يَدَيْهِ حَتَّى يُرَى بَيَاضُ إِبْطَيْهِ","id":"Telah mengabarkan kepadaku [Syu'aib bin Yusuf] dari [Yahya bin Sa'id Al Qaththan] dari [Sa'id] dari [Qatadah] dari ' [Anas bin Malik] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak mengangkat kedua tangannya sedikitpun saat berdoa, kecuali saat meminta hujan. Beliau shallallahu 'alaihi wasallam mengangkat kedua tangannya hingga nampak ketiaknya yang putih.\""},"1481":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ عُمَيْرٍ مَوْلَى آبِي اللَّحْمِ عَنْ آبِي اللَّحْمِأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ أَحْجَارِ الزَّيْتِ يَسْتَسْقِي وَهُوَ مُقْنِعٌ بِكَفَّيْهِ يَدْعُو","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Khalid bin Yazid] dari [Sa'id bin Abu Hilal] dari [Yazid bin 'Abdullah] dari ['Umair] -budak Abu Al Lahm- dari [Abu Al Lahm] bahwa dia pernah melihat Rasulullah Shalallahu 'Alaihi Wa Sallam berada di Ahjaruz Zait (suatu tempat di Madinah) sedang meminta hujan. Beliau berdo? dengan mengangkat telapak tangannya."},"1482":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدٍ وَهُوَ الْمَقْبُرِيُّ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ سَمِعَهُ يَقُولُبَيْنَا نَحْنُ فِي الْمَسْجِدِ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ تَقَطَّعَتْ السُّبُلُ وَهَلَكَتْ الْأَمْوَالُ وَأَجْدَبَ الْبِلَادُ فَادْعُ اللَّهَ أَنْ يَسْقِيَنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ حِذَاءَ وَجْهِهِ فَقَالَ اللَّهُمَّ اسْقِنَا فَوَاللَّهِ مَا نَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِنْبَرِ حَتَّى أُوسِعْنَا مَطَرًا وَأُمْطِرْنَا ذَلِكَ الْيَوْمَ إِلَى الْجُمُعَةِ الْأُخْرَى فَقَامَ رَجُلٌ لَا أَدْرِي هُوَ الَّذِي قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقِ لَنَا أَمْ لَا فَقَالَ يَا رَسُولَ اللَّهِ انْقَطَعَتْ السُّبُلُ وَهَلَكَتْ الْأَمْوَالُ مِنْ كَثْرَةِ الْمَاءِ فَادْعُ اللَّهَ أَنْ يُمْسِكَ عَنَّا الْمَاءَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا وَلَكِنْ عَلَى الْجِبَالِ وَمَنَابِتِ الشَّجَرِ قَالَ وَاللَّهِ مَا هُوَ إِلَّا أَنْ تَكَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ تَمَزَّقَ السَّحَابُ حَتَّى مَا نَرَى مِنْهُ شَيْئًا","id":"Telah mengabarkan kepada kami ['Isa bin Hammad] dia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id Al Maqburi] dari [Syarik bin 'Abdullah bin Abu Namir] dari [Anas bin Malik], bahwasanya dia (Syarik) mendengar Anas berkata; \"Ketika kami sedang di masjid pada hari Jum'at dan Rasulullah Shalallahu 'Alaihi Wa Sallam sedang menyampaikan khutbah kepada manusia, tiba-tiba ada seorang lelaki yang berdiri dan berkata; 'Wahai Rasulullah, jalan-jalan telah terputus, harta benda telah binasa, dan negeri telah paceklik, maka berdoalah kepada Allah agar Dia menurunkan hujan kepada kami'. Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam mengangkat kedua tangannya sejajar dengan wajahnya sambil mengucapkan: 'Ya Alllah, turunkan hujan kepada kami'. Demi Allah, sebelum Rasulullah shallallahu 'alaihi wasallam sempat turun dari mimbarnya, kami sudah diguyur hujan. Kami diberi hujan pada hari itu sampai Jum'at berikutnya. Lalu ada orang lelaki, -aku tidak tahu apakah dia yang telah berkata kepada Rasulullah shallallahu 'alaihi wasallam 'Berilah kami hujan' atau bukan- berkata; 'Wahai Rasulullah, jalan-jalan telah terputus dan harta benda telah hancur karena melimpahnya air, maka berdoalah kepada Allah agar Dia menahan air itu dari kami'. Lalu Rasulullah shallallahu 'alaihi wasallam berdoa: 'Ya Allah (turunkanlah hujan) di sekitar kami dan jangan atas kami, tetapi di gunung-gunung dan di tempat-tempat tumbuhnya pepohonan'.\" Anas berkata; \"Demi Allah, tidaklah Rasulullah shallallahu 'alaihi wasallam mengatakan demikian kecuali awan itu telah berpencar hingga kami tidak melihatnya sedikitpun.\""},"1483":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنِي أَبُو هِشَامٍ الْمُغِيرَةُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي وُهَيْبٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ اسْقِنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dia berkata; telah menceritakan kepadaku [Abu Hisyam Al Mughirah bin Salamah] dia berkata; telah menceritakan kepadaku [Wuhaib] dia berkata; Telah menceritakan kepada kami [Yahya bin Sa'id] dari [Anas bin Malik], bahwa Nabi Shalallahu 'Alaihi Wa Sallam bersabda: \"Ya Allah turunkanlah hujan kepada kami.\""},"1484":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ بْنَ عُمَرَ وَهُوَ الْعُمَرِيُّ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَقَامَ إِلَيْهِ النَّاسُ فَصَاحُوا فَقَالُوا يَا نَبِيَّ اللَّهِ قَحَطَتْ الْمَطَرُ وَهَلَكَتْ الْبَهَائِمُ فَادْعُ اللَّهَ أَنْ يَسْقِيَنَا قَالَ اللَّهُمَّ اسْقِنَا اللَّهُمَّ اسْقِنَا قَالَ وَايْمُ اللَّهِ مَا نَرَى فِي السَّمَاءِ قَزَعَةً مِنْ سَحَابٍ قَالَ فَأَنْشَأَتْ سَحَابَةٌ فَانْتَشَرَتْ ثُمَّ إِنَّهَا أُمْطِرَتْ وَنَزَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى وَانْصَرَفَ النَّاسُ فَلَمْ تَزَلْ تَمْطُرُ إِلَى يَوْمِ الْجُمُعَةِ الْأُخْرَى فَلَمَّا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ صَاحُوا إِلَيْهِ فَقَالُوا يَا نَبِيَّ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ وَتَقَطَّعَتْ السُّبُلُ فَادْعُ اللَّهَ أَنْ يَحْبِسَهَا عَنَّا فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَتَقَشَّعَتْ عَنْ الْمَدِينَةِ فَجَعَلَتْ تَمْطُرُ حَوْلَهَا وَمَا تَمْطُرُ بِالْمَدِينَةِ قَطْرَةً فَنَظَرْتُ إِلَى الْمَدِينَةِ وَإِنَّهَا لَفِي مِثْلِ الْإِكْلِيلِ","id":"Telah mengabarkan kepada kami [Muhammad ibn 'Abdul A'la] dia berkata; telah menceritakan kepada kami [Al Mu'tamir] dia berkata; aku mendengar ['Ubaidullah bin 'Umar Al 'Umari] dari [Tsabit] dari [Anas bin Malik] dia berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam pernah khutbah pada hari Jum'at, maka orang-orang segera berkumpul dan berteriak kepadanya dengan berkata; 'Wahai Nabi Allah, hujan telah terputus dan binatang ternak telah binasa, maka berdoalah kepada Allah agar Dia menurunkan hujan kepada kami'. Beliau Shalallahu 'Alaihi Wa Sallam lalu berdoa: `Ya Allah, berilah kami hujan. Ya Allah, berilah kami hujan'. Anas berkata; \"Demi Allah, kami tidak melihat setitik awan pun di langit.\" Dia melanjutkan lagi, \"Lalu awan muncul dan bertebaran, kemudian menurunkan hujan. Setelah itu Rasulullah turun dari mimbar, kemudian shalat. Manusia pun bubar, sedangkan hujan belum reda sampai dengan Jum'at berikutnya. Ketika Rasulullah shallallahu 'alaihi wasallam berdiri untuk khutbah, orang-orang berteriak kepadanya dengan berkata; 'Wahai Nabi Allah, rumah-rumah telah hancur dan jalan-jalan telah terputus, maka berdoalah agar Dia menahan hujan dari kami'. Rasulullah shallallahu 'alaihi wasallam tersenyum, lalu berdoa: `Ya Allah (berilah hujan) di sekitar kami dan jangan di atas kami'. Maka terhentilah hujan itu di Madinah, dan hujan hanya turun di sekitarnya. Di Madinah tidak turun setetes pun, aku melihat Madinah laksana di kelilingi awan.\""},"1485":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شَرِيكُ بْنُ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا وَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ أَنْ يُغِيثَنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ أَغِثْنَا اللَّهُمَّ أَغِثْنَا قَالَ أَنَسٌ وَلَا وَاللَّهِ مَا نَرَى فِي السَّمَاءِ مِنْ سَحَابَةٍ وَلَا قَزَعَةٍ وَمَا بَيْنَنَا وَبَيْنَ سَلْعٍ مِنْ بَيْتٍ وَلَا دَارٍ فَطَلَعَتْ سَحَابَةٌ مِثْلُ التُّرْسِ فَلَمَّا تَوَسَّطَتْ السَّمَاءَ انْتَشَرَتْ وَأَمْطَرَتْ قَالَ أَنَسٌ وَلَا وَاللَّهِ مَا رَأَيْنَا الشَّمْسَ سَبْتًا قَالَ ثُمَّ دَخَلَ رَجُلٌ مِنْ ذَلِكَ الْبَابِ فِي الْجُمُعَةِ الْمُقْبِلَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَهُ قَائِمًا فَقَالَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ وَسَلَّمَ عَلَيْكَ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ أَنْ يُمْسِكَهَا عَنَّا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ فَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا اللَّهُمَّ عَلَى الْآكَامِ وَالظِّرَابِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ قَالَ فَأَقْلَعَتْ وَخَرَجْنَا نَمْشِي فِي الشَّمْسِقَالَ شَرِيكٌ سَأَلْتُ أَنَسًا أَهُوَ الرَّجُلُ الْأَوَّلُ قَالَ لَا","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il bin Ja'far] dia berkata; telah menceritakan kepada kami [Syarik bin 'Abdullah] dari [Anas bin Malik]; \"Ada seorang lelaki yang datang kepada Rasulullah Shalallahu 'Alaihi Wa Sallam, sedangkan beliau sedang khutbah sambil berdiri, lalu dia menghadap kepada beliau sambil berdiri lantas berkata; 'Wahai Rasulullah, harta benda telah hancur dan jalan-jalan telah terputus, maka berdoalah kepada Allah Azza wa Jalla agar Dia menolong kami'. Kemudian Rasulullah Shalallahu 'Alaihi Wa Sallam mengangkat kedua tangannya dan berdoa: 'Ya Allah, tolonglah kami. Ya Allah, tolonglah kami'.\" Anas berkata; \"Tidak, demi Allah, kami tidak melihat awan di langit, juga tidak ada mendung, padahal tidak ada rumah di antara kami dan gunung Sala' (sebuah gunung di Madinah), lalu muncul awan laksana perisai, dan setelah awan berada di tengah-tengah langit maka awan itu menyebar, sehingga turun menjadi hujan. Demi Allah, kami tidak melihat matahari selama satu pekan.\" Anas melanjutkan, \"Kemudian pada hari Jum'at berikutnya seorang lelaki datang kepada Rasulullah Shalallahu 'Alaihi Wa Sallam dari pintu tadi ketika beliau Shalallahu 'Alaihi Wa Sallam sedang khutbah sambil berdiri, lalu orang tadi berkata; 'Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, harta benda telah hancur dan jalan-jalan telah terputus, maka berdoalah kepada Allah agar Dia menahan hujan dari kami'. Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam mengangkat kedua tangannya sambil berdoa, 'Ya Allah (turunkan hujan) di sekitar kami dan jangan di atas kami. Ya Allah, turunkan di bukit-bukit, gunung-gunung, lubuk lembah, serta di tempat tumbuhnya pepohonan'. Maka awan pun lenyap, lalu kami keluar dan berjalan di bawah teriknya matahari.\" Syarik berkata; \"Aku bertanya kepada Anas; `Apakah dia lelaki yang pertama tadi? ' la menjawab, 'Bukan'.\""},"1486":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ عَنْ ابْنِ أَبِي ذِئْبٍ وَيُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبَّادُ بْنُ تَمِيمٍ أَنَّهُ سَمِعَ عَمَّهُ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يَسْتَسْقِي فَحَوَّلَ إِلَى النَّاسِ ظَهْرَهُ يَدْعُو اللَّهَ وَيَسْتَقْبِلُ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُ ثُمَّ صَلَّى رَكْعَتَيْنِ قَالَ ابْنُ أَبِي ذِئْبٍ فِي الْحَدِيثِ وَقَرَأَ فِيهِمَا","id":"Telah berkata [Al Harits bin Miskin] dalam bentuk baca dan aku mendengarnya dari [Ibnu Wahb] dari [Ibnu Abu Dzi'b] dan [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Abbad bin Tamim] bahwasanya ia mendengar [pamannya] -seorang sahabat Rasulullah Shalallahu 'Alaihi Wa Sallam- dia berkata; \"Pada suatu hari Rasulullah Shalallahu 'Alaihi Wa Sallam keluar untuk meminta hujan, lalu beliau membalik punggungnya (membelakangi manusia) dan berdoa sambil menghadap kiblat. Beliau juga membalik selendangnya, kemudian shalat dua rakaat.\" Ibnu Abu Dzi'ib berkata; 'Dan membaca surat dalam dua rakaat tersebut.'"},"1487":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَحْيَى عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَسْتَسْقِي فَصَلَّى رَكْعَتَيْنِ وَاسْتَقْبَلَ الْقِبْلَةَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yahya] dari [Abu Bakr bin Muhammad] dari ['Abbad bin Tamim] dari ['Abdullah bin Zaid] bahwa Nabi Shalallahu 'Alaihi Wa Sallam keluar untuk shalat Istisqa', lalu shalat dua rakaat dan menghadap kiblat."},"1488":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ كِنَانَةَ عَنْ أَبِيهِ قَالَأَرْسَلَنِي أَمِيرٌ مِنْ الْأُمَرَاءِ إِلَى ابْنِ عَبَّاسٍ أَسْأَلُهُ عَنْ الِاسْتِسْقَاءِ فَقَالَ ابْنُ عَبَّاسٍ مَا مَنَعَهُ أَنْ يَسْأَلَنِي خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَوَاضِعًا مُتَبَذِّلًا مُتَخَشِّعًا مُتَضَرِّعًا فَصَلَّى رَكْعَتَيْنِ كَمَا يُصَلِّي فِي الْعِيدَيْنِ وَلَمْ يَخْطُبْ خُطْبَتَكُمْ هَذِهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] dia berkata; telah menceritakan kepada kami [Waki'] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Hisyam bin Ishaq bin 'Abdullah bin Kinanah] dari [bapaknya] dia berkata; \"Seorang amir mengutusku kepada Ibnu 'Abbas untuk menanyakan tentang shalat Istisqa, maka [Ibnu 'Abbas] berkata; \"Seorang amir (pemimpin) mengutusku kepada Ibnu Abbas, untuk bertanya kepadanya tentang cara shalat lstisqa' Rasulullah Shalallahu 'Alaihi Wa Sallam? la menjawab, 'Apa yang menghalanginya untuk bertanya kepadaku? Rasulullah Shalallahu 'Alaihi Wa Sallam keluar dengan tawadhu', berpakaian sederhana, khusyu', dan merendahkan diri. Lalu shalat dua rakaat sebagaimana shalat dua hari raya, dan beliau tidak berkhutbah seperti khutbah kalian ini'.\""},"1489":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَاسْتَسْقَى فَصَلَّى رَكْعَتَيْنِ جَهَرَ فِيهِمَا بِالْقِرَاءَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] dia berkata; telah menceritakan kepada kami [Yahya bin Adam] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Dzi'b] dari [Az Zuhri] dari ['Abbad bin Tamim] dari [pamannya] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam pernah keluar untuk memohon hujan, maka beliau shalat dua rakaat dan membaca (ayat Al Qur'an) dengan suara yang keras pada dua rakaat tersebut."},"1490":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مِسْعَرٍ عَنْ الْمِقْدَامِ بْنِ شُرَيْحٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا أُمْطِرَ قَالَ اللَّهُمَّ اجْعَلْهُ صَيِّبًا نَافِعًا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Mis'ar] dari [Al Miqdam bin Syuraih] dari [bapaknya] dari ['Aisyah] bahwa Rasulullah Shalallahu 'Alaihi Wa Sallam bila turun hujan, maka beliau mengucapkan: \"Ya, Allah jadikanlah hujan ini bermanfaat.\""},"1491":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادِ بْنِ الْأَسْوَدِ بْنِ عَمْرٍو قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُ عَزَّ وَجَلَّ مَا أَنْعَمْتُ عَلَى عِبَادِي مِنْ نِعْمَةٍ إِلَّا أَصْبَحَ فَرِيقٌ مِنْهُمْ بِهَا كَافِرِينَ يَقُولُونَ الْكَوْكَبُ وَبِالْكَوْكَبِ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad bin Al Aswad bin 'Amr] dia berkata; telah memberitakan kepada kami [Ibnu Wahb] dia berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dia berkata; telah mengabarkan kepadaku ['Ubaidullah bin 'Abdullah bin 'Utbah] dari [Abu Hurairah] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam bersabda: \"Allah Azza wa Jalla berfirman: 'Tidaklah Aku menganugerahkan suatu nikmat kepada hamba-hambaku melainkan sebagian mereka ada yang kufur, mereka berkata; \"Ini terjadi dengan sebab bintang-bintang!\""},"1492":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَمُطِرَ النَّاسُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَلَمْ تَسْمَعُوا مَاذَا قَالَ رَبُّكُمْ اللَّيْلَةَ قَالَ مَا أَنْعَمْتُ عَلَى عِبَادِي مِنْ نِعْمَةٍ إِلَّا أَصْبَحَ طَائِفَةٌ مِنْهُمْ بِهَا كَافِرِينَ يَقُولُونَ مُطِرْنَا بِنَوْءِ كَذَا وَكَذَا فَأَمَّا مَنْ آمَنَ بِي وَحَمِدَنِي عَلَى سُقْيَايَ فَذَاكَ الَّذِي آمَنَ بِي وَكَفَرَ بِالْكَوْكَبِ وَمَنْ قَالَ مُطِرْنَا بِنَوْءِ كَذَا وَكَذَا فَذَاكَ الَّذِي كَفَرَ بِي وَآمَنَ بِالْكَوْكَبِ","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Shalih bin Kaisan] dari ['Ubaidullah bin 'Abdullah] dari [Zaid bin Khalid Al Juhani] dia berkata; \"Pada masa Rasulullah Shalallahu 'Alaihi Wa Sallam, hujan turun, maka beliau bersabda: 'Apakah tadi malam kalian tidak mendengar perkataan Rabb kalian? Dia berfirman, \"Tidaklah Aku menganugerahkan suatu nikmat kepada hamba-hamba-Ku melainkan sebagian mereka ada yang kufur dengan nikmat tersebut, mereka berkata; `Kami diberi hujan dengan sebab bintang ini dan itu. Sedangkan orang yang beriman kepada-Ku, ia memuji-Ku karena air yang Aku turunkan, maka itulah orang yang beriman kepada-Ku dan kufur terhadap bintang-bintang. Sedangkan orang yang berkata; 'Kami diberi hujan dengan sebab bintang ini dan itu' adalah orang yang kufur kepada-Ku dan beriman kepada bintang-bintang'.\""},"1493":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ عَنْ سُفْيَانَ عَنْ عَمْرٍو عَنْ عَتَّابِ بْنِ حُنَيْنٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَمْسَكَ اللَّهُ عَزَّ وَجَلَّ الْمَطَرَ عَنْ عِبَادِهِ خَمْسَ سِنِينَ ثُمَّ أَرْسَلَهُ لَأَصْبَحَتْ طَائِفَةٌ مِنْ النَّاسِ كَافِرِينَ يَقُولُونَ سُقِينَا بِنَوْءِ الْمِجْدَحِ","id":"Telah mengabarkan kepada kami ['Abdul Jabbar bin Al 'Ala] dari [Sufyan] dari ['Amr] dari ['Attab bin Hunain] dari [Abu Sa'id Al Khudri] dia berkata; Rasulullah Shalallahu 'Alaihi Wa Sallam: \"Seandainya Allah menahan hujan kepada para hambanya selama lima tahun, kemudian mengirimkannya, maka pasti sebagian manusia akan kafir sambil mengatakan; 'kami diberi hujan karena bintang Mijdah.' Ket. Bintang Mijdah: Nama sebuah bintang yang dikenal oleh kalangan orang-orang sebagai lambang turunnya hujan."},"1494":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَقَحَطَ الْمَطَرُ عَامًا فَقَامَ بَعْضُ الْمُسْلِمِينَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ جُمُعَةٍ فَقَالَ يَا رَسُولَ اللَّهِ قَحَطَ الْمَطَرُ وَأَجْدَبَتْ الْأَرْضُ وَهَلَكَ الْمَالُ قَالَ فَرَفَعَ يَدَيْهِ وَمَا نَرَى فِي السَّمَاءِ سَحَابَةً فَمَدَّ يَدَيْهِ حَتَّى رَأَيْتُ بَيَاضَ إِبْطَيْهِ يَسْتَسْقِي اللَّهَ عَزَّ وَجَلَّ قَالَ فَمَا صَلَّيْنَا الْجُمُعَةَ حَتَّى أَهَمَّ الشَّابَّ الْقَرِيبَ الدَّارِ الرُّجُوعُ إِلَى أَهْلِهِ فَدَامَتْ جُمُعَةٌ فَلَمَّا كَانَتْ الْجُمُعَةُ الَّتِي تَلِيهَا قَالُوا يَا رَسُولَ اللَّهِ تَهَدَّمَتْ الْبُيُوتُ وَاحْتَبَسَ الرُّكْبَانُ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ ��َسَلَّمَ لِسُرْعَةِ مَلَالَةِ ابْنِ آدَمَ وَقَالَ بِيَدَيْهِ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَتَكَشَّطَتْ عَنْ الْمَدِينَةِ","id":"Telah mengabarkan kepada kami ['Ali bin Hujr] dia berkata; telah menceritakan kepada kami [Isma'il] dia berkata; telah menceritakan kepada kami [Humaid] dari [Anas] dia berkata; '\"Hujan pernah tidak turun selama satu tahun, maka sebagian kaum muslim datang kepada Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at. Mereka berkata; 'Wahai Rasulullah, hujan telah terhenti, bumi telah menjadi tandus, dan harta benda telah hancur'. Lalu Rasulullah Shalallahu 'Alaihi Wa Sallam mengangkat kedua tangannya. Kami tidak melihat awan di langit. Lalu beliau menjulurkan tangannya (hingga kami melihat putihnya ketiak beliau Shalallahu 'Alaihi Wa Sallam) untuk meminta hujan kepada Allah Azza wa Jalla.\" Anas berkata; \"Kami belum (selesai) shalat Jum'at, namun seseorang yang tinggal dekat dengan masjid sudah merasa sulit untuk pulang ke keluarganya (karena derasnya hujan penerj). Hal tersebut berlangsung sampai hari Jum'at berikutnya. Pada hari Jum'at berikutnya orang-orang berkata kepada Rasulullah shallallahu 'alaihi wasallam, 'Wahai Rasulullah, rumah-rumah telah hancur dan kendaraan tak bisa berjalan Anas berkata; \"Rasulullah shallallahu 'alaihi wasallam tersenyum karena cepatnya rasa bosan anak Adam, lalu beliau bersabda: `Ya Allah (turunkanlah hujan) disekitar kami dan jangan di atas kami'. Lalu awan atau hujan itu menjauh dari Madinah.\""},"1495":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ أَنْبَأَنَا أَبُو عَمْرٍو الْأَوْزَاعِيُّ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَأَصَابَ النَّاسُ سَنَةٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ فَقَامَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْمَالُ وَجَاعَ الْعِيَالُ فَادْعُ اللَّهَ لَنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ وَمَا نَرَى فِي السَّمَاءِ قَزَعَةً وَالَّذِي نَفْسِي بِيَدِهِ مَا وَضَعَهَا حَتَّى ثَارَ سَحَابٌ أَمْثَالُ الْجِبَالِ ثُمَّ لَمْ يَنْزِلْ عَنْ مِنْبَرِهِ حَتَّى رَأَيْتُ الْمَطَرَ يَتَحَادَرُ عَلَى لِحْيَتِهِ فَمُطِرْنَا يَوْمَنَا ذَلِكَ وَمِنْ الْغَدِ وَالَّذِي يَلِيهِ حَتَّى الْجُمُعَةِ الْأُخْرَى فَقَامَ ذَلِكَ الْأَعْرَابِيُّ أَوْ قَالَ غَيْرُهُ فَقَالَ يَا رَسُولَ اللَّهِ تَهَدَّمَ الْبِنَاءُ وَغَرِقَ الْمَالُ فَادْعُ اللَّهَ لَنَا فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ فَقَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا فَمَا يُشِيرُ بِيَدِهِ إِلَى نَاحِيَةٍ مِنْ السَّحَابِ إِلَّا انْفَرَجَتْ حَتَّى صَارَتْ الْمَدِينَةُ مِثْلَ الْجَوْبَةِ وَسَالَ الْوَادِي وَلَمْ يَجِئْ أَحَدٌ مِنْ نَاحِيَةٍ إِلَّا أَخْبَرَ بِالْجَوْدِ","id":"Telah mengabarkan kepada kami [Mahmud bin Khalid] dia berkata; telah menceritakan kepada kami [Al Walid bin Muslim] dia berkata; telah memberitakan kepada kami [Abu 'Amr Al Auza'i] dari [Ishaq bin 'Abdullah] dari [Anas bin Malik] dia berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam terjadi paceklik selama satu tahun. Ketika Rasulullah sedang khutbah pada hari Jum'at, tiba-tiba seorang Badui berdiri lalu berkata; 'Wahai Rasulullah shallallahu 'alaihi wasallam, harta benda hancur dan keluarga kelaparan, maka berdoalah kepada Allah untuk kami'. Lalu Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya, dan saat itu kami tidak melihat gumpalan awan di langit. Demi Dzat yang jiwaku ada di tangan-Nya, Rasulullah Shalallahu 'Alaihi Wa Sallam belum meletakkan tangannya kembali, namun awan telah menggumpal laksana gunung. Ketika beliau masih di mimbarnya, kami melihat hujan telah turun hingga menetes ke jenggotnya. Kami diguyur hujan pada hari itu dan besoknya, hingga sampai hari Jum'at berikutnya. Lalu orang Badui itu berdiri atau orang lain kemudian berkata; Wahai Rasulullah Shalallahu 'Alaihi Wa Sallam, bangunan telah hancur dan harta benda telah tenggelam, maka berdoalah kepada Allah untuk kami. Lalu Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya sambil mengucapkan, Ya Allah (turunkanlah hujan) di sekitar kami dan jangan di atas kami'. Tidaklah Rasulullah shallallahu 'alaihi wasallam mengisyaratkan dengan tangannya ke sudut awan itu, melainkan awan itu berpencar sehingga Madinah menjadi cerah laksana kota yang dikelilingi suatu lingkaran. Lembah-lembah telah mengalir airnya dan tak ada orang yang datang ke Madinah dari arah mana saja melainkan ia akan menceritakan tentang hujan yang telah turun dengan sangat lebat.\""},"1496":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَشْعَثِ بْنِ أَبِي الشَّعْثَاءِ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍ قَالَكُنَّا مَعَ سَعِيدِ بْنِ الْعَاصِي بِطَبَرِسْتَانَ وَمَعَنَا حُذَيْفَةُ بْنُ الْيَمَانِ فَقَالَ أَيُّكُمْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَقَالَ حُذَيْفَةُ أَنَا فَوَصَفَ فَقَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ بِطَائِفَةٍ رَكْعَةً صَفٍّ خَلْفَهُ وَطَائِفَةٍ أُخْرَى بَيْنَهُ وَبَيْنَ الْعَدُوِّ فَصَلَّى بِالطَّائِفَةِ الَّتِي تَلِيهِ رَكْعَةً ثُمَّ نَكَصَ هَؤُلَاءِ إِلَى مَصَافّ�� أُولَئِكَ وَجَاءَ أُولَئِكَ فَصَلَّى بِهِمْ رَكْعَةً","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dia berkata; telah menceritakan kepada kami [Waqi'] dia berkata; telah menceritakan kepada kami [Sufyan] dari [Al Asy'ats bin Abu Asy Sya'tsa] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam] dia berkata; kami bersama Sa'id bin Al 'Ashi di Thabristan dan bersama kami [Hudzaifah bin Al Yaman], Sa'id bertanya; 'Siapakah diantara kalian yang pernah shalat khauf bersama Rasulullah Shalallahu 'Alaihi Wa Sallam? ' Hudzaifah menjawab; 'Aku', Lalu dia menggambarkan shalat Khaufnya Rasulullah Shalallahu 'Alaihi Wa Sallam dengan berkata; 'Rasulullah Shalallahu 'Alaihi Wa Sallam mengerjakan shalat Khauf bersama suatu kelompok satu rakaat dengan satu shaf jamaah di belakangnya, dan kelompok yang lain berhadapan dengan musuh. Lalu beliau shalat dengan kelompok lainnya (yang tadi berhadapan dengan musuh) satu rakaat juga. Kemudian mereka (yang shalat bersama beliau) mundur dan menuju kelompok yang tadinya berhadapan dengan musuh, lalu kelompok tadi datang kemudian shalat bersama Rasulullah Shalallahu 'Alaihi Wa Sallam satu rakaat.\""},"1497":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي أَشْعَثُ بْنُ سُلَيْمٍ عَنْ الْأَسْوَدِ بْنِ هِلَالٍ عَنْ ثَعْلَبَةَ بْنِ زَهْدَمٍ قَالَكُنَّا مَعَ سَعِيدِ بْنِ الْعَاصِي بِطَبَرِسْتَانَ فَقَالَ أَيُّكُمْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَقَالَ حُذَيْفَةُ أَنَا فَقَامَ حُذَيْفَةُ فَصَفَّ النَّاسُ خَلْفَهُ صَفَّيْنِ صَفًّا خَلْفَهُ وَصَفًّا مُوَازِيَ الْعَدُوِّ فَصَلَّى بِالَّذِي خَلْفَهُ رَكْعَةً ثُمَّ انْصَرَفَ هَؤُلَاءِ إِلَى مَكَانِ هَؤُلَاءِ وَجَاءَ أُولَئِكَ فَصَلَّى بِهِمْ رَكْعَةً وَلَمْ يَقْضُواأَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي الرُّكَيْنُ بْنُ الرَّبِيعِ عَنْ الْقَاسِمِ بْنِ حَسَّانَ عَنْ زَيْدِ بْنِ ثَابِتٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ صَلَاةِ حُذَيْفَةَ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; telah menceritakan kepada kami [Sufyan] dia berkata; telah menceritakan kepadaku [Asy'ats bin Sulaim] dari [Al Aswad bin Hilal] dari [Tsa'labah bin Zahdam] dia berkata; \"Kami pernah bersama Said bin Al Ash di Thibristan. Aku berkata, `Siapakah di antara kalian yang pernah shalat Khauf bersama Rasulullah Shalallahu 'Alaihi Wa Sallam? ' [Hudzaifah bin Al Yaman] berkata; 'Aku'. lalu ia berdiri dan menyuruh jamaah untuk berbaris menjadi dua baris di belakangnya. Satu baris di belakangnya dan yang satu lagi berhadapan dengan musuh. Dia mengerjakan shalat satu rakaat dengan barisan yang berada di belakangnya, kemudian mereka (yang di belakangnya) pergi menuju barisan yang berhadapan dengan musuh, dan mereka datang kepadanya lalu shalat satu rakaat, dan mereka tidak mengqadhanya'.\" Telah mengabarkan kepada kami ['Amru bin Ali] dia berkata; telah menceritakan kepada kami [Yahya] dia berkata; Telah menceritakan kepada kami [Sufyan] dia berkata; Telah menceritakan kepadaku [Ar Rukain bin Rabi'] dari [Al Qasim bin Hasan] dari [Zaid bin Tsabit] dari Nabi Shalallahu 'Alaihi Wa Sallam, sebagaimana shalatnya Hudzaifah.'"},"1498":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَفَرَضَ اللَّهُ الصَّلَاةَ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْحَضَرِ أَرْبَعًا وَفِي السَّفَرِ رَكْعَتَيْنِ وَفِي الْخَوْفِ رَكْعَةً","id":"Telah mengabarkan kepada kami [Qutaibah] dia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Bukair bin Al Akhnas] dari [Mujahid] dari [Ibnu 'Abbas] dia berkata; \"Allah telah mewajibkan shalat lewat lisan Nabi kalian Shalallahu 'Alaihi Wa Sallam, dalam keadaan bermukim empat rakaat, dalam perjalanan dua rakaat, dan dalam keadaan khauf/takut (perang) satu rakaat.\""},"1499":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ عَنْ مُحَمَّدٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ النَّاسُ مَعَهُ فَكَبَّرَ وَكَبَّرُوا ثُمَّ رَكَعَ وَرَكَعَ أُنَاسٌ مِنْهُمْ ثُمَّ سَجَدَ وَسَجَدُوا ثُمَّ قَامَ إِلَى الرَّكْعَةِ الثَّانِيَةِ فَتَأَخَّرَ الَّذِينَ سَجَدُوا مَعَهُ وَحَرَسُوا إِخْوَانَهُمْ وَأَتَتْ الطَّائِفَةُ الْأُخْرَى فَرَكَعُوا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدُوا وَالنَّاسُ كُلُّهُمْ فِي صَلَاةٍ يُكَبِّرُونَ وَلَكِنْ يَحْرُسُ بَعْضُهُمْ بَعْضًا","id":"Telah mengabarkan kepadaku ['Amr bin 'Utsman bin Sa'id bin Katsir] dari [Muhammad] dari [Az Zubaidi] dari [Az Zuhri] dari ['Ubaidullah bin 'Abdullah bin 'Utbah] bahwasanya ['Abdullah bin 'Abbas] berkata; \"Rasulullah Shalallahu 'Alaihi Wa Sallam berdiri dan orang-orang ikut berdiri bersamanya. Beliau lalu bertakbir dan mereka pun ikut bertakbir bersamanya. Lalu beliau ruku', dan sebagian ikut ruku'. Kemudian beliau sujud, dan (sebagian) juga ikut sujud. Kemudian beliau berdiri ke rakaat yang kedua, dan orang-orang yang ikut sujud tadi mundur lalu menjaga saudara-saudara mereka yang sedang shalat. Setelah itu datang barisan yang lain, mereka segera ruku' dan sujud bersama Nabi Shalallahu 'Alaihi Wa Sallam. Semuanya mengerjakan shalat bersama-sama; mereka bertakbir, namun sebagian mereka menjaga sebagian yang lain."},"1500":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي دَاوُدُ بْنُ الْحُصَيْنِ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَمَا كَانَتْ صَلَاةُ الْخَوْفِ إِلَّا سَجْدَتَيْنِ كَصَلَاةِ أَحْرَاسِكُمْ هَؤُلَاءِ الْيَوْمَ خَلْفَ أَئِمَّتِكُمْ هَؤُلَاءِ إِلَّا أَنَّهَا كَانَتْ عُقَبًا قَامَتْ طَائِفَةٌ مِنْهُمْ وَهُمْ جَمِيعًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَجَدَتْ مَعَهُ طَائِفَةٌ مِنْهُمْ ثُمَّ قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامُوا مَعَهُ جَمِيعًا ثُمَّ رَكَعَ وَرَكَعُوا مَعَهُ جَمِيعًا ثُمَّ سَجَدَ فَسَجَدَ مَعَهُ الَّذِينَ كَانُوا قِيَامًا أَوَّلَ مَرَّةٍ فَلَمَّا جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالَّذِينَ سَجَدُوا مَعَهُ فِي آخِرِ صَلَاتِهِمْ سَجَدَ الَّذِينَ كَانُوا قِيَامًا لِأَنْفُسِهِمْ ثُمَّ جَلَسُوا فَجَمَعَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالتَّسْلِيمِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'd bin Ibrahim] dia berkata; [pamanku] telah menceritakan kepada kami, dia berkata; [bapakku] telah menceritakan kepada kami, dari [Ibnu Ishaq] dia berkata; telah menceritakan kepadaku [Dawud bin Al Hushain] dari ['Ikrimah] dari [Ibnu 'Abbas] dia berkata; \"Shalat Khauf itu dua kali sujud, seperti shalatnya penjaga-penjaga kalian pada hari ini, di belakang pemimpin-pemimpin mereka, tetapi mereka melakukannya secara bergantian; semuanya berdiri bersama Rasulullah shallallahu 'alaihi wasallam, sebagian dari mereka ikut sujud bersamanya (dan sebagian yang lain tetap berdiri), kemudian Rasulullah shallallahu 'alaihi wasallam berdiri dan mereka semuanya ikut berdiri bersamanya. Tatkala beliau ruku', mereka semuanya ikut ruku'. Jika beliau sujud, maka sebagian yang berdiri tadi ikut sujud bersama beliau. Setelah Rasulullah Shalallahu 'Alaihi Wa Sallam duduk bersama orang yang sujud bersamanya di akhir shalat, maka orang-orang yang berdiri tadi sujud lalu mereka duduk. Kemudian mereka semua mengucapkan salam bersama Rasulullah Shalallahu 'Alaihi Wa Sallam secara bersama-sama."}};
